-- Poems batch 144
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('7b5be099-0f6c-4f1b-a6ba-172f32029ed6','孟知府令嗣求法名興福','釋崇嶽','宋','宋诗','song-poetry','','[]','興福奇兒，福無邊表。',20,'全唐诗/poet.song.149000.json','["興福奇兒，福無邊表。", "一點靈臺，青天月皎。"]'),
('0e1cab05-4100-4d8d-af81-5109b49440b3','興密','釋崇嶽','宋','宋诗','song-poetry','','[]','密在汝邊，諸法亦然。',36,'全唐诗/poet.song.149000.json','["密在汝邊，諸法亦然。", "一舉兩得，無黨無偏。", "趙州八百箇中玄，箕裘事業尤堪傳。"]'),
('5752ab4b-216f-4a28-a5d9-c9b84474e1bf','孟府判令嗣求法名興璞','釋崇嶽','宋','宋诗','song-poetry','','[]','真璞無瑕，實際無涯。',20,'全唐诗/poet.song.149000.json','["真璞無瑕，實際無涯。", "心空及第，震耀邦家。"]'),
('9fce69b6-25ad-4b21-8a13-40280d163f63','興一','釋崇嶽','宋','宋诗','song-poetry','','[]','只這一脈，人間顯赫。',20,'全唐诗/poet.song.149000.json','["只這一脈，人間顯赫。", "妙轉綿綿，甚生標格。"]'),
('e83931d5-e05c-4163-b03c-d7928dfdbca5','興祖','釋崇嶽','宋','宋诗','song-poetry','','[]','有祖以來，世不可陪。',20,'全唐诗/poet.song.149000.json','["有祖以來，世不可陪。", "當機日用，著著全該。"]'),
('4f107223-d3c8-4302-8cdf-2dcd962b1b50','示惠文伯宣義二偈  其一','釋崇嶽','宋','宋诗','song-poetry','','[]','見色分明便見心，此心非我亦非人。',32,'全唐诗/poet.song.149000.json','["見色分明便見心，此心非我亦非人。", "臨機不用從它覓，信手拈來著著新。"]'),
('dacbe73f-60e2-40d3-af5c-374788b3699e','示惠文伯宣義二偈  其二','釋崇嶽','宋','宋诗','song-poetry','','[]','盤走珠兮珠走盤，靜中消息閙中看。',32,'全唐诗/poet.song.149000.json','["盤走珠兮珠走盤，靜中消息閙中看。", "一毫頭上忘知解，始覺從前被眼瞞。"]'),
('7e2e604a-807d-4faa-9bea-9d5eef854284','示如理道友','釋崇嶽','宋','宋诗','song-poetry','','[]','如如不動已周遮，理事馳求路轉賒。',32,'全唐诗/poet.song.149000.json','["如如不動已周遮，理事馳求路轉賒。", "直下踏翻樵子徑，知君未到葛洪家。"]'),
('760aee53-47d5-44a6-ad74-29cd3a913b48','題張四直閣容庵','釋崇嶽','宋','宋诗','song-poetry','','[]','大辯若訥，大巧若拙。',32,'全唐诗/poet.song.149000.json','["大辯若訥，大巧若拙。", "太清點雲，千江并月。", "直爲我容庵，故作如是說。"]'),
('89efdaec-d9b3-42b4-9ebe-9b6a15752379','題王子庸上舍實齋','釋崇嶽','宋','宋诗','song-poetry','','[]','世出世間法，和底盡掀翻。',24,'全唐诗/poet.song.149000.json','["世出世間法，和底盡掀翻。", "唯此一事實，真金火裏看。"]'),
('002859ce-971b-4ef5-bfc5-8686e576090a','山居','釋崇嶽','宋','宋诗','song-poetry','','[]','路嶮人稀到，窮居稱野情。',48,'全唐诗/poet.song.149000.json','["路嶮人稀到，窮居稱野情。", "雲開空自闊，月落夜深清。", "風動數莖草，鳥啼三四聲。", "箇中無限意，唯我與誰評。"]'),
('fecc7b46-dcef-4af7-bb78-12bc673ba130','惠康伯宣教請陞堂舉張拙秀才問長沙百千諸佛只聞其名未審居何國土沙云黄鶴樓崔顥題後先輩曾題否拙云不曾沙云無事題取一篇好因說偈','釋崇嶽','宋','宋诗','song-poetry','','[]','黄鶴樓前一首詩，把將掃箒畫娥眉。',32,'全唐诗/poet.song.149000.json','["黄鶴樓前一首詩，把將掃箒畫娥眉。", "百千諸佛真消息，覿面分明舉似伊。"]'),
('4b370e4c-be9d-4938-90e3-6ce14fb8d2ea','送琉書記還長樂  其一','釋崇嶽','宋','宋诗','song-poetry','','[]','相見相從道自親，妙高峰頂謾因循。',32,'全唐诗/poet.song.149000.json','["相見相從道自親，妙高峰頂謾因循。", "業風忽起波濤惡，一錫飄然到七閩。"]'),
('bb4f0d61-c02a-49f0-902a-b37f00f2cf14','送琉書記還長樂  其二','釋崇嶽','宋','宋诗','song-poetry','','[]','甌閩佛法半生滅，江浙叢林日漸凋。',32,'全唐诗/poet.song.149000.json','["甌閩佛法半生滅，江浙叢林日漸凋。", "携手十年如一默，孰云生死不同條。"]'),
('322d074a-7512-47b8-9adf-c825589286de','送琉書記還長樂  其三','釋崇嶽','宋','宋诗','song-poetry','','[]','迢迢故國三千里，忽憶萓堂送別時。',32,'全唐诗/poet.song.149000.json','["迢迢故國三千里，忽憶萓堂送別時。", "拄杖生風興何極，楚天遼邈遠山低。"]'),
('28941471-f33b-48f3-863f-42a3ce6d8c2c','題金山郭璞墓','釋崇嶽','宋','宋诗','song-poetry','','[]','要識先生真實地，龍門浪裏碧崔嵬。',32,'全唐诗/poet.song.149000.json','["要識先生真實地，龍門浪裏碧崔嵬。", "時人著眼這邊立，親切何如到一回。"]'),
('74795e20-cbb3-4ea0-97dd-f883a59a0a84','送光長老住顯親','釋崇嶽','宋','宋诗','song-poetry','','[]','同條端的不同條，箇箇溈山水牯牛。',32,'全唐诗/poet.song.149000.json','["同條端的不同條，箇箇溈山水牯牛。", "一做這般蟲豸去，牽犁拽杷幾時休。"]'),
('64477d66-be75-4a84-be0c-d2af90c7b990','送鹿野珍禪友還七閩  其一','釋崇嶽','宋','宋诗','song-poetry','','[]','共處十年真歲寒，山邊水邊相盤桓。',32,'全唐诗/poet.song.149000.json','["共處十年真歲寒，山邊水邊相盤桓。", "拶倒幾回扶不起，未嘗說著祖師關。"]'),
('7078e7bf-1446-4013-98ce-b3047ba30039','送鹿野珍禪友還七閩  其二','釋崇嶽','宋','宋诗','song-poetry','','[]','密庵的子是冤讎，疾燄過風第二籌。',32,'全唐诗/poet.song.149000.json','["密庵的子是冤讎，疾燄過風第二籌。", "笑裏一場無折合，不容提掇轉風流。"]'),
('7010e64f-2521-4e71-a57c-3f189a4873a6','送鹿野珍禪友還七閩  其三','釋崇嶽','宋','宋诗','song-poetry','','[]','千差坐斷路頭通，萬里鄉關一信風。',32,'全唐诗/poet.song.149000.json','["千差坐斷路頭通，萬里鄉關一信風。", "不負靈山親記莂，好音專待寄來鴻。"]'),
('53e032b0-53a2-4a41-a809-e5cbf8fb590f','送謙侍者還鄉省親','釋崇嶽','宋','宋诗','song-poetry','','[]','有句無句藤倚樹，鐵壁銀山沒回互。',64,'全唐诗/poet.song.149000.json','["有句無句藤倚樹，鐵壁銀山沒回互。", "三千里外面尊堂，一毫頭上全體露。", "睦州謾說編蒲屢，新豐賣峭不歸去。", "今人不比昔時人，出門便是還鄉路。"]'),
('27b7cba5-f53c-45b6-9f05-9ad3c5945918','示智弼禮混源塔','釋崇嶽','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','相逢不相識，去後空相憶，靈骨撒長江。',34,'全唐诗/poet.song.149000.json','["相逢不相識，去後空相憶，靈骨撒長江。", "清風有何極極識，滔滔浪裏休尋覓。"]'),
('0943a845-6a8b-4a3a-8ec2-f3f3a2dc0bd1','示丁都院  其一','釋崇嶽','宋','宋诗','song-poetry','','[]','鑊湯爐炭三禪樂，劍樹刀山大覺場。',32,'全唐诗/poet.song.149000.json','["鑊湯爐炭三禪樂，劍樹刀山大覺場。", "此日撥開心地印，了無佛法可商量。"]'),
('f71e438c-1799-4dec-ab27-0dc6785a418d','示丁都院  其二','釋崇嶽','宋','宋诗','song-poetry','','[]','三千條法爲今時，一性圓明要自知。',32,'全唐诗/poet.song.149000.json','["三千條法爲今時，一性圓明要自知。", "會得自知知底事，人間何處不光輝。"]'),
('5434fc0b-1a17-4f7f-b26c-bb6a5d0d0adb','思齊化士','釋崇嶽','宋','宋诗','song-poetry','','[]','拔劍紅塵斬萬機，直教佛祖浪頭低。',32,'全唐诗/poet.song.149000.json','["拔劍紅塵斬萬機，直教佛祖浪頭低。", "我儂贏得呵呵笑，老倒思賢愧不齊。"]'),
('d99be010-a52d-4dec-ae85-8cc1398c339e','示葛都院','釋崇嶽','宋','宋诗','song-poetry','','[]','從來佛法無多子，利益人天越古今。',32,'全唐诗/poet.song.149000.json','["從來佛法無多子，利益人天越古今。", "棒喝交馳難近傍，信知徹底老婆心。"]'),
('d767aaf9-2ac0-4af2-9f57-14b58d662d4d','贈蜀中李道士','釋崇嶽','宋','宋诗','song-poetry','','[]','透出重關一瘦筇，湖湘江浙絕行蹤。',32,'全唐诗/poet.song.149000.json','["透出重關一瘦筇，湖湘江浙絕行蹤。", "自從得箇安心法，禪道先儒只此宗。"]'),
('89bb2c95-6767-4cf0-b9ee-29b586995976','尤氏妙蓮請普說舉僧問風穴語默涉離微如何通不犯穴云長憶江南三月裏鷓鴣啼處百花香因說偈','釋崇嶽','宋','宋诗','song-poetry','','[]','百花香處鷓鴣啼，百歲光陰七十稀。',32,'全唐诗/poet.song.149000.json','["百花香處鷓鴣啼，百歲光陰七十稀。", "翻憶世間多少事，落便宜是得便宜。"]'),
('17a12085-183c-424d-a2ce-b824785f23e8','鞔法鼓求頌','釋崇嶽','宋','宋诗','song-poetry','','[]','內空外空內外空，一聲纔舉迅雷風。',32,'全唐诗/poet.song.149000.json','["內空外空內外空，一聲纔舉迅雷風。", "流通佛法無多子，千古靈山氣象雄。"]'),
('38658380-0baa-4c5d-9b06-758a71a61883','送普岩維那','釋崇嶽','宋','宋诗','song-poetry','','[]','冶父門庭索索，東湖風波甚惡。',28,'全唐诗/poet.song.149000.json','["冶父門庭索索，東湖風波甚惡。", "知心能有幾人，萬里秋天一鶚。"]'),
('a5e2fc3a-197d-4296-ad95-4d9ba5aa0d07','正現上人遊廬山','釋崇嶽','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u8861\u5c71", "\u897f\u6e56"]','透過重關得自由，相期佛祖雪冤讎。',32,'全唐诗/poet.song.149000.json','["透過重關得自由，相期佛祖雪冤讎。", "西湖風景無留戀，南嶽廬山拄杖頭。"]'),
('0e51614b-4b7b-431e-b85d-6f40dc6214ab','雲翼書記歸鄉','釋崇嶽','宋','宋诗','song-poetry','','[]','慣嘗甘草與黄連，大海波濤盡底掀。',32,'全唐诗/poet.song.149000.json','["慣嘗甘草與黄連，大海波濤盡底掀。", "誤吸冷泉無味水，方知不在舌頭邊。"]'),
('448a7ba2-ea4e-43e6-b9de-9de33f27502c','林上人歸蜀','釋崇嶽','宋','宋诗','song-poetry','','[]','明明此事不由他，喫飯無端咬著沙。',32,'全唐诗/poet.song.149000.json','["明明此事不由他，喫飯無端咬著沙。", "自己靈光皆喪盡，三千里外摘楊花。"]'),
('cdcc93c3-dade-4e0b-91c2-8af080da2b27','三衢椿監寺修造佛殿','釋崇嶽','宋','宋诗','song-poetry','','[]','黄面瞿曇放搭癡，千方百計討便宜。',32,'全唐诗/poet.song.149000.json','["黄面瞿曇放搭癡，千方百計討便宜。", "而今無著渾身處，却要兒孫蓋覆伊。"]'),
('7dcb6af5-5b2d-43b3-aff2-a2344842ad44','白牛接待','釋崇嶽','宋','宋诗','song-poetry','','[]','田園隠密白牛閑，近揖湖光遠對山。',32,'全唐诗/poet.song.149000.json','["田園隠密白牛閑，近揖湖光遠對山。", "何似踏翻無寸土，上方香積在其間。"]'),
('8a1d8ec2-3e9e-4ea7-9a45-f47ce3b11897','示如凈禪人','釋崇嶽','宋','宋诗','song-poetry','','[]','劈面三拳，連顋兩堂。',28,'全唐诗/poet.song.149000.json','["劈面三拳，連顋兩堂。", "撒手懸崖，喪盡伎倆。", "德雲不在別峰上。"]'),
('9ab208bc-c07e-43ce-a112-4810b7672517','茶湯會求頌','釋崇嶽','宋','宋诗','song-poetry','','[]','春風吹落碧桃花，一片流經十萬家。',32,'全唐诗/poet.song.149000.json','["春風吹落碧桃花，一片流經十萬家。", "何似飛來峰下寺，相邀來喫趙州茶。"]'),
('68ba9b14-6c73-449a-bc87-58364b645f4d','福州黄檗送廣州化主','釋崇嶽','宋','宋诗','song-poetry','','[]','不住煙蘿第一層，翻身要勘嶺南能。',32,'全唐诗/poet.song.149000.json','["不住煙蘿第一層，翻身要勘嶺南能。", "謂言檗嶠三千指，不比黄梅七百僧。"]'),
('159ca5b7-1915-4358-8a5e-93279c2e2c91','黄檗送茶化主','釋崇嶽','宋','宋诗','song-poetry','','[]','百草頭邊法戰時，鎗旗未展露全威。',32,'全唐诗/poet.song.149000.json','["百草頭邊法戰時，鎗旗未展露全威。", "直饒陸羽知端的，也落吾家第二機。"]'),
('f3b1975f-233d-42a2-bbec-fd450e319e8f','送泉州化主','釋崇嶽','宋','宋诗','song-poetry','','[]','少林無孔笛橫吹，此曲誰人和得親。',32,'全唐诗/poet.song.149000.json','["少林無孔笛橫吹，此曲誰人和得親。", "向曉洛陽江上路，一聲喚起幾多人。"]'),
('f6f5934a-b0d7-4567-b1e3-5e8b76d62851','衢州祥符僧堂帳化士','釋崇嶽','宋','宋诗','song-poetry','','[]','滿堂蟠蟄卧僧龍，一片閑雲下碧空。',32,'全唐诗/poet.song.149000.json','["滿堂蟠蟄卧僧龍，一片閑雲下碧空。", "舒捲當機元自在，從教蚊蚋弄狂風。"]'),
('8fbf893f-e235-4aff-ae68-02b291cda4f6','示汪居士','釋崇嶽','宋','宋诗','song-poetry','','[]','參禪悟道染泥沙，見佛與祖生冤家。',62,'全唐诗/poet.song.149000.json','["參禪悟道染泥沙，見佛與祖生冤家。", "破塵破的栽荆棘，壁立萬仞有誵訛。", "也大差，也大差，一刀兩段，火裏蓮花。", "十分無伎倆，處處有生涯。"]'),
('d0ec5171-bd44-4fd9-afe3-73e45a8152f3','南侍者還莆陽','釋崇嶽','宋','宋诗','song-poetry','','[]','若將此語定宗綱，任是靈山未廝當。',32,'全唐诗/poet.song.149000.json','["若將此語定宗綱，任是靈山未廝當。", "大地撮來無粟粒，令人翻憶老曾郎。"]'),
('dca91713-1903-452e-a31c-5690bb042187','孜侍者行乞','釋崇嶽','宋','宋诗','song-poetry','','[]','不學文章不學書，孜孜於道自忘軀。',32,'全唐诗/poet.song.149000.json','["不學文章不學書，孜孜於道自忘軀。", "黄塵堆裏挨身轉，一任清風捲太虛。"]'),
('4ce7b378-5677-4370-918d-3d3595ae1a6d','且侍者持鉢','釋崇嶽','宋','宋诗','song-poetry','','[]','靈山無法與人傳，臨濟宗風盡滅門。',32,'全唐诗/poet.song.149000.json','["靈山無法與人傳，臨濟宗風盡滅門。", "唯有道人知此意，赤心扶起破砂盆。"]'),
('577fb2ae-44e0-4c09-a3be-3750c1096f96','接待','釋崇嶽','宋','宋诗','song-poetry','','[]','茶飯家常沒可陪，臨機元不在安排。',32,'全唐诗/poet.song.149000.json','["茶飯家常沒可陪，臨機元不在安排。", "門前有客來相訪，試問朝從何處來。"]'),
('f5a73d73-063f-4d59-b6b9-388747f94919','超禪人持鉢','釋崇嶽','宋','宋诗','song-poetry','','[]','秋風颼颼，乘興悠悠。',46,'全唐诗/poet.song.149000.json','["秋風颼颼，乘興悠悠。", "因行掉臂，南州北州。", "相頭買帽，看樓打樓。", "格外知音纔領略，虎頭虎尾一時收。"]'),
('747e045a-8140-46d9-8a18-9d52e64e6278','祐水頭','釋崇嶽','宋','宋诗','song-poetry','','[]','風吹不入，水灑不著。',46,'全唐诗/poet.song.149000.json','["風吹不入，水灑不著。", "捩轉玄關，隨緣自若。", "任是碧眼胡兒，從頭與汝一杓。", "著不著，誰言過水不濕脚。"]'),
('32c38278-5c49-46de-a0c4-96903106ae38','鹽街坊','釋崇嶽','宋','宋诗','song-poetry','','[]','紅爐鼓浪瞥然間，突出銀山照膽寒。',32,'全唐诗/poet.song.149000.json','["紅爐鼓浪瞥然間，突出銀山照膽寒。", "便是馬師胡亂後，要須不被舌頭瞞。"]'),
('f0228924-a272-40ef-9135-a80548910885','尹山接待','釋崇嶽','宋','宋诗','song-poetry','','[]','千古尹山寺，家風不厭貧。',24,'全唐诗/poet.song.149000.json','["千古尹山寺，家風不厭貧。", "只將這箇意，接待往來人。"]'),
('92d1c3a3-0c95-40af-995b-477986b8c988','送化主  其一','釋崇嶽','宋','宋诗','song-poetry','','[]','即心即佛眼中屑，非心非佛轉乖真。',32,'全唐诗/poet.song.149000.json','["即心即佛眼中屑，非心非佛轉乖真。", "大唐國裏無南北，盡是靈山一會人。"]'),
('f5d4db00-5e75-4bcd-b692-2221e3a4d453','送化主  其二','釋崇嶽','宋','宋诗','song-poetry','','[]','勞生擾擾夢喧譁，夢破喧譁也大差。',32,'全唐诗/poet.song.149000.json','["勞生擾擾夢喧譁，夢破喧譁也大差。", "雲凈水天江上望，一輪皎潔落誰家。"]'),
('148e0cca-bc2e-4409-b57e-f3bfabc7054c','送化主  其三','釋崇嶽','宋','宋诗','song-poetry','','[]','把得袈裟裹草鞋，相逢只麽笑咍咍。',32,'全唐诗/poet.song.149000.json','["把得袈裟裹草鞋，相逢只麽笑咍咍。", "孔門弟子還知否，曾向靈山及第來。"]'),
('88f75d0d-31ee-491f-a575-4cc5ad306dac','送化主  其四','釋崇嶽','宋','宋诗','song-poetry','','[]','百億分身利有情，馿顋馬頷實難明。',32,'全唐诗/poet.song.149000.json','["百億分身利有情，馿顋馬頷實難明。", "有時閙裏聊伸手，意在鈎頭不在星。"]'),
('3a64f8da-e176-44a8-9750-2fe44d4aa106','送化主  其五','釋崇嶽','宋','宋诗','song-poetry','','[]','日用分明直似弦，不將佛法污心田。',32,'全唐诗/poet.song.149000.json','["日用分明直似弦，不將佛法污心田。", "自言世上無仙客，老倒維摩得半邊。"]'),
('cca063c8-67c9-4e23-a058-9c94ed4959e3','送化主  其六','釋崇嶽','宋','宋诗','song-poetry','','[]','不依本分要參禪，賣了山前祖父田。',32,'全唐诗/poet.song.149000.json','["不依本分要參禪，賣了山前祖父田。", "赤手出門無活計，好兒終不使爺錢。"]'),
('75ab22cc-d08e-48d0-80dc-dc1ad256b84b','送化主  其七','釋崇嶽','宋','宋诗','song-poetry','','[]','敗壞多年笤箒樁，等閑拈起定宗綱。',32,'全唐诗/poet.song.149000.json','["敗壞多年笤箒樁，等閑拈起定宗綱。", "這些標格天然別，不比諸方孟八郎。"]'),
('e5efa50a-f2c6-4597-b2a6-8fca7e1be617','題寄巢','釋崇嶽','宋','宋诗','song-poetry','','[]','巢穴通霄眼，塵勞無住心。',24,'全唐诗/poet.song.149000.json','["巢穴通霄眼，塵勞無住心。", "經行及坐卧，萬古至于今。"]'),
('1b00b57b-e7ad-4e63-a51f-36e18d385bdd','題有餘齋','釋崇嶽','宋','宋诗','song-poetry','','[]','日月雙螢火，乾坤一鵲巢。',24,'全唐诗/poet.song.149000.json','["日月雙螢火，乾坤一鵲巢。", "大千沙界外，總在目前包。"]'),
('48e1d9a2-d93e-4711-b6ae-2565c1bbcf99','臨終偈','釋崇嶽','宋','宋诗','song-poetry','','[]','來無所來，去無所去。',20,'全唐诗/poet.song.149000.json','["來無所來，去無所去。", "瞥轉玄關，佛祖罔措。"]'),
('0ec17e2b-74c6-45d5-b9e9-e245390aa6ee','應庵密庵同日忌','釋崇嶽','宋','宋诗','song-poetry','','[]','冤有頭，債有主，撞破砂盆眼卓豎。',32,'全唐诗/poet.song.149000.json','["冤有頭，債有主，撞破砂盆眼卓豎。", "不是佛，不是祖，太白峯前只如許。"]'),
('f9eb3bb8-18a7-48e8-89f3-5512033fa523','亮典座歸中峰菴','釋崇嶽','宋','宋诗','song-poetry','','[]','太白峯高宇宙低，先師靈骨不曾移。',32,'全唐诗/poet.song.149000.json','["太白峯高宇宙低，先師靈骨不曾移。", "兒孫箇箇且如許，路上行人口似碑。"]'),
('08ff09da-43d5-4170-907f-4254f9fd8dcd','頌古六首  其一','釋崇嶽','宋','宋诗','song-poetry','','[]','地獄天堂，八字打開，誰知無去亦無來。',34,'全唐诗/poet.song.149000.json','["地獄天堂，八字打開，誰知無去亦無來。", "若言已得三禪樂，未免將身自活埋。"]'),
('6143b530-3b02-4c14-90ed-4585cdd8207d','頌古六首  其二','釋崇嶽','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','一口吸盡西江水，龐老不曾明自己。',32,'全唐诗/poet.song.149000.json','["一口吸盡西江水，龐老不曾明自己。", "爛醉如泥膽似天，鞏縣茶瓶三隻嘴。"]'),
('c0becd2e-dc68-4daa-9e2d-60ba24ddefb5','頌古六首  其三','釋崇嶽','宋','宋诗','song-poetry','','[]','機輪元不挂絲頭，會有金鱗上直鈎。',32,'全唐诗/poet.song.149000.json','["機輪元不挂絲頭，會有金鱗上直鈎。", "驀口一橈猶未徹，踏反船子有來由。"]'),
('853422cf-3b1e-46cd-82f7-dee2cd97792f','頌古六首  其四','釋崇嶽','宋','宋诗','song-poetry','','[]','狗子佛性無，門上釘桃符。',24,'全唐诗/poet.song.149000.json','["狗子佛性無，門上釘桃符。", "千邪俱不入，百怪盡消除。"]'),
('dcc894fe-cab1-4825-b7ea-4f7d570110a3','頌古六首  其五','釋崇嶽','宋','宋诗','song-poetry','','[]','大機圓應，大用直截。',30,'全唐诗/poet.song.149000.json','["大機圓應，大用直截。", "雪峯雲門，只得一橛。", "畢竟如何，不說不說。"]'),
('196cc071-bd8a-4df7-8c71-b0a58287582b','頌古六首  其六','釋崇嶽','宋','宋诗','song-poetry','','[]','家家盡看野狐兒，鐵笛橫拈撩亂吹。',32,'全唐诗/poet.song.149000.json','["家家盡看野狐兒，鐵笛橫拈撩亂吹。", "吹罷不知何處去，夕陽已挂柳梢西。"]'),
('b1cf14d6-a377-410d-81e9-5117e5651c60','翠屏曲','劉翰','宋','宋诗','song-poetry','','[]','小亭簾幕垂陰陰，梅香入枕春生屏。',64,'全唐诗/poet.song.149000.json','["小亭簾幕垂陰陰，梅香入枕春生屏。", "西窗月落翠被冷，鳥聲殘夢東風醒。", "三年不喚清溪渡，夢裏瀼西春水路。", "江頭女兒雙翠眉，能唱劉郎芳草句。"]'),
('995331e3-f991-41eb-a305-58a49e1f5ed3','小宴','劉翰','宋','宋诗','song-poetry','','[]','一曲歌雲勸玉觴，歸來斜月恰侵床。',32,'全唐诗/poet.song.149000.json','["一曲歌雲勸玉觴，歸來斜月恰侵床。", "小窗細嚼梅花蕊，吐出新詩字字香。"]'),
('78e52a6d-16b9-4a3b-9224-69b36f262f1f','余久客都城秋風思歸作楚語和吳郎採菱叩舷之音','劉翰','宋','宋诗','song-poetry','','[]','秋風兮凄凄，山中兮桂枝。',86,'全唐诗/poet.song.149000.json','["秋風兮凄凄，山中兮桂枝。", "彈余冠兮塵墮，芳草綠兮未歸。", "家遥遥兮辭楚荆，傷去國兮重登臨。", "扶長劍兮增慨，復鳴鋏兮成音。", "採中洲兮蘭芷，望美人兮千里。", "我所思兮天一方，共明月兮隔秋水。"]'),
('ab5c58ec-a19e-442a-bbbc-73ca5d271bf6','種梅','劉翰','宋','宋诗','song-poetry','','[]','凄凉池館欲棲鴉，采筆無心賦落霞。',32,'全唐诗/poet.song.149000.json','["凄凉池館欲棲鴉，采筆無心賦落霞。", "惆悵後庭風味薄，自鋤明月種梅花。"]'),
('418d57ef-64ef-4e1c-b00a-76eca90e7487','紅窗怨','劉翰','宋','宋诗','song-poetry','','[]','啼鶑喚起紗窗夢，紅日滿簾花影弄。',80,'全唐诗/poet.song.149000.json','["啼鶑喚起紗窗夢，紅日滿簾花影弄。", "翠屏香字冷薰爐，羅衣疊損金泥鳳。", "去年君去燕歸時，今日燕來君未歸。", "欲把相思挑錦字，夜寒懶上鴛鴦機。", "起來翠袖香羅薄，東風滿地桃花落。"]'),
('2b264442-0340-4cb0-9e45-b24827a056bf','漁父','劉翰','宋','宋诗','song-poetry','','[]','輕舟一葉一輕篷，上有蕭蕭鶴髮翁。',32,'全唐诗/poet.song.149000.json','["輕舟一葉一輕篷，上有蕭蕭鶴髮翁。", "昨夜不知何處宿，月明都在笛聲中。"]'),
('92429661-7861-46d2-b778-052191b9c045','春晚呈范石湖','劉翰','宋','宋诗','song-poetry','','[]','風日蕭蕭兩鬢華，倦尋銀筆賦餘霞。',64,'全唐诗/poet.song.149000.json','["風日蕭蕭兩鬢華，倦尋銀筆賦餘霞。", "五更枕上無情雨，三月風前薄命花。", "春困有時因病酒，客懷何日不思家。", "年來事事心情懶，惟有歸耕策最嘉。"]'),
('8baa4e50-538e-4004-b78f-c0113f0fd8d0','上元小亭','劉翰','宋','宋诗','song-poetry','','[]','靖康詔令文章種，桐邑公侯國老家。',32,'全唐诗/poet.song.149000.json','["靖康詔令文章種，桐邑公侯國老家。", "種得人間桃李滿，春風無地不開花。"]'),
('8d17e2ae-66ca-4258-a965-c259722f9089','石頭城','劉翰','宋','宋诗','song-poetry','','[]','離離芳草滿吳宮，綠到臺城舊苑東。',32,'全唐诗/poet.song.149000.json','["離離芳草滿吳宮，綠到臺城舊苑東。", "一夜空江煙水冷，石頭明月雁聲中。"]'),
('225a58fb-6f82-40fd-b7a7-4de738f9b988','天上月','劉翰','宋','宋诗','song-poetry','','[]','春冰一片凈無瑕，萬里清光遍海涯。',32,'全唐诗/poet.song.149000.json','["春冰一片凈無瑕，萬里清光遍海涯。", "欲與常娥移桂樹，月中先合種梅花。"]'),
('521887c0-0035-41a4-a633-53cbde70b367','春日','劉翰','宋','宋诗','song-poetry','','[]','沉沉芳酌動金波，笑引疏梅泛玉荷。',64,'全唐诗/poet.song.149000.json','["沉沉芳酌動金波，笑引疏梅泛玉荷。", "幾度天寒歸雁少，一番風雨落花多。", "功名好在知心懶，富貴重來奈老何。", "烏鵲數聲傳喜語，梁間燕子亦能歌。"]'),
('4584bf49-bce0-46d1-97f4-62a460f68411','江南曲','劉翰','宋','宋诗','song-poetry','','[]','我家江南同野老，自紡落毛采蘋藻。',128,'全唐诗/poet.song.149000.json','["我家江南同野老，自紡落毛采蘋藻。", "清風滿袖讀離騷，半畝幽畦種香草。", "門前流水鳴濺濺，日暮歸來自刺船。", "遥山數疊作媚嫵，落日斷霞明晚川。", "雨餘汀草漲新綠，紅衣濕盡鴛鴦浴。", "採蓮女兒何處來，唱我春風湖上曲。", "甕頭酒熟方新篘，白魚如銀初上鈎。", "呼兒洗杓醉明月，酒酣更作商聲謳。"]'),
('9b7638de-6d24-497b-abc6-6d57616ccac0','鴻門宴','劉翰','宋','宋诗','song-poetry','','[]','江東遥遥八千騎，大戰小戰七十二。',160,'全唐诗/poet.song.149000.json','["江東遥遥八千騎，大戰小戰七十二。", "劉郎曉鞭天馬來，踧踏長安開帝里。", "子嬰已降隆準公，君王置酒鴻門東。", "張良已去玉斗碎，三月火照咸陽紅。", "繡衣歸來日將夜，可惜雄心天不借。", "當時已失范增謀，尚引長戈到垓下。", "刁斗乍急營壘驚，夜深旗尾秋風橫。", "玉帳佳人不成夢，月明四面聞歌聲。", "拔劍相看淚如雨，我作楚歌君楚舞。", "明朝寶馬一聲嘶，江北江東皆漢土。"]'),
('bd638676-ff02-4746-99d1-b6501102d39a','玉斗歌','劉翰','宋','宋诗','song-poetry','','[]','漢兵咸陽未休舍，楚王長歌到戲下。',163,'全唐诗/poet.song.149000.json','["漢兵咸陽未休舍，楚王長歌到戲下。", "項伯夜入張良營，沛公倉皇出城謝。", "自言戮力共攻秦，不意入關成此勳。", "閉關籍民備他盜，盡封府庫待將軍。", "項莊拔劍項伯起，漢楚興亡在今爾。", "鴻門壯士斬關來，慷慨一卮誰懼死。", "君不見秦亡鹿走驪山傾，四方盡起諸侯兵。", "龍顔隆準泗上長，天之所授誰能爭。", "英雄肯落他人手，獨遣謀臣談辯口。", "君王間道却歸來，滿地秋聲鳴玉斗。"]'),
('9189320d-46d1-4f52-a235-9bbeaae8320e','吳門行','劉翰','宋','宋诗','song-poetry','','[]','吳歌婉婉清如水，西風曉自閶門起。',64,'全唐诗/poet.song.149000.json','["吳歌婉婉清如水，西風曉自閶門起。", "雙橈艇子採菱來，翠荇綠濱香十里。", "芙蓉影落已知秋，濺濕羅衣眉黛愁。", "回聲蕩槳入門去，明月家家秋水流。"]'),
('06a965c5-42c0-47e4-910b-ebbafcec1a25','客去','劉翰','宋','宋诗','song-poetry','','[]','送客歸來月滿簷，梅花微笑隔疏簾。',32,'全唐诗/poet.song.149000.json','["送客歸來月滿簷，梅花微笑隔疏簾。", "酒醒今夜銀屏冷，沉水薰爐旋旋添。"]'),
('ce296d4c-9caa-4c24-a0ff-b7f17b04e321','哀友人','劉翰','宋','宋诗','song-poetry','','[]','案成歌舞小春嬌，何事君隨草木彫。',32,'全唐诗/poet.song.149000.json','["案成歌舞小春嬌，何事君隨草木彫。", "從此巴江江上月，有人和淚獨吹簫。"]'),
('6bedd015-ad0e-400a-91d9-f6f3fe30cabc','聞笛','劉翰','宋','宋诗','song-poetry','','[]','誰將玉笛按凉州，吹徹春風不下樓。',32,'全唐诗/poet.song.149000.json','["誰將玉笛按凉州，吹徹春風不下樓。", "若道聲聲都是恨，不知消得幾多愁。"]'),
('abc85d7f-d371-4410-80cc-145efa5d2d0d','小亭','劉翰','宋','宋诗','song-poetry','','[]','芳草萋萋怨未歸，西池殘夢要題詩。',32,'全唐诗/poet.song.149000.json','["芳草萋萋怨未歸，西池殘夢要題詩。", "綠窗昨夜東風小，開遍梅花第幾枝。"]'),
('6cf4eb69-aa52-4541-9438-12fea87c7014','題飛雲閣','劉翰','宋','宋诗','song-poetry','','[]','一笑歸來春尚寒，小梅飄盡雪初殘。',32,'全唐诗/poet.song.149000.json','["一笑歸來春尚寒，小梅飄盡雪初殘。", "遲遲更待梨花月，醉倚飛雲十二欄。"]'),
('4bb6cc30-24df-4684-aaba-3b3d139a8d06','立秋日','劉翰','宋','宋诗','song-poetry','','[]','亂鴉啼散玉屏空，一枕新凉一扇風。',32,'全唐诗/poet.song.149000.json','["亂鴉啼散玉屏空，一枕新凉一扇風。", "睡起秋聲無覓處，滿階梧葉月明中。"]'),
('9a1ba714-919d-4019-95e4-7cb36d871e37','句  其一','劉翰','宋','宋诗','song-poetry','','[]','吹入征鴻數字秋。',8,'全唐诗/poet.song.149000.json','["吹入征鴻數字秋。"]'),
('a565217a-f9cf-4a63-a5e5-d6804956a234','句  其二','劉翰','宋','宋诗','song-poetry','','[]','青山經雨菊花盡，白鳥下灘蘆葉盡。',16,'全唐诗/poet.song.149000.json','["青山經雨菊花盡，白鳥下灘蘆葉盡。"]'),
('7770bd7b-0744-4e99-b93f-219b29740a95','挽于湖','沈端節','宋','宋诗','song-poetry','','[]','荒城難訪十全醫，半篋遺書世共悲。',64,'全唐诗/poet.song.149000.json','["荒城難訪十全醫，半篋遺書世共悲。", "寧有故人憐阿騖，但餘息女類文姬。", "忠籌屢畫平戎策，宦蹟常留墮淚碑。", "醉扣西州重回首，山陽鄰笛夜凄其。"]'),
('853e34fb-9b11-4cd6-9d6b-cb5e8b3cdc5e','復挽','沈端節','宋','宋诗','song-poetry','','[]','氣概凌雲孰敢先，中興事業冠英躔。',64,'全唐诗/poet.song.149000.json','["氣概凌雲孰敢先，中興事業冠英躔。", "朝廷議論一言定，翰墨風流四海傳。", "恰跨鰲頭升紫閣，忽騎箕尾上青天。", "竹林笑傲今陳跡，撫櫬江皋涕泫然。"]'),
('fe04fc81-ad4d-4737-8cb5-19a282ee3b23','弔于湖墓在秣陵','沈端節','宋','宋诗','song-poetry','','[]','晚出白門下，疲馬踏秋色。',120,'全唐诗/poet.song.149000.json','["晚出白門下，疲馬踏秋色。", "鍾山度蒼翠，慰我遠遊客。", "暮投清泉寺，花草獻幽寂。", "長廊靜無人，落日照西壁。", "平生張于湖，萬里去一息。", "翻然九州外，汗漫跨鯨脊。", "乾坤能幾時，安用較顔跖。", "文章失津梁，所念斯道厄。", "夜闌耿不寐，搔首賦蕭索。", "懷人感西風，翁仲守孤陌。"]'),
('fd73749e-2469-4ff0-9bba-2c6d0aae93d9','挽于湖','沈端節','宋','宋诗','song-poetry','','[]','十年帥越倦馳驅，適意方謀一壑居。',64,'全唐诗/poet.song.149000.json','["十年帥越倦馳驅，適意方謀一壑居。", "賈誼有才終太傅，薛收無壽處中書。", "傷心風月江山在，過隙光陰夢幻虛。", "紅紫飄零春色盡，後凋松柏獨蕭疏。"]'),
('3a2d22c0-7eee-4610-ab84-0e4f67bc0a5d','句','沈端節','宋','宋诗','song-poetry','','[]','讀書渾不問家事，得酒但知延友生。',16,'全唐诗/poet.song.149000.json','["讀書渾不問家事，得酒但知延友生。"]'),
('1b4017d7-c02c-495b-9f1b-9bb695c3ca75','句','李孚','宋','宋诗','song-poetry','','[]','宮柳不知興廢事，春來還是綠纖纖。',16,'全唐诗/poet.song.149000.json','["宮柳不知興廢事，春來還是綠纖纖。"]'),
('2db4057b-d42b-44d9-9dab-87d42eb3a3aa','誡子弟詞  其一','陸九韶','宋','宋诗','song-poetry','','[]','聽聽聽聽聽聽聽，勞我以生天理定。',40,'全唐诗/poet.song.149000.json','["聽聽聽聽聽聽聽，勞我以生天理定。", "若還惰懶必饑寒，莫到饑寒方怨命。", "虛空自有神明聽。"]'),
('8b358e8c-cf25-489d-a8c5-fad1181a710d','誡子弟詞  其二','陸九韶','宋','宋诗','song-poetry','','[]','聽聽聽聽聽聽聽，衣食生身天付定。',40,'全唐诗/poet.song.149000.json','["聽聽聽聽聽聽聽，衣食生身天付定。", "酒肉貪多折人壽，經營太甚違天命。", "定定定定定定定。"]'),
('462f65af-b178-4e19-a3bb-d346b3034b44','誡子弟詞  其三','陸九韶','宋','宋诗','song-poetry','','[]','聽聽聽聽聽聽聽，好將孝弟酬身命。',44,'全唐诗/poet.song.149000.json','["聽聽聽聽聽聽聽，好將孝弟酬身命。", "更將勤儉答天心，莫把妄思損真性。", "定定定定定定定，早猛省。"]'),
('a0124e1a-7978-44d3-bd51-8f1b9b222786','誡子弟詞  其四','陸九韶','宋','宋诗','song-poetry','','[]','凡聞聲，須有省。',40,'全唐诗/poet.song.149000.json','["凡聞聲，須有省。", "照自心，察前境。", "若方馳騖速回光，悟得昨非由一頃。", "昔人五觀一時領。"]'),
('7035bd14-f85f-432c-a065-ec43ccf349ee','躍馬泉','陸九韶','宋','宋诗','song-poetry','','[]','靈泉蓄幽憤，躍石作良馬。',48,'全唐诗/poet.song.149000.json','["靈泉蓄幽憤，躍石作良馬。", "奔騰曳練駛，追風非汎駕。", "行健石有跡，氣驕珠汗灑。", "何當奮厥志，萬騎陰山下。"]'),
('7101951e-bcfb-4264-9e9d-399f17d04b6e','鳴玉泉','陸九韶','宋','宋诗','song-poetry','','[]','朅來坐幽亭，恍在崑山曲。',72,'全唐诗/poet.song.149000.json','["朅來坐幽亭，恍在崑山曲。", "清越聲盈耳，群工琢良玉。", "又疑躋金闕，仙班珮相屬。", "圓環碎瓊琚，登降互擊觸。", "灑然襟袍爽，無處著利欲。", "不貪以爲寶，對此景高躅。"]'),
('c38996a1-526d-4493-a7ee-3c0bb999f4db','試茗泉','陸九韶','宋','宋诗','song-poetry','','[]','邂逅成山行，往往有異景。',72,'全唐诗/poet.song.149000.json','["邂逅成山行，往往有異景。", "奇峰爭呈露，獨不見試茗。", "逶迤即道周，澄泓得幽井。", "淆之不可濁，凝然如自省。", "龜蒙于越來，儻亦煮石鼎。", "豈爲渴者甘，醉夢當一警。"]'),
('dd83df95-f99b-42cd-bbbc-4dd225920e98','月石','陸九韶','宋','宋诗','song-poetry','','[]','玉兔愛佳泉，飲泉化爲石。',72,'全唐诗/poet.song.149000.json','["玉兔愛佳泉，飲泉化爲石。", "規圓立山趾，萬古終不息。", "應厭舊星躔，盈稀多缺夕。", "自從寄茲蹤，表表無晦蝕。", "光彩雖暫埋，體素得不易。", "神物豈終潛，早晚照九域。"]'),
('76b527df-eaa8-4e12-9789-d87bb6495423','鵝湖示同志','陸九齡','宋','宋诗','song-poetry','','[]','孩提知愛長知欽，古聖相傳只此心。',64,'全唐诗/poet.song.149000.json','["孩提知愛長知欽，古聖相傳只此心。", "大抵有基方築室，未聞無址可成岑。", "留情傳注翻榛塞，著意精微轉陸沉。", "珍重友朋勤切琢，須知至樂在於今。"]'),
('7b13cbb8-ed10-4260-9fe8-c74b9e07fa89','與僧凈璋','陸九齡','宋','宋诗','song-poetry','','[]','自從相見白雲間，離別嘗多會聚難。',64,'全唐诗/poet.song.149000.json','["自從相見白雲間，離別嘗多會聚難。", "兩度逢迎當汝水，數年隔闊是曹山。", "客來濯足旁僧怪，病不烹茶侍者閒。", "不是故人尋舊隠，只應終日閉禪關。"]'),
('7d738140-f496-40b0-886f-5de03b1eb3f0','早過何郎','陸九齡','宋','宋诗','song-poetry','','[]','蕭蕭風雨曉籃輿，沒脛泥深我僕痡。',32,'全唐诗/poet.song.149000.json','["蕭蕭風雨曉籃輿，沒脛泥深我僕痡。", "却憶去年苗欲槁，任從行李且虛徐。"]'),
('4ef671db-e2ff-4a91-8062-ebd94d14d86e','道間示德甫德稱','陸九齡','宋','宋诗','song-poetry','','[]','天地中間本自寬，何須特地起無端。',32,'全唐诗/poet.song.149000.json','["天地中間本自寬，何須特地起無端。", "更宜頓掃從前事，相與携筇一笑歡。"]'),
('4f679cba-3e50-4422-8a4b-c77a932f5fb7','過靈山述懷','岳霖','宋','宋诗','song-poetry','','[]','折腰爲米本憂貧，流落天南瘴海濱。',64,'全唐诗/poet.song.149000.json','["折腰爲米本憂貧，流落天南瘴海濱。", "千里雲山空別恨，十年萍梗可傷神。", "拊膺但覺丹心壯，覽鏡那堪白髮新。", "歸去恩深知感激，只慚無德愧斯民。"]'),
('01ca94af-3622-40b8-98a2-e16269178a09','句','葉祖義','宋','宋诗','song-poetry','','[]','醉來黑漆屏風上，草寫盧仝月蝕詩。',16,'全唐诗/poet.song.149000.json','["醉來黑漆屏風上，草寫盧仝月蝕詩。"]'),
('2be19f08-d7d4-4fc4-93cc-ee6b2e396d80','登虎丘寺','趙善俊','宋','宋诗','song-poetry','','[]','我有家山與茂林，閉門肯復事幽尋。',64,'全唐诗/poet.song.149000.json','["我有家山與茂林，閉門肯復事幽尋。", "偶來千古雲巖寺，洗盡三生宦海心。", "竹綆不停泉溜響，苔花難掩劍痕深。", "秋晴借得重陽意，領客登高共醉吟。"]'),
('e38a4796-6ccf-4548-85b6-d8caea8e7251','吳中羊肉價高有感','高公泗','宋','宋诗','song-poetry','','[]','平江九百一斤羊，俸薄如何敢買嘗。',32,'全唐诗/poet.song.149000.json','["平江九百一斤羊，俸薄如何敢買嘗。", "只把魚蝦充兩膳，肚皮今作小池塘。"]'),
('95a74c7e-961a-475a-857a-63d0c0960170','港口野步懷歸','高公泗','宋','宋诗','song-poetry','','[]','天宇空青晚更佳，溪頭滑石路欹斜。',64,'全唐诗/poet.song.149000.json','["天宇空青晚更佳，溪頭滑石路欹斜。", "山深苦竹方抽笋，日暖甘菘始放花。", "莎草牆垣沾燕屎，棘針籬落聚蠶沙。", "預知半夏當歸去，梔子開時應到家。"]'),
('a429b688-6166-4d94-b655-90f1550f2153','峽塾講中庸第二章','高公泗','宋','宋诗','song-poetry','','[]','滔滔逝者若斯夫，不有耆儒孰共扶。',64,'全唐诗/poet.song.149000.json','["滔滔逝者若斯夫，不有耆儒孰共扶。", "昭揭五條皆達道，由來一本不殊途。", "聖經奧義難窮盡，老筆名言妙寫模。", "我欲研硃同看易，先生肯往此中無。"]'),
('1fd485e0-2e8b-4919-bd53-daca81ab817a','龍多山次馮使君韻  其一','白丙','宋','宋诗','song-poetry','','[]','今日相逢慰別顔，獲參後乘訪龍山。',32,'全唐诗/poet.song.149000.json','["今日相逢慰別顔，獲參後乘訪龍山。", "古仙已去靈蹤在，杖屨尋幽喜共攀。"]'),
('198823f8-72c8-47a2-8dc0-6986de5e224c','龍多山次馮使君韻  其二','白丙','宋','宋诗','song-poetry','','[]','陰陰雲霧埋仙境，不放山巒容易開。',32,'全唐诗/poet.song.149000.json','["陰陰雲霧埋仙境，不放山巒容易開。", "風伯前驅爲除掃，分明認得使君來。"]'),
('ddceae27-661c-4f0a-8c1a-626597679d3e','句','婁壽','宋','宋诗','song-poetry','','[]','飛雲過雨灑明月。',8,'全唐诗/poet.song.149000.json','["飛雲過雨灑明月。"]'),
('f277f7f6-c145-4436-b52c-136affcbb5ca','鑑軒','莊珙','宋','宋诗','song-poetry','','[]','鑿地一鑑小，清照遠山眉。',48,'全唐诗/poet.song.149000.json','["鑿地一鑑小，清照遠山眉。", "不起奔雷浪，微生濯月漪。", "林深來屬玉，萍碎引伊尼。", "緬想人中鏡，披雲覩更奇。"]'),
('5a883d96-214f-490a-a01c-7c484573b644','深靜堂  其一','莊珙','宋','宋诗','song-poetry','','[]','卜築愔愔不記年，蒲團布衲夙因緣。',64,'全唐诗/poet.song.149000.json','["卜築愔愔不記年，蒲團布衲夙因緣。", "一燈明滅照秋雨，殘炷有無縈暮烟。", "空谷風篁自成韻，虛窗霜葉警安禪。", "昔游尚記春强半，幽鳥相呼細柳眠。"]'),
('5cd52af6-2716-4044-9004-f9858d9615bc','深靜堂  其二','莊珙','宋','宋诗','song-poetry','','[]','林泉適意可忘年，靜境寥寥斷俗緣。',64,'全唐诗/poet.song.149000.json','["林泉適意可忘年，靜境寥寥斷俗緣。", "滿戶清風翻貝葉，半窗晴日裊爐烟。", "無塵虛室自生白，隠几安心即是禪。", "杖策每來乘逸興，偷閑聊借北窗眠。"]'),
('3407fdec-7559-440f-bc8a-1a0b088e38fa','寧國寺','邵輶','宋','宋诗','song-poetry','','[]','地勝千巖秀，名高萬古存。',48,'全唐诗/poet.song.149000.json','["地勝千巖秀，名高萬古存。", "丹崖紀靈躅，紺宇蔽祇園。", "樹老垂藤影，池幽浸蘚痕。", "會心多興趣，隨意坐林樊。"]'),
('545c077b-4e23-47b6-bfd9-b0e61f5ff826','鑑軒','邵輶','宋','宋诗','song-poetry','','[]','池光開凈鏡，山影展修眉。',48,'全唐诗/poet.song.149000.json','["池光開凈鏡，山影展修眉。", "石冷映碧色，烟輕生翠漪。", "乞湖思賀監，觀水咏宣尼。", "照坐心神瑩，徜徉殊復奇。"]'),
('2482b78e-c273-4975-928b-a22276682043','郡宴合生','撫州樂妓','宋','宋诗','song-poetry','','[]','同是天邊侍從臣，江頭相遇轉情親。',64,'全唐诗/poet.song.149000.json','["同是天邊侍從臣，江頭相遇轉情親。", "瑩如臨汝無瑕玉，暖作廬陵有脚春。", "五馬今朝成十馬，兩人前日壓千人。", "便看飛詔催歸去，共坐中書秉化鈞。"]'),
('dba296db-2782-43f3-a020-beac4a3c13a0','庸醫行','尹穡','宋','宋诗','song-poetry','','[]','南街醫工門如市，爭傳和扁生後世。',131,'全唐诗/poet.song.149000.json','["南街醫工門如市，爭傳和扁生後世。", "膏肓可爲死可起，瓦屑蓬根盡珍劑。", "歲月轉久術轉疏，十醫九死一活無。", "北市醫工色潛動，大字書牌要驚衆。", "偏收棄藥與遺方，縱有神丹亦無用。", "實者爲虛熱爲寒，幾因顛倒能全安。", "君不見形神枵然卧一室，醫方爭功藥無必。", "左手檢方右顧金，兩手雖殊皆劍戟。"]'),
('ca877801-ffaf-4d7b-904a-539df0f9ca1d','句  其一','尹穡','宋','宋诗','song-poetry','','[]','酬功不惜賞千布，送死惟堪縛一馿。',16,'全唐诗/poet.song.149000.json','["酬功不惜賞千布，送死惟堪縛一馿。"]'),
('e5aec8a2-5691-4e8e-98b3-77619f17e965','句  其二','尹穡','宋','宋诗','song-poetry','','[]','景龍只是當時路，不見金錢打著人。',16,'全唐诗/poet.song.149000.json','["景龍只是當時路，不見金錢打著人。"]'),
('68bcfe19-6943-4217-b191-44a34ff8bf19','句  其三','尹穡','宋','宋诗','song-poetry','','[]','徒然五侍從，不辦一書生。',12,'全唐诗/poet.song.149000.json','["徒然五侍從，不辦一書生。"]'),
('2b2a5597-fc4f-4d27-9789-bd71d67afd95','句  其四','尹穡','宋','宋诗','song-poetry','','[]','本來饑飽非同鼎，安得浮沈自一舟。',16,'全唐诗/poet.song.149000.json','["本來饑飽非同鼎，安得浮沈自一舟。"]'),
('2e13310d-79fc-4906-bc0e-d3e29e876580','句  其五','尹穡','宋','宋诗','song-poetry','','[]','異日是非憂史謬，終身寒餓羨錢愚。',16,'全唐诗/poet.song.149000.json','["異日是非憂史謬，終身寒餓羨錢愚。"]'),
('a262de9a-9063-4359-b835-71741c0cdb34','句  其六','尹穡','宋','宋诗','song-poetry','','[]','草黄眠失犢，石白動知鷗。',12,'全唐诗/poet.song.149000.json','["草黄眠失犢，石白動知鷗。"]'),
('392d5133-a403-4c54-9b91-b2e4b24b5063','少稷賦十二相屬詩戲贈','趙端行','宋','宋诗','song-poetry','','[]','不用爲鼠何數奇，飯牛南山聊自怡。',96,'全唐诗/poet.song.149000.json','["不用爲鼠何數奇，飯牛南山聊自怡。", "探穴取虎有奇禍，守株伺兔非全癡。", "文成雕龍成卷軸，畫蛇失杯坐添足。", "走馬章臺憶舊遊，歲月纔驚羊胛熟。", "羊窗要自息獼猴，異□無應心日休。", "白衣蒼狗變化見，世事何如牧豬戲。"]'),
('73090d88-d765-43ba-b1d9-030ed2c8c6c3','白鶴關','趙端行','宋','宋诗','song-poetry','','[]','危亭石作關，假道一躋攀。',48,'全唐诗/poet.song.149000.json','["危亭石作關，假道一躋攀。", "白鶴何年去，青松盡日閑。", "坐時聞遠水，望處小他山。", "衲子雲衣厚，寒猶宿此間。"]'),
('6baa3a23-a452-4e09-baf3-2f6c915b377b','紹興乙□中秋後五日乘休沐之□□舟□家爲藏真之游','朱某','宋','宋诗','song-poetry','','[]','白首扁舟□訪尋，江山□□□登臨。',32,'全唐诗/poet.song.149000.json','["白首扁舟□訪尋，江山□□□登臨。", "□□□是□藏處，□□平生賞愛心。"]'),
('74703210-97d9-405f-aa47-1418605fd4be','送黄行者','湖南使者','宋','宋诗','song-poetry','','[]','自有棋來不計年，古今唯是說爭先。',32,'全唐诗/poet.song.149000.json','["自有棋來不計年，古今唯是說爭先。", "個中一著如教會，殺盡三千與大千。"]'),
('673c1a47-c190-45e3-b585-f59dd8779a17','句  其一','强彥文','宋','宋诗','song-poetry','','[]','空有青山自龍虎，可能荒塚更衣冠。',16,'全唐诗/poet.song.149000.json','["空有青山自龍虎，可能荒塚更衣冠。"]'),
('a77a52cb-99e4-4cf3-b141-31068cbda64f','句  其二','强彥文','宋','宋诗','song-poetry','','[]','遠山初見疑無路，曲徑徐行漸有村。',16,'全唐诗/poet.song.149000.json','["遠山初見疑無路，曲徑徐行漸有村。"]'),
('5c6f40c9-800f-43bd-9cb2-58b29b301dcb','句  其三','强彥文','宋','宋诗','song-poetry','','[]','船中燈火十年話，枕上江湖萬里心。',16,'全唐诗/poet.song.149000.json','["船中燈火十年話，枕上江湖萬里心。"]'),
('33dbbaee-5555-45bb-8279-a48eb9201764','句  其四','强彥文','宋','宋诗','song-poetry','','[]','客舍三杯酒，漁舟半夜燈。',12,'全唐诗/poet.song.149000.json','["客舍三杯酒，漁舟半夜燈。"]'),
('b8560b38-0d14-4d34-85d5-9c2ba402cc5e','食米倉','宋沆','宋','宋诗','song-poetry','','[]','陋巷顔回獨屢空，生涯惟在一瓢中。',32,'全唐诗/poet.song.149000.json','["陋巷顔回獨屢空，生涯惟在一瓢中。", "太倉腐粟雖山積，非義寧甘君子窮。"]'),
('eb02dd5b-3210-4792-8c81-b47a8c092bba','養蠶','宋沆','宋','宋诗','song-poetry','','[]','男必耕耘女必蠶，古人尚爾我何貪。',32,'全唐诗/poet.song.149000.json','["男必耕耘女必蠶，古人尚爾我何貪。", "浴沂時候成春服，歌詠來歸道味甘。"]'),
('bb337007-3d46-48ec-8b02-2692e5c19a57','神移泉','釋惟嶽','宋','宋诗','song-poetry','','[]','巖頭瀑布瀉寒烟，井底澄清浸月圓。',32,'全唐诗/poet.song.149000.json','["巖頭瀑布瀉寒烟，井底澄清浸月圓。", "性水真空周法界，神從何處更移泉。"]'),
('ec056b11-ea3e-4cec-8de1-7179c5fa8e44','涵虛沼','釋惟嶽','宋','宋诗','song-poetry','','[]','碧虛涵沼沼涵虛，虛沼員同絕欠餘。',32,'全唐诗/poet.song.149000.json','["碧虛涵沼沼涵虛，虛沼員同絕欠餘。", "夜月麗虛知是影，更誰臨沼照蟾蜍。"]'),
('d1d9ff3b-3b87-4e06-b060-3da31a31f368','風雩亭詞','張栻','宋','宋诗','song-poetry','','[]','眷麓山之面隩，有絃誦之一宮。',338,'全唐诗/poet.song.149000.json','["眷麓山之面隩，有絃誦之一宮。", "鬰青林兮對起，背絕壁之穹隆。", "獨樵牧之往來，委榛莽其蒙茸。", "試芟夷而却視，翕衆景之來宗。", "擢連娟之修竹，森偃蹇之喬松。", "山靡靡以旁圍，谷窈窈而潜通。", "翩兩翼兮前張，擁千麾兮後從。", "带湘江之浮淥，矗遠岫兮橫空。", "何地靈之久閟，昉經始乎今公。", "怳棟宇之宏開，列闌楯之周重。", "撫勝概以獨出，信茲山之有逢。", "予揆名而諏義，爰遠取於舞雩之風。", "昔洙泗之諸子，侍函丈以從容。", "因聖師之有問，各跽陳其所衷。", "獨點也之操志，與二三子兮不同。", "方舍瑟而鏗然，諒其樂之素充。", "味所陳之紆餘，夫何有於事功。", "蓋不忘而不助，示何始而何終。", "于鳶飛而魚躍，實天理之中庸。", "覺唐虞之遺烈，儼洋洋乎目中。", "惟夫子之所與，豈虛言之是崇。", "嗟學子兮念此，遡千載以希蹤。", "希蹤兮奈何，盍務勉乎敬恭。", "審操舍兮斯須，凜戒懼兮冥濛。"]'),
('81c711cd-8e9b-4e8a-93f1-44da17b98837','謁陶唐帝廟詞','張栻','宋','宋诗','song-poetry','','[]','溪交流兮谷幽，山作屏兮層丘。',85,'全唐诗/poet.song.149000.json','["溪交流兮谷幽，山作屏兮層丘。", "木偃蹇兮枝相樛，皇胡爲兮于此留。", "藹冠佩兮充庭，潔芳馨兮載陳。", "純衣兮在御，東風吹兮物爲春。", "皇之仁兮其天，四時敘兮何言。", "出門兮四顧，渺宇宙兮茫然。"]'),
('6befaab4-71e3-448a-a660-f01615b3b4a3','公安竹林祠迎神送神樂章','張栻','宋','宋诗','song-poetry','','[]','神之來兮何許，風蕭蕭兮吹雨。',200,'全唐诗/poet.song.149000.json','["神之來兮何許，風蕭蕭兮吹雨。", "悄屏氣兮若思，嚴霓旌兮來下。", "昔公車之自南，民望車以欷歔。", "今乘駒兮入廟，亦孔悲兮若初。", "秋月兮皎皎，嚴霜兮凜凜。", "澤終古兮何窮，噫，微管吾其左袵。", "酌荆江以爲醴兮，擷衆芳以爲羞。", "歌嗚嗚兮鼓坎坎，惠我民，爲此留。", "神之去，何所游。", "風颯颯，挾歸輈。", "倏昭明兮上征，撫一氣兮橫九州。", "有新兮斯宇，竹森森其在戶。", "嗟我民兮勿傷，公時來兮一顧。", "有新兮斯堂，竹猗猗其在旁。", "嗟我民兮勿替，公顧民兮不忘。"]'),
('0a8b69da-6322-4919-87dd-34ec384b57ad','送八兄','張栻','宋','宋诗','song-poetry','','[]','彌旬積雨穗生耳，冬壑未渠收潦水。',192,'全唐诗/poet.song.149000.json','["彌旬積雨穗生耳，冬壑未渠收潦水。", "圍爐情話政爾佳，乃復歸舟行萬里。", "三年百感卧湘城，風急鶺鴒原上情。", "豈無他人意獨真，每覺軟語溫如春。", "少年銳氣凌八區，晚以樂義稱鄉閭。", "聞人有急若己如，天報兩子雙明珠。", "小隠卜築蘭溪邊，修篁喬木今參天。", "是非榮辱不到處，卷書一榻清晝眠。", "人言壽骨隠脩眉，慶事鼎鼎供期頤。", "豈惟宗族託軌範，政倚晚節增光輝。", "有弟有弟復何爲，杜門讀書人謂癡。", "故山未遂掃松願，江頭獨立送歸時。"]'),
('0b527291-28ee-4b4d-8f2e-04cd5f32c57b','五士游嶽麓圖','張栻','宋','宋诗','song-poetry','','[]','閉門六月汗如雨，出門褦襶紛塵土。',320,'全唐诗/poet.song.149000.json','["閉門六月汗如雨，出門褦襶紛塵土。", "文書堆案曲肱卧，夢逐征鴻過前浦。", "西山突兀不可忘，勇往政須求快睹。", "朝暾未升起微風，中流吚啞挾鳴櫓。", "長林秀色已在望，有如出語見肝腑。", "意行愛此松陰直，眼明還喜碑字古。", "高低梵釋著幽居，深隠仙家開閟宇。", "忽看宮牆高十丈，學宮峩峩起鄒魯。", "斯文政倚講磨切，石室重新豈無補。", "危梯徑上不作難，橫欄截出可下俯。", "惟茲翼軫一都會，往事繁華雜歌舞。", "變遷返覆寧重論，昔日樓臺連宿莽。", "邇來人物頗還舊，豈止十年此生聚。", "泉流涓涓日循除，華表何時鶴來語。", "炎氣知不到山林，茗碗蒲團對香縷。", "鼎來杖屨皆勝引，季也亦復同步武。", "洛陽年少空白頭，三閭大夫浪自苦。", "一笑便覺真理存，高談豈畏丞卿怒。", "不圖畫僧聖得知，貌與兒童作夸詡。", "請君爲我添草堂，風雨蕭蕭守環堵。"]'),
('ad2eaece-4043-4114-ac17-f9de043bf748','次韻伯承見簡探梅之什且約人日同遊城東','張栻','宋','宋诗','song-poetry','','[]','江湖漫浪歲年晚，雖有梅花誰寄遠。',64,'全唐诗/poet.song.149000.json','["江湖漫浪歲年晚，雖有梅花誰寄遠。", "城中可人獨吳郎，不惜日力供往返。", "東郭枝頭玉雪明，下有清淺溪流橫。", "新春好趁花前約，莫待飄零空作惡。"]'),
('22978d42-5338-4bbe-8c09-238fd2711de2','張安國約同賦仇氏㔶甕酒','張栻','宋','宋诗','song-poetry','','[]','人間炎熱不可耐，君家甕頭春未央。',64,'全唐诗/poet.song.149000.json','["人間炎熱不可耐，君家甕頭春未央。", "想當醉倒卧永日，夢遶清淮歸故鄉。", "後生那得識此酒，從君乞方還肯否。", "徽州作賦爲欷歔，荆州詩來端起予。"]'),
('7b409331-43ff-448b-bd25-8ea31539aed4','李仁父寄茯苓酥賦長句謝之','張栻','宋','宋诗','song-poetry','','[]','岷峩山中千歲松，枝虬幹直摩青空。',224,'全唐诗/poet.song.149000.json','["岷峩山中千歲松，枝虬幹直摩青空。", "雪霜剝落中不槁，膏液下與靈泉通。", "龜跧鳬伏自磊砢，金堅玉潔仍豐融。", "篝明夜取喜得雋，煮鼎朝聽如吟風。", "杵成坐上看飛雪，更和酪乳收全功。", "當知至味本無味，子若服之壽莫窮。", "巽巖脊梁硬如鐵，冠峩切雲佩明月。", "百好都隨春夢空，大藥獨傳鴻寶訣。", "中霄咀嚼不摇頭，玉池生肥嚥不徹。", "憐我百慮形蚤衰，裹贈扶持意何切。", "丹砂著根謾爾傳，脂澤釀黍計已拙。", "由來妙道初不煩，此法莫從兒輩說。", "徑思舉袂揖浮丘，下視塵世真一吷。", "朱顔留得亦何爲，追逐同堅歲寒節。"]'),
('4c99a423-93e1-41e8-aff2-2e729b0dd429','和吳伯承','張栻','宋','宋诗','song-poetry','','[]','一葦湘可航，風濤逮春深。',168,'全唐诗/poet.song.149000.json','["一葦湘可航，風濤逮春深。", "裴臺咫尺地，勇往復雨淫。", "窗前幾紅藥，俯首如不禁。", "悠悠覽物化，了了知予心。", "卜鄰得佳士，問學方駸駸。", "端如雲間鶴，不受塵埃侵。", "應門有長鬚，杖策許相尋。", "匪爲食有魚，杞桋采牆陰。", "聽我清廟詩，三歎有餘音。", "洋洋百世下，斯道豈陸沉。", "君看有本源，發端自涔涔。", "願君勉勿倦，抱膝試長吟。", "儻臻名教樂，何必懷山林。", "新詩尚來嗣，庶以貽規箴。"]'),
('37219cdf-21ae-4501-a87c-b8e2b2351b65','用前韻送彪德美','張栻','宋','宋诗','song-poetry','','[]','嘗嗜貴知味，短綆難汲深。',168,'全唐诗/poet.song.149000.json','["嘗嗜貴知味，短綆難汲深。", "讀書不能發，但自成書淫。", "况復翻異說，潢流渺難禁。", "豈知言意外，妙此惟微心。", "初無古今異，歲月謾駸駸。", "五峯講學地，歎息風雨侵。", "前時約同途，舊遊愴追尋。", "鳴鳳不可見，修竹餘清陰。", "斯文天未喪，千載發韶音。", "春風滿天宇，魚鳥自飛沉。", "河流貫霄極，芥舟膠寸涔。", "神交獨吾子，妙處但微吟。", "文會匪易得，未應歸故林。", "君無泉石癖，膏肓詎須箴。"]'),
('ce1392da-4195-4ad8-8e7a-493079381121','再用前韻','張栻','宋','宋诗','song-poetry','','[]','元化首萬類，聖學極幾深。',168,'全唐诗/poet.song.149000.json','["元化首萬類，聖學極幾深。", "有如亞聖賢，尚謹殆與淫。", "淺見僅一斑，歡喜不自禁。", "豈知天地全，於穆千聖心。", "嗟哉我學子，進道宜駸駸。", "立志務弘毅，異說毋交侵。", "仁端驗發見，精微試探尋。", "超然見大體，皎日破重陰。", "重新鄒魯傳，挽回韶濩音。", "當年不自勉，與物終堙沉。", "神龍倏變化，豈復顧泥涔。", "有來南山友，更唱共迭吟。", "羣材欲封殖，杞梓看成林。", "慇懃勸學子，逆耳成良箴。"]'),
('abafe799-14ee-4994-a750-05a53467e994','采菊亭','張栻','宋','宋诗','song-poetry','','[]','陶公千載人，高標跨餘子。',132,'全唐诗/poet.song.149000.json','["陶公千載人，高標跨餘子。", "豈無濟時念，歛蔭獨知止。", "歸來卧衡門，無慍復何喜。", "九日天氣佳，東籬擷芳蕊。", "舉頭見南山，佳處政在此。", "地偏心則遠，意得道豈否。", "張侯謝銀魚，築室娛燕几。", "小亭才尋丈，景物自新美。", "頗聞雙瞳清，亦復强步履。", "不妨數登臨，倚杖看雲起。", "高詠悠然篇，飛鴻送千里。"]'),
('dda480fa-d245-4d03-b15b-8f5059dad008','送楊廷芳三首  其一','張栻','宋','宋诗','song-poetry','','[]','自吾友若人，歎息恨不早。',60,'全唐诗/poet.song.149000.json','["自吾友若人，歎息恨不早。", "相逢未出語，已足慰懷抱。", "寒窗逾浹旬，百慮略傾倒。", "霜晴不留客，別語詎能好。", "不盡此時情，梅邊試深討。"]'),
('d0778766-5dee-4652-a88f-8d3556dae2d2','送楊廷芳三首  其二','張栻','宋','宋诗','song-poetry','','[]','昔人忘言處，可到不可會。',48,'全唐诗/poet.song.149000.json','["昔人忘言處，可到不可會。", "還須心眼親，未許一理蓋。", "辭章抑爲餘，子已得其最。", "當知鄒魯傳，有在文字外。"]'),
('daac3320-7ccb-4cfa-9aea-c9da45e1aaf3','送楊廷芳三首  其三','張栻','宋','宋诗','song-poetry','','[]','平生風雨夕，每念名節難。',60,'全唐诗/poet.song.149000.json','["平生風雨夕，每念名節難。", "窮冬百草歇，手自種琅玕。", "吾子三十策，字字起三歎。", "豈欲求人知，正自一心丹。", "請哦碩人詩，匪爲樂考槃。"]'),
('42080fb7-ff73-497f-a14a-a86f3df3288b','送鮮于大任入成都幕','張栻','宋','宋诗','song-poetry','','[]','虜馬昔飲江，扁舟憶同騖。',216,'全唐诗/poet.song.149000.json','["虜馬昔飲江，扁舟憶同騖。", "翁方爲國謀，客以名義故。", "安危匪前料，得失渠異趣。", "淮壖渺風雪，王事有程度。", "息偃多在床，君車不停駐。", "初無作難色，所立詎愆素。", "嗟我吳門別，風木歲徂暮。", "相逢復湘城，往事忍回顧。", "獨餘後凋心，特立凜不懼。", "莫邪雖云利，寧作囊錐露。", "善藏要有待，小試隨所遇。", "終無缺折虞，豈但走狐兔。", "吾州得良牧，民力或可裕。", "本根頼封殖，彊索費調護。", "從容試長思，取急無窘步。", "作別忽草草，懷抱復誰付。", "他時下瞿唐，訪我林下屨。", "儻於功名餘，更講末後句。"]'),
('ca71ec17-fd60-4f94-9529-1a2cbf50067c','同遊嶽麓分韻得洗字','張栻','宋','宋诗','song-poetry','','[]','遊觀不作難，呼舟度清泚。',72,'全唐诗/poet.song.149000.json','["遊觀不作難，呼舟度清泚。", "新晴宿潦凈，羣山政如洗。", "上方著危欄，萬象見根柢。", "寒泉自可斟，况復雜肴醴。", "高談下夕陽，邂逅玄鑰啟。", "中流發浩歌，月色在波底。"]'),
('4070713e-03ff-4fc0-b3fc-d2e5ef02fb7c','送張深道二首  其一','張栻','宋','宋诗','song-poetry','','[]','秋風木葉落，送客麗譙東。',108,'全唐诗/poet.song.149000.json','["秋風木葉落，送客麗譙東。", "豈懷兒女戀，愛此趣味同。", "至理無轍迹，妙在日用中。", "聞言有不信，渠自馬牛風。", "吾子實所畏，立志高冥鴻。", "卓然遊聖門，不受異說訌。", "切磋豈不樂，愧非斲鼻工。", "於皇太極藴，精微浩無窮。", "願言終玩繹，默參元化功。"]'),
('a2ed53f2-6edb-4c88-bdbf-e80e26eb2b1a','送張深道二首  其二','張栻','宋','宋诗','song-poetry','','[]','人言底柱險，袖手不敢邇。',120,'全唐诗/poet.song.149000.json','["人言底柱險，袖手不敢邇。", "孰知人心危，毫釐千萬里。", "有來事物繁，酬酢無披靡。", "雖云應不難，要且辨真僞。", "良知本易直，天機驗所起。", "涵濡自日新，日新乃無蔽。", "聖學非空言，要領故在此。", "吾子端發源，所進渺涯涘。", "我雖念不敏，詎敢忘所止。", "後會儻有時，深功同舉似。"]'),
('f714526e-3ba5-4365-ae5e-c22463e91ef8','留題金山寺','張栻','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江岷山來，灌注天下半。',120,'全唐诗/poet.song.149000.json','["長江岷山來，灌注天下半。", "東行近海門，勇往更瀰漫。", "蒼巒忽中流，屹立助傑觀。", "孤根入層淵，秀色連兩岸。", "我來最奇絕，霜月與璀璨。", "褰衣到絕頂，恍若上河漢。", "悠然發遐思，俯仰爲三歎。", "乾坤無餘藏，今古有長算。", "更深寂羣動，樹杪獨鳴鸛。", "回頭喚山僧，爲記此公案。"]'),
('fdb47f60-d573-4e87-8209-b4be36c5199f','送范西叔教授西歸','張栻','宋','宋诗','song-poetry','','[]','乃祖至和間，忠謀書鼎彝。',192,'全唐诗/poet.song.149000.json','["乃祖至和間，忠謀書鼎彝。", "但知陛下聖，豈知吾言危。", "元祐愛君語，讀者猶涕洟。", "典刑今不亡，盛德故在茲。", "歲晚子過我，秀若齋房芝。", "持身蹈規矩，出語無瑕疵。", "向來長安道，詎肯舍靈龜。", "萬里一泮宮，行囊幾新詩。", "湘山足幽勝，而水清漣漪。", "登臨豈不樂，邂逅枌榆思。", "我懶抱僻學，絕絃理朱絲。", "子獨慕千載，悠然契心期。", "豈不爲我留，感此節物移。", "臨岐撫陳編，爲子三噫嘻。", "高深諒何極，循求有端倪。", "願言勉事此，奕葉光前規。"]'),
('56bcdd87-e412-4641-947c-93bb15dd0f48','王長沙梅園分韻得林字','張栻','宋','宋诗','song-poetry','','[]','令君五畝園，不問蓬蒿深。',96,'全唐诗/poet.song.149000.json','["令君五畝園，不問蓬蒿深。", "江梅忽秀發，邂逅成賞音。", "一笑領諸客，掃地坐牆陰。", "清芳到酒面，落蕊飄衣襟。", "月去未忍去，起舞獨微吟。", "人自賞晤耳，問花亦何心。", "花雖有開落，意則無古今。", "須君戒勿折，嘉實看成林。"]'),
('6f1a4c75-e5bd-4ab5-97cf-eb8dd120272e','送邵懷英赴召','張栻','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','自君之西來，吾徒獲三益。',204,'全唐诗/poet.song.149000.json','["自君之西來，吾徒獲三益。", "匪惟欣晤言，望見意已適。", "俯仰歲再更，交情共金石。", "翩然別我去，寧復得此客。", "諸公有推轂，詔下亟傳驛。", "嘉言久填胸，往覲天咫尺。", "豈其湘水邊，而可滯六翮。", "雖深惜別思，敢後天下責。", "嗟哉善利途，鷄鳴分舜蹠。", "浮雲起毫釐，乃有泰山隔。", "持身與謀國，茲義貫於一。", "君侯天資高，遇事無逼迫。", "所立凜不回，舉手謝物役。", "保此方寸印，勿受一塵隙。", "廓然麗昭回，萬象歸指畫。", "富貴豈君心，事業追往昔。", "贈言不能工，庶以永無斁。"]'),
('78dfe271-49eb-47ec-be9f-eb07ff764881','陪安國舍人勞農北郊分韻得闌字','張栻','宋','宋诗','song-poetry','','[]','寒收花尚瘦，風靜江不湍。',120,'全唐诗/poet.song.149000.json','["寒收花尚瘦，風靜江不湍。", "元戎肅千騎，歷覽無留難。", "好景要徐出，微雲故遮闌。", "惟春布嘉惠，公豈樂遊觀。", "龐眉八十老，扶杖來蹣跚。", "去年幸一稔，何以報長官。", "酌酒公自勞，得無有愁嘆。", "嗟哉三章約，所貴簡且寬。", "黄堂載清靜，自覺田里安。", "須公出妙語，茲遊記不刊。"]'),
('2cef3ad2-f090-4426-a31f-5786f9311e3b','安國晚酌葵軒分韻得成字','張栻','宋','宋诗','song-poetry','','[]','桐花三月寒，風雨滿江城。',120,'全唐诗/poet.song.149000.json','["桐花三月寒，風雨滿江城。", "使君晚被酒，千騎過友生。", "名談宿霧捲，逸氣孤雲橫。", "揮斥看墨妙，笑語皆詩成。", "人物有如此，爾輩頼主盟。", "更呼南鄰客，共此樽酒傾。", "愛我庭下竹，頭角方崢嶸。", "永懷冰雪姿，寧復世俗情。", "新篇一湔祓，凡木不足程。", "願言謹封殖，歲晚長敷榮。"]'),
('335c2354-7b28-46ee-af41-c89521887163','安國置酒敬簡堂分韻得柳暗六春字  其一','張栻','宋','宋诗','song-poetry','','[]','桴鼓息荒村，襏襫盛南畝。',48,'全唐诗/poet.song.149000.json','["桴鼓息荒村，襏襫盛南畝。", "永日省文書，呼客共樽酒。", "主人出塵姿，宛是靈和柳。", "行歸帝所遊，此地豈淹久。"]'),
('b2f5cd10-734f-4576-8171-71405cfd8788','安國置酒敬簡堂分韻得柳暗六春字  其二','張栻','宋','宋诗','song-poetry','','[]','公卧百尺樓，餘子可下瞰。',48,'全唐诗/poet.song.149000.json','["公卧百尺樓，餘子可下瞰。", "我每奉談麈，汲古得深探。", "身外皆爲餘，此道要無憾。", "從渠梅雨天，陰晴遞明暗。"]'),
('efdd3cb0-b47c-4e0a-b0b7-4d4f65d1820f','安國置酒敬簡堂分韻得柳暗六春字  其三','張栻','宋','宋诗','song-poetry','','[]','公憎孔壬面，怪石乃寓目。',48,'全唐诗/poet.song.149000.json','["公憎孔壬面，怪石乃寓目。", "夜堂發深藏，林立驚滿屋。", "我亦苦嗜此，一見下風伏。", "何當載而歸，妙策三十六。"]'),
('3bb9812d-ed08-45c9-b254-f8b803c75a24','安國置酒敬簡堂分韻得柳暗六春字  其四','張栻','宋','宋诗','song-poetry','','[]','堂下列絲竹，堂上娛佳賓。',48,'全唐诗/poet.song.149000.json','["堂下列絲竹，堂上娛佳賓。", "相看夜未艾，樂此笑語真。", "風流今屬公，我輩但逡巡。", "文章千古意，翰墨四時春。"]'),
('c8ef0e30-1848-417b-b4b6-cae30871773b','同元晦擇之遊嶽道遇大雪馬上作','張栻','宋','宋诗','song-poetry','','[]','驅車望衡嶽，羣山政參差。',144,'全唐诗/poet.song.149000.json','["驅車望衡嶽，羣山政參差。", "微風忽南來，雲幕爲四垂。", "炎官挾蓐收，從以萬玉妃。", "庭熒亦何有，尺璧仍珠璣。", "奇貨吾敢居，妙意良自知。", "林巒倏變化，轍迹平高低。", "喬松與修竹，錯立呈瑰姿。", "清新足遐寄，浩蕩多餘思。", "平生湘南道，未省有此奇。", "況復得佳友，晤言相追隨。", "茅簷舉杯酒，旅榻誦新詩。", "更約登絕頂，同觀霽色時。"]'),
('0d445223-e6bd-4808-95c0-6f0e6a8a77cb','詩送元晦尊兄','張栻','宋','宋诗','song-poetry','','[]','君侯起南服，豪氣蓋九州。',192,'全唐诗/poet.song.149000.json','["君侯起南服，豪氣蓋九州。", "頃登文石陛，忠言動宸旒。", "坐令聲利場，縮頸仍包羞。", "却來卧衡門，無愧自日休。", "盡收湖海氣，仰希洙泗游。", "不遠關山阻，爲我再月留。", "遺經得紬繹，心事兩綢繆。", "超然會太極，眼底無全牛。", "惟茲斷金友，出處寧殊謀。", "南山對床語，匪爲林壑幽。", "白雲政在望，歸袂風颼飀。", "朝來出別語，已抱離索憂。", "妙質貴强矯，精微更窮搜。", "毫釐有弗察，體用豈周流。", "驅車萬里道，中途可停輈。", "勉哉共無斁，邈矣追前修。"]'),
('d72953c3-b6b9-4af7-af64-f97b7f8f3420','遊南嶽風雪未已决策登山用春風樓韻','張栻','宋','宋诗','song-poetry','','["\u8861\u5c71"]','人言南山巔，煙雲聳樓觀。',96,'全唐诗/poet.song.149000.json','["人言南山巔，煙雲聳樓觀。", "俯瞰了坤倪，仰攀接天漢。", "勇往愧未能，長吟湘水畔。", "茲來渺遐思，風雪豈中斷。", "行行重行行，敢起自畫歎。", "我聞精神交，石裂冰可泮。", "陰沴驅層霄，呆日麗旭旦。", "决策君勿疑，此理或通貫。"]'),
('dca878df-b064-4c0d-86b0-7fada47b8b46','陪舍人兄過陳仲思溪亭深有買山卜鄰之意舍人兄預以顓壑見名因成古詩贈仲思','張栻','宋','宋诗','song-poetry','','[]','築居湘水濱，歲月亦已久。',192,'全唐诗/poet.song.149000.json','["築居湘水濱，歲月亦已久。", "寧知負郭東，勝處入君手。", "回環烟塢深，有此溪十畝。", "朝暾穿林薄，荷氣薰戶牖。", "堂堂吾州牧，下馬喚賓友。", "主人故喜事，一笑具殽䔩。", "汲泉泛崇蓮，洗醆傾稚酒。", "淋漓壁間書，自可傳不朽。", "我獨留薄莫，并溪時矯首。", "人言君不偶，此豈落人後。", "觀君眉宇間，似亦挾所有。", "隔溪更幽絕，古木蔭高阜。", "却立望遥岑，四序列鍾卣。", "買山吾計决，便欲剪榛莠。", "居然顓一壑，豈羨印如斗。", "未知鄰家翁，還肯見容否。"]'),
('69d0e678-81b8-4e32-9acd-539938deb7ac','送然姪西歸二首  其一','張栻','宋','宋诗','song-poetry','','[]','堂堂希白翁，共惟同出自。',84,'全唐诗/poet.song.149000.json','["堂堂希白翁，共惟同出自。", "百年詩禮傳，名教有樂地。", "嗟予力未勝，永抱蓼莪意。", "積累蓋百艱，承家豈云易。", "惕然履淵冰，中夜耿不寐。", "協心望爾曹，勉力紹前志。", "歲晚期有成，庶或保無墜。"]'),
('1bf1d4e4-bc2f-4dbe-9c7a-32c9d5d0a504','送然姪西歸二首  其二','張栻','宋','宋诗','song-poetry','','[]','自子來見我，倏焉十六秋。',120,'全唐诗/poet.song.149000.json','["自子來見我，倏焉十六秋。", "一聞沂上音，此意便綢繆。", "中間豈不別，會合同轉頭。", "今茲舍我去，萬里不復留。", "豈不能挽子，懼子爲親憂。", "六月送歸船，我思與悠悠。", "愛子剛毅資，不作繞指柔。", "願子進問學，琢磨須自修。", "居然知見廣，百病會有瘳。", "誰謂道云遠，行矣當深求。"]'),
('34b6c722-cd41-4722-bdc3-a2ccf493d040','送黄子默','張栻','宋','宋诗','song-poetry','','[]','元祐不復見，太史今諸孫。',156,'全唐诗/poet.song.149000.json','["元祐不復見，太史今諸孫。", "人物尚論世，典刑故猶存。", "酣歌拓金戟，三年佐雄藩。", "超然車馬中，高韻獨孤騫。", "永懷白鷗盟，修竹滿故園。", "得句見眉睫，外慕何足言。", "顧以感知己，跋馬向修門。", "朝開英俊途，王度待討論。", "小試翰林手，乘槎薄崑崙。", "我懶卧衡麓，秋風擷蘭蓀。", "交遊歎益落，拭目看騰掀。", "軒冕豈足貴，政爾名義尊。", "執手念相聞，此意古所敦。"]'),
('d6c0babf-c275-4336-852f-d8df3019c691','過胡文定公碧泉書堂','張栻','宋','宋诗','song-poetry','','[]','入門認溪碧，循流識深源。',120,'全唐诗/poet.song.149000.json','["入門認溪碧，循流識深源。", "念我昔此來，及今七寒暄。", "人事幾更變，寒花故猶存。", "堂堂武夷翁，道義世所尊。", "永袖霖雨手，琴書賁丘園。", "當時經行地，尚想語笑溫。", "愛此亭下水，固若玻璃盆。", "晴看浪花湧，靜見潜鱗翻。", "朝昏遞日月，俯仰鑑乾坤。", "因之發深感，倚檻更忘言。"]'),
('d2ce566b-8dff-4fa3-94d8-2ba8dc70b4af','次韻德美碧泉感舊之什且約胡廣仲伯逢季丘來會上封','張栻','宋','宋诗','song-poetry','','[]','相逢傾蓋地，回首歎川上。',240,'全唐诗/poet.song.149000.json','["相逢傾蓋地，回首歎川上。", "士窮不足怪，但喜氣愈王。", "凜然歲寒姿，儒林有龍象。", "棲遲似隠君，矍鑠真詩將。", "惟應一彈指，欲了四大藏。", "舊習想冰消，豈復留餘恙。", "新篇更紆餘，和氣與醖釀。", "却思東魯遊，幾載南陽葬。", "風霜摧宰木，日月隨過浪。", "豈期經世心，晚歲成獨往。", "蕭然屋半欹，使我懷抱愴。", "獨有千載傳，此事可憑仗。", "細觀宇宙間，何得復何喪。", "尚期浮雲開，衡嶽來見狀。", "秋壑采蘭蓀，霜林收栗橡。", "曉看日浮空，夜賞雪侵帳。", "更憐二三友，前山屹相望。", "文會儻來尋，勝踐天所相。", "妙理須細論，長歌却雄放。", "褰裳請勿疑，當仁應不讓。"]'),
('867719dc-93a3-4060-a2fd-d3876373f87c','自西園登山','張栻','宋','宋诗','song-poetry','','[]','雨後溪重碧，木落山增明。',48,'全唐诗/poet.song.149000.json','["雨後溪重碧，木落山增明。", "西風肅羣物，感此秋氣清。", "振衣千崖表，俯瞰萬籟生。", "匪云幽遐慕，政爾未忘情。"]'),
('63b3ad60-9ffe-4a84-a0e9-34776c3dc819','路出祝融背仰見上封寺遂登絕頂','張栻','宋','宋诗','song-poetry','','[]','我尋西園路，徑上上封寺。',180,'全唐诗/poet.song.149000.json','["我尋西園路，徑上上封寺。", "竹輿不留行，及此秋容霽。", "磴危霜葉滑，林空山果墜。", "崇蘭供清芬，深壑遞幽吹。", "不知山益高，但覺冷侵袂。", "路回屹陰崖，突兀聳蒼翠。", "故應祝融尊，羣峰拱而侍。", "金碧雖在眼，勇往詎容憩。", "絕頂極遐觀，脚力聊一試。", "昔遊冰雪中，未盡登臨意。", "茲來天宇肅，舉目凈纖翳。", "遠邇無遁形，高低同一視。", "永惟元化功，清濁分萬類。", "運行有機緘，浩蕩見根柢。", "此理復何窮，臨風但三喟。"]'),
('fa734645-ad46-48a1-a4ad-ce7373344537','中夜祝融觀月','張栻','宋','宋诗','song-poetry','','[]','披衣凜中夜，起步祝融巔。',84,'全唐诗/poet.song.149000.json','["披衣凜中夜，起步祝融巔。", "何許冰雪輪，皎皎飛上天。", "清光正在手，空明浩無邊。", "羣峯儼環列，玉樹生瓊田。", "白雲起我旁，兩腋風翩翩。", "舉酒發浩歌，萬籟爲寂然。", "寄言平生友，誦我山中篇。"]'),
('f4bc7142-034b-4a5a-85e5-36e9290d4415','晨鐘動雷池望日','張栻','宋','宋诗','song-poetry','','[]','浮氣列下陳，天凈澄秋容。',84,'全唐诗/poet.song.149000.json','["浮氣列下陳，天凈澄秋容。", "朝暾何處升，彷彿認微紅。", "須臾眩衆采，閶闔開九重。", "金鉦忽湧出，晃蕩浮雙瞳。", "乾坤豁呈露，羣物光芒中。", "誰知雷池景，乃與日觀同。", "徒傾葵藿心，再拜御曉風。"]'),
('546181af-8031-47cd-b33b-784e956cb4a5','道旁見穫者','張栻','宋','宋诗','song-poetry','','[]','腰鎌聲相呼，十百南畝穫。',96,'全唐诗/poet.song.149000.json','["腰鎌聲相呼，十百南畝穫。", "婦持黍漿饋，幼稚走雀躍。", "辛勤既百爲，幸此歲不惡。", "王租敢不供，大室趣逋約。", "雖云粒米多，未辦了升龠。", "姑寬目前饑，詎有卒歲樂。", "樂歲尚爾爲，一歉更何託。", "書生獨多憂，何以救民瘼。"]'),
('466557c5-d02b-416b-a1c6-083bc31ca4cb','臘後一日尋梅東門外馬上遇雪','張栻','宋','宋诗','song-poetry','','[]','羸驂出東郭，靜與幽意期。',96,'全唐诗/poet.song.149000.json','["羸驂出東郭，靜與幽意期。", "尋梅冷入眼，野路信所之。", "寒萼靳未吐，我自愛橫枝。", "雪花忽排空，成此一段奇。", "歲晚故人闊，天寒鴻鴈稀。", "南國少霜霰，北山多蕨薇。", "坐看節物改，莫遣心事違。", "角巾風獵獵，日暮獨吟歸。"]'),
('d949b8e4-4495-4bde-8318-7e8f6468763b','雪中登樓分韻得未字','張栻','宋','宋诗','song-poetry','','[]','南州冬多溫，一雪已可貴。',96,'全唐诗/poet.song.149000.json','["南州冬多溫，一雪已可貴。", "今年臘三白，故足蘇品彙。", "朝來并危欄，舉酒聊自慰。", "翩翩著客衣，漠漠亂雲氣。", "珪璧滿天地，造物初不費。", "更邀二三友，晤賞見風味。", "燭至僕尚更，酒苦飲亦既。", "仍遣探梅花，已折南枝未。"]'),
('3e3ae6c8-4677-4bff-ab2f-2c3e287595e8','笋脯一平馳寄因和去歲詩爲一笑春笋未盛尚續致也','張栻','宋','宋诗','song-poetry','','[]','權門極珍羞，未辦食龍肉。',56,'全唐诗/poet.song.149000.json','["權門極珍羞，未辦食龍肉。", "我家湘楚山，籜龍飫奴僕。", "淮南戶戶有黄虀，公今徑歸亦不癡。", "更包笋脯贈行李，定應笑殺長安兒。"]'),
('573750d8-b050-4c17-a089-f30a41c234ac','湖南使者邵公召赴行在所寓客張某敬賦以餞行李','張栻','宋','宋诗','song-poetry','','[]','公來使湘州，氣象日淳美。',144,'全唐诗/poet.song.149000.json','["公來使湘州，氣象日淳美。", "不爲察察明，自謂平平耳。", "未須走原隰，但使心如水。", "儻無耳目蔽，庭戶即千里。", "頃聞上封章，便欲返桑梓。", "其如矍鑠姿，難著湖山裏。", "春風一札下，趣往覲天咫。", "新淥渺滄洲，揚舲一何駛。", "士方處遠外，憂國抱藴底。", "寧應立君前，輔車有或柅。", "煌煌四門開，側席問民疻。", "百慮願畢陳，高風泚餘子。"]'),
('bd7e434d-184f-408a-b138-b4602371ba1e','次韻元晦擇之雪中見懷','張栻','宋','宋诗','song-poetry','','[]','流水浩無息，游雲去不休。',168,'全唐诗/poet.song.149000.json','["流水浩無息，游雲去不休。", "我思在何許，起步三徑幽。", "男子四方志，胡爲守一丘。", "盍簪未可期，此意空綢繆。", "平生子朱子，砥柱屹橫流。", "探古獨遐觀，萬象供雙眸。", "結友得林子，苦心事窮搜。", "看渠清介姿，便可披羊裘。", "昔者千里駕，共我風雪遊。", "永言清絕景，祇以好語酬。", "居然隔年別，却喜翰墨留。", "詩來尚記憶，知子不我尤。", "講習今難忘，離索古所憂。", "但當勉耘耔，歲晚儻可收。"]'),
('00f9f064-fb32-4e35-b49b-6fa7368cf520','送甘甥可大從定叟弟之桂林','張栻','宋','宋诗','song-poetry','','[]','季也有行役，我思獨悠悠。',168,'全唐诗/poet.song.149000.json','["季也有行役，我思獨悠悠。", "親朋非不多，子能從之遊。", "挂席上湘水，青山挾行舟。", "籃輿問嶺路，政爾荔子秋。", "人言桂林好，頗復類中州。", "近郊多勝概，雉堞冠層樓。", "待渠幕府暇，時與同冥搜。", "吾子有令姿，胸中富九流。", "處世多齟齬，但當付滄洲。", "超然擴遐思，詎可耳目謀。", "願爲百鍊剛，莫作繞指桑。", "昔人不吾欺，子盍試反求。", "預想他年歸，此地復綢繆。", "刮目看二子，一笑紓百憂。"]'),
('82bb410a-aa95-4604-8d1e-47cee41f2c2f','湘中館餞定叟弟分韻得位字','張栻','宋','宋诗','song-poetry','','[]','江樓倚夜闌，樽酒留客醉。',48,'全唐诗/poet.song.149000.json','["江樓倚夜闌，樽酒留客醉。", "挽衣更小語，不盡今夕意。", "吾家德義尊，此豈在名位。", "勉哉嗣芬芳，停此寬別思。"]'),
('295950e0-6139-4913-a3fa-75bde96a39d6','廣漢黄仲秉即轉運使治之東作亭扁以楚翠蓋取杜陵所謂楚岫千峰翠者屬客賦詩','張栻','宋','宋诗','song-poetry','','[]','維衡屹南荒，作鎮自開闢。',168,'全唐诗/poet.song.149000.json','["維衡屹南荒，作鎮自開闢。", "蟠根結地厚，面勢倚空碧。", "陂陀數州境，高下相接迹。", "麓山乃其趾，神秀固未極。", "定王十里城，處處見山色。", "知誰長在眼，嗟此塵中客。", "觀風君獨暇，延納到几席。", "得句恍忘言，寄興渺今昔。", "自君之東來，民瘼極探索。", "仁言徹九關，寧懼虎豹厄。", "諏詢遍南畝，民肥吾則瘠。", "築亭一舒嘯，逮此百憂隙。", "看山儻不愧，隠几亦聊適。", "寄語後來者，此意當無斁。"]'),
('e33cae37-b096-49d4-92eb-a54baf22596b','三茅觀李仁父劉文潜員顯道趙溫叔崔子淵置酒分韻得高字','張栻','宋','宋诗','song-poetry','','[]','節物歲云暮，九衢塵滿袍。',132,'全唐诗/poet.song.149000.json','["節物歲云暮，九衢塵滿袍。", "起我二三友，招要步林皋。", "仰看冥飛鴻，俯覽千丈濤。", "石徑上深窈，竹風更蕭騷。", "杯槃自真率，更起瀉濁醪。", "歎我會合難，慰我涉歷勞。", "薰然鄉社遊，飲少意已陶。", "我亦壽長者，萬里欣所遭。", "嗟哉士業艱，逝矣日月滔。", "古義重金石，外物真秋毫。", "願言共勉厲，勿負岷山高。"]'),
('e3df1fd9-8707-4f8c-a4c2-e854446a8d28','寒食前三日野步烏龍山中石上往往多新芽手擷盈匊酌玉泉煮之芳甘特甚有懷伯承兄賦此以寄','張栻','宋','宋诗','song-poetry','','[]','披雲得新腴，煮泉聽松風。',132,'全唐诗/poet.song.149000.json','["披雲得新腴，煮泉聽松風。", "香永味自真，不與餘品同。", "悠然泊莫留，歸來隠疎鐘。", "念昔湘濱游，年年擷芳叢。", "遲日照高嶺，新雷驚蟄龍。", "落磑快先啜，鼓腹欣策功。", "夜燈紫筠窗，香生編簡中。", "誰與共此樂，臭味有鄰翁。", "朅來七里城，日月轉飛蓬。", "山川豈不好，予憂日忡忡。", "酌此差自慰，思君復無窮。"]'),
('a7600878-b298-47cf-b27d-cf38959ac52c','六月晦發霅川廣德兄與諸友飲餞于漁山已而皆有詩贈別寄此言謝','張栻','宋','宋诗','song-poetry','','[]','平生苕霅夢，邂逅此登臨。',144,'全唐诗/poet.song.149000.json','["平生苕霅夢，邂逅此登臨。", "青山秀而遠，溪水潔且深。", "浮玉千古色，飛鳳何年音。", "小丘闢茺薈，修竹初成林。", "居然得此客，領畧還披襟。", "已歌棠棣詩，更作伐木吟。", "兄嗟弟行役，友念朋盍簪。", "情深語更質，意到酒自斟。", "荷風生泊莫，凉雨洗遥岑。", "翻然放舟去，別緒故難任。", "我行日以遠，佳處長會心。", "作詩寄余韻，併以謝幽尋。"]'),
('45ecceca-8590-4722-941f-9b558d88d14e','遊靈岩','張栻','宋','宋诗','song-poetry','','[]','我登姑蘇臺，笑指前溪水。',252,'全唐诗/poet.song.149000.json','["我登姑蘇臺，笑指前溪水。", "水從具區來，古色映清泚。", "明朝泛舟去，兩岸雜蘋芷。", "縈紆知幾曲，舉目皆可喜。", "稻熟千頃黄，秋入四山紫。", "疎鐘度橫塘，青帘穿野市。", "忽驚秀氣逼，突兀平地起。", "飛閣出林顛，穹石滿山趾。", "褰裳上深徑，鳴蟬聲聒耳。", "木罅露遐觀，欲進足屢止。", "梵宮開何年，金碧煥相倚。", "上方納湖光，千里凈如砥。", "中峯何亭亭，正爾當燕几。", "沙闊鷗鷺微，水落魚龍徙。", "雲遶闔閭邦，草迷于越壘。", "琴臺俯香徑，不念前王侈。", "茲山自古今，詎此能爲疻。", "老松獨堅卧，根株互盤峙。", "頹然閲滄波，愛此青未已。", "我來三日留，幽事付行李。", "領畧寧有窮，登臨聊可紀。"]'),
('c55a9853-7d49-493d-beab-55ade81149ed','遊惠山','張栻','宋','宋诗','song-poetry','','[]','茲泉幾歲月，復此慰渴心。',72,'全唐诗/poet.song.149000.json','["茲泉幾歲月，復此慰渴心。", "諒惟獨鍾秀，源委來何深。", "在昔抱幽獨，邂逅逢賞音。", "希聲聽者難，至味乃可尋。", "兀坐正亭午，凉風度清陰。", "於焉有深晤，三歎復微吟。"]'),
('61b5960d-e56e-428f-a74a-b6a58cd9cbc1','遊池州齊山','張栻','宋','宋诗','song-poetry','','["\u897f\u6e56"]','舊聞齊山勝，抱病來登臨。',144,'全唐诗/poet.song.149000.json','["舊聞齊山勝，抱病來登臨。", "蒼然俯平湖，秀出幾百尋。", "穹石天與巧，修篁近成林。", "高攀極巉巖，俯探窮窈深。", "愛此堅貞姿，摩挲會予心。", "憶行西湖岸，亦復多嶔崟。", "頗恨人力勝，刻畫時見侵。", "誰知醜石面，乃亦變孔壬。", "何如榛莽間，屹立長森森。", "天然抱幽獨，妙質逢賞音。", "支筇到絕頂，孤亭指遥岑。", "樊川有留詠，兀坐一長吟。"]'),
('dbbbb79e-a614-4968-8296-d474abd3137e','齊山石壁間見林擇之題字緬懷其人賦此','張栻','宋','宋诗','song-poetry','','[]','平生子林子，一別今幾春。',96,'全唐诗/poet.song.149000.json','["平生子林子，一別今幾春。", "寧知林壑中，忽見題墨新。", "巉巉屹蒼石，恍若對其人。", "徘徊不忍去，我懷誰爲陳。", "自子來江東，相去亦已邇。", "謂當復相逢，跂首日望子。", "云何竟差池，又此隔千里。", "憑高久佇立，飛鴻渺煙水。"]'),
('56488ac2-2b44-432f-ae35-5b72313e7e58','過馬當山','張栻','宋','宋诗','song-poetry','','[]','千秋馬當廟，千尋獅子磯。',48,'全唐诗/poet.song.149000.json','["千秋馬當廟，千尋獅子磯。", "寒風起崖腹，慘澹含陰威。", "孤帆駕巨浪，瞬息洲渚非。", "忠信儻可仗，神理茲不違。"]'),
('02190935-ee76-4cbe-ada8-2bcac4184e0f','過乖崖堂','張栻','宋','宋诗','song-poetry','','[]','平生乖崖公，及此拜仿像。',204,'全唐诗/poet.song.149000.json','["平生乖崖公，及此拜仿像。", "凜然風埃外，餘子避英爽。", "憶公昔正色，抗論指邪枉。", "念當絕其根，所畏日滋長。", "晴空轟雷霆，下土走魅魍。", "云何廊廟姿，半世江海上。", "徒令治郡聲，迄今滿天壤。", "論相危及公，亦豈坐倔彊。", "嗟哉彼隘俗，利欲扼其吭。", "聞公卓絕風，吐舌仍儻怳。", "豈知古之人，事業係所養。", "臨機隨手應，如爬適苛癢。", "李侯亦高世，希蹤自疇曩。", "萬里見丹青，高堂闢虛敞。", "琅琅壁間記，讀者興慕仰。", "我來歲云莫，霜林振餘響。", "嘆息重徘徊，題詩詔吾黨。"]'),
('3ae5adc9-fdc3-41e8-993d-d25ef43825ac','張子囦携二子西歸求予詩爲賦此以致鄉黨之義','張栻','宋','宋诗','song-poetry','','[]','窮冬泝荆江，風急波濤怒。',216,'全唐诗/poet.song.149000.json','["窮冬泝荆江，風急波濤怒。", "張君一葉舟，追逐任掀舞。", "時從古岸邊，頗得班荆語。", "君家岷山下，須眉挾風雨。", "萬里垂橐歸，問君自何苦。", "兩兒纔過膝，秀色隠眉宇。", "昨者試省中，旁觀正如堵。", "誦書聲琅琅，亦復記訓詁。", "呼前與酬答，進止良應矩。", "我爲三咨嗟，每見必摩拊。", "祝君須愛惜，事業貴有序。", "美質在陶冶，如器無苦窳。", "道遠方愁予，速成戒自古。", "可使利欲風，居然熏肺腑。", "良心人所同，愛敬發端緒。", "岷江本一勺，東流貫吳楚。", "但當養其源，日進自莫禦。", "君歸閉門思，予言或可取。"]'),
('fcf728e1-b3b5-4ffb-95c3-d70d3083150e','補題東都善惠師禪齋','梅堯臣','宋','宋诗','song-poetry','','[]','香象紅蕖坐，花盆白石臺。',48,'全唐诗/poet.song.15000.json','["香象紅蕖坐，花盆白石臺。", "上公金印去，王子玉駒來。", "心是寒缾水，明無寶鏡埃。", "世人何擾擾，時爲一言開。"]'),
('e7687b9a-76e9-474b-9265-7fd065a8d2e5','送萬殿丞虔州安遠軍','梅堯臣','宋','宋诗','song-poetry','','[]','新雷動江雨，百鳥響溪巖。',48,'全唐诗/poet.song.15000.json','["新雷動江雨，百鳥響溪巖。", "逆水送行客，順風催挂帆。", "過山唯廟敬，團飯與烏銜。", "太守雖憐舊，須妨有嫉讒。"]'),
('49be3688-311c-4c98-8467-2557d2f90cd6','野望','梅堯臣','宋','宋诗','song-poetry','','[]','新晴宜野望，最愛是山前。',48,'全唐诗/poet.song.15000.json','["新晴宜野望，最愛是山前。", "遠近花兼竹，高低水拍田。", "呼名鳥無數，問姓客多年。", "此地春耕晚，吳牛樹底眠。"]'),
('31dfacd8-5d1f-4cde-b08f-6db7606c438e','泛溪','梅堯臣','宋','宋诗','song-poetry','','[]','中流清且平，捨楫任船行。',48,'全唐诗/poet.song.15000.json','["中流清且平，捨楫任船行。", "漸近鷺猶立，已遥村覺橫。", "何妨綠樽滿，不畏晚風生。", "屈賈江潭上，愁多未適情。"]'),
('1755fc98-b2c7-44e1-aff3-5a6306bac725','春陰','梅堯臣','宋','宋诗','song-poetry','','[]','雲壓花房冷，風開柳絮遲。',48,'全唐诗/poet.song.15000.json','["雲壓花房冷，風開柳絮遲。", "幽人宿酲在，靜館晝眠時。", "欲雨天無雨，將絲鬢未絲。", "孔融過五十，歲月已堪悲。"]'),
('62c8cef1-bc1d-4b06-ad34-32bfa5f63dab','新燕','梅堯臣','宋','宋诗','song-poetry','','[]','前時春社畢，今日燕來飛。',48,'全唐诗/poet.song.15000.json','["前時春社畢，今日燕來飛。", "將補舊巢缺，不嫌貧屋歸。", "銜泥和草梗，側翅過柴扉。", "豈比驚丸雀，迎人欲拂衣。"]'),
('28149cd1-2a3f-469e-a627-53cc8cf97b2c','梨花','梅堯臣','宋','宋诗','song-poetry','','[]','處處梨花發，看看燕子歸。',48,'全唐诗/poet.song.15000.json','["處處梨花發，看看燕子歸。", "園思前法部，淚濕舊宮妃。", "月白鞦韆地，風吹蛺蝶衣。", "强傾寒食酒，漸老覺歡微。"]'),
('974acb4d-f61c-4db0-8b5b-802b9c6eaf13','新筍','梅堯臣','宋','宋诗','song-poetry','','[]','挑筍春雷後，晴坡過雨時。',48,'全唐诗/poet.song.15000.json','["挑筍春雷後，晴坡過雨時。", "何言江外早，已比洛陽遲。", "園客自偷賣，主人那得知。", "徒令養新竹，待與作藩籬。"]'),
('5b90006c-ef30-4c38-9f77-e4f865e818ef','海棠','梅堯臣','宋','宋诗','song-poetry','','[]','要識吳同蜀，須看線海棠。',48,'全唐诗/poet.song.15000.json','["要識吳同蜀，須看線海棠。", "燕脂色欲滴，紫蠟蔕何長。", "夜雨偏宜著，春風一任狂。", "當時杜子美，吟徧獨相忘。"]'),
('53ddb4c8-0bb4-4039-8a1f-7248a2779ee0','二月十日吳正仲遺活蟹','梅堯臣','宋','宋诗','song-poetry','','[]','年年收稻賣江蟹，二月得從何處來。',64,'全唐诗/poet.song.15000.json','["年年收稻賣江蟹，二月得從何處來。", "滿腹紅膏肥似髓，貯盤青殻大於杯。", "定知有口能噓沫，休信無心便畏雷。", "幸與陸機還往熟，每分吳味不嫌猜。"]'),
('3bb196ea-a75c-45b2-9c57-6dd6676e7500','老馬','梅堯臣','宋','宋诗','song-poetry','','[]','吳人惜燕駿，燕馬卧吳家。',48,'全唐诗/poet.song.15000.json','["吳人惜燕駿，燕馬卧吳家。", "毛骨從前貴，關山欲去賒。", "草深閑楚澤，力盡憶胡沙。", "御史乘來久，時逢避路騧。"]'),
('f285711b-d845-4eda-9e12-8d601b3504e7','自詠','梅堯臣','宋','宋诗','song-poetry','','[]','閉戶無還往，端居廢禮容。',48,'全唐诗/poet.song.15000.json','["閉戶無還往，端居廢禮容。", "花爲貧富燄，燕是舊過從。", "持屐對人蠟，綻衣看婦縫。", "非同叔夜傲，切莫怪疎慵。"]'),
('eb6a6833-6522-4d6f-a695-f929ad342a7c','鸚鵡','梅堯臣','宋','宋诗','song-poetry','','[]','一入秦宮去，千山隴樹秋。',48,'全唐诗/poet.song.15000.json','["一入秦宮去，千山隴樹秋。", "能言依婦女，學語類徘優。", "玉鎖閑拘束，金籠不自由。", "哀良是黄鳥，死爲穆公羞。"]'),
('d988fe28-0cb0-43ac-b46b-2593423c4966','曉','梅堯臣','宋','宋诗','song-poetry','','[]','烏蟾不出海，天地無明時。',48,'全唐诗/poet.song.15000.json','["烏蟾不出海，天地無明時。", "萬國睡未覺，一聲雞已知。", "樹頭星漸沒，枝上露應垂。", "人世紛紛事，勞勞只自爲。"]'),
('c64d05de-01aa-4b07-a9a0-06cbbe75836e','朝二首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','鵝鴨出欄去，兒童臨水驅。',48,'全唐诗/poet.song.15000.json','["鵝鴨出欄去，兒童臨水驅。", "欲開花泫露，聚噪鳥窺厨。", "秣馬刈青草，買薪嫌五銖。", "錢刀豈今古，村叟一何愚。"]'),
('40cb29c1-d295-4e5d-a021-4b1a102c8354','朝二首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','木鎖初開水上城，竹籬深閉日光生。',64,'全唐诗/poet.song.15000.json','["木鎖初開水上城，竹籬深閉日光生。", "青苔井畔雀兒鬭，烏臼樹頭鴉舅鳴。", "世事但知開口笑，俗情休要著心行。", "是非不道任挑撻，唯憶當時阮步兵。"]'),
('0053b7b4-91b2-4650-ad6e-8ba843698023','宣州雜詩二十首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','昭亭萬仞山，古廟半山間。',48,'全唐诗/poet.song.15000.json','["昭亭萬仞山，古廟半山間。", "賽雨使君去，釣潭漁父閑。", "蕨肥巖向日，竹暗壠連關。", "北望高樓上，南飛鳥自還。"]'),
('5db097cb-ba37-440d-b176-b5402876a41a','宣州雜詩二十首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','三洲灘口急，兩水渡頭來。',48,'全唐诗/poet.song.15000.json','["三洲灘口急，兩水渡頭來。", "下過桓彝宅，上通嚴子臺。", "潺湲瀉寒月，滉漾照春梅。", "白鷺驚起處，魚多見底迴。"]'),
('e3b686bd-896a-4905-b63b-bfe0102d5189','宣州雜詩二十首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','一過響山畔，常思路中丞。',48,'全唐诗/poet.song.15000.json','["一過響山畔，常思路中丞。", "開亭宴貔虎，制賊象冰蠅。", "舊刻多磨滅，今人少誦稱。", "茸茸春草長，時有牧牛登。"]'),
('0149d86f-9c13-47bc-9e27-505ada0937c5','宣州雜詩二十首  其四','梅堯臣','宋','宋诗','song-poetry','','[]','伍員奔吳日，蒼皇及水濱。',48,'全唐诗/poet.song.15000.json','["伍員奔吳日，蒼皇及水濱。", "彎弓射楚使，解劍與漁人。", "抉目觀亡國，鞭尸失舊臣。", "猶爲夜濤怒，來往百川頻。"]'),
('c1368c7c-6c0c-42c3-8df1-c8ca2c455e16','宣州雜詩二十首  其五','梅堯臣','宋','宋诗','song-poetry','','[]','每見昭亭壁，高璩筆墨存。',48,'全唐诗/poet.song.15000.json','["每見昭亭壁，高璩筆墨存。", "丹青虛格裏，雲霧碧紗痕。", "鳥屎常愁污，蟲絲幾爲捫。", "貴來曾改觀，世故有誰論。"]'),
('6c8d46e4-e492-421e-a828-a508b29b925a','宣州雜詩二十首  其六','梅堯臣','宋','宋诗','song-poetry','','[]','信讒多見逐，伐國豈無仁。',48,'全唐诗/poet.song.15000.json','["信讒多見逐，伐國豈無仁。", "屈子行江畔，昭王問水濱。", "包茅曾責貢，香草自持紉。", "莽蒼山川在，漁歌屬野人。"]'),
('97595a96-7095-47c6-ae15-f38290e59a66','宣州雜詩二十首  其七','梅堯臣','宋','宋诗','song-poetry','','[]','項籍路由此，力豪聞拔山。',48,'全唐诗/poet.song.15000.json','["項籍路由此，力豪聞拔山。", "八千提楚卒，百二破秦關。", "陔下圍歌合，江頭匹馬還。", "却思諸父老，相見亦何顔。"]'),
('457fdff1-67fc-42d2-8957-acb33120639e','宣州雜詩二十首  其八','梅堯臣','宋','宋诗','song-poetry','','[]','細雨春岡滑，無因駐馬蹄。',48,'全唐诗/poet.song.15000.json','["細雨春岡滑，無因駐馬蹄。", "裘單懷後侶，風急過前溪。", "近寺聞魚鼓，穿林聽竹雞。", "田家舂正急，炊飯待鋤犂。"]'),
('1a6a2279-7407-4796-90dc-c1f6180d7c1e','宣州雜詩二十首  其九','梅堯臣','宋','宋诗','song-poetry','','[]','古有琴高者，騎魚上碧天。',48,'全唐诗/poet.song.15000.json','["古有琴高者，騎魚上碧天。", "小鱗隨水至，三月滿江邊。", "少婦自撈摝，遠人無棄捐。", "憑書不道薄，賣取青銅錢。"]'),
('379f867c-7293-4535-b51a-f449264bf6d6','宣州雜詩二十首  其一○','梅堯臣','宋','宋诗','song-poetry','','[]','諸葛久精妙，已能聞國都。',48,'全唐诗/poet.song.15000.json','["諸葛久精妙，已能聞國都。", "紫毫搜老兔，蒼鼠拔長鬚。", "露筦何明浄，煙丸事染濡。", "班超投此去，死作玉關夫。"]'),
('469c3406-2011-457b-91eb-1a8f3a118954','宣州雜詩二十首  其一一','梅堯臣','宋','宋诗','song-poetry','','[]','大實木瓜熟，壓枝常畏風。',48,'全唐诗/poet.song.15000.json','["大實木瓜熟，壓枝常畏風。", "帖花先漏日，噴露漸成紅。", "青箬包山舍，馳心奉漢宮。", "誰將橐駞載，辛苦向驕戎。"]'),
('792cd692-bc1d-4432-808b-5730b08bd762','宣州雜詩二十首  其一二','梅堯臣','宋','宋诗','song-poetry','','[]','竿頭注腐鼠，水次野蜂知。',48,'全唐诗/poet.song.15000.json','["竿頭注腐鼠，水次野蜂知。", "每視銜飛翅，因薰劚取陴。", "絳囊千里道，乾蛹百鈞馳。", "盡入公侯第，雕盤助酒巵。"]'),
('0f702936-5b2b-4567-b8b5-57e740a187b0','宣州雜詩二十首  其一三','梅堯臣','宋','宋诗','song-poetry','','[]','高林似吳鴨，滿樹蹼鋪鋪。',48,'全唐诗/poet.song.15000.json','["高林似吳鴨，滿樹蹼鋪鋪。", "結子繁黄李，炮仁瑩翠珠。", "神農本草闕，夏禹貢書無。", "遂壓葡萄貴，秋來遍上都。"]'),
('3b80944c-bdba-4e85-b529-d423b6fd01ec','宣州雜詩二十首  其一四','梅堯臣','宋','宋诗','song-poetry','','[]','鳥命若楊葉，夜棲雞翼間。',48,'全唐诗/poet.song.15000.json','["鳥命若楊葉，夜棲雞翼間。", "情知羽毛薄，自禦雪霜難。", "相託爲溫燠，終非學附攀。", "猶勝居鶻握，憂懼得生還。"]'),
('d40b0d2c-3bbd-4916-9f9f-a1c59baf07d5','宣州雜詩二十首  其一五','梅堯臣','宋','宋诗','song-poetry','','[]','高齋謝公歿，此地即危樓。',48,'全唐诗/poet.song.15000.json','["高齋謝公歿，此地即危樓。", "不改窗中岫，無停川上舟。", "壁陰緣薜荔，城暝笑鵂鶹。", "萬井曉煙合，素霓橫樹頭。"]'),
('5d153320-1455-4710-bc19-dbe72d1faae1','宣州雜詩二十首  其一六','梅堯臣','宋','宋诗','song-poetry','','[]','北客多懷北，庖羊舉玉巵。',48,'全唐诗/poet.song.15000.json','["北客多懷北，庖羊舉玉巵。", "吾鄉雖處遠，佳味頗相宜。", "沙水馬蹄鼈，雪天牛尾貍。", "寄言京國下，能有幾人知。"]'),
('04c3b78a-9aaa-47bd-94c6-444251545a7e','宣州雜詩二十首  其一七','梅堯臣','宋','宋诗','song-poetry','','[]','五月黄梅肥，終朝密雨微。',48,'全唐诗/poet.song.15000.json','["五月黄梅肥，終朝密雨微。", "綠苔侵竹閣，潤氣裛人衣。", "背隴霑牛去，銜蟲濕燕歸。", "高山發瀑水，夜漲入吾扉。"]'),
('b9b5b119-7b0e-4f7f-b7ef-282ce1cd9c2c','宣州雜詩二十首  其一八','梅堯臣','宋','宋诗','song-poetry','','[]','斫漆高崖畔，千筒不一盈。',48,'全唐诗/poet.song.15000.json','["斫漆高崖畔，千筒不一盈。", "野糧收橡子，山屋點松明。", "只見樹堪種，曾無田可耕。", "兒孫何所樂，向此是平生。"]'),
('099cd6e1-c0ef-43f7-b6ef-54fe24dfc6c9','宣州雜詩二十首  其一九','梅堯臣','宋','宋诗','song-poetry','','[]','傳道零陵守，茲亭暫解裝。',48,'全唐诗/poet.song.15000.json','["傳道零陵守，茲亭暫解裝。", "分羣同雁鶩，幾日到瀟湘。", "班竹思虞舜，赬萍憶楚王。", "殷勤吏部句，今亦誦無忘。"]'),
('594e4b93-2987-462f-871d-912cdbe0d12b','宣州雜詩二十首  其二○','梅堯臣','宋','宋诗','song-poetry','','[]','宛水過城下，滔滔北去斜。',48,'全唐诗/poet.song.15000.json','["宛水過城下，滔滔北去斜。", "遠船來橘蔗，深步上魚蝦。", "鵝美冒椒葉，蜜香聞稻花。", "歲時風俗美，笑殺異鄉槎。"]'),
('f9635aae-a2f2-4cc5-9db2-04e7a638a9ce','打鴨','梅堯臣','宋','宋诗','song-poetry','','[]','莫打鴨，打鴨驚鴛鴦。',42,'全唐诗/poet.song.15000.json','["莫打鴨，打鴨驚鴛鴦。", "鴛鴦新自南池落，不比孤洲老禿鶬。", "禿鶬尚欲遠飛去，何況鴛鴦羽翼長。"]'),
('89cdeed9-7a8f-4490-9764-3491c5bd1058','暝','梅堯臣','宋','宋诗','song-poetry','','[]','杳杳鐘初發，昏昏戶閉時。',48,'全唐诗/poet.song.15000.json','["杳杳鐘初發，昏昏戶閉時。", "巢禽投樹盡，疲馬入城遲。", "醉唱眠茅屋，曉光透槿籬。", "荷鋤休带月，亭長豎毛眉。"]'),
('b1c7d441-42e9-4f24-8084-5e05bd841eb8','夜','梅堯臣','宋','宋诗','song-poetry','','[]','日從東溟轉，夜向西海沉。',48,'全唐诗/poet.song.15000.json','["日從東溟轉，夜向西海沉。", "羣物各已息，衆星燦然森。", "蝦蟆將食月，魑魅爭出陰。", "阮籍獨不寐，徘徊起彈琴。"]'),
('6356cf82-2ea5-454d-8590-2ae7db37d166','東溪','梅堯臣','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u5c71\u6c34", "\u5199\u666f"]','行到東溪看水時，坐臨孤嶼發船遲。',64,'全唐诗/poet.song.15000.json','["行到東溪看水時，坐臨孤嶼發船遲。", "野鳬眠岸有閑意，老樹著花無醜枝。", "短短蒲茸齊似翦，平平沙石浄於篩。", "情雖不厭住不得，薄暮歸來車馬疲。"]'),
('68d52374-46d9-431a-b22c-ebe95e620d34','呂大監餉鮆魚十尾','梅堯臣','宋','宋诗','song-poetry','','[]','日暖楊花四散開，江邊鮆魚無數來。',48,'全唐诗/poet.song.15000.json','["日暖楊花四散開，江邊鮆魚無數來。", "伊魴洛鯉不堪憶，丙穴漾陂何可咍。", "賀監休思鏡湖去，應知李白跨鯨迴。"]'),
('64827316-0ca3-4228-b15b-7e71ff7c5e14','香爐','梅堯臣','宋','宋诗','song-poetry','','[]','鐵鑄小香爐，壁環平口鋪。',48,'全唐诗/poet.song.15000.json','["鐵鑄小香爐，壁環平口鋪。", "麝焚葵葉大，獸齧竹根趺。", "浄几群書外，閑堂一物無。", "中間任灰燼，終與蕙蘭俱。"]'),
('3b555e4b-afab-48f6-86b5-4198bae3b547','茶磨二首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','楚匠斲山骨，折檀爲轉臍。',48,'全唐诗/poet.song.15000.json','["楚匠斲山骨，折檀爲轉臍。", "乾坤人力內，日月蟻行迷。", "吐雪誇春茗，堆雲憶舊溪。", "北歸唯此急，藥臼不須擠。"]'),
('7b3c3c04-d758-49c9-9f8b-65a5598e9c17','茶磨二首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','盆是荷花磨是蓮，誰礱麻石洞中天。',32,'全唐诗/poet.song.15000.json','["盆是荷花磨是蓮，誰礱麻石洞中天。", "欲將雀舌成雲末，三尺蠻童一臂旋。"]'),
('17f1a609-1b4c-438e-b15a-cfecdec44a49','送白珙秀才','梅堯臣','宋','宋诗','song-poetry','','[]','谿上桃花發，山前桂舸移。',48,'全唐诗/poet.song.15000.json','["谿上桃花發，山前桂舸移。", "水流過峽急，風逆出江遲。", "南國魚蝦厭，東都夢寐思。", "逢人若有問，不似在朝時。"]'),
('49dbc88c-0273-47e8-9c20-0a3dc10044a0','送閭丘殿丞','梅堯臣','宋','宋诗','song-poetry','','[]','每有西歸客，誰無滿袖詩。',48,'全唐诗/poet.song.15000.json','["每有西歸客，誰無滿袖詩。", "都忘將別意，競媚向官資。", "憑在屋頭月，照君牆上旗。", "不同山一定，更遠更相隨。"]'),
('ec008384-93cc-40f8-85b0-d99db99a3ec5','獻甫過','梅堯臣','宋','宋诗','song-poetry','','[]','幾樹桃花夾竹開，阮家閭巷長春苔。',32,'全唐诗/poet.song.15000.json','["幾樹桃花夾竹開，阮家閭巷長春苔。", "啟扉索馬送客出，忽覺青紅入眼來。"]'),
('084fe9b8-b60f-4893-9a10-ca62d06351cd','寄維陽許待制','梅堯臣','宋','宋诗','song-poetry','','[]','當時永叔在楊州，中秋待月後池頭。',223,'全唐诗/poet.song.15000.json','["當時永叔在楊州，中秋待月後池頭。", "約公準擬與我敵，是夜二雄張利矛。", "我時小却避其銳，風愁雨怛常娥羞。", "主人持出紫石屏，上有朏魄桂樹婆娑而枝虬。", "作詩誇詫疑天公，愛惜光彩向此收。", "四坐稽顙歎辯敏，文字響亮如清球。", "更後數日我北去，相與送別城門樓。", "誰知康成能飲酒，一飲三百杯不休。", "雞鳴各自便分散，山光寺側停畫舟。", "我來謁公公未起，卧索大白須扶頭。", "而今倏忽已八載，公領府事予居憂。", "歐陽始是玉堂客，批章草詔傳星流。", "問公可憶羊叔子，雖在軍中常緩带而輕裘。", "寄聲千里能信不。"]'),
('2ade9325-7992-4c38-ad77-f584a6892f10','紫微亭','梅堯臣','宋','宋诗','song-poetry','','[]','江雲如旗脚，墨點飛雁行。',180,'全唐诗/poet.song.15000.json','["江雲如旗脚，墨點飛雁行。", "平圃采芳菊，上水酌桂漿。", "爲言此何時，杜子逢重陽。", "醉思莊生達，哂彼齊景傷。", "至今孤亭間，獨有九日章。", "昔我來齊山，山僧迎道傍。", "騎馬到寺門，亂石屹若牆。", "值雨不徧歷，但取山泉嘗。", "牧之舊遊處，苔滑屐莫將。", "却返弄水涯，隔溪望青蒼。", "絕頂見茅屋，洪波日湯湯。", "雲霞與雁鶩，還動秋客腸。", "去逾十五年，游宦韓陳梁。", "哀哀遘禍殃，乃再居南方。", "欲往尚未可，追吟寄支郎。"]'),
('0e2360cb-6b8f-4cca-9f06-1414cade5326','聞臨淄公薨','梅堯臣','宋','宋诗','song-poetry','','[]','至和癸巳十二月兮，友人語我火犯房。',310,'全唐诗/poet.song.15000.json','["至和癸巳十二月兮，友人語我火犯房。", "芒射鈎鈐而拂上相兮，禍非弼臣誰可當。", "昨日聞太宰悟天道而畏忌兮，歸卧其第三拜章。", "太宰既不得請而賜黄金百兩以爲壽兮，諫官御史猶擊强。", "明年孟陬臨淄公薨兮，果然邦國橈棟梁。", "豈無神醫善藥以起疾兮，固知稟命有短長。", "公自十三歲而先帝兮，謂肖九齡宜相唐。", "後由石渠鳳閣禁林以登樞兮，俄佩相印居廟堂。", "出入藩輔留守兩都兮，其民詠歌盈康莊。", "官爲喉舌勳爵一品兮，經筵講義尊蕭匡。", "年逾順耳不爲夭兮，文字百卷存縑箱。", "子孫侁侁同雁行，二女貴婿富與楊。", "未知歸葬何土鄉，臨川松柏安可忘。", "我爲故吏摧肝腸，洒淚作雨春悲凉。", "精魄其歸於天乎，必爲星宿還高張。", "骨肌其歸於土乎，必爲蕙芷不滅香。", "墓碑墓銘誰能盡其美，我爲欲傳萬古須歐陽。"]'),
('bae5b300-d2f7-4065-9813-738df9ccfa05','吳正仲遺二物詠之 金盞子','梅堯臣','宋','宋诗','song-poetry','','[]','鍾令昔醒酒，豫章留此花。',48,'全唐诗/poet.song.15000.json','["鍾令昔醒酒，豫章留此花。", "黄金盞何小，白玉椀無瑕。", "始入吳郎宅，還歸楚客家。", "從茲不能醉，只恐費流霞。"]'),
('e35245bb-4cda-46e7-b5b4-2490232f8e11','吳正仲遺二物詠之 疊石','梅堯臣','宋','宋诗','song-poetry','','[]','十片寒湖滑，千秋白浪根。',48,'全唐诗/poet.song.15000.json','["十片寒湖滑，千秋白浪根。", "蒼蒼古崖色，疊疊老苔痕。", "欲象巨鼇頂，俯當科斗盆。", "唯愁作險說，平地起崑崙。"]'),
('6791ad03-1f60-4e0a-92a3-9c94b29a8088','依韻和宣城張主簿見贈','梅堯臣','宋','宋诗','song-poetry','','[]','韓子於文章，所貴不相傚。',132,'全唐诗/poet.song.15000.json','["韓子於文章，所貴不相傚。", "譬彼古今人，同心不同貌。", "吉從志久慕，亦以重名教。", "鳴鐘與享鼎，易厭非苦樂。", "祿仕不及親，揚名可爲孝。", "君方佐大邑，美錦同翦鉸。", "遂令吾鄉民，綢直無曲橈。", "既暇乃作詩，欲與前人較。", "朝來忽有贈，捧若管窺豹。", "又如捕鯨魚，空自持網罩。", "心降醉且睡，昏昏不知覺。"]'),
('bd5cc540-3e6f-491f-bb6c-927eed4a7a32','送吳正仲婺倅歸梅谿待闕','梅堯臣','宋','宋诗','song-poetry','','[]','山水東陽去未去，朋親苕霅朝復朝。',64,'全唐诗/poet.song.15000.json','["山水東陽去未去，朋親苕霅朝復朝。", "更無越相逃名舸，猶看吳王送女潮。", "海燕歸齊聲滿屋，谿梅開過子生條。", "明年十月吏迎處，七里灘前棹奏簫。"]'),
('c787dccf-b15f-4c5b-8590-586d121cd3f9','再送正仲','梅堯臣','宋','宋诗','song-poetry','','[]','擬君杜鵑花，發當杜鵑時。',108,'全唐诗/poet.song.15000.json','["擬君杜鵑花，發當杜鵑時。", "朱袍照白日，光彩生路岐。", "自比青鼠爪，中心如亂絲。", "絲亂復不理，況復遠別離。", "傾觴恨不深，立馬恨不遲。", "千山從此隔，三歲或前期。", "爾後各寄書，空識滿紙辭。", "非如笑言樂，但有牽懷悲。", "念昔蘇與李，徘徊問何之。"]'),
('05332b48-6868-4295-a3b0-76b5d6350180','鐵獺','梅堯臣','宋','宋诗','song-poetry','','[]','朝乘鐵獺上青山，最滑春苔亂石間。',32,'全唐诗/poet.song.15000.json','["朝乘鐵獺上青山，最滑春苔亂石間。", "出入白雲勝蠟屐，玉驄雖貴未應閑。"]'),
('48d6adb8-be57-48c4-a98f-dde48d16bbf4','依韻吳正仲廣德路中見寄','梅堯臣','宋','宋诗','song-poetry','','[]','怱怱車馬鳴，趁此天新晴。',269,'全唐诗/poet.song.15000.json','["怱怱車馬鳴，趁此天新晴。", "歸逢暮春月，正值氣候清。", "久已念行邁，遂往不計程。", "吾貧莫具酒，祖席愧羣英。", "美{炙火=肉}割肥鵝，大觥酌冰瓊。", "雖無綠琴奏，尚有青松聲。", "日昃君未醉，睠睠愁將行。", "視景不可駐，漸向西林傾。", "去無兒女悲，慷慨懷抱明。", "明當發野館，跨鞍猶宿酲。", "故人桃州守，走吏來相迎。", "道傍薔薇花，自引蝴蝶輕。", "隨風香襲人，乃覺離思嬰。", "求友彼黄鸝，繞樹啼㗀嚶。", "言會且未涯，返睇還頓驚。", "始憶康樂言，賞心良難并。", "不見水鴨飛，但起野鴛情。", "向來東溪上，相望何盈盈。", "揚鞭動悲吟，復恨隔高城。", "高城在何處，春雲漭然平。", "白醪甕已熟，紫線蒓已生。", "聊尋父老飲，況是溪魚烹。"]'),
('d6ed2808-72ac-4ba8-ab68-7d3a72c77e7e','送回上人','梅堯臣','宋','宋诗','song-poetry','','[]','雲出任西東，飄然意莫窮。',48,'全唐诗/poet.song.15000.json','["雲出任西東，飄然意莫窮。", "山川生眼界，巾舄徧區中。", "去去曾無著，勞勞本是空。", "梅谿人可見，重爾似泓公。"]'),
('739f6f95-5561-406d-bc65-fe48757f794c','送徐絳秘校罷涇尉而歸','梅堯臣','宋','宋诗','song-poetry','','[]','去年茶熟君得補，今來茶熟君已去。',64,'全唐诗/poet.song.15000.json','["去年茶熟君得補，今來茶熟君已去。", "心曾不計茶有無，隼在高風自騰翥。", "昨日我送吳侯歸，未忍重臨離別處。", "不若羣公憐禰衡，相逐縱橫唯柳絮。"]'),
('c08f0793-7a8f-4b4c-91bb-6b599c0e441f','志來上人寄示酴醾花并壓磚茶有感','梅堯臣','宋','宋诗','song-poetry','','[]','京都三月酴醾開，高架交垂自爲洞。',160,'全唐诗/poet.song.15000.json','["京都三月酴醾開，高架交垂自爲洞。", "素葉層層紫蕊香，釀歸光祿春生甕。", "東陌西池走鈿車，芳林廣囿飛朱鞚。", "二年不到大梁城，江邊淚滴肝腸痛。", "況茲齒髮漸衰老，已是憂愁不如衆。", "宣城北寺來上人，獨有一叢盤嫩蕻。", "去歲遊吳求不得，今朝還喜自持送。", "眼底雖同往日看，樽前所憶皆成夢。", "又置新茶采雨前，鳥觜壓磚雲色弄。", "對花却酒煑香泉，强詠才慙非白鳳。"]'),
('3e70b548-d566-40a5-91a2-f8881640803a','聞鶑','梅堯臣','宋','宋诗','song-poetry','','[]','最好聲音最好聽，似調歌舌更叮嚀。',32,'全唐诗/poet.song.15000.json','["最好聲音最好聽，似調歌舌更叮嚀。", "高枝拋過低枝立，金羽脩眉墨染翎。"]'),
('b312dccf-4623-4ddd-99c2-f58827590ef2','杜鵑','梅堯臣','宋','宋诗','song-poetry','','[]','蜀帝何年魄，千春化杜鵑。',48,'全唐诗/poet.song.15000.json','["蜀帝何年魄，千春化杜鵑。", "不如歸去語，亦自古來傳。", "月樹啼方急，山房客未眠。", "還將口中血，滴向野花鮮。"]'),
('e2f15c7f-fb93-423e-880f-8ed402a31bb2','依韻和李察推留別','梅堯臣','宋','宋诗','song-poetry','','[]','我學猶肥腱，一食輒易厭。',120,'全唐诗/poet.song.15000.json','["我學猶肥腱，一食輒易厭。", "君何以名虛，每來車馬淹。", "經術素所淺，道義安得漸。", "獨有寒苦吟，可與前古兼。", "今者抱悲哀，憔悴居窮閻。", "愁鳴無好音，亟別空顧瞻。", "詩言留彼美，欲和慙無鹽。", "短兵當長戈，焉得不盡殲。", "又如握枯蒿，逆風乘烈炎。", "膏肓靡自療，誰復望針砭。"]'),
('7f0d9eed-5c2f-46c3-82ca-98e26e428530','送李節推挈內歸寧池陽并李察推往南康軍嫁妹二君同行','梅堯臣','宋','宋诗','song-poetry','','[]','江上雙畫舸，風帆或先後。',96,'全唐诗/poet.song.15000.json','["江上雙畫舸，風帆或先後。", "晚共泊蘆洲，欣同幕中友。", "一過長風沙，一住貴池口。", "當時驄馬客，今是憑熊守。", "每憐諸女賢，與婿來爲壽。", "上去至南康，嫁妹事箕帚。", "不畏楊瀾險，不爲廬峯秀。", "二君情義著，我送何須酒。"]'),
('079e8ef2-f7ba-4007-8f6c-2ae82bef0822','新開墳路','梅堯臣','宋','宋诗','song-poetry','','[]','古徑約城斜，鋤荒可過車。',48,'全唐诗/poet.song.15000.json','["古徑約城斜，鋤荒可過車。", "直穿深篠去，不比繞村賒。", "伐樹侵籬脚，裨塍掘澗沙。", "欲爲蘭若處，松柏屬吾家。"]'),
('2e47ee6e-c9bf-4b77-b522-853dd1cb5b00','送鄒秀才游浙','梅堯臣','宋','宋诗','song-poetry','','[]','鞍傍带劍魚皮鞘，馬後携童越葛衫。',32,'全唐诗/poet.song.15000.json','["鞍傍带劍魚皮鞘，馬後携童越葛衫。", "度水緣山君底急，區區爲答古千巖。"]'),
('0a79228c-b3e0-4081-986f-94a307205582','四月三日張十遺牡丹二朵','梅堯臣','宋','宋诗','song-poetry','','[]','已過穀雨十六日，猶見牡丹開淺紅。',32,'全唐诗/poet.song.15000.json','["已過穀雨十六日，猶見牡丹開淺紅。", "曾不爭先及春早，能陪芍藥到薰風。"]'),
('57f99e38-056e-4925-bdc3-e79adfa4eaab','依韻和唐彥猷華亭十詠 顧亭林','梅堯臣','宋','宋诗','song-poetry','','[]','鄉林空林木，不見古人居。',48,'全唐诗/poet.song.15000.json','["鄉林空林木，不見古人居。", "猶尋古人跡，更與古人疎。", "昔爲賢豪里，今作魑魅墟。", "湖邊夜夜月，光彩波上餘。"]'),
('e3caf175-8310-4ce4-9a33-9ce3eefaa371','依韻和唐彥猷華亭十詠 寒穴','梅堯臣','宋','宋诗','song-poetry','','[]','山頭寒泉穴，浄若鏡面平。',48,'全唐诗/poet.song.15000.json','["山頭寒泉穴，浄若鏡面平。", "熨齒敲冰冷，貯缾微玉聲。", "傍有野鹿跡，上啼林鳥清。", "何由一往挹，況復方病醒。"]'),
('b6e5cd3f-8c80-4d6b-b76d-cfa4c01adfba','依韻和唐彥猷華亭十詠 吳王獵場','梅堯臣','宋','宋诗','song-poetry','','[]','孫氏有吳國，四海未息戈。',48,'全唐诗/poet.song.15000.json','["孫氏有吳國，四海未息戈。", "獵以耀威武，平野萬騎羅。", "英雄魏與蜀，貔虎一何多。", "世事異莫究，但見桑麻坡。"]'),
('7e87756e-c37f-4727-a126-f3888cbb9f67','依韻和唐彥猷華亭十詠 柘湖','梅堯臣','宋','宋诗','song-poetry','','[]','柘土久陷沒，千里嗟水濱。',48,'全唐诗/poet.song.15000.json','["柘土久陷沒，千里嗟水濱。", "不復吳鹽邑，空有秦女神。", "浩蕩吞海日，曠闊迷天津。", "扁舟誰能往，旦暮逢漁人。"]'),
('c32bba4b-12af-4df4-82a3-79247c6260c5','依韻和唐彥猷華亭十詠 秦始皇馳道通吳城','梅堯臣','宋','宋诗','song-poetry','','[]','秦帝觀滄海，勞人何得脩。',48,'全唐诗/poet.song.15000.json','["秦帝觀滄海，勞人何得脩。", "石橋虹霓斷，馳道鹿麋遊。", "車轍久已沒，馬迹亦無留。", "驪山寶衣盡，萬古空冢丘。"]'),
('635e2a31-60d1-4e04-ac81-763e8697f3a9','依韻和唐彥猷華亭十詠 陸瑁養魚池','梅堯臣','宋','宋诗','song-poetry','','[]','來觀瑁湖水，乃是陸生居。',48,'全唐诗/poet.song.15000.json','["來觀瑁湖水，乃是陸生居。", "春塘草幾變，誰膾此中魚。", "莫容科斗應，亦有魯王餘。", "不隨蛟龍飛，神鼈未可除。"]'),
('bd9ed448-a183-4261-b9d8-735700d4a106','依韻和唐彥猷華亭十詠 華亭谷','梅堯臣','宋','宋诗','song-poetry','','[]','斷岸三百里，縈带松江流。',48,'全唐诗/poet.song.15000.json','["斷岸三百里，縈带松江流。", "深非桃花源，自有漁者舟。", "閑意見水鳥，日共泛觥籌。", "何當騎鯨魚，一去幾千秋。"]'),
('9e822b28-5023-46d4-8e3f-ad78cbc7985a','依韻和唐彥猷華亭十詠 崑山陰','梅堯臣','宋','宋诗','song-poetry','','[]','我思陸平原，廢宅荒草深。',48,'全唐诗/poet.song.15000.json','["我思陸平原，廢宅荒草深。", "才高乃速禍，事往不可箴。", "饑烏噪樹顛，野鼠窟庭陰。", "黄耳亦已死，家書無復尋。"]'),
('c0ff7cf4-060a-4d22-8bb0-6474ca3e7000','依韻和唐彥猷華亭十詠 崑山','梅堯臣','宋','宋诗','song-poetry','','[]','陸氏幾世祖，葬此生令名。',48,'全唐诗/poet.song.15000.json','["陸氏幾世祖，葬此生令名。", "猶如産美璞，遂爾傳嘉聲。", "寒巖畜奇秀，源水日東傾。", "何言千載間，二子不更生。"]'),
('353f8671-7978-4234-b091-bd156a41a3e4','依韻和唐彥猷華亭十詠 三女岡','梅堯臣','宋','宋诗','song-poetry','','[]','吳王葬三女，因留此岡名。',48,'全唐诗/poet.song.15000.json','["吳王葬三女，因留此岡名。", "已化被粲質，合有蘭蕙生。", "嬋娟夜月照，晻藹朝霧平。", "古魂如未泯，不遠闔閭城。"]'),
('250a1bad-e40a-4433-b253-4c8632f96681','李獻甫於南海魏侍郎得椰子見遺','梅堯臣','宋','宋诗','song-poetry','','[]','魏公番禺歸，逢子蕪江口。',60,'全唐诗/poet.song.15000.json','["魏公番禺歸，逢子蕪江口。", "贈以越王頭，還同月支首。", "割鮮爲飲器，津漿若美酒。", "我獨愧先生，饌致崇師友。", "應知愈饑渴，況是懷思久。"]'),
('959ef8ca-9e3f-4c8c-99fe-44931fdbd0fb','時魚','梅堯臣','宋','宋诗','song-poetry','','[]','四月時魚逴浪花，漁舟出沒浪爲家。',32,'全唐诗/poet.song.15000.json','["四月時魚逴浪花，漁舟出沒浪爲家。", "甘肥不入罟師口，一把銅錢趁槳牙。"]'),
('eeb6dbcf-81ea-4c97-a0a6-0c45a63057a0','烏賊魚','梅堯臣','宋','宋诗','song-poetry','','[]','海若有醜魚，烏圖有烏賊。',60,'全唐诗/poet.song.15000.json','["海若有醜魚，烏圖有烏賊。", "腹膏爲飯囊，鬲冒貯飲墨。", "出沒上下波，厭飫吳越食。", "爛腸夾雕蚶，隨貢入中國。", "中國捨肥羊，啗此亦不惑。"]'),
('384e5415-5c3f-44a1-b4e7-0762e290f5a5','依韻和行之枇杷','梅堯臣','宋','宋诗','song-poetry','','[]','五月枇杷黄似橘，誰思荔枝同此時。',32,'全唐诗/poet.song.15000.json','["五月枇杷黄似橘，誰思荔枝同此時。", "嘉名已著上林賦，却恨紅梅未有詩。"]'),
('d765dc7a-b9e8-4236-a346-2625ea6890b5','送紅梅行之有詩和依其韻和','梅堯臣','宋','宋诗','song-poetry','','[]','綴綴紅梅肥似蠟，濛濛飛雨洒如脂。',32,'全唐诗/poet.song.15000.json','["綴綴紅梅肥似蠟，濛濛飛雨洒如脂。", "吳郎齒軟食不得，翻憶張公大谷梨。"]'),
('6062ae02-d10e-4a5e-946d-57579e88d639','送王宗望罷宣城尉歸京','梅堯臣','宋','宋诗','song-poetry','','[]','南土梅已黄，北人舟競發。',48,'全唐诗/poet.song.15000.json','["南土梅已黄，北人舟競發。", "去意方若渴，望林殊未歇。", "言歸向梁宋，獨歎滯楚越。", "行聞拜卿屬，恩下蒼龍闕。"]'),
('27ea5791-6079-47b3-979e-d1b4c7b0f8ed','寄題南陵息亭蕖閣','梅堯臣','宋','宋诗','song-poetry','','[]','竹裏有清館，寺中多藕花。',48,'全唐诗/poet.song.15000.json','["竹裏有清館，寺中多藕花。", "日光穿岸脚，水影射簷牙。", "柱穴蜂歸響，爐檀火過窊。", "已知民訟息，漉酒費巾紗。"]'),
('95eb0461-c600-4f5d-bf99-057d4b2e8af7','讀問月','梅堯臣','宋','宋诗','song-poetry','','[]','我讀李白問月詩，乃知白也心太癡。',128,'全唐诗/poet.song.15000.json','["我讀李白問月詩，乃知白也心太癡。", "明月在上爾在下，月行豈獨君相隨。", "白兔擣藥亦何療，常娥孤棲欲嫁誰。", "古人今人被磨滅，休問有來都幾時。", "唯有長照金樽裏，此言萬世不可移。", "但能自醉月自落，夜夜如此誰復疑。", "一月二十二三日，半是風雨相乖離。", "常願晴明對以飲，耳邊流水勝鳴絲。"]'),
('e271d262-700b-4b52-bc5b-602f8ef8db64','五月十日雨中飲','梅堯臣','宋','宋诗','song-poetry','','[]','梅天下梅雨，綏綏如亂絲。',132,'全唐诗/poet.song.15000.json','["梅天下梅雨，綏綏如亂絲。", "梅生獨抱愁，四顧無與期。", "妻孥解我意，草草陳酒巵。", "檻外百竿竹，新筍高過之。", "竹色入我酒，變作青琉璃。", "一飲眼目光，再飲言語遲。", "三飲頹然兀，左右歎我衰。", "有鳥從東來，引頭闖深枝。", "發聲醒我醉，提壺美無疑。", "典衣不直錢，唯是布與絺。", "安得如古人，車傍挂鴟夷。"]'),
('a7626441-a8b5-4c2d-874e-e818cc15393f','次韻和吳季野游山寺登望文脊山','梅堯臣','宋','宋诗','song-poetry','','[]','楚客好山水，五月上高峯。',96,'全唐诗/poet.song.15000.json','["楚客好山水，五月上高峯。", "峯頂望文脊，草樹皆有容。", "身既近猿鳥，心欲追喬松。", "石壁出雲背，苔磴千萬重。", "下視霹靂飛，忽起枯株龍。", "却還僧居宿，暮踐樵子蹤。", "作詩留粉牆，削藁爲我封。", "美璞世未識，獨令和氏逢。"]'),
('b4d56d36-8b9e-45ba-982a-4e4e4aa2d648','五月十七日四鼓夢與孺人在宮庭謝恩至尊令小黄門宣諭曰今日社與卿喜此佳辰便可作詩進來枕上口占','梅堯臣','宋','宋诗','song-poetry','','[]','同謁未央殿，共霑明主恩。',72,'全唐诗/poet.song.15000.json','["同謁未央殿，共霑明主恩。", "冕旒親日月，蹈舞荷乾坤。", "龍尾三重峻，螭頭幾級尊。", "德音欣社日，撫語走黄門。", "陰會皆如實，陽開不復存。", "空餘破窗月，流影到床垠。"]'),
('a04211ed-7c57-4d32-9f6c-4b900c8421c3','聞進士販茶','梅堯臣','宋','宋诗','song-poetry','','[]','山園茶盛四五月，江南竊販如豺狼。',133,'全唐诗/poet.song.15000.json','["山園茶盛四五月，江南竊販如豺狼。", "頑凶少壯冒嶺險，夜行作隊如刀鎗。", "浮浪書生亦貪利，史笥經箱爲盜囊。", "津頭吏卒雖捕獲，官司直惜儒衣裳。", "却來城中談孔孟，言語便欲非堯湯。", "三日夏雨刺昏墊，五日炎熱譏旱傷。", "百端得錢事酒{炙火=肉}，屋裏餓婦無糇糧。", "一身溝壑乃自取，將相賢科何爾當。"]'),
('c3a30a19-a8fa-404e-a38c-c5119a67c6b8','梅雨','梅堯臣','宋','宋诗','song-poetry','','[]','三日雨不止，蚯蚓上我堂。',120,'全唐诗/poet.song.15000.json','["三日雨不止，蚯蚓上我堂。", "濕菌生枯籬，潤氣醭素裳。", "東池蝦蟆兒，無限相跳梁。", "野草侵花圃，忽與欄干長。", "門前無車馬，苔色何蒼蒼。", "屋後昭亭山，又被雲蔽藏。", "四向不可往，靜坐唯一床。", "寂然忘外慮，微誦黄庭章。", "妻子笑我閑，曷不自舉觴。", "已勝伯倫婦，一醉猶在傍。"]'),
('48ed72eb-d0f0-40c7-b898-4f0562a62edb','烏毀燕巢','梅堯臣','宋','宋诗','song-poetry','','[]','堂間兩胡燕，哺雛銜百蟲。',84,'全唐诗/poet.song.15000.json','["堂間兩胡燕，哺雛銜百蟲。", "老鴉亦養子，偷雛燕巢中。", "燕巢忽墮地，六七皆命窮。", "赤身無羽翼，腸斷彼雌雄。", "來往徒鳴聲，安得置室宮。", "我閔樓簍籔，俄已彊雨風。", "從今更生卵，不若受女娀。"]'),
('a1a270e9-628e-43a9-8621-e5d187d5e17d','五月十三日大水','梅堯臣','宋','宋诗','song-poetry','','[]','誰知山中水，忽向舍外流。',156,'全唐诗/poet.song.15000.json','["誰知山中水，忽向舍外流。", "誰知門前路，已通溪中舟。", "窮蛇上竹枝，聚蚓登階陬。", "我家地勢高，四顧如湖滮。", "浮萍穿籬眼，斷葑過屋頭。", "官吏救市橋，停車當市樓。", "應念此中居，望不辯馬牛。", "危湍瀉天河，漫漫無汀洲。", "羣蛙正得時，日夜鳴不休。", "戢戢後池魚，隨波去難留。", "揚鬐雖自在，江上多網鉤。", "紛紜閭里兒，踴躍競學泅。", "吾慕孔宣父，有意乘桴浮。"]'),
('da49e62e-433b-4c42-8540-5fcd16db5370','依韻和正仲賦楊兵部吳興五題 □□□','梅堯臣','宋','宋诗','song-poetry','','[]','雨過見虹明，長橋欲映城。',48,'全唐诗/poet.song.15000.json','["雨過見虹明，長橋欲映城。", "窗間晴氣入，空際晝凉生。", "有扇徒看畫，無冰自覺清。", "人知太守姓，不減漢公名。"]'),
('977cbd9a-9cb7-4f95-8600-0ac323b39e20','依韻和正仲賦楊兵部吳興五題 清風樓','梅堯臣','宋','宋诗','song-poetry','','[]','在昔有佳句，故人如遠來。',48,'全唐诗/poet.song.15000.json','["在昔有佳句，故人如遠來。", "競生吳客衽，不上楚王臺。", "稍拂清樽動，時吹翠帟開。", "長安在何處，水鳥望中迴。"]'),
('c36103a7-c00d-4b6e-a961-3d6d055c25f9','依韻和正仲賦楊兵部吳興五題 明月樓','梅堯臣','宋','宋诗','song-poetry','','[]','霅霅前溪白，蒼蒼後嶺巍。',48,'全唐诗/poet.song.15000.json','["霅霅前溪白，蒼蒼後嶺巍。", "人疑槎上客，星合蚌中暉。", "影轉闌干迥，杯行漏鼓稀。", "只知誇粉黛，不向桂邊歸。"]'),
('bdeed95a-a6f1-4f2e-9cea-92919c36fea6','依韻和正仲賦楊兵部吳興五題 碧瀾堂','梅堯臣','宋','宋诗','song-poetry','','[]','虛雲臨滉漾，橋勢對隆穹。',48,'全唐诗/poet.song.15000.json','["虛雲臨滉漾，橋勢對隆穹。", "環珮佳人去，汀洲翠带空。", "橘船過砌下，蘭棟起雲中。", "欲問芳菲地，吳王一廢宮。"]'),
('a50db1db-6526-463d-b088-54ba04e107ff','依韻和正仲賦楊兵部吳興五題 逍遥堂','梅堯臣','宋','宋诗','song-poetry','','[]','江東有賢守，好客似春申。',48,'全唐诗/poet.song.15000.json','["江東有賢守，好客似春申。", "自構杏梁地，不生珠履塵。", "樂章思季子，後俊得吳均。", "寢卧在其下，知君學至人。"]'),
('2c455e9d-7d57-4361-afa2-a879efc8a2cf','依韻和行之都官芭蕉詩','梅堯臣','宋','宋诗','song-poetry','','[]','看取有心常不展，亦知隨分坼佳葩。',32,'全唐诗/poet.song.15000.json','["看取有心常不展，亦知隨分坼佳葩。", "無端大葉映蓮幕，却笑菖蒲罕見花。"]'),
('a8366378-21cb-4928-a3aa-de71ec5bce8a','促織','梅堯臣','宋','宋诗','song-poetry','','[]','札札草間鳴，促促機上聲。',60,'全唐诗/poet.song.15000.json','["札札草間鳴，促促機上聲。", "織女夜中起，明河簷外橫。", "一絲不入杼，疎密工未精。", "豈知天孫巧，衣脫六銖輕。", "人間唯貴重，暗蟲休催成。"]'),
('e55713db-27d2-4bd7-b501-9ee1bc69f5f1','吳仲庶殿院寄示與呂沖之馬仲涂唱和詩六篇邀予次韻焉 次韻被命出城共汎','梅堯臣','宋','宋诗','song-poetry','','[]','三驄忽出乘楚艘，直氣突兀如吳濤。',96,'全唐诗/poet.song.15000.json','["三驄忽出乘楚艘，直氣突兀如吳濤。", "大都智勇皆世豪，橫身破浪親戰舠。", "迴舷受箭誰畏曹，猛士心伏寒生毛。", "風聲鶴唳傳九臯，何用寶刀稱孟勞。", "右持酒杯左持螯，功成各慕前人高。", "不言大享烹太牢，下與尺鷃翔於蒿。"]'),
('f157adaf-24be-4b08-9f5c-44be1a8c29ce','吳仲庶殿院寄示與呂沖之馬仲涂唱和詩六篇邀予次韻焉 依韻游陳留禪寺後池','梅堯臣','宋','宋诗','song-poetry','','[]','共逢香剎住，萬景筆頭堆。',48,'全唐诗/poet.song.15000.json','["共逢香剎住，萬景筆頭堆。", "池水蛟龍盡，汀洲鴈鵠來。", "遠遊情莫落，去國意徘徊。", "舟子休𣀃鼓，王程不爾催。"]'),
('f4b83f47-24f4-4b91-9d78-2f68b90c1902','吳仲庶殿院寄示與呂沖之馬仲涂唱和詩六篇邀予次韻焉 次韻晚泊睢陽','梅堯臣','宋','宋诗','song-poetry','','[]','日下繡衣客，江南燕尾艎。',48,'全唐诗/poet.song.15000.json','["日下繡衣客，江南燕尾艎。", "跡雖同鷁退，心不假犀凉。", "舊國旌旄去，包原苑囿荒。", "臨堤一懷古，柳上見微陽。"]'),
('6ca8d3dd-df3f-4b38-bfe6-d585e7006dbf','吳仲庶殿院寄示與呂沖之馬仲涂唱和詩六篇邀予次韻焉 汴渠','梅堯臣','宋','宋诗','song-poetry','','[]','我實山野人，不識經濟宜。',168,'全唐诗/poet.song.15000.json','["我實山野人，不識經濟宜。", "聞歌汴渠勞，謾綴汴渠詩。", "汴水源本清，隨分黄河枝。", "濁流方已盛，清派不可推。", "天王居大梁，龍舉雲必隨。", "設無通舟航，百貨當陸馳。", "人間牛騾馿，定應無完皮。", "苟欲東南蘇，要省聚歛爲。", "兵衛詎能削，乃須雄京師。", "今來雖太平，盡罷未是時。", "願循祖宗規，勿益羣息之。", "譬竭兩川賦，豈由此水施。", "縱有三峽下，率皆麤冗資。", "慎莫尤汴渠，非渠取膏脂。"]'),
('0cdc21d5-57fa-476b-b383-63f5e1907805','吳仲庶殿院寄示與呂沖之馬仲涂唱和詩六篇邀予次韻焉 次韻臨淮感事','梅堯臣','宋','宋诗','song-poetry','','[]','楚舸高帆未可開，滿帆風暴作陰雷。',64,'全唐诗/poet.song.15000.json','["楚舸高帆未可開，滿帆風暴作陰雷。", "聖文亹亹傷漂溺，世路紛紛自往來。", "浮磬猶聞傳激越，沉妖不見鎖淵回。", "連陂蛙黽鳴無數，安得周官爲灑灰。"]'),
('a4380be6-e82e-48e9-b4a5-9e91b2338c2b','吳仲庶殿院寄示與呂沖之馬仲涂唱和詩六篇邀予次韻焉 次韻夜過新開湖憶二御共泛','梅堯臣','宋','宋诗','song-poetry','','[]','出舟湖渺渺，月白絕纖氛。',48,'全唐诗/poet.song.15000.json','["出舟湖渺渺，月白絕纖氛。", "已見水如鑑，莫生波上雲。", "獨征何慕侶，冷酌不知醺。", "露下清吟久，同心本愛君。"]'),
('4ca400f8-85f2-4bde-bb58-9af69668e125','答宣城張主簿遺鴉山茶次其韻','梅堯臣','宋','宋诗','song-poetry','','[]','昔觀唐人詩，茶詠鴉山嘉。',264,'全唐诗/poet.song.15000.json','["昔觀唐人詩，茶詠鴉山嘉。", "鴉銜茶子生，遂同山名鴉。", "重以初槍旗，采之穿煙霞。", "江南雖盛産，處處無此茶。", "纖嫩如雀舌，煎烹比露芽。", "競收青篛焙，不重漉酒紗。", "顧渚亦頗近，蒙頂來以遐。", "雙井鷹掇爪，建溪春剝葩。", "日鑄弄香美，天目猶稻麻。", "吳人與越人，各各相鬭夸。", "傳買費金帛，愛貪無夷華。", "甘苦不一致，精麤還有差。", "至珍非貴多，爲贈勿言些。", "如何煩縣僚，忽遺及我家。", "雪貯雙砂罌，詩琢無玉瑕。", "文字搜怪奇，難於抱長蛇。", "明珠滿紙上，剩畜不爲奢。", "玩久手生胝，窺久眼生花。", "嘗聞茗消肉，應亦可破瘕。", "飲啜氣覺清，賞重歎復嗟。", "歎嗟既不足，吟誦又豈加。", "我今實强爲，君莫笑我耶。"]'),
('54df88f2-d883-4750-b5c7-780ee885783c','送寧國軍宰崔寺丞移臨安','梅堯臣','宋','宋诗','song-poetry','','[]','六月畏嶺險，乃陟川程迂。',72,'全唐诗/poet.song.15000.json','["六月畏嶺險，乃陟川程迂。", "遥看雲中雁，不亂江上鳬。", "魚網離飛鴻，我邑望何殊。", "鱗方懷其剖，鳥反值以刳。", "爲言等王民，豈限楚與吳。", "是維見戀慕，作詩贈路隅。"]'),
('e6ecf712-e5c5-439a-83a9-2039514ece88','辯疑贈獻甫','梅堯臣','宋','宋诗','song-poetry','','[]','一客逢吠狗，無箠制狗狂。',72,'全唐诗/poet.song.15000.json','["一客逢吠狗，無箠制狗狂。", "一客叱狗吠，一客言狗良。", "良狗豈妄吠，好言已莫詳。", "言乃仁之趨，叱乃義所當。", "趨仁不顧義，非是助狗猖。", "吾今不疑仁，仁義嗟何妨。"]'),
('0352bb11-684a-4d74-b08c-1fcbcb7e576d','盜儒','梅堯臣','宋','宋诗','song-poetry','','[]','其衣乃儒服，其說乃墨夷。',48,'全唐诗/poet.song.15000.json','["其衣乃儒服，其說乃墨夷。", "天生物一本，今爾二本爲。", "爾忍不葬親，委以飽狐狸。", "吾心則孟子，不聽爾矢辭。"]'),
('ed35d376-225e-49b6-a90c-6d3707ce69b7','宣城宰郭仲文遺林檎','梅堯臣','宋','宋诗','song-poetry','','[]','右軍好佳果，墨帖求林檎。',48,'全唐诗/poet.song.15000.json','["右軍好佳果，墨帖求林檎。", "君今忽持贈，知有逸少心。", "密枝傳應遠，朱頰映已深。", "不愁炎暑劇，幸同玉漿斟。"]'),
('8dfa5d61-fa19-4758-b418-48f6446ac9c0','自和','梅堯臣','宋','宋诗','song-poetry','','[]','陶公種五柳，華氏戲五禽。',48,'全唐诗/poet.song.15000.json','["陶公種五柳，華氏戲五禽。", "達性與養生，共得古人心。", "佳果能御暑，致之意何深。", "河朔存故事，助飲莫憚斟。"]'),
('fcf08204-4c83-4caa-a3fc-18ced02e3fee','送王克憲奉職之彭澤','梅堯臣','宋','宋诗','song-poetry','','[]','折柳贈子行，況聞彭澤去。',48,'全唐诗/poet.song.15000.json','["折柳贈子行，況聞彭澤去。", "將過五株下，可與青青助。", "渭城人唱罷，羌管愁吹處。", "江上定多閑，疎陰就箕踞。"]'),
('c34ea214-1a58-4d8d-aef0-5caa34ffa8d2','寄潘歙州伯恭','梅堯臣','宋','宋诗','song-poetry','','[]','我貧性愛酒，有酒無錢沽。',98,'全唐诗/poet.song.15000.json','["我貧性愛酒，有酒無錢沽。", "新安走牙兵，六月至我廬。", "手中持尺題，肩上擔瓦壺。", "高山度青天，救此愁腸枯。", "開之聊傾樽，渴肺如澆酥。", "醉來欲學李白騎鯨魚，又思阮籍跨蹇馿。", "上溪無健鱗，下嶺無壯駒，憶君南望空長吁。"]'),
('c6fdd0e4-e284-46ee-a9cd-406222bf3ce0','再寄歙州潘伯恭','梅堯臣','宋','宋诗','song-poetry','','[]','青山截天去，古路蔽雲中。',48,'全唐诗/poet.song.15000.json','["青山截天去，古路蔽雲中。", "不有行人至，安知與郡通。", "高樓雖窈窕，古樹已溟濛。", "今日勞君問，衡門一老翁。"]'),
('dab1f296-a00d-47f3-9eba-c7e38ea2bb8a','依韻和永叔澄心堂紙答劉原甫','梅堯臣','宋','宋诗','song-poetry','','[]','退之昔負天下才，掃掩衆說猶除埃。',256,'全唐诗/poet.song.15000.json','["退之昔負天下才，掃掩衆說猶除埃。", "張籍盧仝鬭新怪，最稱東野爲奇瑰。", "當時辭人固不少，漫費紙札磨松煤。", "歐陽今與韓相似，海水浩浩山嵬嵬。", "石君蘇君比盧籍，以我擬郊嗟困摧。", "公之此心實扶助，更後有力誰論哉。", "禁林晚入接俊彥，一出古紙還相哀。", "曼卿子美人不識，昔嘗吟唱同樽罍。", "因之作詩答原甫，文字駚穩如刀裁。", "怪其有紙不寄我，如此出語亦善詼。", "往年公贈兩大軸，於今愛惜不輙開。", "是時有詩述本末，值公再入居蘭臺。", "崇文庫書作總目，未暇綴韻酬草萊。", "前者京師競分買，罄竭舊府歸鄒枚。", "自慙把筆粗成字，安可遠與鍾王陪。", "文墨高妙公第一，宜用此紙傳將來。"]'),
('f5b8df14-44b4-470a-b528-6afada528dd7','依韻酬永叔示予銀杏','梅堯臣','宋','宋诗','song-poetry','','[]','去年我何有，鴨脚贈遠人。',84,'全唐诗/poet.song.15000.json','["去年我何有，鴨脚贈遠人。", "人將比鵝毛，貴多不貴珍。", "雖少未爲貴，亦以知我貧。", "至交不變舊，佳果幸及新。", "窮坑我易滿，分餉猶奉親。", "計料失廣大，瑣屑且沉淪。", "何用報珠玉，千里來慇懃。"]'),
('2d02eb1b-afc3-41c9-8ca0-3ec5feb01207','依韻酬永叔再示','梅堯臣','宋','宋诗','song-poetry','','[]','前歲守廩京城西，有如勾踐巢會稽。',320,'全唐诗/poet.song.15000.json','["前歲守廩京城西，有如勾踐巢會稽。", "引杯嘗膽未雪恥，怒蛙起揖當涔蹄。", "海天白日蔽光影，霹靂一過收雲霓。", "九臯澄明鶴翅濕，欲暮刷羽聲嘶嘶。", "客來東方美鬚鬣，夜光出袖行無迷。", "授予照眼已希世，自顧臭辣猶萍齏。", "文章製作比善塑，物象變怪一以泥。", "泥雖各用有巧拙，巧之高絕非由梯。", "又聞東夷蹈水底，騎頸直踞通天犀。", "曼卿子美摟入室，似使二嫂治朕棲。", "舜歸在牀不可得，此實素分非能齊。", "而今我獨向田里，秋稼已熟烹黄雞。", "自傾白酒坐溪上，誰念往日無粱稊。", "鄰邦或有寄嘉釀，瓦罌土缶盛玻瓈。", "昨喜得書書滿紙，官尊職大憐我睽。", "怪我書亂苦簡略，疲駑豈敢攀駿驪。", "貴賤交情古來有，胸中不欲置畛畦。", "世間百事厭著意，但願無病年壽躋。", "田園未多亦粗給，兒女況足資提携。", "終當去問綿上叟，自與野老月下犂。"]'),
('252a0825-f337-4b37-8be7-13b5da962b60','池州蕭相樓','梅堯臣','宋','宋诗','song-poetry','','[]','樓中九華峯，天削水蒼玉。',84,'全唐诗/poet.song.15000.json','["樓中九華峯，天削水蒼玉。", "公圭何參差，來雲自聯續。", "我思唐蕭家，八人居宰錄。", "朱欄幾廢興，下視寒江曲。", "吳侯來爲邦，百事無窘束。", "新之以登臨，風月詠玩足。", "安得黄鵠翼，一舉遺世俗。"]'),
('f560ff02-6a19-4f89-a90a-e09ad7b07911','雜興  其一','梅堯臣','宋','宋诗','song-poetry','','[]','苦楝樹，青鵓鴣。',64,'全唐诗/poet.song.15000.json','["苦楝樹，青鵓鴣。", "啄鹽土，鳴嗚嗚。", "老鴉銜茶子，爭噪落嶺隅。", "不覺茶滿山，漁利入江湖。", "鹽由鵓鴣起，茶由老鴉趨。", "誘以觸禁網，二鳥誰與誅。"]'),
('6e97802b-59db-4b29-baae-4dcd6df40bfb','雜興  其二','梅堯臣','宋','宋诗','song-poetry','','[]','東家月吐明，西家犬爭吠。',48,'全唐诗/poet.song.15000.json','["東家月吐明，西家犬爭吠。", "月兔在中天，曾何競窺穢。", "姮娥雖夜行，莫比淫奔廢。", "呶呶籬下音，胡不鈐其喙。"]'),
('63aa2040-4e6b-46f4-b620-3c0e43c49a8c','夢後寄歐陽永叔','梅堯臣','宋','宋诗','song-poetry','','["\u6292\u6000", "\u671f\u671b", "\u53cb\u60c5"]','不趁常參久，安眠向舊溪。',48,'全唐诗/poet.song.15000.json','["不趁常參久，安眠向舊溪。", "五更千里夢，殘月一城雞。", "適往言猶是，浮生理可齊。", "山王今已貴，肯聽竹禽啼。"]'),
('6fa14779-ef03-4bfb-8040-a21b88aa7f14','送王著作赴西京壽安','梅堯臣','宋','宋诗','song-poetry','','[]','去作西畿令，當趨大尹庭。',48,'全唐诗/poet.song.15000.json','["去作西畿令，當趨大尹庭。", "閒尋前代迹，浄掃古槐廳。", "未慣餐周粟，還應憶楚萍。", "但逢花木處，知我昔常經。"]'),
('4e01db36-b223-41c9-8aa0-c25c2cb725fb','答了素上人用其韻','梅堯臣','宋','宋诗','song-poetry','','[]','予心每淡泊，世路多變詐。',108,'全唐诗/poet.song.15000.json','["予心每淡泊，世路多變詐。", "梟鳴與鵩怪，何用思彈射。", "空山雖夜行，猛虎終不怕。", "功名未逢時，壯士且出胯。", "七尺無競軀，市人應亦訝。", "有香知害身，抉臍見窮麝。", "一朝珠出淵，百金未酬價。", "爾尋遠公去，絜鉢廬峯下。", "我趨仁義急，不解如陶謝。"]'),
('e21fd164-4dce-48e5-adfa-5bd65ef24500','送通判黄國博入浙','梅堯臣','宋','宋诗','song-poetry','','[]','西風半空鳴且號，吳天點破吳鴻高。',121,'全唐诗/poet.song.15000.json','["西風半空鳴且號，吳天點破吳鴻高。", "東溪車馬走送客，白露衰蘭輕若毛。", "客當西歸乃東去爲何，欲及八月十五夜觀洪濤。", "洗蕩生前邑邑不平氣，付與滄海之水隨滔滔。", "却來廣陵願相見，拍手大笑傾新醪。", "一飲一石無一錢，莫管寒近脫弊袍。", "脫袍準酒不惜醉，天意未必凍我曹。"]'),
('1bc878c9-d2c0-4295-86bf-a7ce12dbd44b','烏啄棗','梅堯臣','宋','宋诗','song-poetry','','[]','樹頭陽烏饑啄棗，破紅遶地青蠅老。',48,'全唐诗/poet.song.15000.json','["樹頭陽烏饑啄棗，破紅遶地青蠅老。", "青蠅雨濕驚不飛，殘棗入泥人不掃。", "西風落盡鳥亦歸，晉客齒黄終懊惱。"]'),
('38319a1e-4bce-48a7-8d10-c5040234e96b','真上人因送毛令傷足復傷冷  其一','梅堯臣','宋','宋诗','song-poetry','','[]','陶令歸時遠公送，石苔秋雨步遲遲。',32,'全唐诗/poet.song.15000.json','["陶令歸時遠公送，石苔秋雨步遲遲。", "凌霄花在古松上，也笑向人人不知。"]'),
('52267911-876d-4a01-a190-8acee1ac9185','真上人因送毛令傷足復傷冷  其二','梅堯臣','宋','宋诗','song-poetry','','[]','聞道山中出入稀，偶來溪上笑談微。',32,'全唐诗/poet.song.15000.json','["聞道山中出入稀，偶來溪上笑談微。", "野雲不管田袍薄，寒逼瘦膚相伴歸。"]'),
('74970f4c-e02d-4af9-a01a-7b6262e28584','潘歙州怪予遂行與黄君同路黄先游浙矣依韻酬寄','梅堯臣','宋','宋诗','song-poetry','','[]','未識潘岳貌，已知潘岳名。',172,'全唐诗/poet.song.15000.json','["未識潘岳貌，已知潘岳名。", "去年改藩屏，暫此解佩纓。", "一見意已合，談笑僕屢更。", "豈唯文學富，況亦論事精。", "溪邊昔欲罷，屑屑秋雨零。", "於今又聞蟬，重起悲凉情。", "作詩遠見招，值我將西行。", "譬彼矯翼鳥，革然顧侶鳴。", "蒼山不可陟，空入江上舲。", "黄君雖云約同泛，明日自訪柳惲汀。", "寒儒所向多不成，或西或東車馬驚。", "高樓登望酸目睛，欲觀弄濤仍膾鯨。", "新安太守空相迎，舉手謝君江水清。"]'),
('538b1fed-45c3-4c4d-8a01-1c0e213c7002','潘歙州寄紙三百番石硯一枚','梅堯臣','宋','宋诗','song-poetry','','[]','永叔新詩笑原父，不將澄心紙寄予。',80,'全唐诗/poet.song.15000.json','["永叔新詩笑原父，不將澄心紙寄予。", "澄心紙出新安郡，臘月敲冰滑有餘。", "潘侯不獨能致紙，羅紋細硯鎸龍尾。", "墨花磨碧涵鼠鬚，玉方舞盤蛇與虺。", "其紙如彼硯如此，窮儒有之應瞰鬼。"]'),
('280bbf1e-ca74-4de4-98fd-2c84c59166d1','八月七日始見白髭一莖','梅堯臣','宋','宋诗','song-poetry','','[]','昔見白髭驚，今見白髭喜。',72,'全唐诗/poet.song.15000.json','["昔見白髭驚，今見白髭喜。", "人將拔去之，我獨不然耳。", "拔之既更生，留之何所恥。", "白日儻日拔，日拔詎能已。", "黑壯不爲貴，白衰不爲鄙。", "道德保於中，任從髭髮齒。"]'),
('c7b71d4a-186e-45a0-9253-4cd7807d8fba','送僧了素遊廬山','梅堯臣','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','平生愛廬山，夢寢不可去。',84,'全唐诗/poet.song.15000.json','["平生愛廬山，夢寢不可去。", "江上饒賈船，偶來看已飫。", "釋子言南游，徘徊瞻瀑布。", "月飛金熨斗，光展千尺素。", "嫦娥呼織女，機杼勿復措。", "必虞山鬼笑，皎潔無纖汙。", "爾若見遠公，贈之爲坐具。"]'),
('f9cb55ef-f75e-4a9e-a629-0d4030afe86a','送方進士遊廬山','梅堯臣','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','長風沙浪屋許大，羅剎石齒水下排。',193,'全唐诗/poet.song.15000.json','["長風沙浪屋許大，羅剎石齒水下排。", "歷此二險過湓浦，始見瀑布懸蒼崖。", "繫舟上岸入松徑，三日踏穿新蠟鞋。", "路盤深谷出嶺望，後山日照前山霾。", "偶逢風雨恐衣濕，側倚石脇人相乖。", "雨收不覺在高處，却見童僕提携偕。", "水聲不絕鳥聲好，藥草香氣侵人懷。", "老僧避俗去足跣，野客就澗開門䦱。", "樹巖隠映見寺剎，層層杳杳躋雲階。", "塢田將穫烏雀橫，秋果正熟猴猿𪘨。", "東林淡齏應似舊，唯此足以待爾儕。", "子心灑落撇然往，我方塵垢難磨揩。"]'),
('eb802ef9-eed8-41fe-bb97-a0914b8fda4f','讀日者傳答俞生','梅堯臣','宋','宋诗','song-poetry','','[]','宋忠爲大夫，賈誼爲博士。',60,'全唐诗/poet.song.15000.json','["宋忠爲大夫，賈誼爲博士。", "同與休沐下，訪卜長安市。", "吾不如二人，讀書無舉跬。", "借曰當乘肥，乘肥非我指。", "唯思泉石間，坐卧松風美。"]'),
('65d8a588-0132-4679-8194-1165b943ceb3','隠靜山懷賢師自持柏栽二十本種於會慶堂','梅堯臣','宋','宋诗','song-poetry','','[]','新作齋堂祠畫像，又興高閣秘天蹤。',32,'全唐诗/poet.song.15000.json','["新作齋堂祠畫像，又興高閣秘天蹤。", "今朝還藉君移柏，昨日已因鵝種松。"]'),
('1a31f12c-507a-495e-952d-9accd8047e1a','九月六日登舟再和潘歙州紙硯','梅堯臣','宋','宋诗','song-poetry','','[]','文房四寶出二郡，邇來賞愛君與予。',80,'全唐诗/poet.song.15000.json','["文房四寶出二郡，邇來賞愛君與予。", "予傳澄心古紙樣，君使製之精意餘。", "自茲重詠南堂紙，將今世人知首尾。", "又得水底碧玉腴，溪匠畏持如抱虺。", "拜貺雙珍不可辭，年衰只怕歔歈鬼。"]'),
('c41031a7-8aeb-424a-941a-b729d62a7747','九月十一日下昭亭舟中','梅堯臣','宋','宋诗','song-poetry','','[]','平生山野性，坐卧愛流水。',84,'全唐诗/poet.song.15000.json','["平生山野性，坐卧愛流水。", "適從昭亭來，興自明河起。", "小舟浮輕槎，身入星辰裏。", "飲牛誰家郎，照鬢誰家子。", "隔岸心相望，翻然洲鵲喜。", "灘頭磷磷石，欲贈畏指毀。", "留取自支機，成都無卜士。"]'),
('4f2761c6-5ffc-4de8-86b1-522d0d9110ac','和張簿寧國山門六題 山門','梅堯臣','宋','宋诗','song-poetry','','[]','青山中穴爲大門，下通軌轍高莫論。',64,'全唐诗/poet.song.15000.json','["青山中穴爲大門，下通軌轍高莫論。", "飛雲出納不計限，雙峙平削無刀痕。", "入門復見田園美，田外峯巒迴抱尊。", "棲靈畜怪不可詰，夔魈往往來守閽。"]'),
('c41c43cd-1a87-428d-a22f-f6d098bd9678','和張簿寧國山門六題 紫雲巖','梅堯臣','宋','宋诗','song-poetry','','[]','高巖日照雲常起，吹作蘭花透紋綺。',32,'全唐诗/poet.song.15000.json','["高巖日照雲常起，吹作蘭花透紋綺。", "橫爲步障看未收，山雨一來風滿耳。"]'),
('ff32b616-7525-4858-83e5-38c25adba344','和張簿寧國山門六題 夕陽巖','梅堯臣','宋','宋诗','song-poetry','','[]','日脚射空金縷直，下映壁間棱未織。',32,'全唐诗/poet.song.15000.json','["日脚射空金縷直，下映壁間棱未織。", "野老先知雨又風，明朝望此重雲黑。"]'),
('e8324e82-b60d-4dc3-b80e-6f93e79f4ee1','和張簿寧國山門六題 朝陽洞','梅堯臣','宋','宋诗','song-poetry','','[]','洞門雖向扶桑開，洞深不放陽烏入。',32,'全唐诗/poet.song.15000.json','["洞門雖向扶桑開，洞深不放陽烏入。", "古來道士今莫逢，石壁乳流苔正濕。"]'),
('6b45675a-1c07-42f8-9a1a-f5239c9a5bf7','和張簿寧國山門六題 漣漪洞','梅堯臣','宋','宋诗','song-poetry','','[]','流泉决决出洞底，自有細浪非風吹。',32,'全唐诗/poet.song.15000.json','["流泉决决出洞底，自有細浪非風吹。", "山花逐水到山下，漏泄人間春未知。"]'),
('07ec919f-f2af-4d7d-b4e7-80b7bc06aad0','和張簿寧國山門六題 碧雲洞','梅堯臣','宋','宋诗','song-poetry','','[]','誰將萬古倚雲劍，刺破蒼石天窗開。',32,'全唐诗/poet.song.15000.json','["誰將萬古倚雲劍，刺破蒼石天窗開。", "下貯泓淵不可極，有時月漏清光來。"]'),
('712efbcc-03e2-4680-88ed-5dedd0938213','將離宣城寄吳正仲','梅堯臣','宋','宋诗','song-poetry','','[]','吳均詩語多奇揭，苦倩鴛鴦謝明月。',96,'全唐诗/poet.song.15000.json','["吳均詩語多奇揭，苦倩鴛鴦謝明月。", "昭亭川上此禽閑，爲寄吳郎我西發。", "西歸千里浮輕舟，夜觀蟾光逆水流。", "水流東海月西海，各去雖殊意常在。", "月偏皎皎隨人行，水亦沄沄非浪改。", "酒盆龍杓閑到吟，梅花重葉將誰采。"]'),
('312b9929-702a-42ba-abb6-32a8e9f48274','湯珙秘校遺沉水管筆一枝','梅堯臣','宋','宋诗','song-poetry','','[]','沉香細幹天通中，束毫爲呼諸葛翁。',80,'全唐诗/poet.song.15000.json','["沉香細幹天通中，束毫爲呼諸葛翁。", "久從海上厭持握，乞與阮籍書途窮。", "物珍豈宜賤子有，更後應合歸王公。", "虛堂浄几塵不到，硯傍置架珊瑚紅。", "乃知用遇自有處，君今莫歎居蒿蓬。"]'),
('69c1440f-02ee-4993-89fa-19ed3c45a5d4','艤舟昭亭送都官暫歸錢塘','梅堯臣','宋','宋诗','song-poetry','','[]','前枉大梁城，詩賦嘉入幕。',84,'全唐诗/poet.song.15000.json','["前枉大梁城，詩賦嘉入幕。", "茲對昭亭山，將行還有作。", "別離此與彼，終始情不薄。", "我爲解羈馬，君乃高飛鶴。", "塵蹄未能息，健翅懷棲泊。", "尋巢望吳田，一傍華亭郭。", "況多丹頂雛，坐看翔寥廓。"]'),
('185ad99e-64e1-4800-92cf-879c7f3baa53','依韻公擇察推','梅堯臣','宋','宋诗','song-poetry','','[]','君來何所聞，君去何所見。',72,'全唐诗/poet.song.15000.json','["君來何所聞，君去何所見。", "自古慕虛名，往往輕既面。", "竊常恃賦稟，平直如勁箭。", "是以五十年，長甘守貧賤。", "相逢嗟未幾，遽遠劇飛電。", "今雖行已晚，多謝勤相唁。"]'),
('793bcfe2-65b3-4c01-bd58-eceba9c9c65a','晏成續太祝遺雙井茶五品茶具四枚近詩六十篇因以爲謝','梅堯臣','宋','宋诗','song-poetry','','[]','始於歐陽永叔席，乃識雙井絕品茶。',160,'全唐诗/poet.song.15000.json','["始於歐陽永叔席，乃識雙井絕品茶。", "次逢江東許子春，又出鷹爪與露芽。", "鷹爪斷之中有光，碾成雪色浮乳花。", "晏公風流丞相族，以此五色論等差。", "遠走犀兵至蓬巷，青蒻出篋封題加。", "紋柘冰瓷作精具，靈味一啜驅昏邪。", "神還氣王讀高詠，六十五篇金出沙。", "已從鍛鍊出至寶，終老不變傳幽遐。", "自惟平昔所得者，何異瓦礫空盈車。", "滌心洗腑强爲答，愈苦愈拙徒興嗟。"]'),
('b4595fe0-c94c-48d2-bce5-68ec1f82eb10','留題開元寺仙上人平雲閣','梅堯臣','宋','宋诗','song-poetry','','[]','背市面山色，平目觀白雲。',48,'全唐诗/poet.song.15000.json','["背市面山色，平目觀白雲。", "漁舟溪上歌，游客欄邊聞。", "俯簷翠柏瘦，蔓籬秋實蕡。", "偶來心意靜，塵慮如掃坌。"]'),
('1dbe182c-6c02-4aa9-9f8a-c57f933479fe','送黄生','梅堯臣','宋','宋诗','song-poetry','','[]','我本東西南北人，窮途不復淚霑巾。',32,'全唐诗/poet.song.15000.json','["我本東西南北人，窮途不復淚霑巾。", "亦知車馬有行色，爲見長沮與問津。"]'),
('9b9dd3a2-0cd7-494a-a9b7-96dcff5ad11a','別張景嵩','梅堯臣','宋','宋诗','song-poetry','','[]','我雖識君晚，君能知我心。',84,'全唐诗/poet.song.15000.json','["我雖識君晚，君能知我心。", "我心昭亭水，見底無尺尋。", "照之不爲隠，測之不爲深。", "魚蝦既混混，藻荇亦侵侵。", "終當至滄海，浴日開黄金。", "君當下灘去，石浪激寒音。", "猶能洗君目，病瞖雲銷岑。"]'),
('32866abd-529b-4b31-a595-43dae2ee847d','別鍾京','梅堯臣','宋','宋诗','song-poetry','','[]','我憐鍾氏子，冒雨爲求文。',48,'全唐诗/poet.song.15000.json','["我憐鍾氏子，冒雨爲求文。", "暫以經茲邁，與之書所聞。", "野鷗窺筆硯，舟子采蒿芹。", "況有新炊飯，簞漿可送君。"]'),
('f863b2f4-a469-47fa-a5ff-c962ab8b4e36','江口遇劉糾曹赴鄂州寄張大卿','梅堯臣','宋','宋诗','song-poetry','','[]','我同陶淵明，遠憶顔光祿。',104,'全唐诗/poet.song.15000.json','["我同陶淵明，遠憶顔光祿。", "得錢留酒家，醉卧江蕪綠。", "故人已貴身獨賤，籬根枯死佳花菊。", "孤鴻飛去鸚鵡洲，寄聲高樓謝黄鵠。", "使君本是洛陽人，嘗憐酩酊銅駝曲。", "休將玉笛城上吹，武昌老人聽不足。", "已知清音通九霄，定應悔說蘄州竹。"]'),
('017e91dd-d93e-4b0a-bc9a-2dd5495a684c','送劉糾曹','梅堯臣','宋','宋诗','song-poetry','','[]','溪邊前日君辭我，江上今朝我送君。',32,'全唐诗/poet.song.15000.json','["溪邊前日君辭我，江上今朝我送君。", "自去蘆洲寄消息，故人猶在武昌軍。"]'),
('240c810e-8f91-4a6f-8569-75d495b698a1','寄題開元寺明上人院假山','梅堯臣','宋','宋诗','song-poetry','','[]','石是青苔石，山非杳藹山。',48,'全唐诗/poet.song.15000.json','["石是青苔石，山非杳藹山。", "諸峯生鏡裏，小嶺傍池間。", "雨不因雲出，門疑爲客關。", "何須費蠟屐，暫到此中閒。"]'),
('c55a1657-5463-4b71-993f-116e3f6329f6','寄李獻甫','梅堯臣','宋','宋诗','song-poetry','','[]','何言自我去，眼前一似空。',72,'全唐诗/poet.song.15000.json','["何言自我去，眼前一似空。", "城中豈無人，過目猶飛蟲。", "又厭塵事多，枳棘生胸中。", "安知秋江水，浄碧如磨銅。", "尚恨有世累，不及垂釣翁。", "望望當速來，止琴視孤鴻。"]'),
('9d5b36ca-29b8-4e7d-83be-0d84c18d585c','次韻和吳季野題岳上人澄心亭','梅堯臣','宋','宋诗','song-poetry','','[]','空山舊逕綠苔滿，古寺齋盂白薤蒸。',64,'全唐诗/poet.song.15000.json','["空山舊逕綠苔滿，古寺齋盂白薤蒸。", "暑雨坐中飛漠漠，野泉林外落層層。", "從來勝絕皆離俗，未有幽深不屬僧。", "唯愛溪頭一尋水，莫聞流浪莫聞澄。"]'),
('55d31b59-fdfa-4c0a-9589-7f4e012aef94','次韻和馬都官宛溪浮橋','梅堯臣','宋','宋诗','song-poetry','','[]','在昔當陽侯，建橋臨大川。',72,'全唐诗/poet.song.15000.json','["在昔當陽侯，建橋臨大川。", "洪波不爲阻，馳道南北連。", "何此小溪上，擬象坦且平。", "馬頭分朱欄，水底裁碧天。", "白雨緊大笮，斷虹生橫舷。", "游魚不可見，車騎久臨淵。"]'),
('64e5e12b-4d55-4374-9dc6-f660c6b0f463','寄隠靜山懷賢長老','梅堯臣','宋','宋诗','song-poetry','','[]','山有枇杷樹，樹多獼猴羣。',48,'全唐诗/poet.song.15000.json','["山有枇杷樹，樹多獼猴羣。", "高僧心不著，一似五峯雲。", "隨飇來溪口，石上起氤氳。", "果熟獼猴去，自向瀑澗分。"]'),
('bf0c5f08-1469-4bcd-be27-9e755233193d','次韻和馬都官苦熱','梅堯臣','宋','宋诗','song-poetry','','[]','日光亭午時，赫若鎔黄金。',84,'全唐诗/poet.song.15000.json','["日光亭午時，赫若鎔黄金。", "鳴鳶不生風，流雲不成陰。", "赤地有焦土，烈野無沃霖。", "涸潭深幽幽，枯嶽高岑岑。", "火龍將焚鬣，陽烏多渴心。", "肌膚非木石，絺綌煩衣襟。", "冰盤不可見，空對瓊玖吟。"]'),
('7bbd2509-6918-4648-851b-06e92cded4a4','歷陽過杜挺之遂約同入汴','梅堯臣','宋','宋诗','song-poetry','','[]','滄海瀉玉自外天，牛斗傍邊客正迴。',64,'全唐诗/poet.song.15000.json','["滄海瀉玉自外天，牛斗傍邊客正迴。", "人說維摩居士病，我同王子雪舟來。", "汀沙沮洳潮新落，山日曈曚霧始開。", "去約河隄春柳動，與君吹紫步徘徊。"]'),
('6e02f30f-f0bf-4fcb-9eae-e65b5f8235b8','和胡公疎送嶼師移居寶光寺','梅堯臣','宋','宋诗','song-poetry','','[]','宋日天王寺，梁時太子園。',48,'全唐诗/poet.song.15000.json','["宋日天王寺，梁時太子園。", "地猶隨世變，物豈與人存。", "欲問移居意，還應避俗喧。", "相期唯有月，夜夜在高原。"]'),
('96b52488-7b79-4d83-8e45-9c0aff4cb5e2','胡公疎示祖擇之盧氏石詩和之','梅堯臣','宋','宋诗','song-poetry','','[]','袁州太守蓬山客，來過盧家尋怪石。',320,'全唐诗/poet.song.15000.json','["袁州太守蓬山客，來過盧家尋怪石。", "盧家百物今已空，唯石難移留舊蹟。", "埋沒尚存三四分，雨淋日炙如皴皵。", "太守惻然呼健兒，荷鋤秉鍤爭來役。", "健兒掘土不爲堅，旋旋剜沙見圭隙。", "漸奇漸異人忘勞，更索更深知幾尺。", "瘦峯削出嵩華骨，虛竅鑿破蛟螭額。", "千指曳繩車四輪，擊鼓助力歸東陌。", "東陌東頭湖水傍，黄泥洗盡何蒼碧。", "故宅愈冷東湖喧，貴賤競觀無礙隔。", "太守自憐堅直心，愛少憎多屢遭謫。", "南至蒼梧及桂林，名山徧訪無窮僻。", "所宜厭慣不入眼，向此歌吟尤愛惜。", "我思永叔滁陽時，大誇古翠菱溪獲。", "作詩遠寄予與蘇，高唱相隨無節拍。", "今知賢人趣向同，玩好託情亡俗格。", "建康從事胡公疎，一見詫君如李白。", "雄才落筆瀉天河，綴韻孤清仍險窄。", "入探虎穴誰爲難，辭通造化方能敵。", "殿後吾雖膽力强，獨鞭疲馬終無益。"]'),
('ae35327c-1e97-4e21-aa91-7b2395e36adf','逢曾子固','梅堯臣','宋','宋诗','song-poetry','','[]','前出秦淮來，船尾偶攙燕。',96,'全唐诗/poet.song.15000.json','["前出秦淮來，船尾偶攙燕。", "遽傳曾子固，願欲一相見。", "順風吹長帆，舉手但慕羨。", "楊子東園頭，下馬情眷眷。", "昔始知子文，今始識子面。", "吐辭亦何嚴，白晝忽飛霰。", "我病不飲酒，烹茶又非善。", "冷坐對寒流，蕭然未知倦。"]'),
('11b3037a-cfbc-4992-957c-3a13f9544278','真州東園','梅堯臣','宋','宋诗','song-poetry','','[]','國賦有常計，計者豈不賢。',108,'全唐诗/poet.song.15000.json','["國賦有常計，計者豈不賢。", "日夜疲精神，自鑒膏火前。", "新春力有餘，鋤荒東乳偏。", "壘土以起榭，掘沼以秧蓮。", "竹柏爲冬榮，桃李爲春妍。", "役使吳楚艘，來泊常流連。", "下江忘其險，入漕忘其邅。", "許公作此意，吾亦見其權。", "不獨利於己，願書棠樹篇。"]'),
('5f021c8e-73b6-4b8a-9dd4-d730f006b9be','行吟  其一','梅堯臣','宋','宋诗','song-poetry','','[]','持轡趨代北，妄意希名馬。',60,'全唐诗/poet.song.15000.json','["持轡趨代北，妄意希名馬。", "代北馬如雲，由來重取舍。", "王官待才能，高下不苟且。", "行都未脩飭，黄金誰變瓦。", "吾當保吾真，甘歸事田野。"]'),
('05aa1e39-4adf-467d-be0b-8853ab237f94','行吟  其二','梅堯臣','宋','宋诗','song-poetry','','[]','寘蟻橘林下，正在結實時。',60,'全唐诗/poet.song.15000.json','["寘蟻橘林下，正在結實時。", "附緣與出入，安可責於斯。", "養大不問細，使遠不問遲。", "遠遲必有報，細大必有期。", "休哉豢龍氏，終自辨蛟螭。"]'),
('9131b50d-dd16-43f7-a429-7c1626d04b78','僧子思以卷來見','梅堯臣','宋','宋诗','song-poetry','','[]','明珠與翡翠，中國反好之。',60,'全唐诗/poet.song.15000.json','["明珠與翡翠，中國反好之。", "詩書出鄒魯，誦學無蠻夷。", "服彼而習此，養騂安問犂。", "古者耕釣士，處心殊處卑。", "譬彼乃可語，吾病强扶持。"]'),
('8dbfe878-f878-4585-8b73-58c3885e8098','依韻和楊州許待制竹拄杖','梅堯臣','宋','宋诗','song-poetry','','[]','楚竹翦霜叢，何慙漢使筇。',144,'全唐诗/poet.song.15000.json','["楚竹翦霜叢，何慙漢使筇。", "鳩形殊用刻，馬箠不同功。", "挺特生難變，支離分已窮。", "輕肥思比鶴，短髮任如蓬。", "倚以爲高趣，持之見素風。", "步郊聊實下，行樂偶從東。", "屢刺莓苔破，深穿苑圃通。", "辯繁時畫地，默意或書空。", "古血有湘跡，舊林無阮蹤。", "將渠誰覺老，要此豈關慵。", "莫駭傾巢鳥，須虞蠹穴蟲。", "誰能求道術，跨作上天龍。"]'),
('6c92d449-d0c0-4f53-ac14-f525a98109b8','遇畫工來嵩','梅堯臣','宋','宋诗','song-poetry','','[]','朝來又入楊州郭，千萬中人識者誰。',32,'全唐诗/poet.song.15000.json','["朝來又入楊州郭，千萬中人識者誰。", "唯有來嵩曾畫我，依稀見似昔年時。"]'),
('49b447c4-dbd5-456f-bdd3-77a60dc7d94c','省符上人','梅堯臣','宋','宋诗','song-poetry','','[]','春秋一萬八千字，不問吳人楚人事。',64,'全唐诗/poet.song.15000.json','["春秋一萬八千字，不問吳人楚人事。", "佛衣儒談世已罕，節行又與其徒異。", "往來楊州三十年，曾見華堂荆棘地。", "獨聞依舊坐焚香，尚把殘編討遺意。"]'),
('b1d30257-5f37-4f57-8bc5-fabd91f326be','沈學士景休知真州','梅堯臣','宋','宋诗','song-poetry','','[]','太守旛旗近國門，州民迎望若雲屯。',64,'全唐诗/poet.song.15000.json','["太守旛旗近國門，州民迎望若雲屯。", "家風自有東陽詠，主道新移北海罇。", "紅錦臂韝觀粉質，塗金珂勒駕朱軒。", "他時儻使春秋對，莫以周襄出鄭論。"]'),
('495c8cd2-2f1d-4032-84e0-c9b21f00ad88','送杜君懿屯田通判宣州','梅堯臣','宋','宋诗','song-poetry','','[]','京兆外郎稱善書，當時相與集江都。',144,'全唐诗/poet.song.15000.json','["京兆外郎稱善書，當時相與集江都。", "日書藤紙爭持去，長鉤細畫如珊瑚。", "自茲乖隔三十載，始駕吾鄉別乘車。", "吾鄉素誇紫毫筆，因我又加蒼鼠鬚。", "最先賞愛杜丞相，中間喜用蔡君謨。", "爾後倣傳無限數，州符縣板仍抹塗。", "鼠雖可殺不易得，貓口奪之煩叱驅。", "若君字大筆亦大，穿墉瑣質無長胡。", "君到官，治事餘。", "呼諸葛，試問渠。"]'),
('0f2a4af3-de99-427b-9f1b-fee380228c95','張聖民學士出御書并法帖共閱之','梅堯臣','宋','宋诗','song-poetry','','[]','冰膠楚舸歲將窮，廣陵別乘憐老翁。',128,'全唐诗/poet.song.15000.json','["冰膠楚舸歲將窮，廣陵別乘憐老翁。", "殷勤來邀强一往，虛堂肴酒羅甘豐。", "我病胃寒不下咽，匕筯謾舉叨席中。", "主人欲客心意歡，出以飛帛騰龍鸞。", "刑政二字布楷法，古今書帖未足觀。", "坐間杜子好弄筆，詆譏前輩無全完。", "一見寶蹤天下妙，稽首贊仰舌吻乾。", "如此別識已太險，我不頌詠還應難。"]'),
('5c2968ef-3009-497e-8438-6d2e9dac89b9','讀黄莘秘校卷','梅堯臣','宋','宋诗','song-poetry','','[]','嵇康昔彈廣陵散，商聲高與宮聲緩。',112,'全唐诗/poet.song.15000.json','["嵇康昔彈廣陵散，商聲高與宮聲緩。", "託名山鬼未傳人，古桐紉絲絲不斷。", "一聞殭卧竊其音，世間雖得能亦罕。", "賢明以之知盛衰，愚昧以之爲妄誕。", "頃年過我在蕪城，忽聽長拍去欲懶。", "鳳皇養雛飛未高，雞鶩成羣翅終短。", "龍章秀骨苦輕時，繼作五絃須欵欵。"]'),
('04b7f2e1-a645-407b-97bf-8bd75a1bf9ec','贈許待制歲旦生日','梅堯臣','宋','宋诗','song-poetry','','[]','天曆重更端，哲人茲命世。',72,'全唐诗/poet.song.15000.json','["天曆重更端，哲人茲命世。", "嘗聞月旦評，況是高陽裔。", "椒花作壽杯，爆火通鑪桂。", "穹龜及蒼鶴，尚以千年係。", "曰惟五行秀，復與明時契。", "他日求老成，不須從渭汭。"]'),
('ad6f3a24-b3ba-49be-a41a-bdfd0ca3e422','答宣闐司理','梅堯臣','宋','宋诗','song-poetry','','[]','風賦義趣深，傳訓或得失。',156,'全唐诗/poet.song.15000.json','["風賦義趣深，傳訓或得失。", "後人語雖淺，辨識猶百一。", "歐陽最我知，初時且尚窒。", "比以爲橄欖，迴甘始稱述。", "老於文學人，尚不即究悉。", "宜乎與世士，橫爾遭詬唧。", "誓將默無言，負暄方抱膝。", "非非孰是是，都莫答問詰。", "歲暮宣參軍，辭如鮑昭逸。", "粲然傾明珠，褒我頗過實。", "便言楚江萍，光彩侔旭日。", "自慙流浪蹤，不得蒿芹匹。", "復爲苦硬句，酬報强把筆。"]'),
('c26dd82c-b450-4b5c-bceb-06629cd871f6','答鵝湖長老紹元示太玄圖','梅堯臣','宋','宋诗','song-poetry','','[]','鵝湖有鵝吾不問，鵝湖無鵝吾不疑。',51,'全唐诗/poet.song.15000.json','["鵝湖有鵝吾不問，鵝湖無鵝吾不疑。", "道士須換黄庭經，釋子自明太玄辭。", "噫嘻兮此意迥與山陰別，我亦曾非逸少爲。"]'),
('e6cbf18a-3ac9-49f3-b7c4-3d4af88b8c77','新韻曾子進早春','梅堯臣','宋','宋诗','song-poetry','','[]','新雷歲旦發聲嚴，冰管寒銷細滴簷。',64,'全唐诗/poet.song.15000.json','["新雷歲旦發聲嚴，冰管寒銷細滴簷。", "花甲將看枝上坼，蛇鱗不復地中潛。", "黄河分派來應早，白首歸朝意自恬。", "强欲擬君爲秀句，便無才思似江淹。"]'),
('2cd9510b-8119-4286-ba17-eabca8cd2713','依韻和馬都官齊少卿酬和','梅堯臣','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','同時沈宋稱二豪，曾說龍門奪錦袍。',32,'全唐诗/poet.song.15000.json','["同時沈宋稱二豪，曾說龍門奪錦袍。", "我對前流接清唱，泰山輕重於鴻毛。"]'),
('5bb716f7-17a5-400a-a23f-1d752b778857','贈江寧王高士','梅堯臣','宋','宋诗','song-poetry','','[]','自古江南風俗美，喜君高趣慕先賢。',64,'全唐诗/poet.song.15000.json','["自古江南風俗美，喜君高趣慕先賢。", "藥無遠近寧論報，家有圖書不計錢。", "已住秦淮借風月，遍尋吳國舊山川。", "塵纓我繫未能解，每一來過駐畫船。"]'),
('197053bf-0979-4aeb-81a3-50a49783e358','答蕭淵少府卷','梅堯臣','宋','宋诗','song-poetry','','[]','君先大夫臨終時，夢中嘗賦曉寒歌。',112,'全唐诗/poet.song.15000.json','["君先大夫臨終時，夢中嘗賦曉寒歌。", "騎龍跨魚不是誕，直對上帝傳吟哦。", "才如李賀天亦少，宜其在世尤難多。", "文章父子不相似，君今平易祖襲那。", "銅鐵錦褧各有用，高下安得與等科。", "大都精意與俗近，筆力驅駕能逶迤。", "野雉五色且非鳳，知時善鳴雞若何。"]'),
('37dc1060-91c7-4393-9f7c-a66770b85091','答孫直言都官卷','梅堯臣','宋','宋诗','song-poetry','','[]','具深相割啗，不如無勇人。',72,'全唐诗/poet.song.15000.json','["具深相割啗，不如無勇人。", "以詩而酬詩，徒用多少均。", "我言雖至簡，意切誰見親。", "汲井欲到深，磨鑑欲盡塵。", "寒泉與青銅，光潔靡故新。", "臨觴報嘉貺，醉語是天真。"]'),
('68392ba4-a10d-42b1-a31c-bc01d0d03315','依韻王司封寶臣答卷','梅堯臣','宋','宋诗','song-poetry','','[]','王家再見仲宣詩，魚目盈車換斗璣。',64,'全唐诗/poet.song.15000.json','["王家再見仲宣詩，魚目盈車換斗璣。", "自愧不從靈蚌吐，誰教相並夜蟾飛。", "暫增光價千金重，終覺枯陳一芥微。", "已屈至珍來彈雀，恩蛇銜報此能希。"]'),
('2d1f369c-a693-471c-b158-98a9d56d3e94','高士王君歸建業','梅堯臣','宋','宋诗','song-poetry','','[]','風雨起春寒，乘潮曉帆送。',48,'全唐诗/poet.song.15000.json','["風雨起春寒，乘潮曉帆送。", "目看瓜步雲，心近茅家洞。", "忽覺柳已青，來時枝尚凍。", "羨爾向江南，正開新釀甕。"]'),
('7825d3f9-dcf9-46a6-9996-5049fe77b692','呂寺丞家膳','梅堯臣','宋','宋诗','song-poetry','','[]','春雨薄無泥，野苗青入俎。',48,'全唐诗/poet.song.15000.json','["春雨薄無泥，野苗青入俎。", "深堂開畫圖，飛鳥驚寒渚。", "名筆今寂寥，嘉賓競推許。", "主人何太勤，不異具雞黍。"]'),
('536df327-4bbd-456c-b0b3-01f85d9c8466','趙秘校見訪','梅堯臣','宋','宋诗','song-poetry','','[]','文學儒家子，儒本通天人。',48,'全唐诗/poet.song.15000.json','["文學儒家子，儒本通天人。", "蠨蛸尚先喜，吾黨何迷津。", "津亭一相過，不笑復不嚬。", "應此識恬泊，曾匪慢爾賓。"]'),
('ce32fa8b-f92a-42c6-ab6d-6fb1ddbd0926','答張令卷','梅堯臣','宋','宋诗','song-poetry','','[]','嘗聞甥似舅，似舅詩尤少。',48,'全唐诗/poet.song.15000.json','["嘗聞甥似舅，似舅詩尤少。", "古意得河源，新聲變春鳥。", "讀之不敢倦，十未能一曉。", "顛倒文字間，使吾心擾擾。"]'),
('9b878f5f-e0d2-4a9b-9e61-a1a50736bf34','依韻答泰州王道粹學士見寄','梅堯臣','宋','宋诗','song-poetry','','[]','君同黄鵠游海嶠，我學白雲歸帝鄉。',64,'全唐诗/poet.song.15000.json','["君同黄鵠游海嶠，我學白雲歸帝鄉。", "已愛健翅自鼓舞，誰憐孤影猶飄揚。", "字得相從在霄漢，於今留滯嗟縶韁。", "欲隨輕風挹君袂，滿野春雨生迷茫。"]'),
('8349b40a-672d-4cfa-b2bc-697b02b38f4d','依韻和孫浦二都官展墓由大明精舍而歸  其一','梅堯臣','宋','宋诗','song-poetry','','[]','新松煙翠入衣巾，雨後岡原不起塵。',32,'全唐诗/poet.song.15000.json','["新松煙翠入衣巾，雨後岡原不起塵。", "霜露悲懷今正切，曾非結客去尋春。"]'),
('4d30a3f6-85a8-47bc-b1cb-550a24561830','依韻和孫浦二都官展墓由大明精舍而歸  其二','梅堯臣','宋','宋诗','song-poetry','','[]','拜壠忽生寒食心，應緣春入感啼禽。',64,'全唐诗/poet.song.15000.json','["拜壠忽生寒食心，應緣春入感啼禽。", "淚霑宿草根仍凍，馬立荒沙跡已深。", "野老輟耕風料峭，山房開晝日陰森。", "歸鞍却望原頭路，羃歷輕煙物景沉。"]'),
('b9ba256b-8559-4930-b8d3-6e35ca1ce1dc','張聖民席上聽張令彈琴','梅堯臣','宋','宋诗','song-poetry','','[]','一聽履霜霜滿足，再聽綠水聲緣谷。',96,'全唐诗/poet.song.15000.json','["一聽履霜霜滿足，再聽綠水聲緣谷。", "我行日月候春波，嫩苔沙雨侵魚目。", "漁歌晚唱泛水來，天浸滄浪光可掬。", "坐中此意自絃生，中郎五弄人難熟。", "人知難熟獨善彈，彈拍未終脂駕速。", "鄭衛古來多喜聞，卒章爲我歌淇奧。"]'),
('4b17f732-bcf4-4b97-a44e-5e1c45d6efc9','走筆送王琪','梅堯臣','宋','宋诗','song-poetry','','[]','江南二月草青青，送子歸時已滿汀。',32,'全唐诗/poet.song.15000.json','["江南二月草青青，送子歸時已滿汀。", "誰信而今有忠義，祇知七日哭秦庭。"]'),
('0869b4c7-ef1a-4cfb-9977-56404c7e5aa7','宣司理餉蒸鵝','梅堯臣','宋','宋诗','song-poetry','','[]','昔年相國籠之贈，今日參軍饟以蒸。',32,'全唐诗/poet.song.15000.json','["昔年相國籠之贈，今日參軍饟以蒸。", "一咀肥甘酬短句，定應無復謗言興。"]'),
('42416860-3919-4104-80d7-09af2c805385','依韻和許待制春雪','梅堯臣','宋','宋诗','song-poetry','','[]','密雪犯陽和，寒階覆短莎。',48,'全唐诗/poet.song.15000.json','["密雪犯陽和，寒階覆短莎。", "條牙摧不展，鳥舌噤應多。", "變令已爲失，易消如未苛。", "桃花禹門水，早晚見通波。"]'),
('0a405069-987c-40a3-ae66-c6e66c127fc4','送廣西提刑潘比部','梅堯臣','宋','宋诗','song-poetry','','[]','白麻新拜大丞相，黄紙首除南省郎。',64,'全唐诗/poet.song.15000.json','["白麻新拜大丞相，黄紙首除南省郎。", "欲使平刑安遠俗，莫辭乘傳歷炎荒。", "桂林地險通椎髻，陽朔峯奇削劍鋩。", "自有王門舊勳業，且須稀作上書囊。"]'),
('85ba0d3b-e657-426c-ad11-1eca2cb02195','大明寺平山堂','梅堯臣','宋','宋诗','song-poetry','','[]','陸羽烹茶處，爲堂備宴娛。',48,'全唐诗/poet.song.15000.json','["陸羽烹茶處，爲堂備宴娛。", "岡形來自蜀，山色去連吳。", "毫髮開明鏡，陰晴改畫圖。", "翰林能憶否，此景大梁無。"]'),
('3cca485f-2600-46cd-a8d6-82ceb7e6d953','依韻和王平甫見寄','梅堯臣','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','尊王興霸國，古莫重齊桓。',264,'全唐诗/poet.song.15000.json','["尊王興霸國，古莫重齊桓。", "仲尼書大法，亦莫重更端。", "文章革浮澆，近世無如韓。", "健筆走霹靂，龍蛇奮潛蟠。", "颺風何端倪，鼓蕩巨浸瀾。", "明珠及百怪，容畜知曠寬。", "其後漸衰微，餘襲猶未彈。", "我朝三四公，合力興憤歎。", "幸時構明堂，願爲櫨與欒。", "期琢宗廟器，願備次玉玕。", "謝公唱西都，予預歐尹觀。", "乃復元和盛，一變將爲難。", "行將三十載，衣被劇纖紈。", "後生喜成功，往往舞朱干。", "君家兄弟賢，挺拔尤堅完。", "譬彼登泰山，孰辨雲徑槃。", "忽在高高巔，兩腋猶插翰。", "我久知子名，曾未接子驩。", "前者和君詩，薄言慙兒肝。", "淮南喜子來，袖刺字未漫。", "明日聞渡江，留書特相安。", "今又獲嘉辭，至味非鹹酸。"]'),
('c555b2b4-9019-4fe9-bfcb-4a5d6626da30','許待制遺雙鱖魚因懷頃在西京於午橋石瀨中得此魚二尾是時以分餉留臺謝秘監遂作詩與留守推歐陽永叔酬和今感而成篇輒以錄上','梅堯臣','宋','宋诗','song-poetry','','[]','昔時三月在西洛，始得午橋雙鱖魚。',64,'全唐诗/poet.song.15000.json','["昔時三月在西洛，始得午橋雙鱖魚。", "墨蘚點衣鱗細細，紅盤鋪藻尾舒舒。", "麟臺老監分烹去，蓮幙佳賓唱和初。", "今日楊州使君贈，重思二十九年餘。"]'),
('d2296351-8f8c-4dd8-81f3-2d9285368236','依韻和丁元珍寄張聖民及序','梅堯臣','宋','宋诗','song-poetry','','[]','平生天下友，常以道義求。',288,'全唐诗/poet.song.15000.json','["平生天下友，常以道義求。", "良朋既我遘，沒齒無怨尤。", "向來六七輩，非可取次儔。", "議論吐肝膽，慷慨從竄投。", "上能同所樂，下能同所憂。", "出處乃一致，顔色無媚媮。", "詩書每博約，文酒時獻酬。", "其間最達者，今已問喘牛。", "我如溝中斷，不入刀斧鎪。", "未忍捨素業，筆墨老更遒。", "豈願學葛藟，柔弱附彼樛。", "但慕張平子，閑居吟四愁。", "譬若種香蘭，幸勿憂臭蕕。", "顧茲髮向衰，仕路行將休。", "自甘貧賤死，肯作兒女羞。", "夷齊何其清，尚餓不食周。", "末途逢元珍，果然知品流。", "當時守南方，非是寡筭籌。", "城空無一兵，有智欲誰諏。", "直令韓彭處，奚所施善謀。", "在法責固深，屈辱凡幾秋。", "無人一引手，落穽窮更幽。", "乃以詩戰我，摐摐排利矛。", "用多以擊少，左旋而右抽。"]'),
('ac4c308a-f04b-441c-a9e3-217544d3547a','依韻和齊少卿龍興寺鴨脚樹','梅堯臣','宋','宋诗','song-poetry','','[]','百戰蟠根地，雙陰浄梵居。',48,'全唐诗/poet.song.15000.json','["百戰蟠根地，雙陰浄梵居。", "凌雲枝已密，似蹼葉非疎。", "影落鄰僧院，風摇上客裾。", "何當避煩暑，萧洒蓋庭除。"]'),
('5d630fef-1396-42a2-8557-d66050b4d136','依韻和丁元珍見寄','梅堯臣','宋','宋诗','song-poetry','','[]','我從江南來，挂席江上正。',288,'全唐诗/poet.song.15000.json','["我從江南來，挂席江上正。", "輕舟自行速，不與風力競。", "乃省少時學，强勉無佳興。", "初如弄機杼，未解布絲經。", "利器昧其時，或反授人柄。", "及親賢豪游，所尚志已定。", "不厭朝市喧，不須山林靜。", "不爲煦煦妍，不爲嚴嚴冰。", "遇物理自暢，區處劇操令。", "仍類楚野竹，忽從孤根迸。", "便成翠琅玕，久與風霜硬。", "雖然達吾真，誰復究畢竟。", "世間忘坦途，盡欲求密徑。", "哂我是迂疎，宜乎今蹭蹬。", "蹭蹬誠可嗟，所偶亦已併。", "晚逢二三友，喜飲恨多病。", "道路何邅迴，季秋越春孟。", "平生景慕者，邂逅出天幸。", "接迹猶謂榮，況此聲顔並。", "實慙寡時用，又顧無奇行。", "愛之不忍去，自旦還至暝。", "在昔濁世賢，徒知清酒聖。", "但用醉爲娛，一老少不更。", "稍思桃源人，翩爾乘漁艇。"]'),
('560fc6cf-6921-4a04-93a9-0569e1066f1d','泰州王學士寄車螯蛤蜊','梅堯臣','宋','宋诗','song-poetry','','[]','車螯與月蛤，寄自海陵郡。',108,'全唐诗/poet.song.15000.json','["車螯與月蛤，寄自海陵郡。", "謂我抱餘醒，江都多美醖。", "老來飲不滿，一醉已關分。", "甘鮮雖所嗜，易飫亦莫問。", "嬌女巧收殻，燕脂合眉暈。", "貧奩無金玉，狼藉生恚忿。", "妻孥喜食之，婢妾困掃𢬵。", "行當至京華，耳目飽塵坌。", "此味爽口難，書爲厭者訓。"]'),
('8869a7f3-0ce5-42ec-8ac4-38b5998eb1ae','張聖民席上賦紅梅','梅堯臣','宋','宋诗','song-poetry','','[]','吾家有嘉樹，紅蕊開朝霧。',48,'全唐诗/poet.song.15000.json','["吾家有嘉樹，紅蕊開朝霧。", "笑杏少清香，鄙梅多俗趣。", "江都別乘居，似見句溪圃。", "坐中勿苦疑，結子看春暮。"]'),
('5e1ff081-993e-4de2-a948-65201fc493e4','平山堂雜言','梅堯臣','宋','宋诗','song-poetry','','[]','蕪城之北大明寺，闢堂高爽趣廣而意厖。',128,'全唐诗/poet.song.15000.json','["蕪城之北大明寺，闢堂高爽趣廣而意厖。", "歐陽公經始曰平山，山之迤邐蒼翠隔大江。", "天清日明了了見峯嶺，已勝謝朓齪齪遠視於一窗。", "亦笑煬帝造樓摘星放螢火，錦帆落檣旗建杠。", "我今乃來偶同二三友，得句欲霜鍾撞。", "却思公之文字世莫雙，舉酒一使長咽慢肌高揭鼓笛腔，萬古有作心胸降。"]'),
('92a6b22f-bef6-4125-bf97-bbbcdcee9c16','自感  其一','梅堯臣','宋','宋诗','song-poetry','','[]','左目忽昏花，愁心亂劇麻。',48,'全唐诗/poet.song.15000.json','["左目忽昏花，愁心亂劇麻。", "文書都莫見，藥物近憑他。", "眸子終何似，形軀且願嘉。", "唯期一開泰，再望日中鴉。"]'),
('32c23ef2-cae3-42a6-9014-e0b9fb8cfe51','自感  其二','梅堯臣','宋','宋诗','song-poetry','','[]','我不嫌髭白，白髭何自落。',48,'全唐诗/poet.song.15000.json','["我不嫌髭白，白髭何自落。", "雖然失醜衰，將恐日疎薄。", "有生無不老，歲事看秋籜。", "一身憂已大，毫髮誰能度。"]'),
('6e0ba2bb-c58f-422a-ba42-47ef8b1e7399','依韻和孫都官河上寫望','梅堯臣','宋','宋诗','song-poetry','','[]','河上風煙愛此邦，吳艘越舸不相降。',64,'全唐诗/poet.song.15000.json','["河上風煙愛此邦，吳艘越舸不相降。", "魚腥矗矗橋邊市，花暗深深竹裏窗。", "蹴踘漸知寒食近，鞦韆將立小鬟雙。", "年光取次須偷賞，何用功名節與幢。"]'),
('62df93e8-e083-43eb-abb4-da4aedcb8efe','依韻和試筆偶書','梅堯臣','宋','宋诗','song-poetry','','[]','洗硯開書几，拈毫喜子巢。',48,'全唐诗/poet.song.15000.json','["洗硯開書几，拈毫喜子巢。", "不爲微物撓，自向小欄敲。", "已逐游絲末，還緣翠葉梢。", "因知生理大，不必在重爻。"]'),
('c869ea82-a963-48be-8eb5-7091e31e13f7','和張民朝謁建隆寺二次用寫望試筆韻  其一','梅堯臣','宋','宋诗','song-poetry','','[]','荒臺殘壘舊名邦，曾說王師此受降。',64,'全唐诗/poet.song.15000.json','["荒臺殘壘舊名邦，曾說王師此受降。", "西漢衣冠拜原廟，五天龍象護經窗。", "蜀岡井味人猶品，隋帝宮基闕尚雙。", "自古興亡不須問，風鈴閑聽響幡幢。"]'),
('d6a7a88a-38e6-4895-820e-66f5cf84b8b9','和張民朝謁建隆寺二次用寫望試筆韻  其二','梅堯臣','宋','宋诗','song-poetry','','[]','躍馬侵星去，啼鴉未出巢。',48,'全唐诗/poet.song.15000.json','["躍馬侵星去，啼鴉未出巢。", "春裘風易裂，從騎鐙相敲。", "紅日雙行柳，黄金一抹梢。", "乾坤功力大，默誦易中爻。"]'),
('6e3c0bbf-691f-403e-8998-c05b2eb62284','依韻和許待制後園宴賓','梅堯臣','宋','宋诗','song-poetry','','[]','春來無處不幽芳，誰復樽前歎異鄉。',64,'全唐诗/poet.song.15000.json','["春來無處不幽芳，誰復樽前歎異鄉。", "繞榻綺羅觀舊豔，傍池桃杏照新粧。", "柳條拂拂牽絲嫩，蕊粉輕輕落酒香。", "聞道主公偏愛客，翻思當日醉莎場。"]'),
('7f76eeb1-7a38-48fe-9ed8-ad963813d470','依韻和許待制偶書','梅堯臣','宋','宋诗','song-poetry','','[]','曉雨射船珠瀉盤，平明水上舞英殘。',64,'全唐诗/poet.song.15000.json','["曉雨射船珠瀉盤，平明水上舞英殘。", "鬭雞蹠惡輕泥溼，調馬蹄翻軟土乾。", "深屋燕巢將欲補，密房蠶蟻尚憂寒。", "爲言楚客甘蔬蔌，白芷香牙長嫩珊。"]'),
('954810e8-6c82-4552-a8d4-3e48eab0971a','閨思','梅堯臣','宋','宋诗','song-poetry','','[]','望日赤如橘，游梁音信稀。',48,'全唐诗/poet.song.15000.json','["望日赤如橘，游梁音信稀。", "愁心常似醉，春絮等閑飛。", "江鮆看將爛，芹牙吐尚微。", "何時憑燕子，寄取錦書歸。"]'),
('1d66512f-3a85-40cf-a416-91c6c2dc4931','代書寄王道粹學士','梅堯臣','宋','宋诗','song-poetry','','[]','已具扁舟訪使君，忽逢春雨起淮濆。',64,'全唐诗/poet.song.15000.json','["已具扁舟訪使君，忽逢春雨起淮濆。", "花寒蛺蝶猶相守，水冷鴛鴦不暫分。", "況約他時來寄蹟，何須今日去論文。", "解裝無復山陰興，且對荆釵與布裙。"]'),
('4384a480-0b79-44a1-a08e-88ef0e0a4e86','依韻和許待制病起偶書','梅堯臣','宋','宋诗','song-poetry','','[]','桐柳陰陰翠色參，幔房深邃靜於巖。',160,'全唐诗/poet.song.15000.json','["桐柳陰陰翠色參，幔房深邃靜於巖。", "疾疑不是因蛇影，方秘曾傳白玉函。", "煉蜜有時蜂競至，墜羶無數蟻來銜。", "女奚困觸屏風響，林鳥饑尋蠹木鵮。", "趨吏喜聞開便閤，舞姬排比翦春衫。", "嘉賓入幙金樽抹，賀客衝風席帽攙。", "談出古人非騁辯，詩陳王化不言讒。", "提綱勿用銖銖較，列局緣從物物監。", "龍腦篆香蟠屈曲，虎頭彫枕剔空嵌。", "年踰五十惟躭易，能格神明莫若諴。"]'),
('8cb59623-79dd-4a9b-922a-de0afd0e6476','依韻和新栽竹','梅堯臣','宋','宋诗','song-poetry','','[]','劚破煙叢带筍移，映軒臨檻特爲宜。',64,'全唐诗/poet.song.15000.json','["劚破煙叢带筍移，映軒臨檻特爲宜。", "龍孫已見多奇節，鳳實新生入翠枝。", "不向阮家林下集，還思渭北水邊窺。", "一花一草公休詠，慣作蘭臺侍從詩。"]'),
('bdc7bfb1-be21-4617-85f2-b26bb537ae8a','依韻和戲題','梅堯臣','宋','宋诗','song-poetry','','[]','楊州太守重交情，我欲西歸未得行。',32,'全唐诗/poet.song.15000.json','["楊州太守重交情，我欲西歸未得行。", "寒食尚賒花水近，妻孥煎去到天明。"]'),
('492e5d29-9199-4092-91ef-ae13a0a647e9','依韻和春日偶書','梅堯臣','宋','宋诗','song-poetry','','[]','甕面春醅壓嫩藍，盤中鵝{炙火=肉}亦肥甘。',165,'全唐诗/poet.song.15000.json','["甕面春醅壓嫩藍，盤中鵝{炙火=肉}亦肥甘。", "正宜醉夢輕爲蝶，苦怕酬詩密似蠶。", "病起羊公方隠几，歸來陶令只乘籃。", "河堤古木欣欣暗，野水新秧拍拍渰。", "已向官資隨分足，莫將忠憤等閑談。", "況於世上諸般厭，不作人間一例貪。", "陋巷自知當退縮，擁門誰解更趨參。", "高低趣向難爲合，冷暖情懷固飽諳。", "勉意妻兒猶苟祿，强顔冠冕未抽簪。", "唯公恩遇留連久，頻對樽罍也負慙。"]'),
('35d76d8e-1156-43a3-a0f4-dc7c4d2e710d','依韻和禁煙近事之什','梅堯臣','宋','宋诗','song-poetry','','[]','狂風暴雨已頻過，近水棠梨著未多。',128,'全唐诗/poet.song.15000.json','["狂風暴雨已頻過，近水棠梨著未多。", "窈窕踏歌相把袂，輕浮賭勝各飛堶。", "閑牽白日游絲颺，細驀黄金舞带拖。", "小苑芳菲花鬭蕊，華堂嘲哳燕爭窠。", "西州駿馬頭如剝，南國佳人頸似瑳。", "結客追隨傾畫榼，分朋游樂藉青莎。", "鞦韆競打遺鈿翠，芍藥將開翦纈羅。", "我病乞求新火炙，無心更聽竹枝歌。"]'),
('a109dd22-6bd2-4fe1-9c72-ca7c02f7c08f','依韻和寒食偶書','梅堯臣','宋','宋诗','song-poetry','','[]','去歲逢今日，雨寒田舍家。',72,'全唐诗/poet.song.15000.json','["去歲逢今日，雨寒田舍家。", "繫驄烏臼樹，燒眼杜鵑花。", "轉塢泥塍滑，迷村草徑叉。", "旋挑初出筍，漫掐自生茶。", "農斧穿桑齾，牛童綰髻丫。", "鄉園方在遠，看及種胡麻。"]'),
('822587cf-39e2-44b0-9148-8fa68461ced6','依韻和春日見示','梅堯臣','宋','宋诗','song-poetry','','[]','春雨懶從年少狂，一生憔悴爲詩忙。',96,'全唐诗/poet.song.15000.json','["春雨懶從年少狂，一生憔悴爲詩忙。", "不能屑屑隨時輩，亦恥區區憶故鄉。", "白玉笛聲親府席，六幺花拍動衣香。", "龍咽嘹喨留行月，鳳翼趨蹌巧定場。", "粉色酒容歡四座，花光燭影照西牆。", "虛榮浪貴知多少，安得如君展肺腸。"]'),
('ce164c8a-c89c-45b1-b704-bacdb94aef8f','依韻和偶書相留','梅堯臣','宋','宋诗','song-poetry','','[]','在昔有言無不讎，故於嘉詠豈宜休。',96,'全唐诗/poet.song.15000.json','["在昔有言無不讎，故於嘉詠豈宜休。", "出奇吳國將能戰，探隠漢宮人戲鬮。", "吹笛夢來猶記曲，愛歌老去未忘謳。", "車中變服爲秦客，頭上南冠學楚囚。", "日永歡呼遺博齒，夜深談論廢更籌。", "海陵已有從游約，今欲西歸且榜舟。"]'),
('313eccff-ac59-417e-b693-a5f962f811d2','依韻和三月十四日清明在席呈','梅堯臣','宋','宋诗','song-poetry','','[]','太守風流甚，吟牋寫蜀麻。',48,'全唐诗/poet.song.15000.json','["太守風流甚，吟牋寫蜀麻。", "尋春何處客，映柳阿誰家。", "蠟炬傳新火，朱欄發舊花。", "月光將欲滿，特地炤鉛華。"]'),
('e262e2f8-1141-41fb-9402-28bf78ec40e0','讀邵不疑學士詩卷杜挺之忽來因出示之且伏高致輒書一時之語以奉呈','梅堯臣','宋','宋诗','song-poetry','','[]','作詩無古今，唯造平淡難。',96,'全唐诗/poet.song.15000.json','["作詩無古今，唯造平淡難。", "譬身有兩目，瞭然瞻視端。", "邵南有遺風，源流應未殫。", "所得六十章，小大珠落槃。", "光彩若明月，射我枕席寒。", "含香視草郎，下馬一借觀。", "既觀坐長歎，復想李杜韓。", "願執戈與戟，生死事將壇。"]'),
('f161a262-3d48-42cd-aebb-87db8ed8af38','送寧鄉令張沆','梅堯臣','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','長沙過洞庭，水泊風摇矴。',48,'全唐诗/poet.song.15000.json','["長沙過洞庭，水泊風摇矴。", "青山接夷蠻，白晝鳴鴞鸋。", "竹存帝女啼，夔學林雍鑋。", "不嫌卑濕往，教令民須聽。"]'),
('655c2309-bcea-43c6-a11a-054500f86042','依許待制送行詩韻詠燕以寄','梅堯臣','宋','宋诗','song-poetry','','[]','江燕銜泥日，深堂拂玉琴。',48,'全唐诗/poet.song.15000.json','["江燕銜泥日，深堂拂玉琴。", "不教關閤戶，乃見主人心。", "掠水飛殊捷，迎風去已禁。", "短書猶可記，聊影託微吟。"]'),
('5d0cf6ac-059c-4f3f-bcd5-b505075bbb60','依韻和酬邵不疑見答','梅堯臣','宋','宋诗','song-poetry','','[]','君才若巨賈，既富仍深藏。',120,'全唐诗/poet.song.15000.json','["君才若巨賈，既富仍深藏。", "遂兼碌碌貧，共處安可量。", "滔滔大澤陂，渺漫入幽荒。", "徒欲窮端倪，憑高何相望。", "一日以文繡，被此糞土牆。", "門徒三千人，起予唯卜商。", "薄言昧纖悉，懷憂思萱忘。", "美璞委彫琢，以未知我詳。", "但念故時朋，所樂來遠方。", "慎勿以名使，取敗非相當。"]'),
('46fff69d-8e00-42ac-ab1d-32349e033549','贈張伯益','梅堯臣','宋','宋诗','song-poetry','','[]','張伯益，風義自足常遊遨，醉彈琵琶聲嘈嘈。',84,'全唐诗/poet.song.15000.json','["張伯益，風義自足常遊遨，醉彈琵琶聲嘈嘈。", "雷車急輥蛟龍號，曲終放撥解紫絛。", "勇氣索筆作小篆，李斯復出秦碑高。", "不數宣王石鼓文，快健欲敵橫磨刀。", "弈棋絲桐且置之，衆善多取精神勞。"]'),
('00274bb6-9e0b-4062-b96e-f3735510c053','依韻和邵不疑以雨止烹茶觀畫聽琴之會','梅堯臣','宋','宋诗','song-poetry','','[]','彈琴閱古畫，煑茗仍有期。',96,'全唐诗/poet.song.15000.json','["彈琴閱古畫，煑茗仍有期。", "一夕風雨來，且喜農畝滋。", "中河不阻澀，舟楫亦所宜。", "況聞新疾愈，當與嗜好睽。", "何須顧小約，豈不是他時。", "淡泊全精神，老氏吾將師。", "幸因答來章，敢不以此咨。", "此咨有深理，願君勤且思。"]'),
('ce9b9ec2-0aa7-4564-9180-f954e0e224ff','依韻和不疑寄杜挺之以病雨止冷淘會','梅堯臣','宋','宋诗','song-poetry','','[]','邵杜二良守，相逢欲霑醉。',120,'全唐诗/poet.song.15000.json','["邵杜二良守，相逢欲霑醉。", "促膝一開顔，衮衮言有味。", "或歎季路宜，或語伯夷是。", "各懷忠義心，要終豈同異。", "我實疎賤軀，政治未使試。", "預茲高古談，懦志生勇氣。", "明當饌湯餠，疾雨晦天地。", "一日不見君，何止如三歲。", "口腹尚乖期，榮華可推類。", "嗟嗟勿復問，安恬固無媿。"]'),
('996b2f97-8a7f-4853-bf6f-25d88629a565','獨酌偶作','梅堯臣','宋','宋诗','song-poetry','','[]','東路歸梁懶，黄流下汴深。',48,'全唐诗/poet.song.15000.json','["東路歸梁懶，黄流下汴深。", "眼穿南去翼，耳冷北來音。", "風雨昏斜日，乾坤入醉吟。", "不憂貧且老，自有伯鸞心。"]'),
('5c13edb2-6e87-4869-8cbf-dfa6455a6284','答杜挺之遺鰍魚乾','梅堯臣','宋','宋诗','song-poetry','','[]','百年蠹柳根半浮，揭屋顛風吹欲倒。',32,'全唐诗/poet.song.15000.json','["百年蠹柳根半浮，揭屋顛風吹欲倒。", "寸步泥深登岸難，鰍乾助飲鄰船老。"]'),
('c0533f50-0d21-4a00-a750-fee90e91f569','觀邵不疑學士所藏名書古畫','梅堯臣','宋','宋诗','song-poetry','','[]','野性好書畫，無力能自致。',240,'全唐诗/poet.song.15000.json','["野性好書畫，無力能自致。", "每遇高趣人，常許出以視。", "邵侯多奇玩，留我特開笥。", "首觀阮與杜，馿上瞑目醉。", "韓幹貌四馬，臨流解鞍轡。", "花驄照夜白，正側各畜意。", "繫衣穿褲靴，坐立皆廐吏。", "精神宛如生，于腮復穿鼻。", "梅雞徐熙畫，竹間寒雀睡。", "逸少自寫真，對鏡絕相類。", "數本失姓名，古胡并老驥。", "山水樹石硬，荆關藝能至。", "巨然李成者，落筆愈奇異。", "人物張僧繇，雖傳恐非是。", "其餘又莫究，模搭似未備。", "周秦已來書，行草楷篆隸。", "聲名舊烜赫，一一果可喜。", "邵侯愛我曹，咸使紙尾記。", "況侯有古學，小字刻珉翠。", "各贈墨本歸，懷寶誰肯忌。"]'),
('e01c7a3d-40e3-42d7-8bfe-4a0e738af785','先至山陽懷杜挺之','梅堯臣','宋','宋诗','song-poetry','','[]','與君同川途，舟發偶後先。',60,'全唐诗/poet.song.15000.json','["與君同川途，舟發偶後先。", "順風吹我帆，已過飛鳥前。", "寄聲託飛鳥，微意或可傳。", "定逢檣上烏，暫向彼留連。", "薄暮楚城下，踟躕問來船。"]'),
('b0aa3552-9fc4-4bfd-a286-cb178863c376','絕句五首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','風過巳午未肯止，酒病嬰我心無憀。',32,'全唐诗/poet.song.15000.json','["風過巳午未肯止，酒病嬰我心無憀。", "船頭拍翅野鴨浴，水上擺子獰魚跳。"]'),
('58d6595b-f14d-4006-b896-019d7d9dbbe1','絕句五首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','岸邊稚子戲把釣，蚯蚓作餌青條長。',32,'全唐诗/poet.song.15000.json','["岸邊稚子戲把釣，蚯蚓作餌青條長。", "上去下來船不定，自飛自語燕爭忙。"]'),
('c340f4f5-5374-4e10-b339-667c4c518993','絕句五首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','夜欲三更饑鼠鬭，燈殘一點小星紅。',32,'全唐诗/poet.song.15000.json','["夜欲三更饑鼠鬭，燈殘一點小星紅。", "村邊坎坎賽神鼓，船底怦怦駕浪風。"]'),
('f68a4c72-3c8b-4370-932f-e32c78a88b31','絕句五首  其四','梅堯臣','宋','宋诗','song-poetry','','[]','葑田青仄博弈局，島樹墨榅煙雨圖。',32,'全唐诗/poet.song.15000.json','["葑田青仄博弈局，島樹墨榅煙雨圖。", "已去楊州百餘里，迴頭還隔幾重湖。"]'),
('379c2952-12e4-4cf8-a3c1-7566277d2345','絕句五首  其五','梅堯臣','宋','宋诗','song-poetry','','[]','蝦蟆嚎沫爲科斗，蜾臝銜蟲化細腰。',32,'全唐诗/poet.song.15000.json','["蝦蟆嚎沫爲科斗，蜾臝銜蟲化細腰。", "蠹穴荒陂有多少，乾風濕雨各飛跳。"]'),
('ca5826c5-dace-4809-98ae-8300caaf4436','淮南轉運李學士君錫示卷','梅堯臣','宋','宋诗','song-poetry','','[]','李氏世能詩，落落爲時豪。',96,'全唐诗/poet.song.15000.json','["李氏世能詩，落落爲時豪。", "漢陵唐太白，始競二雅高。", "益端正封賀，才各傾吳濤。", "於今幾代孫，手持切玉刀。", "功利既及民，又將薄風騷。", "示我照乘珠，光彩生褐袍。", "曾非貧家有，懷歸徒增勞。", "神物必難秘，恐隨風雨逃。"]'),
('d9b0079f-51ab-48bc-a19a-2abbecc4a8a1','觀王氏書','梅堯臣','宋','宋诗','song-poetry','','[]','先觀雍姬舞六幺，妍葩發豔春風摇。',96,'全唐诗/poet.song.15000.json','["先觀雍姬舞六幺，妍葩發豔春風摇。", "舞罷英英書大字，玉指握管濃雲飄。", "風馳雨驟起變怪，文鰩晝飛明珠跳。", "席客聚立驚且歎，筆何勁健人柔夭。", "昔時裴旻能劍舞，丹青助氣精神超。", "藝雖不同意有會，世事相假非一朝。"]'),
('96ed64c2-276c-41e0-bde1-5b0a91490f35','書二客論呈李君錫學士','梅堯臣','宋','宋诗','song-poetry','','[]','我慕杜挺之，磊落高世談。',96,'全唐诗/poet.song.15000.json','["我慕杜挺之，磊落高世談。", "又愛王平甫，才雄天馬驂。", "二人相議評，最重李淮南。", "踒𧿶文館彥，委曲部政諳。", "能蘇煑海民，變使供租甘。", "雖持使者權，不作自裹蠶。", "諄諄無威慠，雍雍激廉貪。", "書戒易滿人，縱愚須起慙。"]'),
('62172764-c7bd-49ee-9b4a-0b9c4fae3f22','留別李君錫學士','梅堯臣','宋','宋诗','song-poetry','','[]','淮南尚喜風流在，客有殷勤載酒過。',64,'全唐诗/poet.song.15000.json','["淮南尚喜風流在，客有殷勤載酒過。", "不醉不歸情可見，相看相笑意如何。", "瞭眸自解持高論，長頸稀逢缺善歌。", "舊愛陽關亦休唱，西還從此故人多。"]'),
('2df62013-810b-4ba5-8cdd-837a53b0837d','過山陽水陸院智洪上人房','梅堯臣','宋','宋诗','song-poetry','','[]','十載七來此，每嗟多異今。',48,'全唐诗/poet.song.15000.json','["十載七來此，每嗟多異今。", "池灰休辨劫，川月解明心。", "遺墨悲蘇倩，高情想遁林。", "能閑常似舊，翹立水邊禽。"]'),
('1969c331-f138-47e2-a9f9-257c4b4c1c65','淮陰侯','梅堯臣','宋','宋诗','song-poetry','','[]','功既高天下，身何不自防。',48,'全唐诗/poet.song.15000.json','["功既高天下，身何不自防。", "已能成漢業，無復假齊王。", "復恥噲爲伍，安知呂所忘。", "空名流未竭，淮水共湯湯。"]'),
('b3200a9f-cd45-404a-837c-c5b7ca41fc32','閏三月八日淮上遇風杜挺之先至洪澤遣人來迎','梅堯臣','宋','宋诗','song-poetry','','[]','曉出淮口時，夜來風已止。',60,'全唐诗/poet.song.15000.json','["曉出淮口時，夜來風已止。", "半路逢怒號，客心愁欲死。", "忠信雖可仗，魚鼈將異此。", "但慕前行舟，漸入孤汊裏。", "猶能有餘力，遣助良可喜。"]'),
('466432ed-244a-4816-9759-a0ac1feb2b2c','宿洪澤','梅堯臣','宋','宋诗','song-poetry','','[]','舟子起添纜，夜潮同雨來。',48,'全唐诗/poet.song.15000.json','["舟子起添纜，夜潮同雨來。", "寒聲相亂急，遠夢自然迴。", "水鳥鳴還睡，風燈暗復開。", "宦游常作客，未息爲貧催。"]'),
('d46beff0-42dc-4ca7-81ba-aece969d2beb','泗州郡圃四照堂','梅堯臣','宋','宋诗','song-poetry','','[]','官艫客艑滿淮汴，車馳馬驟無閑時。',144,'全唐诗/poet.song.15000.json','["官艫客艑滿淮汴，車馳馬驟無閑時。", "豈有餘力事棟宇，後園荒草長離離。", "朱侯下車百職舉，亦治宴豆頻遊嬉。", "梁冠爵弁各得禮，道路溢譽亡高卑。", "因隙作堂名四照，虛光轉納娥與羲。", "面面懸窗夾花藥，春英秋蕊冬竹枝。", "射堋寬闊習武事，鏡沼清淺吹文漪。", "侯之此意寧自樂，夷情勞士俱忘疲。", "後來出口勤洒掃，莫作廐埒生蒿藜。"]'),
('636eb610-7ad1-4f87-a47f-f00d1d61137f','泗守朱表臣都官剏北園','梅堯臣','宋','宋诗','song-poetry','','[]','樹藝北壕上，直對高城陰。',84,'全唐诗/poet.song.15000.json','["樹藝北壕上，直對高城陰。", "使君朱輪來，歌管樽酒深。", "風雷生淮雨，雲物冒楚岑。", "戰舠習追逐，飛凌捷水禽。", "不獨耳目觀，乃見預禦心。", "事閑賓從樂，景美臺榭臨。", "令人忘羈旅，灑慮起微吟。"]'),
('bc7ec8c0-703c-4253-9769-c2b4c3bcbee9','依韻和誠之淮上相遇','梅堯臣','宋','宋诗','song-poetry','','[]','一別逋翁久不逢，亦知諸葛卧龍中。',64,'全唐诗/poet.song.15000.json','["一別逋翁久不逢，亦知諸葛卧龍中。", "幾年三致千金富，今日重追二謝風。", "形槁已能同散木，鬢霜從聽著寒蓬。", "飛光入酒舊時月，來炤狂歌猶未窮。"]'),
('51707166-f249-474d-b8e3-f3356eab87ed','泗州觀唐氏書','梅堯臣','宋','宋诗','song-poetry','','[]','唐氏能書十載聞，誰教精絕向紅裙。',32,'全唐诗/poet.song.15000.json','["唐氏能書十載聞，誰教精絕向紅裙。", "百金買書蒲葵扇，不必更求王右軍。"]'),
('751f4e6f-8345-4588-b8be-7f68d9e446ed','同朱表臣及諸君游樊氏園','梅堯臣','宋','宋诗','song-poetry','','[]','五年前上去，乃從許公過。',48,'全唐诗/poet.song.15000.json','["五年前上去，乃從許公過。", "舊物此君在，後生新筍多。", "朱櫻繁且熟，黄鳥啄仍歌。", "一一如當日，乘高奈興何。"]'),
('dc37c4b6-f2cb-4c21-b65c-3c2a140416ec','七里灣得朱表臣寄千葉樓子髻子芍藥','梅堯臣','宋','宋诗','song-poetry','','[]','誰稱爲近侍，宜與牡丹尊。',48,'全唐诗/poet.song.15000.json','["誰稱爲近侍，宜與牡丹尊。", "霞綷千千葉，香撩黯黯魂。", "紅樓思俠少，寶髻奉王孫。", "賸插不堪照，顔衰汴水渾。"]'),
('106a0236-7d18-47f8-80f3-b43e6fdf4870','併日得朱表臣酪及櫻桃','梅堯臣','宋','宋诗','song-poetry','','[]','昨日酪將熟，今朝櫻可餐。',48,'全唐诗/poet.song.15000.json','["昨日酪將熟，今朝櫻可餐。", "紫蒓休定價，黄鳥未銜殘。", "甘滑已相美，齒牙仍尚完。", "應知消客熱，遠贈盎盈盤。"]'),
('df47b75b-5f2a-4c04-96ac-563b89afabe5','阻淺挺之平甫來飲','梅堯臣','宋','宋诗','song-poetry','','[]','泛淮忌水大，我行浩以漫。',120,'全唐诗/poet.song.15000.json','["泛淮忌水大，我行浩以漫。", "泝汴忌水淺，我行幾以乾。", "偶與困滯并，將獨爲此難。", "窮堤有來客，芬芳可與言。", "共休綠榆陰，置酒聊慰安。", "主人雖倉卒，猶得具甘酸。", "酸漬楚梅青，甘摘夏櫻丹。", "引觴吞日光，耳熱不復歎。", "俛仰已陳迹，未可忘茲歡。", "誰思費生術，幻惑寧盤桓。"]'),
('795e7516-597f-44fd-89fc-77fca9a1533b','依韻和表臣奎野亭','梅堯臣','宋','宋诗','song-poetry','','[]','淮光抱城去，山翠落樽前。',48,'全唐诗/poet.song.15000.json','["淮光抱城去，山翠落樽前。", "魯叟欲浮海，楚人休問天。", "野雲將拂幔，水鳥不驚船。", "歷覽誰能賦，今聞太守賢。"]'),
('a4cb307d-da06-4166-ada0-fd9216c21395','依韻和表臣先春亭','梅堯臣','宋','宋诗','song-poetry','','[]','雜花紅間白，遠樹短參長。',48,'全唐诗/poet.song.15000.json','["雜花紅間白，遠樹短參長。", "天近春歸疾，城高地易凉。", "千尋浮遠水，五兩動連檣。", "置酒未終樂，山煙生暝隍。"]'),
('708148cd-68cc-4a96-a471-0ccefe8e38d1','和表臣河南庾署西軒','梅堯臣','宋','宋诗','song-poetry','','[]','飛烏欲下蟾生時，斜光冷魄常相隨。',64,'全唐诗/poet.song.15000.json','["飛烏欲下蟾生時，斜光冷魄常相隨。", "右山左水清洗目，虛簷曲檻生揚眉。", "白魚甘肥網可得，公酒美滑杯可持。", "臨淮使君有閑佚，長橋直度來莫遲。"]'),
('3b74fef8-2d93-4e61-a98e-04d83f935031','依韻和表臣見贈','梅堯臣','宋','宋诗','song-poetry','','[]','中間會與別，不啻二十年。',168,'全唐诗/poet.song.15000.json','["中間會與別，不啻二十年。", "向來君之官，我必贈以篇。", "今過臨淮郡，惠好情聯聯。", "訪我車騎都，宴我鶑花然。", "此當舟航衝，旅泊逾百千。", "迓高而撫下，酒壺柜食連。", "使予一日爲，立可見華顛。", "遽行恐勞君，數里不得前。", "三月汴水淺，蹇滯無我先。", "君乃遺我詩，盛稱我爲賢。", "比之少陵豪，望我何太全。", "又令入時用，目堪事高眠。", "安能事孔聖，終學美周宣。", "勤答以明懷，矢辭敢欺天。"]'),
('1796e41b-df86-4bf1-842a-4aa38b5df0d2','依韻和表臣聞與挺之宣叔平甫飲','梅堯臣','宋','宋诗','song-poetry','','[]','舟淺不能進，反羨車馬馳。',48,'全唐诗/poet.song.15000.json','["舟淺不能進，反羨車馬馳。", "同行各在野，有酒相與期。", "堤上聞禽處，桑間落日時。", "使君羊筍贈，更飲更追隨。"]'),
('6fcf9672-820e-4de8-bc00-69d99b7b4576','表臣惠蜀箋偕玉硯池','梅堯臣','宋','宋诗','song-poetry','','[]','蜀箋珉硯池，爲贈知雅故。',48,'全唐诗/poet.song.15000.json','["蜀箋珉硯池，爲贈知雅故。", "慙無左軍書，亦乏左思賦。", "環水象辟雍，紋花如織素。", "願傳君德政，況已聞行路。"]'),
('1cd3c4d7-a340-4f3d-b8f7-bb463186e49a','表臣以阻水見勉次其韻','梅堯臣','宋','宋诗','song-poetry','','[]','野叟津難問，賢人酒不空。',48,'全唐诗/poet.song.15000.json','["野叟津難問，賢人酒不空。", "行吟同去國，退翼欲乘風。", "憂已先天下，窮方坐井中。", "予生一如此，安得免衰翁。"]'),
('4cd8c303-1529-4cab-b51a-b5bb01314d42','聞宣叔挺之圍棊','梅堯臣','宋','宋诗','song-poetry','','[]','人以棊銷日，我觀棊輒寐。',48,'全唐诗/poet.song.15000.json','["人以棊銷日，我觀棊輒寐。", "未必盡死生，何茲較愚智。", "只將多勝少，復取先爲利。", "不若酒之賢，悠然共醒醉。"]'),
('f2e5205f-0c38-416f-8840-0c290d3f5fb8','五倩篇','梅堯臣','宋','宋诗','song-poetry','','[]','倩然五蛾眉，妙曲動金絃。',72,'全唐诗/poet.song.15000.json','["倩然五蛾眉，妙曲動金絃。", "犀椎玉鈴鈴，龍撥雷𨋮𨋮。", "響急能愈靜，意閑情常專。", "主人昔結客，一醉百金捐。", "觀濤來吳都，遇我泗水邊。", "夜飲向明月，非同聞鄰船。"]'),
('25880bdd-772f-4169-8b1d-db8f42e217c5','釋悶','梅堯臣','宋','宋诗','song-poetry','','[]','燕丹未歸馬未角，卞子抱玉無兩脚。',48,'全唐诗/poet.song.15000.json','["燕丹未歸馬未角，卞子抱玉無兩脚。", "孤城食盡兵未却，度笮中懷挂一索。", "我輩於此酒宜酌，百歲千秋奈何樂。"]'),
('5409e31a-c529-4a93-b348-59308a6c3552','釋滯','梅堯臣','宋','宋诗','song-poetry','','[]','帝在蒼梧妃泣竹，蘇武餐毛海西曲。',48,'全唐诗/poet.song.15000.json','["帝在蒼梧妃泣竹，蘇武餐毛海西曲。", "窮山遠道車折軸，深井渴汲綆不續。", "我輩於此酒正綠，貴無奈何歡且足。"]'),
('37fd957a-b6bd-4b3e-97f8-eda04068756c','依韻和表臣憶遊竹園山寺','梅堯臣','宋','宋诗','song-poetry','','[]','山携謝公妓，竹似阮家林。',48,'全唐诗/poet.song.15000.json','["山携謝公妓，竹似阮家林。", "花發日初暖，鳥啼春欲深。", "朱櫻連葉摘，綠酒带醅斟。", "猶想聞歌吹，僧房未暇吟。"]'),
('fb75ef0a-9166-4802-9d8d-72c9ebc3da59','依韻和挺之晨起見寄','梅堯臣','宋','宋诗','song-poetry','','[]','淺水不堪泛，暗灘時激聲。',48,'全唐诗/poet.song.15000.json','["淺水不堪泛，暗灘時激聲。", "晨都望迢遞，窮旅思屏營。", "芳草同誰藉，投壺自喚名。", "得君晨起詠，遠遠見交情。"]'),
('1bcbcef7-4643-4328-82eb-3b7724b771f4','李宣叔秘丞遺川牋及粉紙二軸','梅堯臣','宋','宋诗','song-poetry','','[]','蜀人擣玉屑，楚客調金粉。',48,'全唐诗/poet.song.15000.json','["蜀人擣玉屑，楚客調金粉。", "製牋君有贈，草疏我無藴。", "宜書楊雄辭，莫寫屈原憤。", "誰識此意微，曾非事摇吻。"]'),
('7b7f090c-3491-4ce7-9ae3-ee28dbe0b979','錢志道推官遺紗帽','梅堯臣','宋','宋诗','song-poetry','','[]','遠贈烏紗帽，能無白也詩。',24,'全唐诗/poet.song.15000.json','["遠贈烏紗帽，能無白也詩。", "山花不更插，野客莫驚窺。"]'),
('8b322d93-c54f-40d6-ae29-5d69779de85e','次韻和表臣惠符離去歲重醖酒時與杜挺之李宣叔王平甫飲於阻水仍有筍醤之遺','梅堯臣','宋','宋诗','song-poetry','','[]','贈以榴花酒，沉清貴隔年。',48,'全唐诗/poet.song.15000.json','["贈以榴花酒，沉清貴隔年。", "不憂航滯磧，爲汎盞如船。", "加品盈盤內，無花到眼前。", "還招李杜醉，野釀莫稱賢。"]'),
('b8e8c63b-1558-45e8-88c8-3ce2a072f0e1','表臣齋中閱畫而飲','梅堯臣','宋','宋诗','song-poetry','','[]','嘗觀韓幹馬，人物亦如生。',168,'全唐诗/poet.song.15000.json','["嘗觀韓幹馬，人物亦如生。", "君收四病骨，無肉只崢嶸。", "二匹癢磨樹，二匹縱其情。", "意思若不任，千里未可行。", "古絹蠹已盡，彩色無精明。", "歎惜傳至此，幾人金帛輕。", "隋時有名筆，獨寫嚴君平。", "猶持杖頭錢，罷肆心莫營。", "魁然中貴人，坐榻不知名。", "畫中有畫屏，山石侔天成。", "今時長沙叟，獼猴檞林橫。", "疏毛與設色，前代何角爭。", "餘存品雖高，我未易敢評。", "主人愈好事，緘笥酒壺傾。"]'),
('1e3d5491-0919-4e03-be32-a6f0224d2f39','寄送許待制知越州','梅堯臣','宋','宋诗','song-poetry','','[]','喜公新拜會稽章，五月平湖鏡水光。',64,'全唐诗/poet.song.15000.json','["喜公新拜會稽章，五月平湖鏡水光。", "菡萏花迎金板舫，葡萄酒瀉玉壺漿。", "雲歸秦望山頭靜，雨洗若耶溪上凉。", "天子不能煩侍從，可將吟詠報時康。"]'),
('94ec71c7-3bea-4f5c-8772-b32d8d78862d','依韻和王司封離白沙途中感懷','梅堯臣','宋','宋诗','song-poetry','','[]','淮雨夜飛氛祲銷，星躔歷歷轉隨杓。',64,'全唐诗/poet.song.15000.json','["淮雨夜飛氛祲銷，星躔歷歷轉隨杓。", "黄童謾對日如月，賈誼休悲鵩似鴞。", "市骨已知求駿馬，輶車何用載田驕。", "不唯忠憤心如此，王佐才高賦小鷯。"]'),
('8dc79d85-953c-4a75-bef1-67503370d501','將赴表臣會呈杜挺之','梅堯臣','宋','宋诗','song-poetry','','[]','莫怪去遲遲，予心君亦知。',48,'全唐诗/poet.song.15000.json','["莫怪去遲遲，予心君亦知。", "膝前嬌小女，眼底寧馨兒。", "學語渠渠問，牽裳步步隨。", "出門雖不遠，情愛未能移。"]'),
('90c2e136-422f-449c-9b83-0edc44cb1f62','醉中和王平甫','梅堯臣','宋','宋诗','song-poetry','','[]','王瓜未赤方牽蔓，李子纔青已近樽。',32,'全唐诗/poet.song.15000.json','["王瓜未赤方牽蔓，李子纔青已近樽。", "我最年高雜年少，風流還有杜陵孫。"]'),
('11a51a56-4583-4edf-acf2-69a89fb993a8','將解舟走筆呈表臣','梅堯臣','宋','宋诗','song-poetry','','[]','昨夜謳吟瀉春酒，今朝波浪下黄河。',32,'全唐诗/poet.song.15000.json','["昨夜謳吟瀉春酒，今朝波浪下黄河。", "主人不暇怱怱別，爲倩流鶑寄語過。"]'),
('476594ed-7b4c-42c5-a582-50a48085378a','答再和','梅堯臣','宋','宋诗','song-poetry','','[]','舟行纔及二三里，已復淺流如凍河。',32,'全唐诗/poet.song.15000.json','["舟行纔及二三里，已復淺流如凍河。", "君有短書誰遠寄，時因燕子拂檣過。"]'),
('a0bfe848-a409-413b-a6ea-ed9e6577bba8','非意篇呈表臣','梅堯臣','宋','宋诗','song-poetry','','[]','人言厨傳繁，乃是郡久例。',72,'全唐诗/poet.song.15000.json','["人言厨傳繁，乃是郡久例。", "一日苟不修，未免衆吠睨。", "飽尚謗所興，饑必慍不細。", "損之禮漸隳，存之禮未替。", "心莫忽賤微，意莫徇貴勢。", "我將取是然，敢以爲君計。"]'),
('66c22a07-4438-40e6-b127-79266fde6427','依韻和錢深推官見寄','梅堯臣','宋','宋诗','song-poetry','','[]','無才不敢學陽秋，嗜酒時能問大酋。',32,'全唐诗/poet.song.15000.json','["無才不敢學陽秋，嗜酒時能問大酋。", "前日偶從河上飲，文章何可並英遊。"]'),
('95f035b7-1cd8-4cbd-8f49-60bb7d88ff02','依韻答宣叔行舟相隔見寄','梅堯臣','宋','宋诗','song-poetry','','[]','汴漲濺濺費挽牽，輕舟難若上青天。',32,'全唐诗/poet.song.15000.json','["汴漲濺濺費挽牽，輕舟難若上青天。", "只知乘駃及先去，不意遲留落那邊。"]'),
('9af58533-58f3-4460-893f-f8a623c2b8c6','力漕篇呈發運王司封寶臣','梅堯臣','宋','宋诗','song-poetry','','[]','兵外肢强，兵內體壯。',200,'全唐诗/poet.song.15000.json','["兵外肢强，兵內體壯。", "斂之盡歸，歲以多餉。", "東南舳艫，銜尾而上。", "浮江浮淮，泝汴之湍。", "汴湍不常，水衡不官。", "惟虞溢毀，靡虞舟槃。", "舟槃糧覆，糧孰爲足。", "大計之數，萬百惟六。", "帛幣錯貨，三倍其穀。", "曰主厥漕，王之藎臣。", "日憂河涸，運智煩神。", "以舫實土，約流束津。", "百步之間，若牙與齦。", "朝漲夕降，滯舸次鱗。", "亟乞于朝，朝不即報。", "下上經營，風并日曝。", "其躬其勤，秉心有操。", "士豈無祿，視此則冒。", "彼以榮佚，此以劬耗。", "願答其劬，錫命錫誥。"]'),
('8d83c77c-d7c7-449d-b7f5-ef8475678a73','四月十三日唐店寄錢推官','梅堯臣','宋','宋诗','song-poetry','','[]','昨夜月如水，君能携酒來。',48,'全唐诗/poet.song.15000.json','["昨夜月如水，君能携酒來。", "破除愁悶去，洗蕩肺腸開。", "露氣林間落，河聲地底迴。", "相知不須早，語合自無猜。"]'),
('86f17485-937d-4f6a-9c07-06a1a1efdc3b','徒步訪李宣叔宣叔有詩依韻答','梅堯臣','宋','宋诗','song-poetry','','[]','渡河誰道去，我重子雲才。',48,'全唐诗/poet.song.15000.json','["渡河誰道去，我重子雲才。", "鴻雁汀洲去，牛羊井落徠。", "乍行初覺倦，暫語不能該。", "日色看看暮，將歸意復迴。"]'),
('8f430794-c2fc-4b72-90da-8a191ed46e2f','答高判官知唐店夜飲','梅堯臣','宋','宋诗','song-poetry','','[]','露宿勤王客，相從月下來。',48,'全唐诗/poet.song.15000.json','["露宿勤王客，相從月下來。", "黄流何日漲，綠酒暫時開。", "風定燈花爛，天高斗柄迴。", "醉言多脫略，吾黨不須猜。"]'),
('5c521da3-9b78-4c2a-ba47-bbaab6e82f04','依韻和劉原甫舍人赴楊州途次贈予翩翩河中船','梅堯臣','宋','宋诗','song-poetry','','[]','我船緩而西，君船迅而東。',72,'全唐诗/poet.song.15000.json','["我船緩而西，君船迅而東。", "緩迅各所尚，不意中路逢。", "驥馬方騰雲，野鶴還就籠。", "亦言出處異，同是天地中。", "我豈不知命，人空嗟其窮。", "何當遂逸性，川上作釣翁。"]'),
('0cc508cf-ad11-4c7f-8860-fc69aa59524c','聞禽','梅堯臣','宋','宋诗','song-poetry','','[]','禽鳴脫破褲，定無新易故。',24,'全唐诗/poet.song.15000.json','["禽鳴脫破褲，定無新易故。", "此語莫相譏，善貧知有素。"]'),
('90d4d300-6183-49fc-a51e-cf47d269d22a','表臣都官至十三里店','梅堯臣','宋','宋诗','song-poetry','','[]','風雨催車騎，駸駸來自南。',72,'全唐诗/poet.song.15000.json','["風雨催車騎，駸駸來自南。", "道旁有茅屋，寧容使君驂。", "不謂忽下馬，濕衣逢我談。", "田家已刈楚，田婦正好蠶。", "既將國漕急，復與民事諳。", "他年此茅屋，便比棠樹甘。"]'),
('7f4e56c0-0ef8-423f-b1be-7164fdab69e9','泊徐城寄杜挺之王平甫','梅堯臣','宋','宋诗','song-poetry','','[]','十里五里一值淺，千愁萬愁過徐城。',64,'全唐诗/poet.song.15000.json','["十里五里一值淺，千愁萬愁過徐城。", "王君論與河流阻，杜老談思月色清。", "岸若屹牆空自面，樹如張蓋欲誰傾。", "二人黨及親朝夕，更晚更遲何計程。"]'),
('2c749acf-3d5f-4bf5-8a1c-c19f6c5166b3','至第四鋪二首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','第四鋪前風雨急，搭河過盡不憂灘。',32,'全唐诗/poet.song.15000.json','["第四鋪前風雨急，搭河過盡不憂灘。", "却愁蓬漏霑征橐，始信人間行路難。"]'),
('48a0985f-7e00-4d72-80e5-fa9ff496a653','至第四鋪二首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','輕舟已過第四鋪，憶著陽關末尾聲。',32,'全唐诗/poet.song.15000.json','["輕舟已過第四鋪，憶著陽關末尾聲。", "怊惆杜公行底急，白醪何處得同傾。"]'),
('ce5c9fc6-e992-4c2f-bf45-42d401947fa6','倡嫗歎','梅堯臣','宋','宋诗','song-poetry','','[]','萬錢買爾身，千錢買爾笑。',24,'全唐诗/poet.song.15000.json','["萬錢買爾身，千錢買爾笑。", "老笑空媚人，笑死人不要。"]'),
('9253c6c0-1be2-44e7-92f6-60ed06d082d6','夾道岡','梅堯臣','宋','宋诗','song-poetry','','[]','舟脫鵝㿉淺，兵牽鴈脚齊。',48,'全唐诗/poet.song.15000.json','["舟脫鵝㿉淺，兵牽鴈脚齊。", "兼沙水黄濁，穿壠岸高低。", "瘦土黄薑石，枯株長樹雞。", "薄言歸向晚，路入赤雲西。"]'),
('a3afba88-fa2f-4c01-87f2-e7f647dd2674','過青陽驛使風','梅堯臣','宋','宋诗','song-poetry','','[]','天應憐逆旅，乞與順風初。',48,'全唐诗/poet.song.15000.json','["天應憐逆旅，乞與順風初。", "不假卒添力，任從帆自疎。", "燕攙舟尾健，鷁漱水花餘。", "會與王都近，何須問疾徐。"]'),
('dcfaa1e4-133b-4331-be02-52968269e385','妾薄命','梅堯臣','宋','宋诗','song-poetry','','[]','妾命似春冰，不受杲日照。',48,'全唐诗/poet.song.15000.json','["妾命似春冰，不受杲日照。", "有分定隨流，綠波應解笑。", "不是郎情薄，自是郎年少。", "待郎歡厭足，妾髮如蓬藋。"]'),
('76753ddf-85da-442e-9b7e-3cc50cfec0e4','蠅','梅堯臣','宋','宋诗','song-poetry','','[]','乘炎出何許，人意以微看。',48,'全唐诗/poet.song.15000.json','["乘炎出何許，人意以微看。", "怒劍休追逐，疑屏漫指彈。", "與蚊更晝夜，共蜜上杯盤。", "自有堅冰在，能令畏不難。"]'),
('2e4a148f-9012-4a0e-b811-a97d6c100b78','蟬','梅堯臣','宋','宋诗','song-poetry','','[]','柳上一聲蟬，沙頭千里船。',48,'全唐诗/poet.song.15000.json','["柳上一聲蟬，沙頭千里船。", "行經朝雨後，思亂暑風前。", "物趣時時改，人情忽忽遷。", "感新猶感舊，更復幾多年。"]'),
('9ceba3d1-2513-4dae-bf1c-bda711c08123','鶑','梅堯臣','宋','宋诗','song-poetry','','[]','綠柳陰猶薄，黄鸝囀已清。',48,'全唐诗/poet.song.15000.json','["綠柳陰猶薄，黄鸝囀已清。", "年年舟上客，處處樹頭聲。", "髣髴佳人語，依稀太子笙。", "夕陽聽不足，飛入舊荒城。"]'),
('ff8312ab-e9c2-4eea-8191-ac0ed3707db6','雞','梅堯臣','宋','宋诗','song-poetry','','[]','昂然大雄雞，高冠紫沉羽。',48,'全唐诗/poet.song.15000.json','["昂然大雄雞，高冠紫沉羽。", "星占太史局，樹棲丞相府。", "知時不失晦，得食曾呼伍。", "幸無終夜鳴，須防人起舞。"]'),
('e772742d-47bb-4b9b-a174-a68a1dbfaf5c','鶴','梅堯臣','宋','宋诗','song-poetry','','[]','何時別遼海，俛啄雜庭鵾。',48,'全唐诗/poet.song.15000.json','["何時別遼海，俛啄雜庭鵾。", "去作仙人駕，來乘衛國軒。", "雲中晴引唳，松上舊能言。", "但說長千歲，予非學羨門。"]'),
('ce5acb6a-e623-4637-804d-2e413ace880a','挑燈杖','梅堯臣','宋','宋诗','song-poetry','','[]','油燈方照夜，此物用能行。',48,'全唐诗/poet.song.15000.json','["油燈方照夜，此物用能行。", "焦首終無悔，橫身爲發明。", "盡心常欲曉，委地始知輕。", "若比飄飄梗，何邀世上名。"]'),
('bab7e292-8954-4494-adfc-888020230d3e','蛙','梅堯臣','宋','宋诗','song-poetry','','[]','陂蛙怒目生，科斗亦縱橫。',48,'全唐诗/poet.song.15000.json','["陂蛙怒目生，科斗亦縱橫。", "自得君王揖，能爲鼓吹聲。", "越人嘗入饌，秦客不須驚。", "誰解緣明月，徒誇兩股輕。"]'),
('4c6c3ebc-cf6b-4376-9310-b449e8ced83c','鳩','梅堯臣','宋','宋诗','song-poetry','','[]','一世爲巢拙，長年與鵲爭。',48,'全唐诗/poet.song.15000.json','["一世爲巢拙，長年與鵲爭。", "欲知雲脚雨，先向屋頭鳴。", "頸上玉花碎，臆前檀粉輕。", "何時將刻杖，扶助老夫行。"]'),
('1137e4e2-8d01-4804-9bda-99a5ae714fc7','蚊','梅堯臣','宋','宋诗','song-poetry','','[]','向晚化污積，羣飛來戶庭。',48,'全唐诗/poet.song.15000.json','["向晚化污積，羣飛來戶庭。", "蟭螟許巢睫，琥珀爲留形。", "夜色徧容蔽，雷音亦感聽。", "猶矜負山力，血食也霑醒。"]'),
('1a9ebf5b-719a-42bf-8ab1-5cce1dd9a8a0','鹿','梅堯臣','宋','宋诗','song-poetry','','[]','羣處空山中，跡在深松下。',48,'全唐诗/poet.song.15000.json','["羣處空山中，跡在深松下。", "周穆得同狼，秦人指爲馬。", "驚顧遠世網，脫質去田野。", "誰思充腶脩，自是無全者。"]'),
('b0eba813-49a3-46d8-91a4-9a8f322092a1','犬','梅堯臣','宋','宋诗','song-poetry','','[]','常隨輕騎獵，不獨朱門守。',48,'全唐诗/poet.song.15000.json','["常隨輕騎獵，不獨朱門守。", "鷹前任指蹤，雪下還狂走。", "人思上蔡遲，書寄華亭後。", "莫將呼作龍，粱肉纔經口。"]'),
('13de00e4-e945-4417-9fbf-6726462843c1','豕','梅堯臣','宋','宋诗','song-poetry','','[]','司原豢俗豨，日見容陰昵。',48,'全唐诗/poet.song.15000.json','["司原豢俗豨，日見容陰昵。", "喜比爲白麟，惟憂不豐溢。", "烈飇澤雨作，真聲向人出。", "司原悔何由，肝膽空駭慄。"]'),
('d8dd9d73-30a1-4b1d-a18b-9223c74b183a','蛟','梅堯臣','宋','宋诗','song-poetry','','[]','橋邊三尺劍，江上六鈞弧。',48,'全唐诗/poet.song.15000.json','["橋邊三尺劍，江上六鈞弧。", "漢武帝何處，周將軍已無。", "織綃深有室，泣淚自爲珠。", "誰爲九淵害，人猶能爾圖。"]'),
('867cde86-dbf7-4439-9b74-c4706f7a6897','兔','梅堯臣','宋','宋诗','song-poetry','','[]','迷蹤在塵土，衣褐戀蓬蒿。',48,'全唐诗/poet.song.15000.json','["迷蹤在塵土，衣褐戀蓬蒿。", "有狡誰窮穴，中書惜拔毫。", "獵從原上脫，靈向月邊逃。", "死作功勳戒，良弓合自弢。"]'),
('c328840d-0128-490e-9293-0cd2e030dc6e','魚','梅堯臣','宋','宋诗','song-poetry','','[]','洛水美赬鯉，入河西去時。',48,'全唐诗/poet.song.15000.json','["洛水美赬鯉，入河西去時。", "三春登玉浪，一日到天池。", "垂釣豈容羨，小鱗應莫隨。", "腹中無匕首，已不助吳兒。"]'),
('60a84481-cc16-48c4-ab33-be15ca1a1d8c','龜','梅堯臣','宋','宋诗','song-poetry','','[]','王府有寶龜，名存骨未朽。',48,'全唐诗/poet.song.15000.json','["王府有寶龜，名存骨未朽。", "初爲清江使，因落豫且手。", "白玉刻佩章，黄金鑄印紐。", "辭聘彼莊生，曳塗誠自有。"]'),
('a0c416ee-a957-44a9-893d-ca404bb81fed','蝦','梅堯臣','宋','宋诗','song-poetry','','[]','自生江海涯，小大形拳曲。',48,'全唐诗/poet.song.15000.json','["自生江海涯，小大形拳曲。", "宮簾織以鬚，水母憑爲目。", "貴將蔽其私，賤用資不足。", "於物豈無助，況能參鼎肉。"]'),
('8ac7dd55-0306-463f-a70b-5b486d8717a4','至靈壁鎮於許供奉處得杜挺之書及詩','梅堯臣','宋','宋诗','song-poetry','','[]','去冬過尋歷陽守，江沙半遮當利口。',256,'全唐诗/poet.song.15000.json','["去冬過尋歷陽守，江沙半遮當利口。", "口頭沙蹙浪如山，浦溆排舟魚貫柳。", "却畏浪高難苦留，聞解符來時不久。", "平明挂席入楊州，主人釀成百斛酒。", "酒上玉蛆如笑花，一日倒空罌與缶。", "主人亦欲君舊友，請我遲君同此首。", "清明君果渡江至，與君繼舳曾無負。", "過淮風緊到洪澤，使人助我如臂肘。", "暮春泝汴汴流澀，自假輕航去如走。", "千憂萬阻經靈壁，留書津吏情何厚。", "副之佳句二十言，文昌光芒夜侵斗。", "平時相恤以此稀，緩急求之更難有。", "風牽月挽望符離，水館野亭能駐不。", "葛巾輕服約登步，葱𦞦冷淘誇其滫。", "書中不說王平甫，應又先行君在後。", "我今趁君君趁王，趁入大梁須執手。"]'),
('b0296b6e-6ff2-428a-be49-def8f92dc6f9','永城杜寺丞大年暮春白杏花','梅堯臣','宋','宋诗','song-poetry','','[]','孤素發殘枝，非關比衆遲。',24,'全唐诗/poet.song.15000.json','["孤素發殘枝，非關比衆遲。", "殷勤勝菖葉，重疊爲農時。"]'),
('bc7ff811-962f-49cb-814a-030f650da0d6','午日三首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','有酒不病飲，況無菖蒲根。',24,'全唐诗/poet.song.15000.json','["有酒不病飲，況無菖蒲根。", "空懷楚風俗，角黍弔沉魂。"]'),
('78002a73-24b2-4ba1-84df-75b68eaad033','午日三首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','佳人五色縷，道士張囊符。',24,'全唐诗/poet.song.15000.json','["佳人五色縷，道士張囊符。", "瘦臂不中繫，百邪何用驅。"]'),
('878bb69d-f582-4400-ace4-b6dfe350c471','午日三首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','百草堪爲藥，舟行不及收。',24,'全唐诗/poet.song.15000.json','["百草堪爲藥，舟行不及收。", "岸旁蕭與艾，從聽到寒休。"]'),
('93308d3f-eb95-48b5-91d5-5f0d7e9d4b7b','晚得菖蒲','梅堯臣','宋','宋诗','song-poetry','','[]','薄暮得菖蒲，猶勝竟日無。',24,'全唐诗/poet.song.15000.json','["薄暮得菖蒲，猶勝竟日無。", "我焉能免俗，三揖向樽壺。"]'),
('073d14ed-48e3-4a63-8a30-5671dc1ee861','祭貓','梅堯臣','宋','宋诗','song-poetry','','[]','自有五白貓，鼠不侵我書。',120,'全唐诗/poet.song.15000.json','["自有五白貓，鼠不侵我書。", "今朝五白死，祭與飯與魚。", "送之於中河，呪爾非爾疎。", "昔爾齧一鼠，銜鳴遶庭除。", "欲使衆鼠驚，意將清我廬。", "一從登舟來，舟中同屋居。", "糗糧雖甚薄，免食漏竊餘。", "此實爾有勤，有勤勝雞豬。", "世人重驅駕，謂不如馬馿。", "已矣莫復論，爲爾聊欷歔。"]'),
('a685cf80-d002-45ec-a07c-b73be2895409','依韻和酬太師相公','梅堯臣','宋','宋诗','song-poetry','','[]','相國推心本至平，欲使蕭艾作蘭馨。',64,'全唐诗/poet.song.15000.json','["相國推心本至平，欲使蕭艾作蘭馨。", "孤根易變終微賤，美澤難霑漫晦冥。", "楚客嘗聞紉若若，王孫誰復顧青青。", "東風已與生成足，不敢希蓂在帝庭。"]'),
('9bb5ebf6-dcb3-4345-9779-233250a041f0','依韻答僧圓覺早梅','梅堯臣','宋','宋诗','song-poetry','','[]','江南自寒苦，花不與時同。',48,'全唐诗/poet.song.15000.json','["江南自寒苦，花不與時同。", "清向三冬足，香傳一國中。", "雲湖藏舊市，雪樹認新豐。", "未有虧冰素，隨粧入漢宮。"]'),
('e526dea4-7255-4566-b193-f4540d29602b','雍丘遇雨','梅堯臣','宋','宋诗','song-poetry','','[]','日暮風雨急，逆水舟難牽。',132,'全唐诗/poet.song.15000.json','["日暮風雨急，逆水舟難牽。", "波波入杞國，悄悄誰憂天。", "闐闐陂中雷，羃羃隄外煙。", "驟然沃大熱，蒸飫如炊煎。", "飲水徒脹滿，渴喉殊未蠲。", "摇篷已煩倦，汗額常不乾。", "如何一席地，長少皆在前。", "衣巾不敢去，又以禮數纏。", "安得化嚴石，兩脛沒流泉。", "每暑起此念，念之凡幾年。", "終當逐逸志，奚必事華顛。"]'),
('f9dd8491-362e-434d-b4b8-1861249d6be8','廟子灣下作','梅堯臣','宋','宋诗','song-poetry','','[]','廟子灣下百尺船，杞人楚人相雜牽。',80,'全唐诗/poet.song.15000.json','["廟子灣下百尺船，杞人楚人相雜牽。", "水底老蜃倚以怪，樹頭挂紙吹作錢。", "江蛟海鵾千萬里，軒風簸日蠻島邊。", "長安舊去天尺五，此在大梁眉睫前。", "高冠長劍乃不畏，沙雨夜起噴腥涎。"]'),
('53292b46-66c9-4311-8d5d-bf9cea6c5dc0','留侯廟下作','梅堯臣','宋','宋诗','song-poetry','','[]','貌如女子心如鐵，五世相韓韓已滅。',176,'全唐诗/poet.song.15000.json','["貌如女子心如鐵，五世相韓韓已滅。", "家童三百不足使，倉海君初去相結。", "秦皇東從博浪過，力士袖椎同决烈。", "曉入沙中風正昏，誤擊副車搜迹絕。", "亡命下邳圯上游，老父墮履意未別。", "顧謂孺子下取之，心始不平終折節。", "舒足既受笑且去，行及里所還可說。", "可教後當五日來，三返其期付書閱。", "他日則爲王者師，果輔高皇號奇傑。", "留國存祠汴水傍，逢逢簫鼓賽肥羊。", "赤松不見天地長，黄石共葬丘冢荒。"]'),
('a0fe4f34-83fe-40cd-8759-9559dc706a60','高車再過謝永叔內翰','梅堯臣','宋','宋诗','song-poetry','','[]','世人重貴不重舊，重舊今見歐陽公。',284,'全唐诗/poet.song.15000.json','["世人重貴不重舊，重舊今見歐陽公。", "昨朝喜我都門入，高車臨岸進船篷。", "俯躬拜我禮愈下，騶徒竊語音微通。", "我公聲名壓朝右，何厚於此瘦老翁。", "笑言啞啞似平昔，妻子信說如梁鴻。", "自茲連雨泥沒脛，未得謁帝明光宮。", "冒陰履濕就稅地，親賓未過知巷窮。", "復聞傳呼公又至，黄金絡馬聲瓏瓏。", "紫袍寶带照屋室，飲水啜茗當清風。", "邀以新詩出古律，霜髯屢頷摇寒松。", "因嗟近代貴莫比，官爲司空仍侍中。", "今成冢丘已寂寞，文字豈得留無窮。", "以此易彼可勿媿，浮榮有若送雨虹。", "須臾斷滅不復見，唯有明月常當空。", "況我學不爲買祿，直欲到死攀軻雄。", "一飯足以飽我腹，一衣足以飾我躬。", "老雖得職不足顯，願與公去驩樂同。", "驩樂同，治園田，潁水東。"]'),
('04273307-0ce2-46c1-b997-d90045f26f9b','李審言相招與刁景純周仲章裴如晦馮當世沈文通謝師厚師直會開寶塔院','梅堯臣','宋','宋诗','song-poetry','','[]','自君命我飲，朝暮雨傾瓦。',168,'全唐诗/poet.song.15000.json','["自君命我飲，朝暮雨傾瓦。", "城東與城北，大道泥沒馬。", "敢忘主人勤，顛撲困馭者。", "衆客亦如期，陳肴藉蘭若。", "馮裴與沈謝，辯論過終賈。", "刁周事老成，危坐言語寡。", "酒半時謔劇，揣狀類模寫。", "或譏項髮禿，或指舌端傻。", "或將冠带身，勸作梁武捨。", "謂我大耳兒，此實已見假。", "又效井市態，屈强體非雅。", "順風手沙沙，逆風口哆哆。", "竟席屢絕倒，去忌肝膽瀉。", "規規豈無儕，達識高天下。"]'),
('da97950b-54c7-41e6-9a8f-2c5959e5a3f3','送周仲章都官通判湖州','梅堯臣','宋','宋诗','song-poetry','','[]','溪水日霅霅，弁峯日峨峨。',144,'全唐诗/poet.song.15000.json','["溪水日霅霅，弁峯日峨峨。", "中有水精宮，此名其謂何。", "湖水傳玉孃，揚光遡常娥。", "昔人美清夜，高樓發微歌。", "風流百年餘，所歷才彥多。", "我嘗居其下，醉舞或傞傞。", "君行貳郡事，結騎黄金珂。", "容儀苦白皙，度橋鳴橐駝。", "士女夾道看，秋風吹縠羅。", "言是公侯家，大體儂弗過。", "問儂底未辨，撐船入芰荷。", "應莫勸蠶織，生計非杼梭。"]'),
('aae19b50-89a1-4749-b14f-7f4066092b99','依韻答吳安勗太祝','梅堯臣','宋','宋诗','song-poetry','','[]','我於文字無一精，少學五言希李陵。',144,'全唐诗/poet.song.15000.json','["我於文字無一精，少學五言希李陵。", "當時巨公特推許，便將格力追西京。", "卞和無足定抱寶，乘驥走行天下老。", "玉已累人馬不逢，皇皇何之饑欲倒。", "還思二十居洛陽，公侯接跡論文章。", "文章自此日怪奇，每出一篇爭誦之。", "其鋒雖銳我敢犯，新語能如夏侯湛。", "于今窮困人已衰，不見懸金規呂覽。", "乃遭吾子求琢磋，珠璣獲斗奈我何。"]'),
('358145f7-01c3-4a76-82d2-e975c40e3c65','吳沖卿學士以王平甫言淮甸會予予久未至沖卿與平甫作詩見寄答之','梅堯臣','宋','宋诗','song-poetry','','[]','老馬力盡道路長，豈若壯驥思騰驤。',192,'全唐诗/poet.song.15000.json','["老馬力盡道路長，豈若壯驥思騰驤。", "項窮臨流歎不逝，燕骨埋沒庸可傷。", "我今六十趨南北，饑腸不足面黧黑。", "少年心志一點無，千里區區安所得。", "往居閭閈乏經過，閉門讀書多廢食。", "便從冠带向仕途，强顔希祿非貪職。", "昨逢王倩昧平生，一見如舊心相傾。", "談經樹下任日炙，酒狂便欲騎長鯨。", "誰意同行有遲疾，先入大梁凡幾日。", "大梁故人憐鈍衰，迭爲寄唱辭嚴密。", "卒章言買羊與酒，雖齒動摇能飫溢。", "亦知紅頰教新成，更願舊朋邀六七。"]'),
('02a1eb88-56d1-4248-a8f0-9e3085285686','寄題絳守園池','梅堯臣','宋','宋诗','song-poetry','','[]','老柏麝不食，古色侵青冥。',168,'全唐诗/poet.song.15000.json','["老柏麝不食，古色侵青冥。", "淺沼龍不入，秋水生浮萍。", "屋屢圬堊幾太守，壁上彪蔚遺丹青。", "黑石鎸辭澀如棘，今昔往來人不識。", "酸睛欲抉無聲形，既不可問不可聽。", "懸泉瀉竇晝未停，飛玉貯藍光入屏。", "苞潭梁島甲癸丁，蔓刺交綴垂組綎。", "蒼官屭槐朋在庭，風蟲日鳥聲嚶嚀。", "卉葩木菓黏枝條，集臺脫熱昏痾醒。", "樊文韓詩怪若是，徑取一二傳優伶。", "仍寄河東薛太守，更與斟酌無閑扃。"]'),
('f8ff5aa5-9db2-424a-a6a4-bec6d10b0cc6','陸子履見過','梅堯臣','宋','宋诗','song-poetry','','[]','劉郎謫去十年歸，長樂鐘聲下太微。',64,'全唐诗/poet.song.15000.json','["劉郎謫去十年歸，長樂鐘聲下太微。", "屈指故人無曩日，平明騎馬扣吾扉。", "論情論舊彈冠少，多病多愁飲酒稀。", "猶喜醉翁時一見，攀炎附熱莫相譏。"]'),
('88a7c19e-e518-437a-b75e-e2d14296ade2','重送周都官','梅堯臣','宋','宋诗','song-poetry','','[]','水上朱樓畫角鳴，濛濛雨裏榜舟輕。',64,'全唐诗/poet.song.15000.json','["水上朱樓畫角鳴，濛濛雨裏榜舟輕。", "未逢甫里先生謁，多見吳興太守迎。", "荷葉半黄蓮子老，霜苞微綠橘林明。", "十年不到風煙改，君去將詩與晝評。"]'),
('6ed5773d-4593-4872-8a4a-24a946297145','醉翁吟','梅堯臣','宋','宋诗','song-poetry','','[]','翁來，翁來，翁乘馬。',163,'全唐诗/poet.song.15000.json','["翁來，翁來，翁乘馬。", "何以言醉，在泉林之下。", "日暮煙愁谷暝，蹄聳足音響原野。", "月從東方出照人，攬暉曾不盈把。", "酒將醒，未醒又挹玉斝向身瀉，翁乎醉也。", "山花炯兮，山木挺兮，翁酩酊兮。", "禽鳴右兮，獸鳴左兮，翁䫥鵝兮。", "蟲蜩嚎兮，石泉嘈兮，翁酕醄兮。", "翁朝來以暮往，田叟野父徒倚望兮。", "翁不我搔，翁自陶陶。", "翁捨我歸，我心依依。", "博士慰我，寫我意之微兮。"]'),
('51612968-07e2-49f9-8e82-0a93dea13445','送李載之殿丞赴海州榷務','梅堯臣','宋','宋诗','song-poetry','','[]','瓜蔓水生風雨多，吳船發棹唱吳歌。',64,'全唐诗/poet.song.15000.json','["瓜蔓水生風雨多，吳船發棹唱吳歌。", "槎從秋漢下應快，人憶故園歸奈何。", "世事靜思同轉轂，物華催老劇飛梭。", "茶官到有清閑味，海月團團入酒蠃。"]'),
('4e9b3e69-c64a-4467-af8d-55ffff8fa472','和吳沖卿學士石屏','梅堯臣','宋','宋诗','song-poetry','','[]','吳夫子，佩銀龜。',200,'全唐诗/poet.song.15000.json','["吳夫子，佩銀龜。", "乘天馬，索怪奇。", "忽得虢略一片石，其中白色圓如規。", "又有樹與烏，畫手雖妙何能爲。", "吳乃持問歐陽公，比公曩獲尤可疑。", "疑不爲辨賦以詩，詩辭粲粲明星垂。", "復遣齎來使我和，坐上鉅公傍睨之。", "范侯實有楊雄學，咸云此理難究推。", "我歸滌慮反覆思，義雖不經聊解頤。", "月與太陽合朔時，陽烏飛上桂樹枝。", "枝上作窠生羣兒，人不知天公。", "天公欲俾世間見，影著石面如黏黐。", "烏既不得去，月亦不可移。", "留爲千古作好玩，慎勿傾撲同玉碑。"]'),
('ce63bc60-1c99-4f87-b9f7-a2bb2eb6bb82','永叔贈絹二十匹','梅堯臣','宋','宋诗','song-poetry','','[]','鳳皇拔羽覆鶉鷃，鶉鷃幸脫僵蒿蓬。',176,'全唐诗/poet.song.15000.json','["鳳皇拔羽覆鶉鷃，鶉鷃幸脫僵蒿蓬。", "昔公處貧我同困，我無金玉可助公。", "公今既貴我尚窘，公有縑帛周我窮。", "古來朋儕義亦少，子貢不顧顔淵空。", "復聞韓孟最相善，身仆道路哀妻僮。", "生前曾未獲一飽，徒脫吟響如秋蟲。", "自驚此贈已過足，外可畢嫁內禦冬。", "況無杜甫海圖坼，天吳且免在褐躬。", "瘦兒兩脛不赤凍，病婦十指休補縫。", "厨中餒婢喜有望，服鮮棄垢必所蒙。", "梁上君子切莫下，吾非陳寔何爾容。"]'),
('eb44cf9d-a0c4-43e2-aec8-9d898f5a187c','依韻奉和永叔感興五首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','泉上有君子，齋祠達主誠。',72,'全唐诗/poet.song.15000.json','["泉上有君子，齋祠達主誠。", "向來霖雨暴，觸處蛟鼉鳴。", "既祈致日出，杲杲紓民情。", "天子遣以報，固菲媚取名。", "因成感興章，庶用語平生。", "蹈道久已熟，情田不須耕。"]'),
('3839cccd-5e1f-4ce7-bec4-6bdc89532dd9','依韻奉和永叔感興五首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','既負天下望，必憂天下責。',72,'全唐诗/poet.song.15000.json','["既負天下望，必憂天下責。", "每聞諫諍辭，苦意多矯激。", "心存義勇赤，氣與虹霓白。", "所論言必從，豈若水投石。", "陰邪日已銷，事理頗已得。", "莫將經濟術，抑鬰向胸臆。"]'),
('6a4b1d8b-7924-4dc4-9192-812591b9c39a','依韻奉和永叔感興五首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','勿驚年齒遲，勿歎時節晚。',96,'全唐诗/poet.song.15000.json','["勿驚年齒遲，勿歎時節晚。", "寒松翳林麓，射干生隴坂。", "野蓬隨飄飄，秋實綴纂纂。", "萬物更盛衰，有益必有損。", "損益皆自然，曷增鳬脛短。", "人爲智慮役，白髮安得免。", "利澤欲及時，唯恐不行遠。", "後世豈皆愚，計校徒勉勉。"]'),
('4aced9c4-25f5-4507-9149-99908f7ded6f','依韻奉和永叔感興五首  其四','梅堯臣','宋','宋诗','song-poetry','','[]','日出各馳趨，皆爲利所迫。',60,'全唐诗/poet.song.15000.json','["日出各馳趨，皆爲利所迫。", "秋蟲至微物，役役網自織。", "古來高世人，林下遺憂責。", "扛鼎絕臏者，乃自恃以力。", "積金苟如山，何異魚貪食。"]'),
('5e33b4d2-34ed-4e7b-b9b4-1a1bddde05a8','依韻奉和永叔感興五首  其五','梅堯臣','宋','宋诗','song-poetry','','[]','唧唧復唧唧，長沙何太息。',72,'全唐诗/poet.song.15000.json','["唧唧復唧唧，長沙何太息。", "秋風入破衣，瘦婦思補剌。", "手中把長線，無帛縫不得。", "夜夜憂向寒，斗柄漸垂北。", "嫁夫欲夫富，歡樂要終極。", "歡樂既未能，鬢髮霜花易。"]'),
('2c897a07-a623-4d33-a971-5e94b5ba8e17','依韻奉和永叔社日','梅堯臣','宋','宋诗','song-poetry','','[]','玉卵不吞龍嗜肉，燕子成兒去華屋。',96,'全唐诗/poet.song.15000.json','["玉卵不吞龍嗜肉，燕子成兒去華屋。", "老櫪半黄田鼓鳴，樹下宰平誰似玉。", "茂陵長說泣秋風，王母惜傳雙鬢綠。", "東方伏日思早歸，長饑不及侏儒腹。", "豶豕新烹白醪熟，奮衣地坐無拘束。", "驪山夜寒坑底哭，漫把漆書留冢竹。"]'),
('0faf6dc9-1842-4899-b917-b9065f57bc83','社日飲永叔家','梅堯臣','宋','宋诗','song-poetry','','[]','雨未，雨濛濛，野田擊鼓賽社翁。',79,'全唐诗/poet.song.15000.json','["雨未，雨濛濛，野田擊鼓賽社翁。", "折條跨馬社翁去，醉叟卧倒梨葉紅。", "鼇頭主人邀客飲，玉酒新賜蓬萊宮。", "彭宣不預後堂會，康成一舉三百鍾。", "更邀明月出海底，爛醉等是歸蒿蓬。"]'),
('0c5c8bba-7de8-40de-956b-2563aaff8deb','八月十三日觀長星','梅堯臣','宋','宋诗','song-poetry','','[]','長星彗雲出，天狗欲墮鳴。',48,'全唐诗/poet.song.15000.json','["長星彗雲出，天狗欲墮鳴。", "狗掃不見跡，昭晰河漢橫。", "河漢秋轉浄，箕斗垂光晶。", "觀爾長星酒，收祲看太平。"]'),
('0004a035-c27f-47a8-8a0e-5495536c63c8','送李才元學士知邛州','梅堯臣','宋','宋诗','song-poetry','','[]','太守車煌煌，莫如還故鄉。',72,'全唐诗/poet.song.15000.json','["太守車煌煌，莫如還故鄉。", "昔登蜀郡籍，今得臨邛章。", "過家禮耆舊，接境跪壺漿。", "寒經道路遠，春入山川長。", "俗將樂其化，詔亦美其良。", "相如有遺跡，誰復酒壚傍。"]'),
('9aa5be7c-ffab-4276-9185-e4af67aa3d8b','弔仲源','梅堯臣','宋','宋诗','song-poetry','','[]','世家吳季子，皇籍漢諸孫。',48,'全唐诗/poet.song.15000.json','["世家吳季子，皇籍漢諸孫。", "嘒管行車失，虛堂隠几存。", "枝摧從玉樹，星殞自天垣。", "寧復下貧賤，停驂來里門。"]'),
('397ed952-3beb-44cc-a66f-76efb83cbd45','送梁學士知襄州','梅堯臣','宋','宋诗','song-poetry','','[]','騎吹荆州去，喬林漢水前。',48,'全唐诗/poet.song.15000.json','["騎吹荆州去，喬林漢水前。", "鄉亭逢故老，牛酒問高年。", "翠巘臨關路，黄柑逐賈船。", "習家池館在，賓從與留連。"]'),
('ec161706-6f46-40a9-ae37-271d98a8f617','送薛氏婦歸絳州','梅堯臣','宋','宋诗','song-poetry','','[]','在家勗爾勤，女功無不喜。',156,'全唐诗/poet.song.15000.json','["在家勗爾勤，女功無不喜。", "既嫁訓爾恭，恭己乃遠恥。", "我家本素風，百事無有侈。", "隨宜具奩箱，不陋復不鄙。", "當須記母言，夜寐仍夙起。", "慎勿窺窗戶，慎勿輒笑毀。", "妄非勿較競，醜語勿辨理。", "每順舅姑心，況逆舅姑耳。", "爲婦若此能，乃是儒家子。", "看爾十九年，門閫未嘗履。", "一朝陟太行，悲傷黄河水。", "車徒望何處，哭泣動鄰里。", "生女不如男，天親反由彼。"]'),
('218aed6f-8ecd-452f-b5fb-3b6346fc5dc2','送劉繼鄴秀才歸當塗','梅堯臣','宋','宋诗','song-poetry','','[]','鵷雛始出巢，欲矜五色羽。',84,'全唐诗/poet.song.15000.json','["鵷雛始出巢，欲矜五色羽。", "乃見郡鴟盤，壤中將有取。", "梧桐與竹實，安得在平土。", "所趣固已殊，而何不遠舉。", "幸失網羅目，宜還蘭蕙圃。", "故鄉有嘉林，其下可以處。", "會侍朝陽鳴，賀夔成律呂。"]'),
('d442d1f5-e526-4ab6-95e3-c150df746313','送裴如晦宰吳江','梅堯臣','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','吳江田有粳，粳香舂作雪。',84,'全唐诗/poet.song.15000.json','["吳江田有粳，粳香舂作雪。", "吳江下有鱸，鱸肥膾堪切。", "炊粳調橙齏，飽食不爲餮。", "月從洞庭來，光映寒湖凸。", "長橋坐虹背，衣濕霜未結。", "四顧無纖雲，魚跳明鏡裂。", "誰能與子同，去若秋鷹掣。"]'),
('87091bf0-3d14-4185-8e9a-0a67d345f1a6','送撫州通判袁世弼寺丞','梅堯臣','宋','宋诗','song-poetry','','[]','帆疏疏，纖綠蒲，二十四幅輕江湖。',80,'全唐诗/poet.song.15000.json','["帆疏疏，纖綠蒲，二十四幅輕江湖。", "高秋逆水上天去，朝過瓜步暮濡須。", "長風沙頭問鯉魚，大孤山側鳴寒烏。", "魚腹無書報家信，憑烏爲到西山區。", "西山松柏應更好，及取之官來拜掃。"]'),
('7340837e-cc0e-4c1a-9b80-dd1f038c0708','送石昌言舍人使匈奴','梅堯臣','宋','宋诗','song-poetry','','[]','燕然山北大單于，漢家皇帝與璽書。',112,'全唐诗/poet.song.15000.json','["燕然山北大單于，漢家皇帝與璽書。", "持書大夫腰金魚，飛龍借馬出國都。", "胡沙九月草已枯，草上霜花如五銖。", "白裘貂帽著不暖，莽莽黄塵車欵欵。", "野廬邊月出隴來，風靜天遥鴈聲短。", "聞到罽庭尤若寒，譯言揉耳不譏彈。", "公於是時已觀禮，踏雪再拜辭可汗。"]'),
('bb67e2cb-5612-49a6-8084-7d83da4e8485','依韻和宋中道觀八月二十八日車駕朝謁景靈宮','梅堯臣','宋','宋诗','song-poetry','','[]','都人夾望禁槐傍，閶闔初開旭日光。',64,'全唐诗/poet.song.15000.json','["都人夾望禁槐傍，閶闔初開旭日光。", "彫玉翠鞍牽騕褭，盤龍朱輦爛文章。", "焚香閟殿開嚴帳，汲水寒溝洒廣莊。", "一見天顔萬人喜，却迴宮禁樂聲長。"]'),
('d91d3375-3ec3-408c-b832-30e7caf58517','度支蘇才翁挽詞三首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','二十識君貌，交游非一朝。',48,'全唐诗/poet.song.15000.json','["二十識君貌，交游非一朝。", "魄光沉碧海，志業隕青霄。", "洛客舊爲社，楚人今作招。", "素車京峴路，應不似嶣嶤。"]'),
('d98bd0b2-3bdd-4851-b3fe-2ea5beb3a7cf','度支蘇才翁挽詞三首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','盛世雖多士，唯公與衆殊。',48,'全唐诗/poet.song.15000.json','["盛世雖多士，唯公與衆殊。", "高才飛健鶻，逸句吐明珠。", "未入周官采，爭持楚璞模。", "莫悲泉骨朽，青史見賢愚。"]'),
('c8197601-81e4-4c81-8f04-7d8c853d3238','度支蘇才翁挽詞三首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','自昔愛春物，罇深眼底紅。',48,'全唐诗/poet.song.15000.json','["自昔愛春物，罇深眼底紅。", "日斜花在落，身醉客西東。", "歿歎千年隔，生悲百事空。", "君嘗知此理，不悞學陶公。"]'),
('39bda497-83bb-4abc-b971-56989b3dcfa7','重送袁世弼','梅堯臣','宋','宋诗','song-poetry','','[]','臨川內史謝康樂，貝葉翻經有故臺。',64,'全唐诗/poet.song.15000.json','["臨川內史謝康樂，貝葉翻經有故臺。", "春草生塘猶夢句，秋蕖出水似君才。", "驐雞肥脆聊供膳，篘酒甘濃可薦杯。", "亦說右軍遺跡在，墨池科斗喜風雷。"]'),
('205ae866-c811-43ce-9ea3-2566ffcea6b0','留題景德寺吉祥講僧','梅堯臣','宋','宋诗','song-poetry','','[]','我講異爾講，我書非爾書。',48,'全唐诗/poet.song.15000.json','["我講異爾講，我書非爾書。", "彼將希白馬，此亦猶大車。", "皆行國都內，轍不入委閭。", "世人日擾擾，來慕清凉居。"]'),
('7909e82e-82bf-4d4b-a584-68f501849ee9','閤門水','梅堯臣','宋','宋诗','song-poetry','','[]','宮井固非一，獨傳甘與清。',48,'全唐诗/poet.song.15000.json','["宮井固非一，獨傳甘與清。", "釀成光祿酒，調作太宮羹。", "上舍鋹缾貯，齋廬玉茗烹。", "相如方病渴，空聽轆轤聲。"]'),
('b9c57e1f-bf4a-48dd-ba94-e1bd6f206d3d','朝堂齋宿','梅堯臣','宋','宋诗','song-poetry','','[]','玉屬陪祠日，宮廬寓宿時。',48,'全唐诗/poet.song.15000.json','["玉屬陪祠日，宮廬寓宿時。", "鐘來建章遠，月過羽林遲。", "寒入清綾被，風牽翠鳳旗。", "賈生誰復召，安問鬼神爲。"]'),
('5f8343b9-537d-4cee-bb6d-0c33c9498a3f','送杜挺之郎中知虔州','梅堯臣','宋','宋诗','song-poetry','','[]','大庾嶺邊無臘雪，惟有梅花與明月。',176,'全唐诗/poet.song.15000.json','["大庾嶺邊無臘雪，惟有梅花與明月。", "月光如水來向人，太守得閑杯耳熱。", "吹香入酒望梁宋，正是苦寒綿可折。", "亦當念君君行南，南方無冰地不裂。", "此身不到五侯門，肥羔釀酒槐槽咽。", "玉色少年生頰春，解笑吟腸冷如鐵。", "衝風冒霰入廣文，老與諸生開反切。", "重嗟君遠隔江湖，雖得豐甘牙已缺。", "官娥執樂一千指，脩頸慢肌衣錯纈。", "定逢賓客强排娖，舞徹六幺紅袖掣。", "人競羨君君愈疲，夜歸坐閤思予說。"]'),
('c6ebfeea-00ed-43b2-ad4b-9c877341cfda','送吳辯叔知鞏縣','梅堯臣','宋','宋诗','song-poetry','','[]','言爲西邑宰，本是洛陽人。',48,'全唐诗/poet.song.15000.json','["言爲西邑宰，本是洛陽人。", "送馹往歸魏，迎車來入秦。", "山川成鞏固，陵廟壯威神。", "好學河陽政，栽花作縣春。"]'),
('f75d827d-5515-42f6-a3b7-055eec17a2a1','當世家觀畫','梅堯臣','宋','宋诗','song-poetry','','[]','冰蠶吐絲織纖紈，妙娥貌玉輕邯鄲。',96,'全唐诗/poet.song.15000.json','["冰蠶吐絲織纖紈，妙娥貌玉輕邯鄲。", "曲眉淺臉鴉髮盤，白角瑩薄垂肩冠。", "銅青羅衫日月團，紅裙撮暈朝霞乾。", "手中把筆書小字，字以通情形以觀。", "形隨畫去能長好，歲歲年年應不老。", "相逢熟識眼生春，重伴忘憂作萱草。"]'),
('1608f750-6622-47cf-9f14-09b31c97aa65','送韓簽判玉汝還南京','梅堯臣','宋','宋诗','song-poetry','','[]','天子甘泉祀，歡聲浹九圍。',48,'全唐诗/poet.song.15000.json','["天子甘泉祀，歡聲浹九圍。", "綠章馳騎入，朱服佩魚歸。", "賦雪上賓席，買鬟更舞衣。", "清池無限雁，莫道信音稀。"]'),
('6d9b987d-2544-452c-89f9-a3b5f557dd6b','桃花源詩','梅堯臣','宋','宋诗','song-poetry','','[]','鹿爲馬，龍爲蛇，鳳皇避羅麟避罝。',176,'全唐诗/poet.song.15000.json','["鹿爲馬，龍爲蛇，鳳皇避羅麟避罝。", "天下逃難不知數，入海居巖皆是家。", "武陵源中深隠人，共將雞犬栽桃花。", "花開記春不記歲，金椎自刼博浪沙。", "亦殊商顔采芝草，唯與少長親胡麻。", "豈意異時漁者入，各各因問人閒賒。", "秦已非秦孰爲漢，奚論魏晉如割瓜。", "英雄滅盡有石闕，智惠屏去無年華。", "俗骨思歸一相送，慎勿與世言雲霞。", "出洞沿溪夢寐覺，物景都失同迴槎。", "心寄草樹欲復往，山幽水亂尋無涯。"]'),
('4f592ecd-4e6e-4599-918b-fe836566ffa8','永叔席上分韻送裴如晦','梅堯臣','宋','宋诗','song-poetry','','[]','霜華夜夜濃，汴水日日減。',48,'全唐诗/poet.song.15000.json','["霜華夜夜濃，汴水日日減。", "行邁唯恐遲，離懷不須黯。", "遠輕吳江潮，乃見丈夫膽。", "君意應洗然，吾方困塵慘。"]'),
('d92acbbe-460b-490f-a669-3f26a0234ac8','永叔白兔','梅堯臣','宋','宋诗','song-poetry','','[]','可笑常娥不了事，走却玉兔來人間。',96,'全唐诗/poet.song.15000.json','["可笑常娥不了事，走却玉兔來人間。", "分寸不落獵犬口，滁州野叟獲以還。", "霜毛蘴茸目睛殷，紅絛金練相繫擐。", "馳獻舊守作異玩，况乃已在蓬萊山。", "月中辛勤莫擣藥，桂旁杵臼今應閑。", "我欲拔毛爲白筆，研朱寫詩破公顔。"]'),
('f0d6c476-a45a-4ffe-a6bc-242cfd3a379d','直宿廣文舍下','梅堯臣','宋','宋诗','song-poetry','','[]','前夜宿廣文，葉響竹打雪。',108,'全唐诗/poet.song.15000.json','["前夜宿廣文，葉響竹打雪。", "昨夜宿廣文，窗影竹照月。", "頼此數竿竹，與我爲暖熱。", "上有寒鵲棲，拳足如瘦蕨。", "平明欲飛去，唶唶若告說。", "我無喜可報，煩爾弄觜舌。", "亦嘗苦老鴉，鳴噪每切切。", "爲學本爲道，窮蹙令素髮。", "但能得酒飲，終日自兀兀。"]'),
('b42d529e-08b0-413f-89f3-b40619fcc8ec','送宋中道太博倅廣平','梅堯臣','宋','宋诗','song-poetry','','[]','行役無冬春，車馬無南北。',108,'全唐诗/poet.song.15000.json','["行役無冬春，車馬無南北。", "急若機上梭，離別腸自織。", "其間走聲利，晝夜不能息。", "晚得二友生，胸蜺吐五色。", "各思强祿仕，安肯坐仰食。", "一之毛遂鄉，一之太伯國。", "豈無穎脫才，可邁古風力。", "明當隔大河，去路指斗極。", "誰念平原君，能於衆中識。"]'),
('9a4d8cdf-064c-483e-a04c-b73ee69a5066','送宋端明知成都','梅堯臣','宋','宋诗','song-poetry','','[]','伯仲俱邦棟，朝廷倚以隆。',120,'全唐诗/poet.song.15000.json','["伯仲俱邦棟，朝廷倚以隆。", "出爲周九牧，入是漢三公。", "歲易星辰轉，天均雨露同。", "威聲滿河北，事業出山東。", "賦壓臨邛馬，文高益部雄。", "英靈當自伏，教化已先通。", "彀騎花川隘，壺漿錦里空。", "道途來笮馬，都邑貴郫筒。", "刀夢殊祥後，鋒車急占中。", "春江須愛賞，花鳳在梧桐。"]'),
('4c6eb535-bf7c-407b-b479-3a0a4065c139','戲作常娥責','梅堯臣','宋','宋诗','song-poetry','','[]','我昨既賦白兔詩，笑他常娥誠自癡。',242,'全唐诗/poet.song.15000.json','["我昨既賦白兔詩，笑他常娥誠自癡。", "正值十月十五夜，月開冰團上東籬。", "畢星在傍如張羅，固謂走失應無疑。", "不意常娥早覺怒，使令烏鵲繞樹枝。", "啅噪言語誰可辨，徘徊赴寢搴寒帷。", "又將清光射我腹，但覺軫粟生枯皮。", "乃夢女子下天來，五色雲擁端容儀。", "雕瓊刻肪肌骨秀，聲音柔響揚雙眉。", "以理責我我爲聽，何擬玉兔爲凡卑。", "百獸皆有偶然白，神靈獨冒由所推。", "裴生亦有如此作，專意見責心未夷。", "遂云裴生少年爾，謔弄溫軟在酒巵。", "爾身屈强一片鐵，安得妄許成怪奇。", "翰林主人亦不愛爾說，爾猶自惜知不知。", "叩頭再謝沋已去，起看月向西南垂。"]'),
('f6936d05-ff17-49ba-a76c-ed6450d64c71','送李涇州審言  其一','梅堯臣','宋','宋诗','song-poetry','','[]','古章乘一障，不過提千兵。',72,'全唐诗/poet.song.15000.json','["古章乘一障，不過提千兵。", "今握數萬衆，獨自制名城。", "諸將俯聽命，莫敢輒吐聲。", "堂下選騕褭，帳中圖崢嶸。", "山川在目中，虜寇來必平。", "誰人識謝艾，只是一書生。"]'),
('3715cb61-bd61-4c23-8da3-7759185e571d','送李涇州審言  其二','梅堯臣','宋','宋诗','song-poetry','','[]','漢家舊日回中路，天子新除太守行。',64,'全唐诗/poet.song.15000.json','["漢家舊日回中路，天子新除太守行。", "牙將握刀趨遠驛，羌人下馬拜高旌。", "雲間白草開邊隴，山上朱樓壓郡城。", "勇脫區區簿書內，壯心應欲請長纓。"]'),
('13009869-b6a7-4481-a6a4-fee6993b534c','送刁景純學士使北','梅堯臣','宋','宋诗','song-poetry','','[]','嘗聞朔北寒尤甚，已見黄河可過車。',64,'全唐诗/poet.song.15000.json','["嘗聞朔北寒尤甚，已見黄河可過車。", "驛騎駸駸持漢節，邊風慘慘聽胡笳。", "朝供酪粥冰生椀，夜卧氊廬月照沙。", "侍女新傳教坊曲，歸來偷賞上林花。"]'),
('786d69f8-c045-4e88-b978-e3990f9e0142','送馬仲途司諫使北','梅堯臣','宋','宋诗','song-poetry','','[]','每逆龍鱗司諫諍，又持旄節使陰山。',64,'全唐诗/poet.song.15000.json','["每逆龍鱗司諫諍，又持旄節使陰山。", "貂裘不見風霜勁，雁磧遥知道路艱。", "冰膾芥齏非楚味，玉苕蘭茁說燕顔。", "單于不敢輕中國，名馬新調爲送還。"]'),
('f1e2198f-8101-4918-838b-3c78dcaef6e6','重）賦白兔','梅堯臣','宋','宋诗','song-poetry','','[]','毛氏穎出中山中，衣白兔褐求文公。',114,'全唐诗/poet.song.15000.json','["毛氏穎出中山中，衣白兔褐求文公。", "文公嘗爲穎作傳，使穎名字存無窮。", "徧走五嶽都不逢，乃至瑯琊聞醉翁。", "醉翁傳是昌黎之後身，文章節行一以同。", "滁人喜其就籠紲，遂與提携來自東。", "見公於鉅鼇之峯，正草命令辭如虹。", "筆禿願脫冠以從，赤身謝德歸蒿蓬。"]'),
('3ee984b5-3723-4331-abc0-1ae838d5f7c0','王祁公北園','梅堯臣','宋','宋诗','song-poetry','','[]','園林多高樛，園卉多芳柔。',161,'全唐诗/poet.song.15000.json','["園林多高樛，園卉多芳柔。", "紅紫經幾春，青枯經幾秋。", "我至每懷浮觴之卿翁，但見浮觴之水汩汩流。", "水流日夜曾未休，高門世世生賢侯。", "不比平泉碑缺花木記，又非家鴟嘯鳳皇樓。", "洛陽城中亦有園與宅，常同歐陽翰林携酒遊。", "竹閒池館遺翠羽，戶外楊柳繫紫騮。", "今嗟齒似舊屐作博士，嘉趣只與心相仇。", "强騎瘦馬往城北，二十三年如轉頭。", "歸來作此辭，且應主人求。"]'),
('a3914c42-4d99-4ae6-b14a-359efba9faaa','觀楊之美盤車圖','梅堯臣','宋','宋诗','song-poetry','','[]','谷口長松葉老瘦，澗畔古樹身枯高。',184,'全唐诗/poet.song.15000.json','["谷口長松葉老瘦，澗畔古樹身枯高。", "土山慘憺遠復遠，坡路曲折盤車勞。", "二車迴正轅接軫，繼下三車來嶾嶙。", "過橋已有一乘歇，解牛離軛童可哂。", "黄衫烏巾驅舉鞭，經險就易將及前。", "轂輪傍側輻可數，蹄角攙錯捲箱聯。", "古絲昏晦三尺絹，畫此當是展子虔。", "坐中識別有公子，意思往往疑魏賢。", "子虔與賢皆妙筆，觀玩磨滅窮歲年。", "塗丹抹青尚欺俗，旱龍雨日猶賣錢。", "是亦可以秘，疑亦不可捐。", "爲君題卷尾，願君世世傳。"]'),
('05d03c0f-50f8-4b1a-9671-3308c8870800','寄許越州','梅堯臣','宋','宋诗','song-poetry','','[]','開元冠蓋裏，無若賀知章。',168,'全唐诗/poet.song.15000.json','["開元冠蓋裏，無若賀知章。", "乞得鏡湖水，洗出明月光。", "行坐鏡與月，身衣羽人裳。", "心存黄庭經，目視白鳥行。", "歲時忽已古，高韻抗彭莊。", "今聞許子春，來守稽山傍。", "稽山風月在，鏡水菰蒲長。", "臘市開梅萼，霰雪凌早芳。", "卧龍生茗舌，鼓角催新陽。", "焙邊可以啜，樹間可以觴。", "賀老於當日，必定無此嘗。", "唯有李白詩，酒船芙蓉香。", "安得效白也，賸載借艅艎。", "與君同醉翁，智慮收肝腸。"]'),
('dc78fac7-b375-4071-b4be-8b8627d3e31f','永叔請賦車螯','梅堯臣','宋','宋诗','song-poetry','','[]','素脣紫錦背，漿味壓蚶菜。',84,'全唐诗/poet.song.15000.json','["素脣紫錦背，漿味壓蚶菜。", "海客穿海沙，拾貯寒潮退。", "王都有美醖，此物實當對。", "相去三千里，貴力致以配。", "翰林文章宗，炙鮮尤所愛。", "旋坼旋沽飲，酒船如落埭。", "殊非北人宜，肥羊噉臠塊。"]'),
('1e0872a8-f8a7-4973-a272-96cf146e11b0','寄題郢州白雪樓','梅堯臣','宋','宋诗','song-poetry','','[]','楚之襄王問於宋玉，玉時對以郢中歌。',144,'全唐诗/poet.song.15000.json','["楚之襄王問於宋玉，玉時對以郢中歌。", "歌爲白雪陽春曲，始唱千人和，再唱百人逐。", "至此和者纔數人，乃知高調難隨俗。", "後來感槩起危樓，足接浮雲聲出屋。", "中古客應無，怊悵鯤魚孟諸宿。", "樓傾復構春又春，酒瀉瑠璃烹錦鱗。", "青山繞欄看不盡，眼穿盪槳石城人。", "去知何在，寒花雨歛自生嚬。", "今聞太守新梁棟，試選清喉可動塵。"]'),
('acdb2cde-d92b-4487-baa6-7616042cd8de','和永叔答劉原甫遊平山堂寄','梅堯臣','宋','宋诗','song-poetry','','[]','黄土坡陁岡頂寺，青煙羃歷浙西山。',64,'全唐诗/poet.song.15000.json','["黄土坡陁岡頂寺，青煙羃歷浙西山。", "半荒樵牧舊城下，一月陰晴連嶼間。", "人指廢興都莫問，眼看今古總輸閑。", "劉郎寄詠公酬處，夜對金鑾步輦還。"]'),
('20c51585-2d7c-4bed-ad33-b0fb1e967406','平山堂留題','梅堯臣','宋','宋诗','song-poetry','','[]','蜀岡莽蒼臨大邦，雄雄太守駐旌幢。',96,'全唐诗/poet.song.15000.json','["蜀岡莽蒼臨大邦，雄雄太守駐旌幢。", "相基樹楹氣勢厖，千山飛影橫過江。", "峯嶠俯仰如奔降，雷塘坡小鸂鶒雙。", "陸羽井苔黏瓦缸，煎鐺瀉鼎聲淙淙。", "雨牙鳥爪不易得，碾雪恨無居士龐。", "已見宣城謝公陋，吟看遠岫通高窗。"]'),
('e07db22b-d7f6-4d56-bea7-49a10bc72d1b','答張子卿秀才','梅堯臣','宋','宋诗','song-poetry','','[]','茫茫九土中，天網該時秀。',288,'全唐诗/poet.song.15000.json','["茫茫九土中，天網該時秀。", "有鳳不收羅，有麟不獲狩。", "賢豪爲咨嗟，都邑誦瓊琇。", "而我當是時，欲見恨未遘。", "忽過廣平居，遇子乃邂逅。", "懷中二新篇，幸出洗昏瞀。", "一美韓公子，一語南方寇。", "鏗然青琅玕，交戛風雨驟。", "輒用告衆多，亦未甚便售。", "固知至珍物，不入市井貿。", "昨朝驚扉鳴，始悟子來扣。", "鉅編高貯襟，細卷仍函袖。", "麻衣踏犀靴，再拜謹以授。", "因之重感愴，世德實有舊。", "文體古爲徒，家聲喜能又。", "其間贊愚辭，愧累將恐詬。", "摩拂李杜光，誠與日月鬭。", "退之心伏降，安得此孤陋。", "豈能造春榮，豈解易星宿。", "一身猶寒饑，生未飽蔾豆。", "高高河漢流，肯下借湔漱。", "蟲魚儻無施，捉撮不乖繆。", "聊此慰窮愁，文章終莫就。", "庭前枯石榴，寒雀並清晝。"]'),
('4324ab32-955b-4e18-b988-646423f4e64f','江鄰幾學士寄酥梨','梅堯臣','宋','宋诗','song-poetry','','[]','興平烹瓊乳，咸陽摘冰枝。',48,'全唐诗/poet.song.15000.json','["興平烹瓊乳，咸陽摘冰枝。", "秦女點山日，張公開谷時。", "刻破玉漿壺，泛融金酒巵。", "適從關中寄，不見博士卑。"]'),
('fca48003-ca0e-4bb1-a6f7-bf627f66783f','答劉原甫寄糟薑','梅堯臣','宋','宋诗','song-poetry','','[]','名國萬家城，千畦等封侯。',120,'全唐诗/poet.song.15000.json','["名國萬家城，千畦等封侯。", "劚當燕去前，醃牙費糟丘。", "無筋偃王笑，有味三閭羞。", "寄入翰林席，聖以不撤優。", "又寄蓬門下，作賦誰肯休。", "唯我廣文舍，免爲齏鹽仇。", "劉公漢家裔，才學歆向儔。", "胸懷飽經史，辨論出九州。", "曾不奉權貴，但與故人投。", "贈辛非贈甘，此意當自求。"]'),
('8ffe9fd6-3dc8-48b3-be0e-97772cb4668f','銅雀硯','梅堯臣','宋','宋诗','song-poetry','','[]','歌舞人已死，臺殿棟已傾。',132,'全唐诗/poet.song.15000.json','["歌舞人已死，臺殿棟已傾。", "舊基生黑棘，古瓦埋深耕。", "玉質先骨朽，松棟爲埃輕。", "築緊風雨剝，埏和鉛膏精。", "不作鴛鴦飛，乃有科斗情。", "磨失沙礫粗，扣知金石聲。", "初求畎畝下，遂厠几席清。", "入用固爲貴，論古莫與并。", "端溪割紫雲，空負世上名。", "韓著毛穎傳，何獨稱陶泓。", "儻以較歲年，泓當視如兄。"]'),
('df41414e-5ce0-48d4-926d-20ea44f9f807','歐陽永叔王原叔二翰林韓子華吳長文二舍人同過弊廬值出不及見','梅堯臣','宋','宋诗','song-poetry','','[]','枯竹爲門扉，不可容車騎。',132,'全唐诗/poet.song.15000.json','["枯竹爲門扉，不可容車騎。", "況如鄭廣文，無氊藉賓位。", "窮冬月破七，貴客聯玉轡。", "傳騶肅里閭，下榻呼童稚。", "問我何所往，共留牆上字。", "兒愚不知誰，金章言照地。", "既屈卿大夫，恨莫親帚篲。", "星躔回已高，麟趾寧復至。", "戢戢鄰巷居，相見竊自喟。", "豈料瘦老翁，能令賢達至。", "昔時蓬蒿徑，安有此盛事。"]'),
('b565b598-6873-49ab-94ef-c9cfd90e4ce8','元忠示胡人下程圖','梅堯臣','宋','宋诗','song-poetry','','[]','單于獵罷卧錦紅，解鞍休騎荒磧中。',160,'全唐诗/poet.song.15000.json','["單于獵罷卧錦紅，解鞍休騎荒磧中。", "蒼駒騧駱六十匹，隠谷映坡分尾鬉。", "九駞五牛羊頗倍，沙草晚牧生寒風。", "貴賤小大指五百，執作意態皆不同。", "二鷹在臂二鷹架，駿犬當對寧爭功。", "氊廬鼎列帳幙擁，鼓角未吹驚塞鴻。", "土山高高置烽燧，毛囊貯獲閑刀弓。", "水泉在側挹其上，長河杳杳流無窮。", "素紈六幅筆何巧，胡瓌盡妙誰能通。", "今日都城有別識，別識共許劉元忠。"]'),
('b6348597-f212-4ff0-92a5-95256e315a10','送李太保知儀州','梅堯臣','宋','宋诗','song-poetry','','[]','出塞開牙帳，論兵啟玉鈐。',48,'全唐诗/poet.song.15000.json','["出塞開牙帳，論兵啟玉鈐。", "漢泉思白馬，秦冢弔蒙恬。", "族本西山大，聲從渭北兼。", "相如嘗學劍，文士亦何嫌。"]'),
('fd17d9c1-fe0e-45de-920b-8ad9c8de7ba6','劉元忠遺金橘','梅堯臣','宋','宋诗','song-poetry','','[]','南方生美果，具體橘包微。',48,'全唐诗/poet.song.15000.json','["南方生美果，具體橘包微。", "韓彈有輕薄，楚萍知是非。", "甘香奉華俎，咀嚼破明璣。", "欲換齏鹽腹，盈匳忽我歸。"]'),
('582a3352-8b35-4e59-9e6c-1e5041156bed','王原叔內翰宅觀山水圖','梅堯臣','宋','宋诗','song-poetry','','[]','石蒼蒼，連峭峯，大山嵯峨雲霧中。',108,'全唐诗/poet.song.15000.json','["石蒼蒼，連峭峯，大山嵯峨雲霧中。", "老松瘦樹無筆蹤，巧奪造化何能窮。", "古絹脆裂再黏續，氣象一似高高嵩。", "上有荆浩字，特歸翰林公。", "願換廷圭一丸墨，誰言賣錢須青銅。", "范寬到老學未足，李成但得平遠工。", "黄金白璧未爲貴，丈人師臣無不通。"]'),
('f9cc981a-0901-442b-b24a-2c156403af3c','送廖倚歸衡山','梅堯臣','宋','宋诗','song-poetry','','["\u8861\u5c71", "\u6d1e\u5ead\u6e56"]','雌猿夜啼別湘東，曉尋故人背孤桐。',144,'全唐诗/poet.song.15000.json','["雌猿夜啼別湘東，曉尋故人背孤桐。", "孤桐有聲彈不響，弦絕曲在埋蒿蓬。", "知音萬古期必逢，今日已聞天下雄。", "陟山涉水不辭遠，文章大名居禁中。", "扣門一見顔色喜，抱琴三歎含徵宮。", "九疇不汨微禹力，堯舜豈無明與聰。", "推根致本賢意合，敘述況值太史公。", "貿金得玉莫忘寶，却過洞庭乘朔風。", "猿休啼月月色好，還來舊山伴狙翁。"]'),
('80c6da61-334f-49ce-8af4-14d056959f0d','還吳長文舍人詩卷','梅堯臣','宋','宋诗','song-poetry','','[]','松液化茯苓，又因爲琥珀。',240,'全唐诗/poet.song.15000.json','["松液化茯苓，又因爲琥珀。", "遇物必得形，毛髮曾不隔。", "君子亦豹變，其文蔚可覿。", "今者逢吳侯，滿腹貯經籍。", "噴吐五色霓，自堪垂典冊。", "詩教始二南，皆著賢聖跡。", "後世竟翦裁，破碎隨刀尺。", "我輩强追倣，畫龍成蜥蜴。", "有唐文最盛，韓伏甫與白。", "甫白無不包，甄陶咸所索。", "侯初守二郡，山水多助益。", "升高觴嘉賓，賦筆速鷹翮。", "葺書成大軸，許我觀琮璧。", "真物固易辨，恨無百金易。", "借從懷袖歸，誦玩廢朝夕。", "譬如遊國都，惝怳失阡陌。", "苦吟三十年，所獲唯巾幗。", "豈比夸受降，甲齊熊耳積。", "重見元和風，珠玉敵海舶。", "自慙寒餓爲，何張空避席。"]'),
('95a8450f-88f1-4a79-aa9a-3d947b96aa58','和正月六日沈文通學士遺溫柑','梅堯臣','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','禹書貢厥包，未知黄柑美。',60,'全唐诗/poet.song.15000.json','["禹書貢厥包，未知黄柑美。", "競傳洞庭熟，又莫永嘉比。", "適觀隠侯詩，獲此殊可喜。", "誦句擘露囊，香甘冷熨齒。", "明朝鏁禮闈，何暇醉鄰里。"]'),
('c571f929-da8d-4643-a046-b9d67816436a','史供奉羣鶴','梅堯臣','宋','宋诗','song-poetry','','["\u592a\u6e56"]','出珥銀貂侍太清，迴看雙鶴舞中庭。',64,'全唐诗/poet.song.15000.json','["出珥銀貂侍太清，迴看雙鶴舞中庭。", "翩翩曾是仙人驥，兩兩尚儀君子形。", "靜夜欲還緱嶺月，終朝思啑太湖萍。", "莫將樹上雞相並，會待歸飛向杳冥。"]'),
('aee92417-d593-4603-ad44-e9e36e94ed9b','雪竇達觀禪師見寄依韻答','梅堯臣','宋','宋诗','song-poetry','','[]','巖竇常留雪，山雪不有心。',48,'全唐诗/poet.song.15000.json','["巖竇常留雪，山雪不有心。", "禪衣百衲重，香剎四明深。", "馴鹿來銜果，栽松去作林。", "自緣冠紱累，未解遠公尋。"]'),
('682fad37-9517-45bf-98fb-6f08c36126a1','和孫端叟寺丞農具十五首 田廬','梅堯臣','宋','宋诗','song-poetry','','[]','結廬野田中，其高足以覘。',48,'全唐诗/poet.song.15000.json','["結廬野田中，其高足以覘。", "坐卧劣自容，巢棲未嘗厭。", "但能風雨蔽，何惜茅蓬苫。", "終當收刈畢，寂寞慙山店。"]'),
('b383109c-e62d-47b5-8277-108fb296c36a','和孫端叟寺丞農具十五首 颺扇','梅堯臣','宋','宋诗','song-poetry','','[]','白扇非團扇，每來場圃見。',48,'全唐诗/poet.song.15000.json','["白扇非團扇，每來場圃見。", "因風吹糠籺，編竹破筠箭。", "任從高下手，不爲暄寒變。", "去粗而得精，持之莫言倦。"]'),
('c7ac7f4f-955c-4d87-95d1-2a566b17fa71','和孫端叟寺丞農具十五首 摟','梅堯臣','宋','宋诗','song-poetry','','[]','農人力已勤，要在布嘉種。',48,'全唐诗/poet.song.15000.json','["農人力已勤，要在布嘉種。", "手持高斗柄，觜瀉三犂壠。", "月下叱黄犢，原邊過廢冢。", "安知俠少年，玉食金羈擁。"]'),
('1d82d0cc-373a-4705-ae58-4576fc28868d','和孫端叟寺丞農具十五首 樵斧','梅堯臣','宋','宋诗','song-poetry','','[]','適從伐枯桑，莫悟刃已缺。',48,'全唐诗/poet.song.15000.json','["適從伐枯桑，莫悟刃已缺。", "蠶工向欲迫，田事不可徹。", "丁丁背谷聲，役役持柯熱。", "積薪高於山，焉用先後別。"]'),
('1c3310cd-4452-4a70-9b12-eded4163c8a4','和孫端叟寺丞農具十五首 耒耜','梅堯臣','宋','宋诗','song-poetry','','[]','古聖通物宜，揉斲資粒食。',48,'全唐诗/poet.song.15000.json','["古聖通物宜，揉斲資粒食。", "稼穡盡民勤，墾耕窮地力。", "推化本神農，維時思后稷。", "我老欲歸田，茲器已先識。"]'),
('8bf67016-567e-4b64-a84c-fcd7da0b65ef','和孫端叟寺丞農具十五首 錢鎛','梅堯臣','宋','宋诗','song-poetry','','[]','詩稱庤錢鎛，南畝興農作。',48,'全唐诗/poet.song.15000.json','["詩稱庤錢鎛，南畝興農作。", "寧唯務芟薙，豈不在刈穫。", "收功向嘉穀，託用隨芒屩。", "太平茲所重，坐見銷鋒鍔。"]'),
('4917774b-de63-444a-a0d8-663349dbb6c2','和孫端叟寺丞農具十五首 耰鋤','梅堯臣','宋','宋诗','song-poetry','','[]','蕪穢或不治，良苗安得長。',48,'全唐诗/poet.song.15000.json','["蕪穢或不治，良苗安得長。", "薅來露未晞，荷去月初上。", "侵煙濕鵝頸，近茇翻蟻壤。", "生具自有餘，何辭汗沾顙。"]'),
('b09ec806-e4e4-49e8-b126-b85a6f033e5a','和孫端叟寺丞農具十五首 襏襫','梅堯臣','宋','宋诗','song-poetry','','[]','上襏與下襫，青蓑苦能織。',48,'全唐诗/poet.song.15000.json','["上襏與下襫，青蓑苦能織。", "曉披春雨來，晚曬陽坡側。", "蔽身常自足，衝濕曾爲得。", "任從野風吹，已敵寒蓬色。"]'),
('f0689276-3f60-4a71-9a2e-7cffb77a338e','和孫端叟寺丞農具十五首 臺笠','梅堯臣','宋','宋诗','song-poetry','','[]','力田冒風雨，緝籜爲臺笠。',48,'全唐诗/poet.song.15000.json','["力田冒風雨，緝籜爲臺笠。", "寒蓑相與用，陰野低迷入。", "足屨固易濡，鬢葆何嘗濕。", "斯須未可去，赫日資乃急。"]'),
('d401fa35-d35e-452d-a175-c6c225038649','和孫端叟寺丞農具十五首 耕牛','梅堯臣','宋','宋诗','song-poetry','','[]','破領耕不休，何暇顧羸犢。',48,'全唐诗/poet.song.15000.json','["破領耕不休，何暇顧羸犢。", "夜歸喘明月，朝出穿深谷。", "力雖窮田疇，腸未飽芻粟。", "稼收風雪時，又向寒坡牧。"]'),
('8c4d5d38-1c12-4c2c-b754-5beea09914a7','和孫端叟寺丞農具十五首 牛衣','梅堯臣','宋','宋诗','song-poetry','','[]','覆牛畏嚴霜，愛之如愛子。',48,'全唐诗/poet.song.15000.json','["覆牛畏嚴霜，愛之如愛子。", "朔風吹欄牢，禦凍頼苴枲。", "惡薄將異韉，貧棲乃同被。", "重畜不忘劬，老農非可鄙。"]'),
('6c3481bd-ede2-42b3-af1b-330b8d85d71a','和孫端叟寺丞農具十五首 水車','梅堯臣','宋','宋诗','song-poetry','','[]','既如車輪轉，又若川虹飲。',48,'全唐诗/poet.song.15000.json','["既如車輪轉，又若川虹飲。", "能移霖雨功，自致禾苗稔。", "上傾成下流，損少以益甚。", "漢陰抱甕人，此理未可諗。"]'),
('b33a71c9-2eb8-4b42-902e-0e33775631af','和孫端叟寺丞農具十五首 田漏','梅堯臣','宋','宋诗','song-poetry','','[]','瓦罌貯谿流，滴作耘田漏。',48,'全唐诗/poet.song.15000.json','["瓦罌貯谿流，滴作耘田漏。", "不爲陰晴惑，用識早暮候。", "辛勤無侵星，簡易在白晝。", "同功以爲準，一决不可又。"]'),
('646f034a-eec6-449d-90c6-498c278d7d20','和孫端叟寺丞農具十五首 耘鼓','梅堯臣','宋','宋诗','song-poetry','','[]','挂鼓大樹枝，將以一耘耔。',48,'全唐诗/poet.song.15000.json','["挂鼓大樹枝，將以一耘耔。", "逢逢達遠近，汨汨來田里。", "功既由此興，餉亦從此始。", "固殊調猿猴，欲取兒童喜。"]'),
('d0f1ca7e-9767-4278-b37c-891fec077721','和孫端叟寺丞農具十五首 牧笛','梅堯臣','宋','宋诗','song-poetry','','[]','牧人樂下牧，背騎吹短笛。',48,'全唐诗/poet.song.15000.json','["牧人樂下牧，背騎吹短笛。", "聲穿吳雲低，韻入楚梅的。", "誰嗟苦調急，自與幽意寂。", "應同堯時民，歌將土壤擊。"]'),
('d87eebbe-1206-4803-a60e-d1d4deb343d7','和孫端叟蠶具十五首 繭館','梅堯臣','宋','宋诗','song-poetry','','[]','漢儀后親蠶，採桑來繭館。',48,'全唐诗/poet.song.15000.json','["漢儀后親蠶，採桑來繭館。", "雲母飾車上，鉤籠載車畔。", "援條露已乾，受葉日將晏。", "爲言天下婦，茲事不可慢。"]'),
('b84faf6e-c45e-4147-afb9-60fdc89c6baa','和孫端叟蠶具十五首 織室','梅堯臣','宋','宋诗','song-poetry','','[]','常聞漢皇后，織室數來觀。',48,'全唐诗/poet.song.15000.json','["常聞漢皇后，織室數來觀。", "宮女豈不勤，帝衮得以完。", "亦將成纁黄，非用競龍鸞。", "意在奉宗廟，後人其可安。"]'),
('797e4cb3-0da6-44f5-a9a8-5afd02713936','和孫端叟蠶具十五首 桑原','梅堯臣','宋','宋诗','song-poetry','','[]','原上種良桑，桑下種茂麥。',48,'全唐诗/poet.song.15000.json','["原上種良桑，桑下種茂麥。", "雉雊麥秀時，蠶眠葉休摘。", "空條漏日多，餘椹更誰惜。", "會待黄落來，酒壚燒斗石。"]'),
('a9fc9a00-df21-4fa5-bedc-888db21f2dcf','和孫端叟蠶具十五首 高几','梅堯臣','宋','宋诗','song-poetry','','[]','桑柔不倚梯，摘桑頼高几。',48,'全唐诗/poet.song.15000.json','["桑柔不倚梯，摘桑頼高几。", "每於得葉易，曾靡憂校披。", "躋陞類拾級，下上異緣蟻。", "閑置草屋傍，鳴雞或棲止。"]'),
('8cbd1d2a-b63f-47a2-bb3a-1321d3c1a669','和孫端叟蠶具十五首 科斧','梅堯臣','宋','宋诗','song-poetry','','[]','科桑持野斧，乳濕新磨刃。',48,'全唐诗/poet.song.15000.json','["科桑持野斧，乳濕新磨刃。", "繁枿一去除，肥條更豐潤。", "魯葉大如掌，吳蠶食若駿。", "始時人謂戕，利倍今乃信。"]'),
('f74ace21-2ffc-4653-9c7a-515e4bf2816f','和孫端叟蠶具十五首 桑鉤','梅堯臣','宋','宋诗','song-poetry','','[]','長鉤扳桑枝，短鉤挂桑籠。',48,'全唐诗/poet.song.15000.json','["長鉤扳桑枝，短鉤挂桑籠。", "南陌露氣寒，東方日光動。", "少婦首且笄，幼女角已𩮰。", "競以採葉歸，曾非事梳櫳。"]'),
('ad5f9d17-b8a7-429e-90ba-dffa5cc0b16b','和孫端叟蠶具十五首 桑筥','梅堯臣','宋','宋诗','song-poetry','','[]','采采向桑郊，盈盈自持筥。',48,'全唐诗/poet.song.15000.json','["采采向桑郊，盈盈自持筥。", "挂鉤带月往，稚葉和煙貯。", "一心恐蠶饑，搔首促儔侶。", "到家傾嫩綠，刀几爲㕮咀。"]'),
('9761f3ee-fdb0-471c-b099-02b2171abf70','和孫端叟蠶具十五首 蠶女','梅堯臣','宋','宋诗','song-poetry','','[]','自從蠶蟻生，日日憂蠶冷。',48,'全唐诗/poet.song.15000.json','["自從蠶蟻生，日日憂蠶冷。", "草室常自溫，雲髻未暇整。", "但采原上桑，不顧門前杏。", "辛苦得絲多，輸官官莫省。"]'),
('47277b3a-413a-4847-bc24-d42c1fa7e339','和孫端叟蠶具十五首 蠶簇','梅堯臣','宋','宋诗','song-poetry','','[]','冰蠶三眠休，作繭當具簇。',48,'全唐诗/poet.song.15000.json','["冰蠶三眠休，作繭當具簇。", "漢北取蓬蒿，江南藉茅竹。", "蒿疎無鬰浥，竹浄亦森束。", "競畏風雨寒，露置未如屋。"]'),
('99dad81d-86a4-41ad-b200-f0aec22916a6','和孫端叟蠶具十五首 蠶槌','梅堯臣','宋','宋诗','song-poetry','','[]','三月將掃蠶，蠶妾具其器。',48,'全唐诗/poet.song.15000.json','["三月將掃蠶，蠶妾具其器。", "丘植先㧹括，辟室亦塗塈。", "衆材疎以成，多薄所得寄。", "拾老歸簇時，應無慙棄置。"]'),
('e5433019-2008-459d-b104-c2862913ca9b','和孫端叟蠶具十五首 蠶薄','梅堯臣','宋','宋诗','song-poetry','','[]','河上緯蕭人，女歸又織葦。',48,'全唐诗/poet.song.15000.json','["河上緯蕭人，女歸又織葦。", "相與爲蠶曲，還殊作筠篚。", "入用此何多，往售獲能幾。", "願豐天下衣，不歎貧服卉。"]'),
('32d1d3cc-6cc0-455d-9666-d02c822c8aa0','和孫端叟蠶具十五首 繰盎','梅堯臣','宋','宋诗','song-poetry','','[]','朝漬一盎繭，繰就幾絢絲。',48,'全唐诗/poet.song.15000.json','["朝漬一盎繭，繰就幾絢絲。", "絲成繭已盡，盎亦誰復持。", "道上有墮甑，車傍有鴟夷。", "二物且莫笑，顧藉各因時。"]'),
('da6554f3-fe68-427b-bcdd-3844ab83a375','和孫端叟蠶具十五首 紡車','梅堯臣','宋','宋诗','song-poetry','','[]','蠶月必紡績，絲車方挑擲。',48,'全唐诗/poet.song.15000.json','["蠶月必紡績，絲車方挑擲。", "燈下絡緯鳴，林端河漢白。", "纖縷自有緒，虛輪運無跡。", "腕手已爲勞，誰經用刀尺。"]'),
('56672ab9-295e-4f8c-b4c7-98ac4556dbe1','和孫端叟蠶具十五首 龍梭','梅堯臣','宋','宋诗','song-poetry','','[]','給給機上梭，往反如度日。',48,'全唐诗/poet.song.15000.json','["給給機上梭，往反如度日。", "一經復一絲，成寸遂成匹。", "虛腹銳兩端，素手投未出。", "陶家挂壁間，雷雨龍飛出。"]'),
('277f8a6d-0a1d-4e11-960e-24e7c85c28a4','和孫端叟蠶具十五首 織婦','梅堯臣','宋','宋诗','song-poetry','','[]','織婦手不停，心與日月速。',48,'全唐诗/poet.song.15000.json','["織婦手不停，心與日月速。", "常憂里胥來，不待雞黍熟。", "但言督縣官，立要斷機軸。", "誰知公侯家，賜帛堆滿屋。"]'),
('4da6cbee-ec03-4c9b-ad65-c6c2c13eb38d','上元從主人登尚書省東樓','梅堯臣','宋','宋诗','song-poetry','','[]','閶闔前臨萬歲山，燭龍銜火夜珠還。',64,'全唐诗/poet.song.15000.json','["閶闔前臨萬歲山，燭龍銜火夜珠還。", "高樓迥出星辰裏，曲蓋遥瞻紫翠間。", "轣轆車聲碾明月，參差蓮焰競紅顔。", "誰教言語如鸚鵡，便著金籠密鎖關。"]'),
('883d6d4a-4ec1-48fe-b385-9880c8a19951','自和','梅堯臣','宋','宋诗','song-poetry','','[]','沉水香焚金博山，杜陵誰復與車還。',64,'全唐诗/poet.song.15000.json','["沉水香焚金博山，杜陵誰復與車還。", "馬尋綺陌知何曲，人在珠簾第幾間。", "法部樂聲長滿耳，上樽醇味易酡顔。", "更貧更賤皆能樂，十二重門不上關。"]'),
('dad8893a-0214-461d-8c2e-725baf83825e','又和','梅堯臣','宋','宋诗','song-poetry','','[]','康莊咫尺有千山，欲問紫姑應已還。',64,'全唐诗/poet.song.15000.json','["康莊咫尺有千山，欲問紫姑應已還。", "人似常娥來陌上，燈如明月在雲間。", "車頭小女雙垂髻，簾裏新粧一破顔。", "却下玉梯雞已唱，謾言齊客解偷關。"]'),
('ff2e797d-dc5f-4d65-9e9b-63afa703977c','和公儀龍圖戲勉','梅堯臣','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','五公雄筆厠其間，媿似丘陵擬泰山。',32,'全唐诗/poet.song.15000.json','["五公雄筆厠其間，媿似丘陵擬泰山。", "豈意來嘲飯顆句，忙中唯此是偷閑。"]'),
('2a048675-e4c8-4ba2-b0a4-007ba5945c36','再和公儀龍圖','梅堯臣','宋','宋诗','song-poetry','','[]','千重海浪漁人醉，百戰沙場野叟閑。',32,'全唐诗/poet.song.15000.json','["千重海浪漁人醉，百戰沙場野叟閑。", "能向鬧中還得靜，乃知朝市即青山。"]'),
('5262e61c-b39d-4ca2-8502-cc2bd41898cd','放鶉','梅堯臣','宋','宋诗','song-poetry','','[]','獸烹羊豬，鳥烹鴨雞。',64,'全唐诗/poet.song.15000.json','["獸烹羊豬，鳥烹鴨雞。", "唯鶉不殺，置奴而携。", "公坐堂上，見而悲悽。", "急令開笯還故棲，其間無力飛不齊。", "公只知魚之洋洋，鵝之鶂鶂。", "噫兮噫兮。"]'),
('ce05b252-5764-4bfa-9337-c8a7a61853f3','莫登樓','梅堯臣','宋','宋诗','song-poetry','','[]','莫登樓，脚力雖健勞雙眸，下見紛紛馬與牛。',136,'全唐诗/poet.song.15000.json','["莫登樓，脚力雖健勞雙眸，下見紛紛馬與牛。", "馬矜鞍轡牛服輈，露臺歌吹聲不休。", "腰鼓百面紅臂褠，先打六幺後梁州。", "棚簾夾道多夭柔，鮮衣壯僕獰髭虬。", "寶撾呵叱倚王侯，夸妍鬭豔目已偷。", "天寒酒醺誰爾侜，倚楹心往形獨留，有此光景無能遊。", "粉署深沉空翠幬，青綾被冷風颼颼。", "懷抱既如此，何須望樓頭。"]'),
('84e92d22-3a7c-4135-a80b-d8307fa07895','莫飲酒','梅堯臣','宋','宋诗','song-poetry','','[]','莫飲酒，酒豈讎，顔回不飲不白頭。',76,'全唐诗/poet.song.15000.json','["莫飲酒，酒豈讎，顔回不飲不白頭。", "千鍾稱帝堯，百觚號聖丘。", "定國數石無滯留，康成三百盃未休。", "阮籍作詩語更遒，聖賢在前誰與謀。", "喉乾舌强須潤柔，照見文字勝膏油。"]'),
('650526a7-1ae5-44e6-a7bc-9cd02e588fa8','依韻和永叔勸飲酒莫吟詩雜言','梅堯臣','宋','宋诗','song-poetry','','[]','我生無所嗜，唯嗜酒與詩。',144,'全唐诗/poet.song.15000.json','["我生無所嗜，唯嗜酒與詩。", "一日舍此心腸悲，名存貴大不輙思。", "甑空釜冷不俛眉，妻孥凍饑數恚之。", "但自吟醉與世違，此外萬事皆莫知。", "王公謁請衆去早，既衰愈懶身到遲。", "日高倦僕顔色沮，况騎瘦馬兩耳垂。", "厭此勞苦不喜出，唯有文字時能爲。", "諸公尚恐竭智慮，勤勤勸飲莫我卑。", "再拜受公言，竊意公矯時。", "只愛詩，謂余癡。"]'),
('39435335-1e34-46ca-9bc6-d39ab514bded','和永叔內翰','梅堯臣','宋','宋诗','song-poetry','','[]','來時擘蠒正探官，走馬傳宣夾路看。',64,'全唐诗/poet.song.15000.json','["來時擘蠒正探官，走馬傳宣夾路看。", "便鏁青春辭上閤，徒知白日近長安。", "思歸有夢同誰說，强意題詩只自寬。", "猶喜共量天下士，亦勝東野亦勝韓。"]'),
('d2e5a935-e1d2-46b9-9b48-3644e17b9799','和公儀龍圖憶小鶴','梅堯臣','宋','宋诗','song-poetry','','[]','聞憶華亭雙鶴雛，蒼毛未變頂微朱。',64,'全唐诗/poet.song.15000.json','["聞憶華亭雙鶴雛，蒼毛未變頂微朱。", "閑情且與稻粱飽，寄語休將雞鶩驅。", "丁令再歸移歲月，王襃端爲約僮奴。", "主人必欲看飛舞，太液池寬肯放無。"]'),
('d51023ea-048c-453f-8260-f15fd8dbbfd2','和永叔內翰思白兔答憶鶴雜言','梅堯臣','宋','宋诗','song-poetry','','[]','醉翁在東堂，爲他栽桂樹。',204,'全唐诗/poet.song.15000.json','["醉翁在東堂，爲他栽桂樹。", "待將枝條與人折，憶著家中玉色兔。", "夜看明月海上來，光彩離離入庭戶。", "且問常娥一借觀，翁家雖有來無路。", "常娥對面幾萬里，不聲漸漸西南去。", "是時翁生懷抱惡，却恨陸機先憶鶴。", "致令亦念眼迷離，不似傍池能飲啄。", "始憂兔饑僮失哺，又恐白毛塵土汙。", "仍不如鶴有淺泉，自在引吭時刷羽。", "花前舉翅鼓春風，只待公歸向朝暮。", "我聞二公趣向殊，一養月中物，一養華亭雛。", "一畏奔海窟，一畏巢松株。", "我雖老矣無物惑，欲去東家看舞姝。"]'),
('68f887ca-451f-4d0f-9f3d-261c9c11bef0','和永叔內翰戲答','梅堯臣','宋','宋诗','song-poetry','','[]','從他舞姝笑我老，笑終是喜不是惡。',93,'全唐诗/poet.song.15000.json','["從他舞姝笑我老，笑終是喜不是惡。", "固勝兔子固勝鶴，四蹄撲握長啄啄。", "任看色與月光混，只欲走飛情意薄。", "拘之以籠縻以索，必不似纖腰夸綽約。", "主人既賢豪，能使賓客樂。", "便歸膏面染髭鬚，從今宴會應頻數。"]'),
('635cc39b-7e63-4c23-87ed-80f81e2f9ae2','二月五日雪','梅堯臣','宋','宋诗','song-poetry','','[]','二月狂風雪，寒威曉更加。',48,'全唐诗/poet.song.15000.json','["二月狂風雪，寒威曉更加。", "省闈輕妬粉，苑樹暗添花。", "有夢皆蝴蝶，逢袍只紵麻。", "凍吟誰料我，相與賭流霞。"]'),
('15fa869f-5c7e-47e7-994f-866f08a0d511','和公儀龍圖小桃花','梅堯臣','宋','宋诗','song-poetry','','[]','三分春色一分休，始見桃花著樹頭。',32,'全唐诗/poet.song.15000.json','["三分春色一分休，始見桃花著樹頭。", "霰雪斗來如約勒，爲公留作上林遊。"]'),
('d5ea6924-1315-4599-9a86-d0167fe11404','感李花','梅堯臣','宋','宋诗','song-poetry','','[]','重門雖鏁春風入，先坼桃花後李花。',64,'全唐诗/poet.song.15000.json','["重門雖鏁春風入，先坼桃花後李花。", "赤白鬭妍思舊曲，舊聲傳在五王家。", "五王不見留華萼，華萼壞來碑缺落。", "當時李白欲騎黥，醉向江南曾不錯。"]'),
('71d4255d-1549-4467-8d67-8bd1b8d97e37','琴高魚和公儀','梅堯臣','宋','宋诗','song-poetry','','[]','大魚人騎上天去，留得小鱗來按觴。',32,'全唐诗/poet.song.15000.json','["大魚人騎上天去，留得小鱗來按觴。", "吾物吾鄉不須念，太官常膳有肥羊。"]'),
('1f0d59ce-9e43-4da2-9df2-34fc9e7da94d','嘗茶和公儀','梅堯臣','宋','宋诗','song-poetry','','[]','都藍携具向都堂，碾破雲團北焙香。',64,'全唐诗/poet.song.15000.json','["都藍携具向都堂，碾破雲團北焙香。", "湯嫩水輕花不散，口甘神爽味偏長。", "莫夸李白仙人掌，且作盧仝走筆章。", "亦欲清風生兩腋，從教吹去月輪傍。"]'),
('1dd1ceb5-6e73-4e11-a13f-b8eaa07f8fd7','刑部廳看竹效孟郊體和永叔','梅堯臣','宋','宋诗','song-poetry','','[]','蒼蒼庭中竹，事莫歎遲速。',96,'全唐诗/poet.song.15000.json','["蒼蒼庭中竹，事莫歎遲速。", "不同欄下草，一歲一迴綠。", "朝開花照曜，暮落風相逐。", "何如飽霜雪，冬夏森寒玉。", "誰將種官舍，本合近巖屋。", "不可一日無，蕭灑看未足。", "阮生豈其愚，林中醉醽醁。", "我當明月時，移床來此宿。"]'),
('6138dd6d-b335-435a-ad34-c4ea73c01d54','較藝和王禹玉內翰','梅堯臣','宋','宋诗','song-poetry','','[]','分庭答拜士傾心，却下朱簾絕語音。',64,'全唐诗/poet.song.15000.json','["分庭答拜士傾心，却下朱簾絕語音。", "白蟻戰來春日暖，五星明處夜堂深。", "力搥頑石方逢玉，盡撥寒沙始見金。", "淡墨牓名何日出，清明池苑可能尋。"]'),
('ad1ae7a6-1cc3-4f3f-94b6-da7792be7372','再和','梅堯臣','宋','宋诗','song-poetry','','[]','廉纖小雨破花寒，野雀爭巢鬭作團。',64,'全唐诗/poet.song.15000.json','["廉纖小雨破花寒，野雀爭巢鬭作團。", "手卷白雲光引素，舌飛明月響傾盤。", "羣公錦繡爲腸胃，獨我塵埃滿肺肝。", "强應小詩無氣味，猶慙白髮厠郎官。"]'),
('384daf4c-41f4-4cde-b1ba-3e2499979855','謝永叔答述舊之作和禹玉','梅堯臣','宋','宋诗','song-poetry','','[]','天下才名罕有雙，今逢陸海與潘江。',64,'全唐诗/poet.song.15000.json','["天下才名罕有雙，今逢陸海與潘江。", "筆生造化多多辦，聲滿華夷一一降。", "金带繫袍迴禁署，翠娥持燭侍吟窗。", "人間榮貴無如此，誰愛區區擁節幢。"]'),
('252a118d-6f95-456c-97ac-6dd6ee3cdd00','較藝贈永叔和禹玉','梅堯臣','宋','宋诗','song-poetry','','[]','今看座主與門生，事事相同舉世榮。',64,'全唐诗/poet.song.15000.json','["今看座主與門生，事事相同舉世榮。", "並直禁林司詔令，又來西省選豪英。", "飛龍借馬天邊下，光祿供醪月底傾。", "食葉蠶聲句偏美，當時曾記賦將成。"]'),
('6c6c9616-151f-49ae-9a05-05da2061bcde','戲答持燭之句依韻和永叔','梅堯臣','宋','宋诗','song-poetry','','[]','盧仝只有赤脚婢，吏部曾吟似笑仝。',64,'全唐诗/poet.song.15000.json','["盧仝只有赤脚婢，吏部曾吟似笑仝。", "紅燭射眸從結客，清歌帖耳苦憐翁。", "歸時雖已過寒食，芳物猶能逐暖風。", "但點紗籠續清夜，西園遊興古何窮。"]'),
('d2cdcad3-ef1f-4989-a884-7c0b2c8c7117','重答和永叔','梅堯臣','宋','宋诗','song-poetry','','[]','我家唯有一團月，挂在颼颼草屋東。',32,'全唐诗/poet.song.15000.json','["我家唯有一團月，挂在颼颼草屋東。", "玉兔已爲公取玩，更休窺望桂叢中。"]'),
('ca4ce7d5-2ab9-4645-a358-59ad977b72ff','又依韻','梅堯臣','宋','宋诗','song-poetry','','[]','多病相如不復云，更何曾有卓文君。',32,'全唐诗/poet.song.15000.json','["多病相如不復云，更何曾有卓文君。", "他時我向會稽去，只是荆釵與布裙。"]'),
('73a91c59-0205-4a81-9dea-244de960c157','刑部廳海棠見贈依韻答永叔二首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','摇摇牆頭花，蒨蒨有好色。',84,'全唐诗/poet.song.15000.json','["摇摇牆頭花，蒨蒨有好色。", "高枝笑粲粲，低枝明皪皪。", "但與風相撩，不與風相得。", "風吹莫苦急，游子歎日昃。", "彭祖與顔回，相去猶瞬息。", "每觀形影篇，曷在神所釋。", "不可廢我吟，畢竟焉免白。"]'),
('1fb940e2-977b-40d3-9c96-213ca97d16a6','刑部廳海棠見贈依韻答永叔二首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','摇摇牆頭花，一一如舞娥。',72,'全唐诗/poet.song.15000.json','["摇摇牆頭花，一一如舞娥。", "春風買豔逸，豔逸此何多。", "不爲游蜂撓，即爲狂蝶過。", "日光苦給給，魯叟白波波。", "人生若朝菌，不飲奈老何。", "楊雄寂寞居，豈若阮生歌。"]'),
('3fd2ba62-73a4-4581-a00c-0d6d629f13fc','春雨呈主文','梅堯臣','宋','宋诗','song-poetry','','[]','蛟龍上漢魚潛動，梁棟生雲燕未知。',64,'全唐诗/poet.song.15000.json','["蛟龍上漢魚潛動，梁棟生雲燕未知。", "風點稍聞寒瓦急，玉條初向畫簷垂。", "何郎夜聽應逢句，謝朓朝觀必有詩。", "老大莫將文字困，爲公牽强不勝疲。"]'),
('4355b055-6f71-4f45-9cfa-d7a2df963c05','謝鷴和公儀','梅堯臣','宋','宋诗','song-poetry','','[]','聞有白鷴夢，遂作白鷴詩。',240,'全唐诗/poet.song.15000.json','["聞有白鷴夢，遂作白鷴詩。", "詩記白鷴語，意公於鶴私。", "公意無薄厚，爾將聽我辭。", "朝給一瓢水，晝給一盎糜。", "曾不令爾渴，曾不令爾饑。", "事事不異鶴，安得於鶴疑。", "鶴鳴爾不和，鶴舞爾不隨。", "無以一供悅，飽食番頑癡。", "公所念爾久，李白當畜之。", "白固有篇詠，公偶未暇爲。", "遣爾心不平，謂此鈍見遺。", "我持爾此意，請公吟莫遲。", "公便納我言，濡筆灑淋漓。", "書爾在南言，野羽霜雪披。", "弄啄紅豆實，飛上桄榔枝。", "翡翠不敢顧，孔雀不敢窺。", "將擬是白鳳，脩尾晝漣漪。", "虺頸而雞首，峨峨如有儀。", "而今與鶴爭，此識固已卑。", "公初待爾厚，鷴兮知不知。"]'),
('142d8fce-4e2f-4fcb-bef2-2f16649e09c1','較藝將畢和禹玉','梅堯臣','宋','宋诗','song-poetry','','[]','窗前高樹有棲鵲，記取明朝飛向東。',64,'全唐诗/poet.song.15000.json','["窗前高樹有棲鵲，記取明朝飛向東。", "家在望春門外住，身居華省信難通。", "夜聞相府催張牓，曉聽都堂議奏中。", "龍閣鳳池人漸隔，猶因朝謁望鼇宮。"]'),
('06adbf48-ddab-415a-9a10-aaf390a3fbd7','送白鷴與永叔依韻和公儀','梅堯臣','宋','宋诗','song-poetry','','[]','致鷴猶恐鷴饑渴，細織筠籠小瓦缸。',64,'全唐诗/poet.song.15000.json','["致鷴猶恐鷴饑渴，細織筠籠小瓦缸。", "玉免精神憐已久，金鑾人物世無雙。", "休爭白鶴臨清沼，且伴鳴雞向綠窗。", "美羽奇毛有多少，爾身高穩勝他邦。"]'),
('6b3184cf-fe8c-4d19-9359-730d45081c75','書事和韓子華舍人','梅堯臣','宋','宋诗','song-poetry','','[]','見憑蝴蝶過牆飛，却夢翩然入綺闈。',32,'全唐诗/poet.song.15000.json','["見憑蝴蝶過牆飛，却夢翩然入綺闈。", "欲撲翅輕縈不住，覺時疑有粉沾衣。"]'),
('8a1c2733-3f5a-49e9-9187-7c0345c223a8','明經試大義多不通有感依韻和范景仁舍人','梅堯臣','宋','宋诗','song-poetry','','[]','明經與進士，皆欲取公卿。',48,'全唐诗/poet.song.15000.json','["明經與進士，皆欲取公卿。", "自是俗儒陋，非於吾道輕。", "昔由羔雁聘，今乃草萊并。", "不措一辭去，緣何祿代耕。"]'),
('950dfa30-3669-47c8-b2ad-ac36ca73f46c','出省有日書事和永叔','梅堯臣','宋','宋诗','song-poetry','','[]','辭家綵勝人爲日，歸路梨花雨合晴。',64,'全唐诗/poet.song.15000.json','["辭家綵勝人爲日，歸路梨花雨合晴。", "庭下鞦韆應未拆，籠中鸚鵡即聞聲。", "千門走馬將看牓，廣市吹簫尚賣餳。", "已是瓊林芳卉晚，不須遊處避門生。"]'),
('7406b532-8077-4d54-870b-adc4334e1931','定號依韻和禹玉','梅堯臣','宋','宋诗','song-poetry','','[]','言出君門日，遥聞紫禁鐘。',72,'全唐诗/poet.song.15000.json','["言出君門日，遥聞紫禁鐘。", "詔書中使降，駿馬上閑供。", "天下持平手，毫偏不置胸。", "文從有司較，卷是近臣封。", "勝陣無容敵，精后已善攻。", "明朝當奏號，鴛鷺看歸雝。"]'),
('7b627abb-3a0c-4c80-a075-6a765d45def5','寄桂州張諫議和永叔','梅堯臣','宋','宋诗','song-poetry','','[]','桂林太守幾時行，泛汴桃花浪已騰。',64,'全唐诗/poet.song.15000.json','["桂林太守幾時行，泛汴桃花浪已騰。", "目極雲陰低遠樹，夜寒風急亂春燈。", "巢鳴翡翠愁無限，水宿鴛鴦冷不勝。", "陽朔山前好峯嶺，爲公憐愛萬千層。"]'),
('6e892407-59b4-4e3e-8adb-b550d619e78f','觀張中樂書大字','梅堯臣','宋','宋诗','song-poetry','','[]','芝旭馳名世有孫，大書如曉過秋原。',32,'全唐诗/poet.song.15000.json','["芝旭馳名世有孫，大書如曉過秋原。", "長松怪柏皆成炭，豫氏觀傍不解吞。"]'),
('d13173ec-e893-4db9-b78d-4f651bbe2325','張淳叟獻詩永叔同永叔和之','梅堯臣','宋','宋诗','song-poetry','','[]','張君獻詩詩詞巧，美女插花嬌醉春。',64,'全唐诗/poet.song.15000.json','["張君獻詩詩詞巧，美女插花嬌醉春。", "公答七言夸筍笴，我無千里學騏驎。", "夜吟謝朓澄江練，露濕陶潛漉酒巾。", "歸去應將錦囊貯，已勝珠玉莫愁貧。"]'),
('390bb5c5-1d9d-4e08-937a-4baa86ea586c','上馬和公儀','梅堯臣','宋','宋诗','song-poetry','','[]','煙火千門曉欲開，王花驕馬肯徘徊。',64,'全唐诗/poet.song.15000.json','["煙火千門曉欲開，王花驕馬肯徘徊。", "井閭已是經時隔，親舊全如遠別來。", "帝闕重看多氣象，天街新霽少塵埃。", "振冠浣服無容久，便見池門放牓催。"]'),
('659ecf62-2248-49e9-a0bb-786cc96c4482','太師杜公挽詞五首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','國佐三公進，師臣一品歸。',48,'全唐诗/poet.song.15000.json','["國佐三公進，師臣一品歸。", "接賓忘素貴，還綬遠危機。", "憶奉追尊冊，當觀副輅旂。", "生榮人莫及，無恨掩泉扉。"]'),
('cd8ea84a-d793-412c-a113-aa1c1f9df135','太師杜公挽詞五首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','既老仍開國，因歸得賜金。',48,'全唐诗/poet.song.15000.json','["既老仍開國，因歸得賜金。", "念懷知主意，堅介見臣心。", "筆札尚存紙，性情猶託吟。", "向來門下客，東首淚盈襟。"]'),
('0bd4f85f-60b5-4e66-a1ae-9ec6a7c6a6f4','太師杜公挽詞五首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','莫怪霑襟血，無由作弔賓。',48,'全唐诗/poet.song.15000.json','["莫怪霑襟血，無由作弔賓。", "故池歸去雁，春信見何人。", "已寫虛堂影，猶鎸守冢麟。", "門生與舊吏，將立道傍珉。"]'),
('7b3c8f7c-b9f9-419a-945f-53be4b6829e9','太師杜公挽詞五首  其四','梅堯臣','宋','宋诗','song-poetry','','[]','言爲當代法，行不古人慙。',48,'全唐诗/poet.song.15000.json','["言爲當代法，行不古人慙。", "天子貴元老，史官傳美談。", "名高漢亞相，學嗣晉征南。", "有子即家寶，未嘗金玉貪。"]'),
('72a0a684-0788-41db-b709-dd00652ef993','太師杜公挽詞五首  其五','梅堯臣','宋','宋诗','song-poetry','','[]','見錄尋常詠，親裝復手題。',48,'全唐诗/poet.song.15000.json','["見錄尋常詠，親裝復手題。", "言從永嘉後，重與建安齊。", "自古難知己，孤生每擇棲。", "春風寄黄鳥，爲向墓間啼。"]'),
('be262262-4f75-47b2-8fce-9126a4210641','送方云秀才下第','梅堯臣','宋','宋诗','song-poetry','','[]','從來釣者意，豈不在得魚。',60,'全唐诗/poet.song.15000.json','["從來釣者意，豈不在得魚。", "餌寡魚口多，曾非投竿疎。", "向登百金貴，首尾必吹墟。", "竭澤古所戒，但保腹中書。", "風雷變有詩，且復歸孟豬。"]'),
('f34129c9-f340-4b1d-9035-ca56f88b2970','送張待制知越州','梅堯臣','宋','宋诗','song-poetry','','[]','滄海東邊會稽郡，朱輪遠下相臣家。',64,'全唐诗/poet.song.15000.json','["滄海東邊會稽郡，朱輪遠下相臣家。", "已同雲漢星辰轉，不與鑑湖風月賒。", "越箭抽萌供美茹，秦山堆翠照高牙。", "買臣嚴助前時貴，破盜論功未足誇。"]'),
('f2d9fecb-5285-407a-9616-c670e1757f78','送甥蔡駰下第還廣平','梅堯臣','宋','宋诗','song-poetry','','[]','爾持金錯刀，不入鵝眼貫。',60,'全唐诗/poet.song.15000.json','["爾持金錯刀，不入鵝眼貫。", "已遭俗棄擲，妄意堪憤惋。", "他時有識別，終必爲寶玩。", "懷之歸河朔，慎勿輙鎔鍛。", "改作毛遂錐，穎脫奚足算。"]'),
('2ea1e267-a558-4fe4-be9b-e431d6d372ec','送唐紫微知蘇臺','梅堯臣','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭五月水生寒，盧橘楊梅已滿盤。',64,'全唐诗/poet.song.15000.json','["洞庭五月水生寒，盧橘楊梅已滿盤。", "泰伯廟前看走馬，闔閭城下見驂鸞。", "吳娃結束迎新守，府吏趨鏘拜上官。", "曾過楊州能慣否，劉郎盞底勸須寬。"]'),
('564d2447-f77f-42ed-b361-634f1218c63a','韓持國遺洛筍','梅堯臣','宋','宋诗','song-poetry','','[]','龍孫春吐一尺牙，紫錦包玉離泥沙。',80,'全唐诗/poet.song.15000.json','["龍孫春吐一尺牙，紫錦包玉離泥沙。", "金刀璀錯截嫩節，銅駞不與大梁賒。", "持寄韓郎綠蒲束，莫令衛女苦思家。", "韓郎才調偏能賦，分餉唯思楚景差。", "因之善謔誦淇澳，欲學報投無木瓜。"]'),
('4b103088-b387-49a5-8cb0-6deff9fd185a','萊宣遺酒','梅堯臣','宋','宋诗','song-poetry','','[]','白日對芳樹，靜夜愛明月。',120,'全唐诗/poet.song.15000.json','["白日對芳樹，靜夜愛明月。", "我飲雖不多，杯杓安可闕。", "破屋有空缸，冷竈無黔突。", "投餐聞韓辱，乞食使陶訥。", "鑒此不求人，終身其鏤骨。", "儻有佳客過，未免貰袍笏。", "風從東南來，語向西北發。", "西北多鳳雛，枝間報清越。", "玉壺盛曉露，贈置醉莫歇。", "却少可飲人，爲告月休沒。"]'),
('2ec11082-2f7a-4bdf-85a6-3fffdd2f2e53','送王正卿寺丞赴睢陽幙','梅堯臣','宋','宋诗','song-poetry','','[]','廢囿孝王國，離宮天子都。',48,'全唐诗/poet.song.15000.json','["廢囿孝王國，離宮天子都。", "古今雖且異，文物未嘗無。", "族有栽槐美，名從得桂殊。", "應聞漢丞相，待士倒樽壺。"]'),
('9ff04359-6b83-4290-8013-83297313daea','送王道粹郎中知華州','梅堯臣','宋','宋诗','song-poetry','','[]','往年入關中，道傍見太華。',108,'全唐诗/poet.song.15000.json','["往年入關中，道傍見太華。", "始識仙掌大，頗似攬造化。", "赤手無所爲，風雨漏指罅。", "又觀蓮華峯，上有蓮開謝。", "一朝秋色高，蓮葉或飄下。", "今聞太守行，見隼畫車駕。", "仙掌與蓮花，日久可以詫。", "長安道上人，任見不須借。", "况多耐老藥，民將待黄霸。"]'),
('f9173d37-34c5-4791-887e-2d843ece41b7','韓玉汝遺油','梅堯臣','宋','宋诗','song-poetry','','[]','朝讀百紙書，夜成幾篇書。',88,'全唐诗/poet.song.15000.json','["朝讀百紙書，夜成幾篇書。", "明明白晝有陽烏，黕黕暗室無蟾蜍。", "目睛須藉外物光，日月不到卑蔀居。", "君能置以清油壺，暝照文字燈焰舒。", "婦將膏髮雲鬢梳，缾底濁濃留脂車。", "所益既如此，所感當何如。"]'),
('c9dfe149-9916-4ec2-aa87-6d3e21ad80e1','王幾道罷磁州遺澄泥古瓦二硯','梅堯臣','宋','宋诗','song-poetry','','[]','澄泥叢臺泥，瓦斲鄴宮瓦。',60,'全唐诗/poet.song.15000.json','["澄泥叢臺泥，瓦斲鄴宮瓦。", "共爲几桉用，相與筆墨假。", "賦無左思作，書媿右軍寫。", "初從故人來，來自邯鄲下。", "物因人以重，謬當好事者。"]'),
('8ddb277f-d22b-4d89-8aef-539796ae535e','送咸陽主簿王秘校','梅堯臣','宋','宋诗','song-poetry','','[]','昔見蘭叢牙，今見連蔓瓜。',48,'全唐诗/poet.song.15000.json','["昔見蘭叢牙，今見連蔓瓜。", "持入咸陽市，本出故侯家。", "五色相鉤蔕，秦人應自誇。", "行當七月薦，乞巧雜盤花。"]'),
('06e496bc-d8a9-47fa-97bf-5bc1fc49df81','和楚屯田同曾子固陸子履觀予堂前石榴花','梅堯臣','宋','宋诗','song-poetry','','[]','堂下一匹鄭虔馬，欄邊兩株安石榴。',64,'全唐诗/poet.song.15000.json','["堂下一匹鄭虔馬，欄邊兩株安石榴。", "但能有酒邀佳客，亦任狂花落素甌。", "侍女紅裙無好色，主人白髮自侵頭。", "欲歌翠樹芳條曲，已去洛陽三十秋。"]'),
('0f9a7e5c-95cf-441f-9b5a-5416ea801248','送史供奉汴口都大','梅堯臣','宋','宋诗','song-poetry','','[]','河爲中國患，亦爲中國利。',180,'全唐诗/poet.song.15000.json','["河爲中國患，亦爲中國利。", "其患齧堤防，其利通糧饋。", "分流入浚汴，萬貨都城萃。", "積淫或暴漲，旱暵或滯疐。", "疏導欲其宜，徑度有所異。", "曩者多邀功，用之殊未至。", "十私而五公，歲久害愈熾。", "潰溢必歸尤，廟堂難决議。", "明明聖天子，自選中常侍。", "銀鐺插在貂，身小勇且智。", "上從廣武城，下及淮與泗。", "迴險帖鑿繁，所畫由所寄。", "嘗以勤厥身，又能和衆吏。", "前日有盡心，於今病憔悴。", "此職方藉人，加餐當自爲。"]'),
('b010b144-7a31-43e1-b6b4-60276e4462e3','呂晉','梅堯臣','宋','宋诗','song-poetry','','[]','四葉及王游，共家原坂嶺。',108,'全唐诗/poet.song.15000.json','["四葉及王游，共家原坂嶺。", "歲摘建溪春，爭先取晴景。", "大窠有壯液，所發必奇穎。", "一朝團焙成，價與黄金逞。", "呂侯得鄉人，分贈我已幸。", "其贈幾何多，六色十五餠。", "每餠包青蒻，紅籤纏素檾。", "屑之雲雪輕，啜已神魄惺。", "會待嘉客來，侑談當晝永。"]'),
('a26f4912-cc1e-495c-9817-01c4ecfb74a2','送畢甥之臨邛主簿雜言','梅堯臣','宋','宋诗','song-poetry','','[]','自我歷官三十年，有脚未曾行蜀川。',174,'全唐诗/poet.song.15000.json','["自我歷官三十年，有脚未曾行蜀川。", "李白嘗言道之艱險，長嗟難劇上青天。", "鳥悲猿嚎馬蹄脫，苔梯雨棧愁傾顛。", "蒼崖下窺不見底，但聽雷聲輥石懸湍濺。", "曉盤青泥上高煙，暮盤青泥到下泉。", "劍閣如劍，巉然割腸刺恨今古連。", "爾去三千九百里，巴山小馬烏布韉。", "一婦一奚行李單，家具日貨能幾錢。", "人皆畏避不敢往，此獨敢往何所便。", "况是初宦無遠適，心意自許非由銓。", "異乎哉，我今送爾徒哀憐。"]'),
('311bce88-6d42-46c3-a4de-9cf31b2824bd','哀馬','梅堯臣','宋','宋诗','song-poetry','','[]','瘠彼單于馬，贈我信都侯。',228,'全唐诗/poet.song.15000.json','["瘠彼單于馬，贈我信都侯。", "信都惡頑惡，不使服車輈。", "我從南土歸，涉河假扁舟。", "將趨未央朝，無乘誰可求。", "信都固朋義，百乏能以周。", "遺此燕山駿，買韉安轡頭。", "朝斬一束芻，夕煑一盎麰。", "漸平崢嶸骨，幸騎歷冬秋。", "自春鎖禮闈，既出被輕囚。", "飽秣不復駕，狂躍如生虬。", "更番一老卒，湔刷常預愁。", "前欲往城東，始跨人立侔。", "首落而尾擲，衰軀幾墜投。", "邇者將贖金，行當謁冕旒。", "私呼貴鄰兵，言調變馴柔。", "晨往及暮還，踣地氣不收。", "彼兵隸天廐，國馬皆仰騶。", "其能量馬力，國馬安得稠。", "以吾窮使然，爾能亦可羞。"]'),
('89fa215b-eadc-4b61-a5ed-d80a06191e49','依韻和公儀龍圖招諸公觀舞及畫三首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','落花浄掃青陰長，野蝶閑飛綠草閒。',32,'全唐诗/poet.song.15000.json','["落花浄掃青陰長，野蝶閑飛綠草閒。", "侍從歸來看鶴舞，便將樽酒欲招閑。"]'),
('1deba8aa-1fce-44e4-a88f-caad52869f29','依韻和公儀龍圖招諸公觀舞及畫三首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','陰森園圃牆東地，携挈兒童樹下吟。',32,'全唐诗/poet.song.15000.json','["陰森園圃牆東地，携挈兒童樹下吟。", "更約天邊鳳皇侶，閱書觀畫味尤深。"]'),
('0bd597a9-8688-41c1-ab75-ec06516740fc','依韻和公儀龍圖招諸公觀舞及畫三首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','初約看花花已盡，重新邀客客應歡。',32,'全唐诗/poet.song.15000.json','["初約看花花已盡，重新邀客客應歡。", "真花既不能長豔，畫在霜紈更好看。"]'),
('3fd5fece-83f6-465c-8341-fadcaacf87d9','送王介甫知毗陵','梅堯臣','宋','宋诗','song-poetry','','[]','吳牛常畏熱，吳田常畏枯。',192,'全唐诗/poet.song.15000.json','["吳牛常畏熱，吳田常畏枯。", "有樹不蔭犢，有水不滋䅳。", "孰知事春農，但知急秋租。", "太守追縣官，堂上怒奮鬚。", "縣官促里長，堂下鞭扑俱。", "不體天子仁，不恤黔首逋。", "借問彼爲政，一一何所殊。", "今君請郡去，預喜民將蘇。", "每觀二千石，結束辭國都。", "絲韉加錦緣，銀勒以金塗。", "兵吏擁後隊，劍撾盛前驅。", "君又不若此，革轡障泥烏。", "欵行問風俗，低意騎更駑。", "下情靡不達，略細舉其麤。", "曾肯爲衆異，亦罔爲世趨。", "學詩聞已熟，愛棠理豈無。"]'),
('2784a7a7-3816-4115-bd9b-cc1bc4922b92','送曾子固蘇軾','梅堯臣','宋','宋诗','song-poetry','','[]','屈宋出於楚，王馬出於蜀。',132,'全唐诗/poet.song.15000.json','["屈宋出於楚，王馬出於蜀。", "荀楊亦二國，自接大儒躅。", "各去百數年，高下非近局。", "鉤陳豹尾科，登俊何炳縟。", "楚蜀得曾蘇，超然皆絕足。", "父子兄弟間，光輝自聯屬。", "古何相遼闊，今何相邇續。", "朝廷有巨公，講索無遺錄。", "正如唐虞時，元凱同啟沃。", "何言五百載，此論不可告。", "二君從茲歸，名價同驚俗。"]'),
('77329385-6ffc-4da4-8d41-39f735a4eb7d','寄題張光祿榮佚堂','梅堯臣','宋','宋诗','song-poetry','','[]','疏氏昔二傅，張氏今兩卿。',132,'全唐诗/poet.song.15000.json','["疏氏昔二傅，張氏今兩卿。", "相去千餘載，能與同令名。", "亦嘗更侍從，况有冰玉清。", "世懷山東業，力制河北兵。", "雲煙忽起晦，日月不得明。", "白首無所爲，脫身吳楚城。", "七十還印綬，不以名教輕。", "葺堂讀舊書，時出郊郭行。", "水邊觀游魚，樹底愛啼鶑。", "適逢野老語，復問農人耕。", "紛紛世上士，車馬無此情。"]'),
('55eb26c7-175e-4b76-8427-74338d9e2970','送建州通判沈太博','梅堯臣','宋','宋诗','song-poetry','','[]','昔聞醉翁吟，是沈夫子所作。',186,'全唐诗/poet.song.15000.json','["昔聞醉翁吟，是沈夫子所作。", "今聽醉翁吟，是沈夫子所彈。", "聲如冰凘下石灘，嚼齧碎玉遶齒寒。", "四坐整衣容色端，醉翁雖醉無慢官。", "其音正以樂，其俗便且安，何害酩酊顔渥丹。", "沈夫子，邂逅相遇必已歡。", "玉琴能寫人肺肝，人所爲難君不難。", "平明解船建谿去，輕齎快意不長湍。", "谿東白茗象月團，來奉至尊龍屈盤。", "餘爲带銙與臠片，散在六合雲漫漫。", "况君五臟清如水，宜飲沆瀣采木欄。", "更留瓦硯贈我看，鄴宮鴛鴦誰刻剜。"]'),
('4c24a792-e5d5-4987-b0fb-4bcc975e79a0','送王平甫擬離騷','梅堯臣','宋','宋诗','song-poetry','','[]','識君兮不早，君尚少兮我老。',132,'全唐诗/poet.song.15000.json','["識君兮不早，君尚少兮我老。", "蘭與蕙兮多薰，搴雜佩兮芳芬。", "蘭倏往兮蕙隨，心俯仰兮徘徊。", "與識吳兮吳樂，嘗適楚兮楚悅，君何爲兮我闊。", "麒麟縶兮不馳，鳳皇蔽兮挑達。", "均莫悲兮別離，悵公子兮何之。", "絕大江兮無波，奉赤鯉兮藉荷。", "芼蒓荇兮陳羹，親意得兮忘榮。", "世反是兮從貴，聊送君兮傷情。"]'),
('3b3d86a1-1fc0-434e-9e70-c2fabf30a3e6','送僧遊廬山','梅堯臣','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','欲遊廬山去，將託楚舸梢。',60,'全唐诗/poet.song.15000.json','["欲遊廬山去，將託楚舸梢。", "暮行長河曲，月上黄金坳。", "悠悠幾千里，身世非繫匏。", "恣觀瀑布虹，不畏潯陽蛟。", "誦經東林下，小宇結香茅。"]'),
('1f050ca5-ba1a-4f2e-b5be-ab55ef965db1','韓持國再遺洛中斑竹筍','梅堯臣','宋','宋诗','song-poetry','','[]','牡丹開盡桃花紅，班筍迸林犀角豐。',112,'全唐诗/poet.song.15000.json','["牡丹開盡桃花紅，班筍迸林犀角豐。", "兩株遠寄川上鴻，韓郎輟口贈楚翁。", "便令剝錦煑荆玉，甘脆不道簞瓢空。", "小謝舊城昭亭下，侵天筀竹谿西東。", "螗蜋生後出牙茁，羅列滿地爭强雄。", "是時楚翁所食寡，朝飯暮飯唯其充。", "今來得此謂過分，一貴一賤物苟同。"]'),
('7e9eaa14-efb8-421c-aec2-7cbdbe9dec66','送僧惠思','梅堯臣','宋','宋诗','song-poetry','','[]','大車高馬塵塞軌，弄石洗泉人不喜。',56,'全唐诗/poet.song.15000.json','["大車高馬塵塞軌，弄石洗泉人不喜。", "慨然擺落還吳都，歸心勁於弦上矢。", "强弩發復開，矢往不可迴。", "常應笑燕子，時能海邊來。"]'),
('10f78ca8-f6f8-493f-bb25-343db2d2f37a','送魯玉太博挽詞三首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','射策志何遠，闔棺人共疑。',48,'全唐诗/poet.song.15000.json','["射策志何遠，闔棺人共疑。", "奠觴朋友去，泣血母兄悲。", "霧氣窗間盡，車聲戶外知。", "玉樓成作記，此語可能欺。"]'),
('1fa7ade6-9513-461d-99fc-73849353837f','送魯玉太博挽詞三首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','自昔稱王謝，於今亦盛門。',48,'全唐诗/poet.song.15000.json','["自昔稱王謝，於今亦盛門。", "尚看珠樹秀，應見玉麟存。", "書史辛勤學，文章苦死論。", "都然莫施設，恨向九原吞。"]'),
('216fb5cc-2991-4936-b5b0-5e951adfe37f','送魯玉太博挽詞三首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','試問於天下，誰從百歲心。',48,'全唐诗/poet.song.15000.json','["試問於天下，誰從百歲心。", "短長從所盡，禍福乃相尋。", "只以名賓實，那論古至今。", "未能忘物境，空復歎人琴。"]'),
('ff9167b6-fafb-4e18-ba65-747517622898','蘇明允木山','梅堯臣','宋','宋诗','song-poetry','','[]','空山枯楠大蔽牛，霹靂夜落魚鳬洲。',113,'全唐诗/poet.song.15000.json','["空山枯楠大蔽牛，霹靂夜落魚鳬洲。", "魚鳬水射千秋蠹，肌爛隨沙蕩漾流。", "唯存堅骨蛟龍鎪，形如三山中雄酋。", "左右兩峯相挾翊，尊奉君長無慢尤。", "蘇夫子見之驚且異，買於溪叟憑貂裘。", "因嗟大不爲梁棟，又歎殘不爲薪槱。", "雨侵蘚澀得石瘦，宜與夫子歸隠丘。"]'),
('893b2a4a-967a-4096-b09e-def8b49ec649','哀國子黄助教','梅堯臣','宋','宋诗','song-poetry','','[]','儒者務欲博，誦說窮冬秋。',168,'全唐诗/poet.song.15000.json','["儒者務欲博，誦說窮冬秋。", "衣裙未及解，含珠以見求。", "閩稱黄夫子，常恐學不流。", "有徒如浮萍，匝匝圍刳舟。", "聚書將萬卷，載行無馬牛。", "去年來京師，滿篋分寄投。", "半在吳楚間，半入趙衛陬。", "昨日大官薦，青袍變綈裘。", "今朝爲異物，寸祿與命讎。", "獨聞邯鄲公，哀之使斂收。", "曷其稟賦薄，安得被王侯。", "旅殯欲焉託，定將葬何州。", "生爲四方遊，死當不擇丘。", "豈必歸故鄉，萬里過山頭。"]'),
('aa4b81e8-3dc7-4556-b10f-cb97fae9a80e','沅江李氏書堂','梅堯臣','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','船從洞庭來，非賈即遊宦。',108,'全唐诗/poet.song.15000.json','["船從洞庭來，非賈即遊宦。", "宦賈事風檣，誰能樂清晏。", "不如蓄書史，萬古無與間。", "上觀堯舜仁，下覽魏晉篡。", "善惡彼既殊，智巧徒以辨。", "君心於此得，用捨不自慢。", "堂中羅高厨，戶外望鳴雁。", "菰菱可采掇，魚鼈可釣汕。", "卒歲身多餘，世俗莫習慣。"]'),
('c9fc7a87-9c46-488e-a479-44ebc86055c6','坐睡依韻和持國','梅堯臣','宋','宋诗','song-poetry','','[]','坐久既生倦，漸看冠佩斜。',48,'全唐诗/poet.song.15000.json','["坐久既生倦，漸看冠佩斜。", "鐘聲傳紫禁，烏影轉西華。", "竊印後當致，觸屏前未嘉。", "不爲疎慢意，何用北窗誇。"]'),
('c481d6b6-11d4-47db-bc0a-03167b59f4c8','張堯夫寺丞改葬挽詞三首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','洛陽交舊裏，過半已凋殘。',48,'全唐诗/poet.song.15000.json','["洛陽交舊裏，過半已凋殘。", "在昔義投漆，最先悲闔棺。", "誰知二紀水，重卜九原安。", "聞說塞門路，白楊風更寒。"]'),
('31bf29df-5bcd-44dc-b7ba-1e00dbe46beb','張堯夫寺丞改葬挽詞三首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','當時嗟遽歿，二子未能言。',48,'全唐诗/poet.song.15000.json','["當時嗟遽歿，二子未能言。", "頻歲折丹桂，買塋遷陸渾。", "重銘太史筆，不替故人恩。", "爲善有終慶，此焉天意存。"]'),
('6aac4502-75fb-4017-a000-380c5bc390d4','張堯夫寺丞改葬挽詞三首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','舊墳爲潤齧，新塚得山深。',48,'全唐诗/poet.song.15000.json','["舊墳爲潤齧，新塚得山深。", "斬木來荒路，移松出近岑。", "黄鸝啼棘上，玉女問泉音。", "强作挽人唱，儻知哀感心。"]'),
('50ae9b8e-3457-43f9-b26c-08b42e8f128c','讀黄節推卷','梅堯臣','宋','宋诗','song-poetry','','[]','磊落黄從事，清吟古氣多。',48,'全唐诗/poet.song.15000.json','["磊落黄從事，清吟古氣多。", "少年知任俠，欲老解登科。", "辨起公卿坐，時爲慷慨歌。", "又持珠玉贈，將奈老貧何。"]'),
('70b4a75b-c7b0-4bc6-8b05-341a14b81004','得陳天常屯田斑筇竹二枚','梅堯臣','宋','宋诗','song-poetry','','[]','客初西蜀來，遺我雙筇竹。',179,'全唐诗/poet.song.15000.json','["客初西蜀來，遺我雙筇竹。", "上有紅淚斑，斷非湘娥哭。", "嘗聞帝魂哀，嚎血滴草木。", "春露洒更鮮殷痕侵粉綠。", "截爲扶衰杖，萬里出浴谷。", "今來入我手，君勤意有囑。", "區區四十年，重趼生兩足。", "冠丱三男子，且與詩書讀。", "翁雖文章窮，尚以字遮目。", "忍棄不以教，携歸事樵牧。", "故茲九節贈，用助老追逐。", "楊朱非爲岐，賈誼非爲鵩。", "及其悲慟時，豈不沾盈掬。", "揮之儻著物，無迹染林麓。", "因持此竹紋，勿歎前人獨。"]'),
('4cbdaccd-b021-4f6e-aa07-1d6b13f3e881','送余少卿知睦州','梅堯臣','宋','宋诗','song-poetry','','[]','青山峽裏桐廬郡，七里灘頭太守船。',64,'全唐诗/poet.song.15000.json','["青山峽裏桐廬郡，七里灘頭太守船。", "雲霧未開藏宿鳥，坡原將近見燒田。", "養茶摘蕊新春後，種橘收包小雪前。", "民事蕭條官政簡，家書時問霅溪邊。"]'),
('aa716f78-6e53-4646-ba21-ff5f8f4c5afa','夜直廣文有感寄曾子固','梅堯臣','宋','宋诗','song-poetry','','[]','日暮蛛絲動，月暗螢火明。',84,'全唐诗/poet.song.15000.json','["日暮蛛絲動，月暗螢火明。", "方茲步庭戶，浩然懷友生。", "友生將東歸，泛若赴海鯨。", "已從龍門出，不慕朱鼈輕。", "朱鼈過吳洲，飛飛就東瀛。", "沉浮未可問，名有萬里程。", "須憂小水魴，勞勞將尾赬。"]'),
('eb59c03d-bb03-4ea1-ae0d-13a59ff5c03f','重送曾子固','梅堯臣','宋','宋诗','song-poetry','','[]','楚澤多年一卧龍，新春雷雨起鱗蹤。',64,'全唐诗/poet.song.15000.json','["楚澤多年一卧龍，新春雷雨起鱗蹤。", "誰知天上爭騰躍，偶落池中雜噞喁。", "且自摧藏隨浪去，何當駕馭使雲從。", "劉累只說古來有，暫屈泥蟠莫便慵。"]'),
('0c08ce53-aa85-4ea5-a9dd-2bf622e702ee','寄題沈比部江州齊雲樓','梅堯臣','宋','宋诗','song-poetry','','[]','遠目不高不可極，朱樓要與浮雲齊。',96,'全唐诗/poet.song.15000.json','["遠目不高不可極，朱樓要與浮雲齊。", "江流萬古平泱莽，山雨一過寒凄迷。", "賈客檣下望吹笛，漁郎浦前看斷霓。", "佽飛射蛟水花伏，高士種柳煙條低。", "羣雁有時至自北，洪潮到此不更西。", "君家隠侯有八詠，風雅未盡留人題。"]'),
('0382e0d9-d71d-4f7e-99b3-70a8e3912e25','雲間月','梅堯臣','宋','宋诗','song-poetry','','[]','明明雲間月，皎皎莫可指。',72,'全唐诗/poet.song.15000.json','["明明雲間月，皎皎莫可指。", "雄烏與牡兔，萬歲不生子。", "三旬後乃合，徒用成甲癸。", "焉見下土物，長養各私己。", "蛇蝎滿窟隙，嗣毒自未已。", "天地豈有意，盛德名不死。"]'),
('1cf817c4-e9e9-47c8-90ef-3ea7ed89da97','依韻和梅龍圖觀小錄','梅堯臣','宋','宋诗','song-poetry','','[]','四百鸞皇羽翼成，高低輕重出權衡。',32,'全唐诗/poet.song.15000.json','["四百鸞皇羽翼成，高低輕重出權衡。", "他時俱作公卿去，誇是王家門下生。"]'),
('d4c9975b-8c06-4132-a124-392c4d65256f','送鮮于秘丞通判黔州','梅堯臣','宋','宋诗','song-poetry','','[]','壺頭山下俗，巴婦曲中聽。',48,'全唐诗/poet.song.15000.json','["壺頭山下俗，巴婦曲中聽。", "汲井熬鹽白，燒田種穀青。", "巖風來虎嘯，江雨過龍腥。", "事簡能談者，楊雄所草經。"]'),
('c268fef7-1470-4d64-873f-7d173cdf3b12','依韻閻中孚職方暴雨幸凉','梅堯臣','宋','宋诗','song-poetry','','[]','天津赫日欲焦拆，西北風來斗減威。',64,'全唐诗/poet.song.15000.json','["天津赫日欲焦拆，西北風來斗減威。", "太帝宮庭無暑入，大明冠佩退朝歸。", "泠泠冷襲瑠璃簟，奕奕凉翻翡翠幃。", "交扇不須煩素手，淋漓誰復汗頻揮。"]'),
('20c3bfea-b0f1-4555-b53d-ede5d8bf9cd2','愛月','梅堯臣','宋','宋诗','song-poetry','','[]','終夜每愛月，見月常苦稀。',84,'全唐诗/poet.song.15000.json','["終夜每愛月，見月常苦稀。", "不雨即雲晦，何能攬光輝。", "儻有一夕明，豈畏露濕衣。", "素娥領玉兔，孤寡命亦微。", "堂堂罕開耀，多是半掩扉。", "曾負萬家望，空是隨人歸。", "一歲復一歲，白髮思釣磯。"]'),
('9b44689a-40c9-46e9-817b-268c3dfd7aa2','呂縉叔云永嘉僧希用隠居能談史漢書講說邀余寄之','梅堯臣','宋','宋诗','song-poetry','','[]','奈苑談經者，蘭臺著作稱。',48,'全唐诗/poet.song.15000.json','["奈苑談經者，蘭臺著作稱。", "吾儒不兼習，爾學若多能。", "每愛前峯好，閑穿弊屐登。", "定將修史筆，添傳入高僧。"]'),
('df3c2bb5-b8e4-4818-b813-80209a745d26','送陳仲容寺丞知冤句','梅堯臣','宋','宋诗','song-poetry','','[]','憶昨宿蘭省，每倦喜君談。',108,'全唐诗/poet.song.15000.json','["憶昨宿蘭省，每倦喜君談。", "月色夜正寒，舉盃無再三。", "既出罕相遇，必謂跨歸驂。", "忽來冒炎暑，別我爲子男。", "冤句隸濟陰，桑柘宜農蠶。", "應如襲祖德，遺道使之慙。", "初聞不擇邑，公秫豈所貪。", "但能亦種柳，五株垂毿毿。", "板輿與東征，足以奉旨甘。"]'),
('ebcc6931-7850-4fb9-b768-c9bbd47bc183','依韻和王景彝馬上忽見槐花','梅堯臣','宋','宋诗','song-poetry','','[]','六月御溝馳道間，青槐花上夏雲山。',64,'全唐诗/poet.song.15000.json','["六月御溝馳道間，青槐花上夏雲山。", "退朝側帽驚時晚，近樹聞香暗詠閑。", "新雨賈生車喜出，舊年潘岳鬢添斑。", "老慙太學無經術，空飽齏鹽强往還。"]'),
('5edb1056-3d25-4842-90da-7c11f13ccb71','送家靜寺丞知洛南','梅堯臣','宋','宋诗','song-poetry','','[]','秦愛商於地，信美洛水南。',72,'全唐诗/poet.song.15000.json','["秦愛商於地，信美洛水南。", "銀鉛與丹砂，鑿山民爭貪。", "蜀客善製錦，當先務桑蠶。", "衣老以及少，使煦如春酣。", "摘蔬有筍蕨，釣庖有巖潭。", "頗同故鄉味，將喜獲所諳。"]'),
('88dec69e-50a3-4212-ab63-cd72e4dc1c63','和王景彝省中詠孤竹','梅堯臣','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','愛此孤生竹，碧葉琅玕柯。',48,'全唐诗/poet.song.15000.json','["愛此孤生竹，碧葉琅玕柯。", "結根甘泉裏，豈必泰山阿。", "曾莫學兔絲，徒以附女蘿。", "風爲掃庭戶，夜月誰與過。"]'),
('8bb8ba0f-69c9-47c2-8e05-61eeb13b0832','送曾孝寬寺丞宰桐城','梅堯臣','宋','宋诗','song-poetry','','[]','嗇夫苟有惠，前世猶立祠。',60,'全唐诗/poet.song.15000.json','["嗇夫苟有惠，前世猶立祠。", "既爲邦邑長，必欲風化施。", "長松蔭公庭，流水循堂基。", "俱可助琴彈，亦足忘事縻。", "况君公侯家，清尚人所期。"]'),
('068e16c7-05bb-4436-a908-3db7dec996d3','永叔內翰遺李太博家新生鴨脚','梅堯臣','宋','宋诗','song-poetry','','[]','北人見鴨脚，南人見胡桃。',144,'全唐诗/poet.song.15000.json','["北人見鴨脚，南人見胡桃。", "識內不識外，疑若橡栗韜。", "鴨脚類綠李，其名因葉高。", "吾鄉宣城郡，每以此爲勞。", "種樹三十年，結子防山猱。", "剝核手無膚，持置宮省曹。", "今喜生都下，薦酒壓葡萄。", "初聞帝苑夸，又復主第襃。", "纍纍誰採掇，玉椀上金鼇。", "金鼇文章宗，分贈我已叨。", "豈無異鄉感，感此微物遭。", "一世走塵土，鬢顛得霜毛。"]'),
('02ac0cff-bdb7-44e7-a916-031257d96c72','陸子履示秦篆寶','梅堯臣','宋','宋诗','song-poetry','','[]','秦既并諸侯，斯乃一度量。',144,'全唐诗/poet.song.15000.json','["秦既并諸侯，斯乃一度量。", "鑄寶以永傳，萬世俾勿喪。", "精銅不生花，小篆著丞相。", "一沒咸陽宮，千秋事更王。", "陸君居洛城，客有來渭上。", "曰因農人耕，發壤破古藏。", "遂獲此物還，文完字何壯。", "始號爲皇帝，立語已超曠。", "意將愚黔首，釁起危博浪。", "其後同玉璽，不隨驪山葬。", "今蓄於君家，徒爾資奇尚。", "物以用爲珍，異時皆似妄。"]'),
('59c20e3c-f042-4e16-8a6f-f1f756f46c1d','王屋高送王屋知縣孫秘丞','梅堯臣','宋','宋诗','song-poetry','','[]','王屋山高無猿猱，下有黄河水滔滔。',112,'全唐诗/poet.song.15000.json','["王屋山高無猿猱，下有黄河水滔滔。", "天壇半夜見海白，光動古邑雞先嘷。", "雞先嘷，絕吠獒，巖居林栖吏莫搔。", "山膚有時得虞獵，不比彘肉烹連毛。", "聞君今去將效陶，縣前種柳芟蓬蒿。", "不問公田問民俗，民安事簡教兒曹。", "河南太守喜愷悌，如此可以無厭勞。"]'),
('a0af81f1-fada-4555-a78c-180a627df5b5','聽文都知吹簫','梅堯臣','宋','宋诗','song-poetry','','[]','虞舜已去蒼梧野，秦女驂鸞無復下。',112,'全唐诗/poet.song.15000.json','["虞舜已去蒼梧野，秦女驂鸞無復下。", "簫管人間不解傳，帝樂部中能亦寡。", "欲買小鬟試教之，教坊供奉誰知者。", "晏識文公始致來，勸接賤生宜强且。", "乃呼側坐吹一曲，驚顧頓嘶堂下馬。", "吾妻閨中聞不聞，稚女扳簾笑嬌奼。", "未敢多聽便遣還，贈飲單杯向身瀉。"]'),
('43134526-e3a3-4269-973a-fa1eebaf6c71','雜言送王無咎及第後授江都尉先歸建昌','梅堯臣','宋','宋诗','song-poetry','','[]','白袍來，黄綬迴。',56,'全唐诗/poet.song.15000.json','["白袍來，黄綬迴。", "來跨騫馿迴跨馬，麻源三谷桂花開。", "江都作尉入風埃，主人劉向西京才。", "心如明月無不照，恐君已到還鸞臺。"]'),
('b7d6813e-5563-43ba-9531-2242ecd71c81','依韻和王景彝憶秋','梅堯臣','宋','宋诗','song-poetry','','[]','隴首欲看飛去雲，槎頭安得卷輕輪。',64,'全唐诗/poet.song.15000.json','["隴首欲看飛去雲，槎頭安得卷輕輪。", "流烏不轉天邊日，乘馬猶知果下人。", "空渴魏臺冰在井，從悲楚客淚緣巾。", "炎炎赫日偏憎老，眼耳昏聾半塞塵。"]'),
('33ca944d-d614-41c3-b08f-3f1bd4eebc6b','七夕永叔內翰遺鄭州新酒言值內直不暇相邀','梅堯臣','宋','宋诗','song-poetry','','[]','詰朝持鄭醖，向夕望星津。',48,'全唐诗/poet.song.15000.json','["詰朝持鄭醖，向夕望星津。", "俗意願添巧，古心思變淳。", "予窮少陵老，公似謫仙人。", "獨對金鸞月，宮詞付小臣。"]'),
('91c25f70-fd42-4578-bfd4-8e0c6b3c789b','依韻和永叔久在病告近方赴直道懷見寄二章  其一','梅堯臣','宋','宋诗','song-poetry','','[]','浴堂深殿近皇居，秋夕詞臣直宿初。',64,'全唐诗/poet.song.15000.json','["浴堂深殿近皇居，秋夕詞臣直宿初。", "宮女穿針爭落月，官奴持獨看殘書。", "萬家乞巧心無盡，斜漢飛光望有餘。", "枕上江山夢猶熟，五更風雨過簾疎。"]'),
('61742514-f54c-4129-9998-66fb234233e2','依韻和永叔久在病告近方赴直道懷見寄二章  其二','梅堯臣','宋','宋诗','song-poetry','','[]','玉轡瓏瓏出絳宮，青槐馳道曉煙中。',64,'全唐诗/poet.song.15000.json','["玉轡瓏瓏出絳宮，青槐馳道曉煙中。", "塵頭尚裛洗車雨，馬耳前趨吹鬣風。", "聞說自將身許國，不須仍以醉爲公。", "我今才薄都無用，六十棲棲未歎窮。"]'),
('1bcd48bf-9acf-4e02-95a0-ad9e37790b9e','文豹篇贈黄介夫','梅堯臣','宋','宋诗','song-poetry','','[]','壯哉南山豹，不畏白額虎。',60,'全唐诗/poet.song.15000.json','["壯哉南山豹，不畏白額虎。", "澤霧毛雖雜鼮鼠，朝將具鬚暮爲乳。", "文章子雲久已許，還笑大夫費五羖。", "天子仗中儀勿舉，尾與旂常願看取。"]'),
('6a99bbe4-2d1c-4bd1-8074-ff55b2035118','送韓欽聖學士京西提刑','梅堯臣','宋','宋诗','song-poetry','','[]','王朝慎常刑，恐民陷非辟。',156,'全唐诗/poet.song.15000.json','["王朝慎常刑，恐民陷非辟。", "分命遣使車，謬枉得舉摘。", "兼之勸農桑，欲野無曠隙。", "韓侯夙所志，功利豈止百。", "茫茫唐鄧間，荒土無牛跡。", "邵閼廢未久，柘陽仍舊白。", "二地儻復營，萬世不可易。", "昔在漢家時，近親多占籍。", "苟或非膏腴，當應徒畿赤。", "每念輒歎嗟，未能俾盡畫。", "天將富斯民，事與願不隔。", "其易謂何如，拾芥由琥珀。", "我今送韓侯，書以贈無責。"]'),
('c6448969-b4f1-45f2-873f-a36906132842','送陸子履學士通判宿州','梅堯臣','宋','宋诗','song-poetry','','[]','雷雨初過草木新，汴堤楊柳綠陰勻。',64,'全唐诗/poet.song.15000.json','["雷雨初過草木新，汴堤楊柳綠陰勻。", "已看畫舸逐流水，不惜長條折與人。", "淮境秋傳蟹螯美，郡齋凉愛蟻醅醇。", "睢南莫久留才子，宣室歸來問鬼神。"]'),
('eb66ea4e-1071-4906-a90e-19c0d84e5b47','得福州蔡君謨密學書并茶','梅堯臣','宋','宋诗','song-poetry','','[]','薛老大字留山峯，百尺倒插非人蹤。',160,'全唐诗/poet.song.15000.json','["薛老大字留山峯，百尺倒插非人蹤。", "其下長樂太守書，矯然變怪神淵龍。", "薛老誰何果有意，千古乃與奇筆逢。", "太守姓出東漢邕，名齊晉魏王與鍾。", "尺題寄我憐衰翁，刮青茗籠藤纏封。", "紙中七十有一字，丹砂鐵顆攢芙蓉。", "光照陋室恐飛去，鎖以漆篋緘重重。", "茶開片銙碾葉白，亭午一啜驅昏慵。", "顔生枕肱飲瓢水，韓子飯齏居辟雍。", "雖窮且老不媿昔，遠荷好事紓情悰。"]'),
('5dee51ae-67b1-4a4e-bf1c-c7e17f873f2e','嘉祐二年七月九日大雨寄永叔內翰','梅堯臣','宋','宋诗','song-poetry','','[]','去年龍母沐，今年龍婦浴。',264,'全唐诗/poet.song.15000.json','["去年龍母沐，今年龍婦浴。", "民何競相傳，訛言初願戮。", "沐水不濕纓，浴波吞目睛。", "連歲果爲患，準度非人情。", "島夷尚弗爾，况乃此京城。", "天公亦鑒詳，天子大聖明。", "堯時不昏墊，安見堯憂煢。", "今但微禹力，上心常屏營。", "祠官駿奔走，請禱必竭誠。", "廟堂列土偶，椒酒空湛盈。", "靈氣自莫主，非以堯言輕。", "霹靂夜復作，蝦蟆尚聽鳴。", "輦道有白水，都人無陸行。", "浮萍何處來，青青繞我楹。", "連牆已壞破，屋頼搘撐牢。", "緬懷所親友，親友皆占高。", "獨知歐陽公，直南望滔滔。", "遺奴揭厲往，答言頗力勞。", "正取舊戽斗，自課僮僕操。", "明日苟不已，挈家仍避逃。", "賢者尚若是，焉用數我曹。", "免爲不弔鬼，世上一鴻毛。"]'),
('f0dd34c4-47ac-48bc-bab8-f720564b7879','韓子華吳長文石昌言三舍人見訪','梅堯臣','宋','宋诗','song-poetry','','[]','當時載酒客，共過草玄人。',48,'全唐诗/poet.song.15000.json','["當時載酒客，共過草玄人。", "今日一寒士，能來三侍臣。", "竹門容大馬，金絡照諸鄰。", "雞瘦莫爲具，阮家依舊貧。"]'),
('a4fe1bf5-1fe4-4ff4-9d26-09f661ce6ded','送吉老學士兩浙提刑','梅堯臣','宋','宋诗','song-poetry','','[]','重本恤刑天子聖，舟車持詔使臣賢。',64,'全唐诗/poet.song.15000.json','["重本恤刑天子聖，舟車持詔使臣賢。", "部中漢吏無冤獄，葑上吳人益美田。", "重過故鄉逢故老，一聞鳴鶴訪山川。", "不須歌管唯詩酒，况有餘杭白樂天。"]'),
('81815935-dac1-4fa9-8720-c211ce02506d','永叔內翰見訪','梅堯臣','宋','宋诗','song-poetry','','[]','內相能來顧，爲郎樂有餘。',48,'全唐诗/poet.song.15000.json','["內相能來顧，爲郎樂有餘。", "兒童爭拂榻，門巷劣容車。", "掩扇知秋意，窺牆省舊書。", "經年三枉駕，未與故人疎。"]'),
('30151742-0b1a-4f7c-a125-1483548be75a','送石昌言舍人還蜀拜掃','梅堯臣','宋','宋诗','song-poetry','','[]','紫微星宿何煌煌，掖垣華閣上相當。',208,'全唐诗/poet.song.15000.json','["紫微星宿何煌煌，掖垣華閣上相當。", "舍人亦與泰階近，兩兩聯裾如雁行。", "其間飛星入王壘，天子賜告歸故鄉。", "錦韉金轡照棧去，文園渴令難可望。", "楊雄位卑纔執戟，豈有爵祿多文章。", "石公官顯職且貴，還家展墓酹椒漿。", "太守趨塵里人避，岷山松柏風淒涼。", "椎牛行酒與耆舊，耆舊醉歸呼此郎。", "公置名分共其樂，敦厚世俗時陶唐。", "郎呼只作曩日視，安知鏘玉侍明光。", "歸來却向鳳池直，詔言一出稱廟堂。", "廟堂蕭曹不草草，潤色鼓動辭琅琅。", "鰲頭蓬萊便可到，蜀人更賀烹豬羊。"]'),
('bd51db66-c53f-43ef-810d-cafcfeae9420','送劉元忠學士還南京','梅堯臣','宋','宋诗','song-poetry','','[]','昔見相公登瀛洲，今見公子爲校讎。',96,'全唐诗/poet.song.15000.json','["昔見相公登瀛洲，今見公子爲校讎。", "鯤鵬變化三十載，我生安得不白頭。", "君前拜恩父前慶，暫向南都乘順流。", "南都留守頗爲喜，將吏入賀靴聲遒。", "酒舁銀甕羊臠炙，上下和煦移凉秋。", "歸來却上柳堤路，西風健馬控花虬。"]'),
('2c652088-6c90-4447-a541-f1ac248f2ca1','送潤州通判李屯田','梅堯臣','宋','宋诗','song-poetry','','[]','過江始與風沙隔，京口山連北固牢。',64,'全唐诗/poet.song.15000.json','["過江始與風沙隔，京口山連北固牢。", "刺史丰儀於體重，邦人全伏以名高。", "宴盤紫蟹方多味，古寺青林不厭遨。", "定挈傳家舊圖籍，漕河應莫費吳艘。"]'),
('6ae1eef6-b4e1-4137-95f2-7ac786aa1522','寄題知儀州太保蒲中書齋','梅堯臣','宋','宋诗','song-poetry','','[]','中條插遠近，黄河瀉直斜。',124,'全唐诗/poet.song.15000.json','["中條插遠近，黄河瀉直斜。", "蒲坂之城在其涯，渠渠碧瓦十萬家。", "官商工農共擾擾，侯獨理齋窗照紗。", "侯方守邊聽胡笳，滿屋蓄書凡幾車。", "他年不按清商樂，亦莫學種東陵瓜。", "老繫戰馬向庭下，厨架整娖齊籤牙。", "朝聞鳴雞夕聞鴉，眼昏秋匣生銅花。", "兒孫誦習且盈耳，客來休論常山蛇。"]'),
('6ecf8098-fa36-40e7-a7b7-e22f1967a5b6','哭孫明復殿丞三首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','魯國先生歿，夷門吉士哀。',48,'全唐诗/poet.song.15000.json','["魯國先生歿，夷門吉士哀。", "因讒君席遠，時賻帝恩該。", "寂寞蒿宮啟，悠揚茜旐迴。", "昔賢皆不免，松下作寒灰。"]'),
('7516a4ba-ae55-4cb2-ac58-682c19e1668f','哭孫明復殿丞三首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','舊業居東岱，中年謁紫庭。',48,'全唐诗/poet.song.15000.json','["舊業居東岱，中年謁紫庭。", "要塗無往跡，至死守殘經。", "詔許求遺稿，朋鄰與葬銘。", "世人無怪我，涕淚爲之零。"]'),
('23ac79aa-03bc-486c-a334-a48faa8aad14','哭孫明復殿丞三首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','自古春秋學，皆知不可過。',48,'全唐诗/poet.song.15000.json','["自古春秋學，皆知不可過。", "生前恩禮少，歿後薦章多。", "妻子將焉託，田園有幾何。", "汶陽秋樹裏，黄鳥謾聽歌。"]'),
('4d99b4dc-9748-4df0-9a1d-e32022776960','程文簡公挽詞三首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','嘗預巖廊政，終爲社稷臣。',48,'全唐诗/poet.song.15000.json','["嘗預巖廊政，終爲社稷臣。", "作藩安舊俗，飲酒得賢人。", "葬禮鐃簫咽，明儀幣馬陳。", "泉堂一經掩，原上只麒麟。"]'),
('30883836-8e47-4879-8c0b-9018e6c2847b','程文簡公挽詞三首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','將相榮難及，唐虞世已遭。',48,'全唐诗/poet.song.15000.json','["將相榮難及，唐虞世已遭。", "名將官愈大，節固位同高。", "哀悼王朝輟，鎸埋史筆操。", "空山伊水外，松柏冷蕭騷。"]'),
('93f1b27c-20ae-4f87-b1b3-47aded8a301e','程文簡公挽詞三首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','闕塞秋雲冷，伊川苦霧陰。',48,'全唐诗/poet.song.15000.json','["闕塞秋雲冷，伊川苦霧陰。", "薤歌金鐸碎，蒿里石宮深。", "燃漆爲長夜，栽松作茂林。", "空留舊冠劍，家廟四時心。"]'),
('e5b7699c-5fed-4e01-a469-bc5b93b25e2c','送李殿丞通判蜀州','梅堯臣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','嘗聞蜀國海棠盛，因送李侯宜有詩。',96,'全唐诗/poet.song.15000.json','["嘗聞蜀國海棠盛，因送李侯宜有詩。", "日愛西湖照空錦，醉看春雨洗燕脂。", "郡無公事中園樂，民喜羣邀匝樹窺。", "望帝鳥啼空有血，相如人恨不同時。", "最鮮深淺非有染，解賦才華未得知。", "聞說趙昌今已老，試教圖畫兩三枝。"]'),
('61e29c94-0037-48b7-9e97-38cac17f7f11','八月十夜廣文直聞永叔內當','梅堯臣','宋','宋诗','song-poetry','','[]','聞向蓬萊宿，鼇峯第幾層。',48,'全唐诗/poet.song.15000.json','["聞向蓬萊宿，鼇峯第幾層。", "秋聲暗葉雨，殘夢空堂燈。", "推枕感孤雁，抽琴彈壞陵。", "誰知廣文直，桃簟冷於冰。"]'),
('02bf4bfe-818b-47a1-af71-cd28bce15401','和公儀龍圖新居栽竹二首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','八月竹根移要雨，逢陰便向阮家求。',32,'全唐诗/poet.song.15000.json','["八月竹根移要雨，逢陰便向阮家求。", "請公靜聽蕭蕭葉，斗變江南一夜秋。"]'),
('4a8902d1-5c53-48f7-b279-86d5bb8f566d','和公儀龍圖新居栽竹二首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','都城有地誰栽竹，只見寒樗與老槐。',32,'全唐诗/poet.song.15000.json','["都城有地誰栽竹，只見寒樗與老槐。", "聞種琅玕向新第，翠光秋影上屏來。"]'),
('da272ddc-265c-4ae4-950c-8adfa60dcca0','贈京西陳郎中','梅堯臣','宋','宋诗','song-poetry','','[]','忽枉乘軺車，鏘然響金轡。',96,'全唐诗/poet.song.15000.json','["忽枉乘軺車，鏘然響金轡。", "駐軫與我言，琅琅有深意。", "乃知故相家，事業已不墜。", "信哉渥洼種，千里可立致。", "顯祖實令君，名聲取高位。", "伯叔與懿考，聯榮重當世。", "于今多昆孫，朱紫紛曳地。", "勉勉崇令德，蘇李何難至。"]'),
('7310d264-0c97-4b19-9fae-871e367c7a20','送董著作知北海縣','梅堯臣','宋','宋诗','song-poetry','','[]','君嘗佑王屬，議平天下刑。',48,'全唐诗/poet.song.15000.json','["君嘗佑王屬，議平天下刑。", "出宰得古邑，農鋤多带經。", "素琴伴飲酒，綠蘚生訟庭。", "舉首望海雁，高懷在青冥。"]'),
('181c8db3-0a6e-40b3-b3f2-7b913e3321d6','送王微之學士知池州','梅堯臣','宋','宋诗','song-poetry','','[]','秋江渺然生寒潮，北風吹帆上青霄。',124,'全唐诗/poet.song.15000.json','["秋江渺然生寒潮，北風吹帆上青霄。", "旗脚舒舒戰紅鬣，旗心閃閃交皂雕。", "檣下健兒發金鐃，屋上鸞僮鳴紫簫。", "岸傍舟人望且拜，溪口直入當高譙。", "正聞鼓角波動摇，齊山舞翠挹岧嶢。", "郭西猛虎夜莫入，太守號令如怒飈。", "長戈樁爾喉，長刀斷爾腰。", "牙兵將吏無敢囂，新威烈烈野火燒。"]'),
('c787251a-add6-40aa-a1c8-5da78c20f9f1','讀永叔集古錄目','梅堯臣','宋','宋诗','song-poetry','','[]','古史書不足，磨璞鎸美辭。',140,'全唐诗/poet.song.15000.json','["古史書不足，磨璞鎸美辭。", "周宣石鼓文已缺，秦政嶧山字苦隳。", "西漢都無半畫在，黄初而上猶得窺。", "下及隋唐莫可數，奇言偉迹恐所遺。", "信都力黏大小軸，集十爲秩仍第之。", "隨目證訛甲癸推，青編是非皆究知。", "有益於古今不疑，碑雖滅絕事弗移。", "後人覽錄尚若披，信都用意無窮期。", "天灰地燼乃終畢，信都信都名愈出。"]'),
('c056cd19-2fa6-48fb-a68b-f95a6f5c676c','依韻和永叔秋日東城郊行','梅堯臣','宋','宋诗','song-poetry','','[]','郊原物老莽然中，寓興驅車向國東。',64,'全唐诗/poet.song.15000.json','["郊原物老莽然中，寓興驅車向國東。", "夾道名園迷屈曲，壓枝秋實亂青紅。", "寒畦覆綠將收菜，野蝶雙飛尚繞叢。", "田父欣來問行幸，依稀還似鬭雞翁。"]'),
('67e307e8-29de-49b0-8612-eddb4aee6569','送王景彝學士使虜','梅堯臣','宋','宋诗','song-poetry','','[]','持節共知過碣石，銜蘆相背有飛鴻。',64,'全唐诗/poet.song.15000.json','["持節共知過碣石，銜蘆相背有飛鴻。", "地寒狐腋著不暖，沙闊馬蹄行未窮。", "隴上牛羊衝密霰，帳前徒御立酸風。", "歸時莫問程多少，却到河湟杏萼紅。"]'),
('6aced3bc-cb8b-4c24-b0b2-499e53b105b2','哭王幾道職方三首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','前罷邯鄲守，孤高與世違。',48,'全唐诗/poet.song.15000.json','["前罷邯鄲守，孤高與世違。", "青雲舊知在，白首故園歸。", "既沒無兒女，元貧只帳幃。", "平生洛陽友，從此更應稀。"]'),
('f16264ea-e941-4ef0-aa8e-1cba8995ab54','哭王幾道職方三首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','我今過五十，萬事日消磨。',48,'全唐诗/poet.song.15000.json','["我今過五十，萬事日消磨。", "熟識世間寡，故交泉下多。", "葉秋知易隕，松耐竟如何。", "嘗亦悲前哲，荒墳野鼠窠。"]'),
('f49ecd51-6fb8-4b1e-a073-7b7fafe2d7a2','哭王幾道職方三首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','得君音信近，安穩在緱山。',48,'全唐诗/poet.song.15000.json','["得君音信近，安穩在緱山。", "不是國醫誤，寧辭蜀道艱。", "終然有脩短，猶免歷間關。", "便作千秋別，霑襟涕淚班。"]'),
('fb13a44f-15bb-4d97-98e4-1ff2c2de9fca','依韻和楊直講九日有感','梅堯臣','宋','宋诗','song-poetry','','[]','也持黄菊蕊，時望白衣人。',48,'全唐诗/poet.song.15000.json','["也持黄菊蕊，時望白衣人。", "苜蓿從來厭，茱萸却乍親。", "護霜雲不散，吹帽客何貧。", "莫要悲摇落，秋花更勝春。"]'),
('c7beb136-bb86-4871-a889-aff6fc030873','王侍講原叔挽詞三首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','衣冠今盛族，蘭玉舊家聲。',48,'全唐诗/poet.song.15000.json','["衣冠今盛族，蘭玉舊家聲。", "博古無遺悞，遭時有重名。", "魂輿臨水發，靈馬向郊鳴。", "歸葬商丘外，森森柏已成。"]'),
('1c0e4f3a-b373-473a-b060-b5d8807fba07','王侍講原叔挽詞三首  其二','梅堯臣','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','稽古逢堯舜，鏘金侍冕旒。',48,'全唐诗/poet.song.15000.json','["稽古逢堯舜，鏘金侍冕旒。", "生員尊鄭學，子舍預夔謀。", "翰苑事猶著，岱宗魂已遊。", "無情是天地，玉樹掩蒿丘。"]'),
('d11c4cfc-e421-4805-ac57-b134c05e5e0c','王侍講原叔挽詞三首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','丹旐秋風急，清笳曉月寒。',48,'全唐诗/poet.song.15000.json','["丹旐秋風急，清笳曉月寒。", "明衣裛草露，素士挽桐棺。", "行哭賓徒盛，觀儀里巷殫。", "空餘舊編在，千載莫能刊。"]'),
('94980555-e227-468c-b54c-493bbf8ab9a0','送公儀龍圖知杭州','梅堯臣','宋','宋诗','song-poetry','','[]','在昔漢中微，我祖入吳門。',156,'全唐诗/poet.song.15000.json','["在昔漢中微，我祖入吳門。", "公今領名都，千騎擁高軒。", "與古異出處，素節古本原。", "江觀白馬潮，水花長鯨奔。", "山飄月桂子，天香一國繁。", "壯奇已若此，纖侈尚亦存。", "舊聞其風俗，色易而柔溫。", "太守朝駕車，閭巷焚蘭蓀。", "太守暮還府，燈燭照旗旛。", "清歌延冠蓋，廣湖浮酒樽。", "成都與餘杭，天下莫比論。", "彼爲公故鄉，此爲公偃藩。", "吏民宜寡事，愷悌有謠言。"]'),
('5bc437e5-91f7-46b6-8b9b-b7ef14e72d6e','和楊直講夾竹花圖','梅堯臣','宋','宋诗','song-poetry','','[]','桃花夭紅竹浄綠，春風相間連溪谷。',176,'全唐诗/poet.song.15000.json','["桃花夭紅竹浄綠，春風相間連溪谷。", "花留蜂蝶竹有禽，三月江南看不足。", "徐熙下筆能逼真，蠒素畫成纔六幅。", "萼繁葉密有向背，枝瘦節疎有直曲。", "年深粉剝見墨縱，描寫工夫始驚俗。", "從初李氏國破亡，圖書散入公侯族。", "公侯三世多衰微，竊貿擔頭由婢僕。", "太學楊君固甚貧，直緣識別爭來鬻。", "朝質綈袍暮質琴，不憂明日鐺無粥。", "裝成如得驪頷珠，誰能更問龍牙軸。", "竹真似竹桃似桃，不待生春長在目。"]'),
('4ca08329-c5f9-48ca-97c7-3ecf15753a54','送李端明知河中府','梅堯臣','宋','宋诗','song-poetry','','[]','才業人終服，聰明帝所聞。',72,'全唐诗/poet.song.15000.json','["才業人終服，聰明帝所聞。", "來希段干木，去識大馮君。", "金絡鳴津口，朱旗颭雁羣。", "山河虞舊國，簫鼓漢橫汾。", "古蝶臨秋月，高樓等白雲。", "應同羊叔子，緩带隔囂氛。"]'),
('18dd14b7-8ffa-4077-824b-54e781d6fceb','依韻和永叔內翰西齋手植菊花過節始開偶書見寄','梅堯臣','宋','宋诗','song-poetry','','[]','晝惜日易沉，夜惜月易曉。',120,'全唐诗/poet.song.15000.json','["晝惜日易沉，夜惜月易曉。", "重陽種菊花，此意亦大好。", "所嗟時節晚，又失澆培早。", "開榮獨是遲，造化徒費巧。", "霜前擁繁萼，籬下同隕槁。", "微根發再綠，復笑王孫草。", "莊生語鵬鷃，樂不計大小。", "能齊乃有餘，但恐知者少。", "常愛阮嗣宗，遇酒醉則倒。", "杯中得賢趣，世上逐金裊。"]'),
('e77ca2fa-51b6-45dd-9547-b9c2d5ec6888','依韻和丁學士陪諸公城東飲','梅堯臣','宋','宋诗','song-poetry','','[]','黄花秋草滿荒臺，聯馬鳴珂未欲迴。',64,'全唐诗/poet.song.15000.json','["黄花秋草滿荒臺，聯馬鳴珂未欲迴。", "上苑自將馳道隔，高林空望白雲開。", "薦肴已去紗籠羃，賜醖新從蟻甕來。", "天氣正清風景好，重門雖禁不辭杯。"]'),
('8a77f3b8-f48f-484d-9b9f-7ae28a94bb70','依韻和池守王微之訪別','梅堯臣','宋','宋诗','song-poetry','','[]','君榮初出守，我老未東歸。',48,'全唐诗/poet.song.15000.json','["君榮初出守，我老未東歸。", "病眼生花早，蒼毛似葉稀。", "往還從更少，談笑暫相依。", "不及秋鴻翼，能隨向楚飛。"]'),
('4f9b5d79-e7f1-4ff8-a7b4-ab4ec122c879','寄題資州錢固秀才道勝堂','梅堯臣','宋','宋诗','song-poetry','','[]','醮壇舊山下，高卧一儒生。',48,'全唐诗/poet.song.15000.json','["醮壇舊山下，高卧一儒生。", "有室羅經籍，無心取組纓。", "芋肥收歲計，柑熟摘霜晴。", "暫向京都見，添書入蜀城。"]'),
('3e9fd96e-8f8e-4793-afb3-e7b946ef47dc','送黄國博知撫州','梅堯臣','宋','宋诗','song-poetry','','[]','逆水乘風上，蒲帆滿挂檣。',48,'全唐诗/poet.song.15000.json','["逆水乘風上，蒲帆滿挂檣。", "日行知幾里，江渺不分疆。", "宿浦隨潮入，逢人問路長。", "臨川十萬戶，勸勞執壺漿。"]'),
('d4c33315-84bb-49a8-b977-8e4cc9ccc47d','觀韓玉汝胡人貢奉圖','梅堯臣','宋','宋诗','song-poetry','','[]','時世重古不重新，破圖誰畫四胡人。',128,'全唐诗/poet.song.15000.json','["時世重古不重新，破圖誰畫四胡人。", "臂鷹捧盤犀利水，鐵鎖師子同麒麟。", "翹翹雉尾插頭上，深目鉅鼻青搭巾。", "塗朱點綠筆畫大，筋骨怒露蠻祠神。", "茜袍白馬韓公子，從何得此來秘珍。", "定應海客遠爲贈，中國未睹難擬倫。", "公子自言吳生筆，吳筆精勁瘦且勻。", "我恐非是不敢贊，退歸書此任從嗔。"]'),
('47baef04-6716-4520-b28d-8171d0c53521','送韓文饒贊善宰河南','梅堯臣','宋','宋诗','song-poetry','','[]','退之曾作河南宰，韓氏于今又見君。',64,'全唐诗/poet.song.15000.json','["退之曾作河南宰，韓氏于今又見君。", "縣政從來人有望，家聲不墜世多文。", "後池分洛貯藍水，高檻看嵩迷嶺雲。", "主簿堂前七葉樹，手栽應莫已刳焚。"]'),
('6813706f-73bb-4e45-a53d-050a1821b1f3','送刁秘校授漣水主簿歸四明省親','梅堯臣','宋','宋诗','song-poetry','','[]','桂得常娥枝，婦得黄姑女。',48,'全唐诗/poet.song.15000.json','["桂得常娥枝，婦得黄姑女。", "直歸東海頭，翁嫗笑相語。", "何當却之官，古縣入平楚。", "莫嫌簿書繁，百事由區處。"]'),
('8fde0e0d-8a99-4357-93d3-99c6f5014301','依韻和永叔戲作','梅堯臣','宋','宋诗','song-poetry','','[]','琵琶轉撥聲繁促，學作饑禽啄寒木。',264,'全唐诗/poet.song.15000.json','["琵琶轉撥聲繁促，學作饑禽啄寒木。", "木蠹生蟲細穴深，長啄歊鏗未充腹。", "朧弦疊響入衆耳，發自深林答空谷。", "上弦急逼下弦清，正如螗螂捕蟬聲。", "坐中賓歡呼酒飲，門外客疑將欲行。", "主人語客客莫去，彈到古樹裂丁丁。", "內賓外客曾未聽，乍聞此曲無不驚。", "還憶昭君入胡虜，烏孫帳下邊馬鳴。", "安知如今有樂事，能使女奚飛玉觥。", "女奚年小殊流俗，十月單衣體生粟。", "言事關西楊廣文，廣文空腹貪教曲。", "曲奇譜新偷法部，妙在取音時轉軸。", "翰林先生多所知，又笑畫圖收滿屋。", "不肯那錢買珠翠，任從堆插階前菊。", "功曹時借乃許出，他日求觀龜殻縮。", "我嗟老鈍不如渠，幸得交朋時借娛。", "但樂休計有與無。"]'),
('0a1a72aa-54fa-4949-9eac-2b357eb56b65','送吳仲庶殿院使北','梅堯臣','宋','宋诗','song-poetry','','[]','漢朝重結單于好，歲遣名臣禮數增。',64,'全唐诗/poet.song.15000.json','["漢朝重結單于好，歲遣名臣禮數增。", "紫鼠皮裘從去著，飛龍廐馬借來乘。", "天寒將遇磧中雪，鼻息暗添髭上冰。", "定見南鴻起歸思，家書欲寄不堪憑。"]'),
('1bb3594a-2d7e-4dfd-ab89-e710dabe41ae','送呂沖之司諫使北','梅堯臣','宋','宋诗','song-poetry','','[]','虜人多竊朝廷禮，譯者交傳應對辭。',64,'全唐诗/poet.song.15000.json','["虜人多竊朝廷禮，譯者交傳應對辭。", "羊酪調羹尊漢使，氈堂舉酒見閼氏。", "曚曚白日穿雲出，漭漭黄沙作霧吹。", "知去燕京幾千里，胡笳亂動月明時。"]'),
('7404af89-e7c2-40e0-8122-853a3656dd31','送孫隠之都官通判秀州','梅堯臣','宋','宋诗','song-poetry','','[]','柳條枯落盡，不折意徘徊。',48,'全唐诗/poet.song.15000.json','["柳條枯落盡，不折意徘徊。", "泛汴趨殘水，到吳看早梅。", "無耽聽鶴唳，有信寄鴻來。", "聞說閭亭改，靈光化劫灰。"]'),
('b5cfe0e7-6dad-4f5a-9ac7-d667e18c90e2','依韻和王平甫見寄','梅堯臣','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','兄爲太守兩輪朱，仲泛吳人燕尾艫。',64,'全唐诗/poet.song.15000.json','["兄爲太守兩輪朱，仲泛吳人燕尾艫。", "且看洞庭多橘柚，莫懷江國有枌榆。", "少遊山水殊非俗，老愛詩書又似愚。", "百事輸君休問我，風沙不比在雲湖。"]'),
('d2404d93-b520-46db-80ab-6a220f0467dc','得王介甫常州書','梅堯臣','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','斜封一幅竹膜紙，上有文字十七行。',378,'全唐诗/poet.song.15000.json','["斜封一幅竹膜紙，上有文字十七行。", "字如瘦棘攢黑刺，文如溫玉爛虹光。", "別時春風吹榆莢，及此已變蒹葭霜。", "道途與弟奉親樂，後各失子懷悲傷。", "到郡紛然因事物，舊守數易承蔽藏。", "搜姦證繆若治絮，蚤虱盡去煩爨湯。", "事成條舉作書尺，不肯勞人魚腹將。", "魚沉魚浮任所適，偶能及我爲非常。", "勤勤問我詩小傳，國風纔畢葛屨章。", "昔時許我到聖處，且避俗子多形相。", "未即寄去慎勿怪，他時不惜傾箱囊。", "知君亦欲此從事，君智自可施廟堂。", "何故區區守黄卷，蠹魚尚恥親芸香。", "我今正值雁南翔，報書與君倒肺腸。", "直須趁取筋力强，炊粳烹鱸加桂薑。", "洞庭綠橘包甘漿，舊楚黄橙綿作瓤。", "東山故遊携舞孃，不飲學舉黄金觴。", "谿如罨畫水泱泱，刺船靜入白鷺傍。", "菱葉已枯鏡面凉，月色飛上白石牀。", "坐看魚躍散星芒，左右寂寂夜何長。", "烏棲古曲傳吳王，千年萬年歌未央。", "莫作腐儒針膏肓，莫作健吏繩餓狼。", "儻如龔遂勸農桑，儻如黄霸致鳳皇。", "來不來，亦莫愛嘉祥。"]'),
('fb431b92-b0fa-465e-aaa1-41d30ff48e9d','司馬君實遺甘草杖','梅堯臣','宋','宋诗','song-poetry','','[]','美草將爲杖，孤生馬嶺危。',48,'全唐诗/poet.song.15000.json','["美草將爲杖，孤生馬嶺危。", "難從荷篠叟，寧入化龍陂。", "去與秦人采，來扶楚客衰。", "藥中稱國老，我懶豈能醫。"]'),
('7b1fdffe-889f-4dfb-bc09-9e6481bb3ea8','逢雷太簡殿丞','梅堯臣','宋','宋诗','song-poetry','','[]','長安初見君，君頷微有鬚。',156,'全唐诗/poet.song.15000.json','["長安初見君，君頷微有鬚。", "後於河內逢，秀峻美髯胡。", "又會在桐鄉，談時多孟盧。", "寧書得天然，鐘王不能奴。", "荏苒三十載，邂逅遇京都。", "朝接北扉飯，暮應西垣呼。", "坐中如夢寐，相語故人無。", "昔由處士召，胸懷開廟謨。", "今看髭已白，議論恥非夫。", "拜章陳時事，皆與相意符。", "其識固不淺，其用當亦殊。", "人多惜老大，我復歎羈孤。", "終朝重相笑，爲君傾酒壺。"]'),
('efc5d8c6-90e9-4d54-83f3-7fe4c25fdc74','雷太簡遺蜀鞭','梅堯臣','宋','宋诗','song-poetry','','[]','蜀道山之峭壁兮，如快刀一削平無痕。',137,'全唐诗/poet.song.15000.json','["蜀道山之峭壁兮，如快刀一削平無痕。", "其間春雷驚龍走，竹根迸石垂虺尾，骨節瘦密風霜吞。", "野夫采之縋懸蔓，分寸脫死持還奔。", "他人不可得此物，乃重太守公侯孫。", "獻來一錢不肯要，只乞斗酒抱歸村。", "太守立性豈諂貴，將贈故人唯義存。", "我騎瘦馬固莫稱，破韉爛轡沙塵昏。", "明日試執趨君門，孰不怪視竊笑言。"]'),
('8ee7e597-2653-4476-be66-83f3ce9457c9','得雷太簡自製蒙頂茶','梅堯臣','宋','宋诗','song-poetry','','[]','陸羽舊茶經，一意重蒙頂。',180,'全唐诗/poet.song.15000.json','["陸羽舊茶經，一意重蒙頂。", "比來唯建谿，團片敵金餠。", "顧渚及陽羨，又復下越茗。", "近來江國人，鷹爪夸雙井。", "凡今天下品，非此不覽省。", "蜀荈久無味，聲名謾馳騁。", "因雷與改造，带露摘牙穎。", "自煑至揉焙，入碾只俄頃。", "湯嫩乳花浮，香新舌甘永。", "初分翰林公，豈數博士冷。", "醉來不知惜，悔許已向醒。", "重思朋友義，果决在勇猛。", "倏然乃以贈，蠟囊收細梗。", "吁嗟茗與鞭，二物誠不幸。", "我貧事事無，得之似贅癭。"]'),
('02b7d680-4717-40f8-b449-6e1c309c2766','送呂寺丞希彥邠州簽判','梅堯臣','宋','宋诗','song-poetry','','[]','自有仲宣樂，從軍仍近親。',48,'全唐诗/poet.song.15000.json','["自有仲宣樂，從軍仍近親。", "關河歷周鄭，風雪過咸秦。", "原上方驅馬，鞍傍忽起鶉。", "世家傳釣玉，重問渭川濱。"]'),
('aea6bc49-8602-4471-a58c-2f2144c30187','送施司封福建提刑','梅堯臣','宋','宋诗','song-poetry','','[]','命使得才臣，欽刑聖主仁。',48,'全唐诗/poet.song.15000.json','["命使得才臣，欽刑聖主仁。", "銅苗休問發，田種去教親。", "白茗出溪上，紅蕉連海濱。", "輕車莫道遠，詔意重生民。"]'),
('35cd27b1-86c9-4b15-bc46-e495f03cda6b','江鄰幾暫來相見去後戲寄','梅堯臣','宋','宋诗','song-poetry','','[]','低頭拜我蒼髯翁，來如飛鳥去如風。',64,'全唐诗/poet.song.15000.json','["低頭拜我蒼髯翁，來如飛鳥去如風。", "一夕共飲斗柄北，平明已向函關東。", "衆中舊騎跛鼈馬，塞下新買連錢驄。", "疾驅似逐鄧林日，不肯暫往行何窮。"]'),
('3676c7e8-ca8f-4696-b348-8dde608b56f6','送徐無黨歸婺州','梅堯臣','宋','宋诗','song-poetry','','[]','吳蠶吐柔絲，越女織美紈。',96,'全唐诗/poet.song.15000.json','["吳蠶吐柔絲，越女織美紈。", "機杼固已勤，刀尺誠獨難。", "裁縫失分寸，長短爲損殘。", "嘗聞仲山甫，能補帝衮完。", "衮完民衣足，天下無苦寒。", "徐從信都學，染翦宜弃冠。", "彼實山甫徒，爾亦非綷剜。", "東歸道自勝，人誰故時看。"]'),
('b5389735-1dc5-4415-837c-01cecd925354','依韻和永叔內翰酬寄楊州劉原甫舍人','梅堯臣','宋','宋诗','song-poetry','','[]','東望淮海間，恨無鴻鵠羽。',132,'全唐诗/poet.song.15000.json','["東望淮海間，恨無鴻鵠羽。", "鴻鵠日已飛，風雪歲將暮。", "憶聽談老莊，達生無恐懼。", "我今齒髮疎，何異樹有蠹。", "離別不必道，俛仰已成故。", "書問雖懶爲，夢寐則往屢。", "乘桴思仲尼，好勇慙季路。", "願希隆中卧，不是邀三顧。", "二公廊廟才，酬寄封尺素。", "臯夔久相稱，舜禹時已遇。", "舉杯向明月，此意聊可寓。"]');
